window.HADITH_CACHE["ibnu-majah_8"] = {"4001":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ أَبِي مَالِكٍ الْأَشْجَعِيِّ عَنْ رِبْعِيِّ بْنِ حِرَاشٍ عَنْ حُذَيْفَةَ بْنِ الْيَمَانِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدْرُسُ الْإِسْلَامُ كَمَا يَدْرُسُ وَشْيُ الثَّوْبِ حَتَّى لَا يُدْرَى مَا صِيَامٌ وَلَا صَلَاةٌ وَلَا نُسُكٌ وَلَا صَدَقَةٌ وَلَيُسْرَى عَلَى كِتَابِ اللَّهِ عَزَّ وَجَلَّ فِي لَيْلَةٍ فَلَا يَبْقَى فِي الْأَرْضِ مِنْهُ آيَةٌ وَتَبْقَى طَوَائِفُ مِنْ النَّاسِ الشَّيْخُ الْكَبِيرُ وَالْعَجُوزُ يَقُولُونَ أَدْرَكْنَا آبَاءَنَا عَلَى هَذِهِ الْكَلِمَةِ لَا إِلَهَ إِلَّا اللَّهُ فَنَحْنُ نَقُولُهَافَقَالَ لَهُ صِلَةُ مَا تُغْنِي عَنْهُمْ لَا إِلَهَ إِلَّا اللَّهُ وَهُمْ لَا يَدْرُونَ مَا صَلَاةٌ وَلَا صِيَامٌ وَلَا نُسُكٌ وَلَا صَدَقَةٌ فَأَعْرَضَ عَنْهُ حُذَيْفَةُ ثُمَّ رَدَّهَا عَلَيْهِ ثَلَاثًا كُلَّ ذَلِكَ يُعْرِضُ عَنْهُ حُذَيْفَةُ ثُمَّ أَقْبَلَ عَلَيْهِ فِي الثَّالِثَةِ فَقَالَ يَا صِلَةُ تُنْجِيهِمْ مِنْ النَّارِ ثَلَاثًا","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Abu Malik Al Asyja'i] dari [Rib'I bin Hirasy] dari [Hudzaifah bin Yaman] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"(Ajaran) Islam akan terkikis sebagaimana hiasan baju yang terkikis sehingga tidak di ketahui apa itu puasa, apa itu shalat, apa itu ibadah dan apa itu sedekah, dan akan ditanggalkan Kitabullah di malam hari, sehingga tidak tersisa di muka bumi satu ayat pun. Yang tersisa adalah beberapa kelompok manusia yang telah lanjut usia dan lemah, mereka berkata, 'Kami menemui bapak-bapak kami di atas kalimat 'Tidak ada tuhan yang berhak disembah kecuali Allah', maka kami mengucapkannya.\" Shilah berkata kepadanya, \"Kalimat LA ILAAHA ILLALLAH tidak cukup bagi mereka, karena mereka tidak tahu apa itu shalat, apa itu puasa, apa itu ibadah dan apa itu sedekah.\" Maka Hudzaifah berpaling darinya, namun dia menolaknya, dan itu dilakukan sampai tiga kali, dan pada kali ketiganya dia menerimanya dan berkata, \"Wahai Shilah, kamu telah menyelamatkan mereka dari neraka.\" Ia mengucapkannya sebanyak tiga kali."},"4002":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبِي وَوَكِيعٌ عَنْ الْأَعْمَشِ عَنْ شَقِيقٍ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَكُونُ بَيْنَ يَدَيْ السَّاعَةِ أَيَّامٌ يُرْفَعُ فِيهَا الْعِلْمُ وَيَنْزِلُ فِيهَا الْجَهْلُ وَيَكْثُرُ فِيهَا الْهَرْجُ وَالْهَرْجُ الْقَتْلُ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [Ayahku] dan [Waki'] dari [Al A'masy] dari [Syaqiq] dari [Abdullah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hari-hari menjelang datangnya hari kiamat ilmu akan diangkat, banyak kebodohan dan menyebarnya al haraj. Dan al haraj adalah pembunuhan.\""},"4003":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ شَقِيقٍ عَنْ أَبِي مُوسَى قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْ وَرَائِكُمْ أَيَّامًا يَنْزِلُ فِيهَا الْجَهْلُ وَيُرْفَعُ فِيهَا الْعِلْمُ وَيَكْثُرُ فِيهَا الْهَرْجُ قَالُوا يَا رَسُولَ اللَّهِ وَمَا الْهَرْجُ قَالَ الْقَتْلُ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Syaqiq] dari [Abu Musa] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dibelakang kalian akan ada hari-hari dimana pada hari itu banyak menyebar kebodohan, ilmu diangkat dan banyak menyebar al haraj.\" Para sahabat bertanya, \"Wahai Rasulullah, apakah yang dimaksud dengan al haraj?\" beliau menjawab: \"Pembunuhan.\""},"4004":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا عَبْدُ الْأَعْلَى عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَيَرْفَعُهُ قَالَ يَتَقَارَبُ الزَّمَانُ وَيَنْقُصُ الْعِلْمُ وَيُلْقَى الشُّحُّ وَتَظْهَرُ الْفِتَنُ وَيَكْثُرُ الْهَرْجُ قَالُوا يَا رَسُولَ اللَّهِ وَمَا الْهَرْجُ قَالَ الْقَتْلُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdul A'la] dari [Ma'mar] dari [Az Zuhri] dari [Sa'id bin Musayyab] dari [Abu Hurairah] yang dimarfu'kan kepada Nabi, beliau bersabda: \"Waktu semakin cepat, ilmu semakin kurang, banyak kekikiran, fitnah banyak menyebar dan al haraj merajalela.\" Para sahabat bertanya, \"Wahai Rasulullah, apakah maksud dari al haraj?\" beliau menjawab: \"Pembunuhan.\""},"4005":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ الْأَعْمَشِ عَنْ زَيْدِ بْنِ وَهْبٍ عَنْ حُذَيْفَةَ قَالَحَدَّثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدِيثَيْنِ قَدْ رَأَيْتُ أَحَدَهُمَا وَأَنَا أَنْتَظِرُ الْآخَرَ قَالَ حَدَّثَنَا أَنَّ الْأَمَانَةَ نَزَلَتْ فِي جَذْرِ قُلُوبِ الرِّجَالِ قَالَ الطَّنَافِسِيُّ يَعْنِي وَسْطَ قُلُوبِ الرِّجَالِ وَنَزَلَ الْقُرْآنُ فَعَلِمْنَا مِنْ الْقُرْآنِ وَعَلِمْنَا مِنْ السُّنَّةِ ثُمَّ حَدَّثَنَا عَنْ رَفْعِهَا فَقَالَ يَنَامُ الرَّجُلُ النَّوْمَةَ فَتُرْفَعُ الْأَمَانَةُ مِنْ قَلْبِهِ فَيَظَلُّ أَثَرُهَا كَأَثَرِ الْوَكْتِ وَيَنَامُ النَّوْمَةَ فَتُنْزَعُ الْأَمَانَةُ مِنْ قَلْبِهِ فَيَظَلُّ أَثَرُهَا كَأَثَرِ الْمَجْلِ كَجَمْرٍ دَحْرَجْتَهُ عَلَى رِجْلِكَ فَنَفِطَ فَتَرَاهُ مُنْتَبِرًا وَلَيْسَ فِيهِ شَيْءٌ ثُمَّ أَخَذَ حُذَيْفَةُ كَفًّا مِنْ حَصًى فَدَحْرَجَهُ عَلَى سَاقِهِ قَالَ فَيُصْبِحُ النَّاسُ يَتَبَايَعُونَ وَلَا يَكَادُ أَحَدٌ يُؤَدِّي الْأَمَانَةَ حَتَّى يُقَالَ إِنَّ فِي بَنِي فُلَانٍ رَجُلًا أَمِينًا وَحَتَّى يُقَالَ لِلرَّجُلِ مَا أَعْقَلَهُ وَأَجْلَدَهُ وَأَظْرَفَهُ وَمَا فِي قَلْبِهِ حَبَّةُ خَرْدَلٍ مِنْ إِيمَانٍوَلَقَدْ أَتَى عَلَيَّ زَمَانٌ وَلَسْتُ أُبَالِي أَيَّكُمْ بَايَعْتُ لَئِنْ كَانَ مُسْلِمًا لَيَرُدَّنَّهُ عَلَيَّ إِسْلَامُهُ وَلَئِنْ كَانَ يَهُودِيًّا أَوْ نَصْرَانِيًّا لَيَرُدَّنَّهُ عَلَيَّ سَاعِيهِ فَأَمَّا الْيَوْمَ فَمَا كُنْتُ لِأُبَايِعَ إِلَّا فُلَانًا وَفُلَانًا","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Waki'] dari [Al A'masy] dari [Zaid bin Wahb] dari [Hudzaifah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam menceritakan kepadaku dua peristiwa, aku telah melihat satu dari keduanya dan aku sedang menunggu yang lainnya. Beliau memberitahukan kepada kami bahwa amanat telah turun dilubuk hati seseorang. -At Thanafisi berkata; maksudnya di tengah hati seseorang- Al-Qur'an turun hingga kami pun bisa mengetahui darinya, dan juga dari sunnah. Kemudian beliau menceritakan kepada kami tentang diangkatnya amanat, beliau mengatakan: \"Seseorang terlelap dalam tidurnya lalu diangkatlah amanat tersebut dari hatinya, dan hanya tertinggal sedikit. Lalu ia tidur dan diangkatlah amanah hingga tertinggal bekasnya seperti lepuh kulit, seperti bara api yang kamu gelincirkan dengan kakimu hingga melepuh (terluka), dan kamu melihatnya menggembung, padahal tidak ada sesuatu di dalamnya.\" Kemudian Hudzaifah mengambil segenggam kerikil, lalu ia menggelincirkan dengan betisnya seraya berkata, \"Maka orang-orang pun akan saling berbaiat, dan nyaris tidak ada seorangpun yang menjalankan amanat. Hingga dikatakan, 'Sesungguhnya di Kabilah si Fulan terdapat seorang laki-laki yang jujur.' Kemudian dikatakan kepada seorang laki-laki yang jujur itu, 'Pandai sekali ia, dan beruntunglah ia.' Padahal di dalam hatinya tidak ada keimanan sebesar biji gandum sekalipun.\" Sesungguhnya telah tiba suatu zaman kepadaku saat aku tidak peduli mana yang layak aku baiat. Jika ia seorang muslim, maka pastilah ia akan memperlihatkan kepadaku keIslamannya. Jika ia seorang Yahudi atau Nashrani, pastilah ia akan memperlihatkan kepadaku usahanya. Adapun hari ini, tidaklah aku hanya membaiat si fulan dan si fulan.\""},"4006":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُصَفَّى حَدَّثَنَا مُحَمَّدُ بْنُ حَرْبٍ عَنْ سَعِيدِ بْنِ سِنَانٍ عَنْ أَبِي الزَّاهِرِيَّةِ عَنْ أَبِي شَجَرَةَ كَثِيرِ بْنِ مُرَّةَ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى ال��َّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ عَزَّ وَجَلَّ إِذَا أَرَادَ أَنْ يُهْلِكَ عَبْدًا نَزَعَ مِنْهُ الْحَيَاءَ فَإِذَا نَزَعَ مِنْهُ الْحَيَاءَ لَمْ تَلْقَهُ إِلَّا مَقِيتًا مُمَقَّتًا فَإِذَا لَمْ تَلْقَهُ إِلَّا مَقِيتًا مُمَقَّتًا نُزِعَتْ مِنْهُ الْأَمَانَةُ فَإِذَا نُزِعَتْ مِنْهُ الْأَمَانَةُ لَمْ تَلْقَهُ إِلَّا خَائِنًا مُخَوَّنًا فَإِذَا لَمْ تَلْقَهُ إِلَّا خَائِنًا مُخَوَّنًا نُزِعَتْ مِنْهُ الرَّحْمَةُ فَإِذَا نُزِعَتْ مِنْهُ الرَّحْمَةُ لَمْ تَلْقَهُ إِلَّا رَجِيمًا مُلَعَّنًا فَإِذَا لَمْ تَلْقَهُ إِلَّا رَجِيمًا مُلَعَّنًا نُزِعَتْ مِنْهُ رِبْقَةُ الْإِسْلَامِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mushaffa] telah menceritakan kepada kami [Muhammad bin Harb] dari [Sa'id bin Sinan] dari [Abu Az Zahiriyah] dari [Abu Syajarah Katsir bin Murrah] dari [Ibnu Umar], bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Apabila Allah 'azza wajalla hendak membinasakan seorang hamba maka Dia akan memcabut rasa malu darinya, apabila rasa malu sudah dicabut darinya maka kamu akan mendapatinya dalam keadaan sangat dibenci. Jika kamu tidak mendapatinya melainkan dalam keadaan sangat dibenci, maka akan dicabut amanah darinya, apabila amanah telah dicabut darinya, maka kamu tidak mendapatinya kecuali dalam keadaan menipu dan tertipu. Apabila kamu tidak menjumpainya melainkan dalam keadaan menipu dan tertipu, maka akan dicabut darinya sifat kasih sayang, dan apabila dicabut darinya kasih sayang, kamu tidak akan menjumpainya kecuali dalam keadaan terlaknat lagi terusir, dan apabila kamu tidak menjumpainya melainkan dalam keadaan terlaknat lagi terusir, maka akan dicabut darinya ikatan Islam.\""},"4007":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ فُرَاتٍ الْقَزَّازِ عَنْ عَامِرِ بْنِ وَاثِلَةَ أَبِي الطُّفَيْلِ الْكِنَانِيِّ عَنْ حُذَيْفَةَ بْنِ أَسِيدٍ أَبِي سَرِيحَةَ قَالَاطَّلَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ غُرْفَةٍ وَنَحْنُ نَتَذَاكَرُ السَّاعَةَ فَقَالَ لَا تَقُومُ السَّاعَةُ حَتَّى تَكُونَ عَشْرُ آيَاتٍ طُلُوعُ الشَّمْسِ مِنْ مَغْرِبِهَا وَالدَّجَّالُ وَالدُّخَانُ وَالدَّابَّةُ وَيَأْجُوجُ وَمَأْجُوجُ وَخُرُوجُ عِيسَى ابْنِ مَرْيَمَ عَلَيْهِ السَّلَام وَثَلَاثُ خُسُوفٍ خَسْفٌ بِالْمَشْرِقِ وَخَسْفٌ بِالْمَغْرِبِ وَخَسْفٌ بِجَزِيرَةِ الْعَرَبِ وَنَارٌ تَخْرُجُ مِنْ قَعْرِ عَدَنِ أَبْيَنَ تَسُوقُ النَّاسَ إِلَى الْمَحْشَرِ تَبِيتُ مَعَهُمْ إِذَا بَاتُوا وَتَقِيلُ مَعَهُمْ إِذَا قَالُوا","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Sufyan] dari [Farrat Al Qazzaz] dari ['Amir bin Wastsilah Abu At Thufail Al Kinani] dari [Hudzaifah bin Asid Abu Sarihah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah melongok dari suatu ruangan ketika kami sedang berdiskusi mengenai hari Kiamat. Lalu beliau bersabda: \"Hari kiamat tidak akan terjadi sampai terjadinya sepuluh dari tanda-tandanya, yatiu terbitnya matahari dari barat, munculnya Dajjal, munculnya awan, keluarnya binatang melata, datangnya Ya'juj dan Ma'juj, keluarnya Isa putera Maryam 'Alaihi salam, terjadinya tiga gerhana, yaitu; gerhana di timur, gerhana di barat dan gerhana di Jazirah Arab, dan api yang keluar dari Qar' adn yang menggiring mereka ke padang Mahsyar. Api tersebut akan berhenti bersama mereka jika mereka berhenti, dan akan bicara dengan mereka jika mereka bicara.\""},"4008":{"ar":"حَدَّثَنَا حَرْمَلَةُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ وَابْنُ لَهِيعَةَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ سِنَانِ بْنِ سَعْدٍ عَنْ أَنَسِ بْنِ مَالِكٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَادِرُوا بِالْأَعْمَالِ سِتًّا طُلُوعَ الشَّمْسِ مِنْ مَغْرِبِهَا وَالدُّخَانَ وَدَابَّةَ الْأَرْضِ وَالدَّجَّالَ وَخُوَيْصَّةَ أَحَدِكُمْ وَأَمْرَ الْعَامَّةِ","id":"Telah menceritakan kepada kami [Harmalah bin Yahya] telah menceritakan kepada kami [Abdullah bin Wahb] telah mengabarkan kepadaku ['Amru bin Al Harits] dan [Ibnu Lahi'ah] dari [Yazid bin Abu Habib] dari [Sinan bin Sa'd] dari [Anas bin Malik] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Lekaslah kalian beramal sebelum datangnya enam perkara; terbitnya matahari dari barat, keluarnya asap, binatang melata bumi, Dajjal, kematian salah seorang dari kalian dan hancurnya dunia.\""},"4009":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ حَدَّثَنَا عَوْنُ بْنُ عُمَارَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُثَنَّى بْنِ ثُمَامَةَ بْنِ عَبْدِ اللَّهِ بْنِ أَنَسٍ عَنْ جَدِّهِ عَنْ أَنَسِ بْنِ مَالِكٍ عَنْ أَبِي قَتَادَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْآيَاتُ بَعْدَ الْمِائَتَيْنِ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali Al Khallal] telah menceritakan kepada kami ['Aun bin 'Umarah] telah menceritakan kepada kami [Abdullah bin Al Mutsanna bin Tsumamah bin Abdullah bin Anas] dari [Kakeknya] dari [Anas bin Malik] dari [Abu Qatadah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tanda-tandanya adalah setelah dua ratus.\""},"4010":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا نُوحُ بْنُ قَيْسٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَعْقِلٍ عَنْ يَزِيدَ الرَّقَاشِيِّ عَنْ أَنَسِ بْنِ مَالِكٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أُمَّتِي عَلَى خَمْسِ طَبَقَاتٍ فَأَرْبَعُونَ سَنَةٍ أَهْلُ بِرٍّ وَتَقْوَى ثُمَّ الَّذِينَ يَلُونَهُمْ إِلَى عِشْرِينَ وَمِائَةِ سَنَةٍ أَهْلُ تَرَاحُمٍ وَتَوَاصُلٍ ثُمَّ الَّذِينَ يَلُونَهُمْ إِلَى سِتِّينَ وَمِائَةِ سَنَةٍ أَهْلُ تَدَابُرٍ وَتَقَاطُعٍ ثُمَّ الْهَرْجُ الْهَرْجُ النَّجَا النَّجَاحَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ حَدَّثَنَا خَازِمٌ أَبُو مُحَمَّدٍ الْعَنَزِيُّ حَدَّثَنَا الْمِسْوَرُ بْنُ الْحَسَنِ عَنْ أَبِي مَعْنٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُمَّتِي عَلَى خَمْسِ طَبَقَاتٍ كُلُّ طَبَقَةٍ أَرْبَعُونَ عَامًا فَأَمَّا طَبَقَتِي وَطَبَقَةُ أَصْحَابِي فَأَهْلُ عِلْمٍ وَإِيمَانٍ وَأَمَّا الطَّبَقَةُ الثَّانِيَةُ مَا بَيْنَ الْأَرْبَعِينَ إِلَى الثَّمَانِينَ فَأَهْلُ بِرٍّ وَتَقْوَى ثُمَّ ذَكَرَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Nahsr bin Ali Al Jahdlami] telah menceritakan kepada kami [Nuh bin Qais] telah menceritakan kepada kami [Abdullah bin Ma'qil] dari [Yazid Ar Raqasyi] dari [Anas bin Malik] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Umatku akan terbagi menjadi lima tingkatan, empat puluh tahun adalah orang yang berprilaku baik dan bertakwa, kemudian setelah mereka sampai ke seratus dua puluh tahun adalah orang-orang yang suka menyayangi dan menyambung silaturrahim, kemudian setelah mereka sampai seratus enam puluh tahun adalah orang-orang yang suka bermusuhan dan saling memutus hubungan, kemudian pembunuhan, kemudian pembunuhan, kemudian keselamatan, kemudian keselamatan.\" Telah menceritakan kepada kami [Nahsr bin Ali] telah menceritakan kepada kami [Khazim Abu Muhammad Al 'Anazi] telah menceritakan kepada kami [Al Miswar bin Al Hasan] dari [Abu Ma'an] dari [Anas bin Malik] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ummatku berada dilima tingkatan, dari setiap tingkatan berjarak empat puluh tahun. Adapun tingkatanku adalah tingkatan sahabat-sahabatku, mereka adalah ahli ilmu dan iman. Tingkatan yang kedua adalah antara empat puluh sampai delapan puluh, mereka adalah pelaku kebaikan dan ketakwaan…kemudian ia menyebutkan seperti yang di atas.\""},"4011":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا أَبُو أَحْمَدَ حَدَّثَنَا بَشِيرُ بْنُ سَلْمَانُ عَنْ سَيَّارٍ عَنْ طَارِقٍ عَنْ عَبْدِ اللَّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَيْنَ يَدَيْ السَّاعَةِ مَسْخٌ وَخَسْفٌ وَقَذْفٌ","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] telah menceritakan kepada kami [Abu Ahmad] telah menceritakan kepada kami [Basyir bin Salman] dari [Sayyar] dari [Thariq] dari [Abdullah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Diantara tanda-tanda hari Kiamat adalah akan terjadi perubahan bentuk, penenggelaman dan pemfitnahan (tuduhan zina terhadap wanita).\""},"4012":{"ar":"حَدَّثَنَا أَبُو مُصْعَبٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِي حَازِمِ بْنِ دِينَارٍ عَنْ سَهْلِ بْنِ سَعْدٍأَنَّهُ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَكُونُ فِي آخِرِ أُمَّتِي خَسْفٌ وَمَسْخٌ وَقَذْفٌ","id":"Telah menceritakan kepada kami [Abu Mush'ab] telah menceritakan kepada kami [Abdurrahman bin Zaid bin Aslam] dari [Abu Hazim bin Dinar] dari [Sahl bin Sa'd], bahwa dia mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Akan terjadi di akhir ummatku suatu peneggelaman (ke perut bumi), perubahan bentuk, dan pemfitnahan (tuduhan zina terhadap wanita).\""},"4013":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ وَمُحَمَّدُ بْنُ الْمُثَنَّى قَالَا حَدَّثَنَا أَبُو عَاصِمٍ حَدَّثَنَا حَيْوَةُ بْنُ شُرَيْحٍ حَدَّثَنَا أَبُو صَخْرٍ عَنْ نَافِعٍأَنَّ رَجُلًا أَتَى ابْنَ عُمَرَ فَقَالَ إِنَّ فُلَانًا يُقْرِئُكَ السَّلَامَ قَالَ إِنَّهُ بَلَغَنِي أَنَّهُ قَدْ أَحْدَثَ فَإِنْ كَانَ قَدْ أَحْدَثَ فَلَا تُقْرِئْهُ مِنِّي السَّلَامَ فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَكُونُ فِي أُمَّتِي أَوْ فِي هَذِهِ الْأُمَّةِ مَسْخٌ وَخَسْفٌ وَقَذْفٌ وَذَلِكَ فِي أَهْلِ الْقَدَرِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] dan [Muhammad bin Mutsanna] keduanya berkata; telah menceritakan kepada kami [Abu 'Ashim] telah menceritakan kepada kami [Haiwah bin Syuraih] telah menceritakan kepada kami [Abu Shahr] dari [Nafi'] bahwa seorang laki-laki datang kepada Ibnu 'Umar dan berkata, \"Sesungguhnya Fulan mengirimkan salam untukmu.\" [Ibnu Umar] lalu berkata, \"Telah sampai kabar kepadaku bahwa dia telah melakukan perbuatan yang baru (bid'ah), jika dia telah melakukan perkara baru maka janganlah kamu sampaikan salam dariku kepadanya, karena aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Akan terjadi pada ummatku atau diummat ini perubahan bentuk, penenggelaman (ke perut bumi) dan pemfitnahan (tuduhan zina kepada wanita). Dan hal itu telah terjadi pada pengikut paham Qadariyah.\""},"4014":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ وَمُحَمَّدُ بْنُ فُضَيْلٍ عَنْ الْحَسَنِ بْنِ عَمْرٍو عَنْ أَبِي الزُّبَيْرِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَكُونُ فِي أُمَّتِي خَسْفٌ وَمَسْخٌ وَقَذْفٌ","id":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Abu Mu'awiyah] dan [Muhammad bin Fudlail] dari [Al Hasan bin 'Amru] dari [Abu Az Zubair] dari [Abdullah bin 'Amru] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Akan terjadi pada umatku penenggelaman ke dalam bumi, perubahan bentuk dan tuduhan zina (terhadap wanita).\""},"4015":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أُمَيَّةَ بْنِ صَفْوَانَ بْنِ عَبْدِ اللَّهِ بْنِ صَفْوَانَ سَمِعَ جَدَّهُ عَبْدَ اللَّهِ بْنَ صَفْوَانَ يَقُولُ أَخْبَرَتْنِي حَفْصَةُأَنَّهَا سَمِعَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَيَؤُمَّنَّ هَذَا الْبَيْتَ جَيْشٌ يَغْزُونَهُ حَتَّى إِذَا كَانُوا بِبَيْدَاءَ مِنْ الْأَرْضِ خُسِفَ بِأَوْسَطِهِمْ وَيَتَنَادَى أَوَّلُهُمْ آخِرَهُمْ فَيُخْسَفُ بِهِمْ فَلَا يَبْقَى مِنْهُمْ إِلَّا الشَّرِيدُ الَّذِي يُخْبِرُ عَنْهُمْفَلَمَّا جَاءَ جَيْشُ الْحَجَّاجِ ظَنَنَّا أَنَّهُمْ هُمْ فَقَالَ رَجُلٌ أَشْهَدُ عَلَيْكَ أَنَّكَ لَمْ تَكْذِبْ عَلَى حَفْصَةَ وَأَنَّ حَفْصَةَ لَمْ تَكْذِبْ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Umayyah bin Shafwan bin Abdullah bin Shafwan] dia mendengar kakeknya [Abdullah bin Shafwan] berkata; telah mengabarkan kepadaku [Hafshah], bahwa dia pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Rumah ini (Masjidil Haram) akan senantiasa diperangi oleh sekelompok pasukan yang akan memeranginya. Sehingga ketika mereka berada di Biada (nama tempat), maka mereka yang berada di tengah-tengah ditenggelamkan ke dasar bumi sehingga orang-orang yang berada di barisan pertama menyeru kepada orang-orang yang berada di barisan ter akhir, hingga mereka tenggelam semuanya. Dan tidak ada seorang pun yang tersisa melainkan yang tersisa itu akan menceritakan kabar mereka.\" Maka tatkala tentara Hajjaj datang, kami menyangka tentara itulah yang di maksud, lantas seorang laki-laki berkata, \"Saya bersaksi bahwa kamu tidak berdusta atas Hafshah, dan Hafshah tidak berdusta atas Nabi shallallahu 'alaihi wasallam.\""},"4016":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا الْفَضْلُ بْنُ دُكَيْنٍ حَدَّثَنَا سُفْيَانُ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ أَبِي إِدْرِيسَ الْمُرْهِبِيِّ عَنْ مُسْلِمِ بْنِ صَفْوَانَ عَنْ صَفِيَّةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَنْتَهِي النَّاسُ عَنْ غَزْوِ هَذَا الْبَيْتِ حَتَّى يَغْزُوَ جَيْشٌ حَتَّى إِذَا كَانُوا بِالْبَيْدَاءِ أَوْ بَيْدَاءَ مِنْ الْأَرْضِ خُسِفَ بِأَوَّلِهِمْ وَآخِرِهِمْ وَلَمْ يَنْجُ أَوْسَطُهُمْ قُلْتُ فَإِنْ كَانَ فِيهِمْ مَنْ يُكْرَهُ قَالَ يَبْعَثُهُمْ اللَّهُ عَلَى مَا فِي أَنْفُسِهِمْ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Al Fadhl bin Dukain] telah menceritakan kepada kami [Sufyan] dari [Salamah bin Kuhail] dari [Abu Idris Al Murhibi] dari [Muslim bin Shafwan] dari [Shafiyah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang-orang tidak akan berhenti memerangi rumah ini (Ka'bah) sampai ada sekelompok pasukan yang akan memeranginya, Disaat mereka berada di Baida atau di satu padang sahara di atas bumi, mereka ditenggelamkan baik yang pertama dan yang terakhir, dan orang-orang yang ada di barisan tengah pun tidak ada yang selamat.\" Aku bertanya, \"Bagaimana dengan orang-orang yang dipaksa di antara mereka?\" beliau menjawab: \"Allah akan membangkitkan mereka berdasarkan apa yang ada dihati mereka.\""},"4017":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ وَنَصْرُ بْنُ عَلِيٍّ وَهَارُونُ بْنُ عَبْدِ اللَّهِ الْحَمَّالُ قَالُوا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ مُحَمَّدِ بْنِ سُوقَةَ سَمِعَ نَافِعَ بْنَ جُبَيْرٍ يُخْبِرُ عَنْ أُمِّ سَلَمَةَ قَالَتْذَكَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْجَيْشَ الَّذِي يُخْسَفُ بِهِمْ فَقَالَتْ أُمُّ سَلَمَةَ يَا رَسُولَ اللَّهِ لَعَلَّ فِيهِمْ الْمُكْرَهَ قَالَ إِنَّهُمْ يُبْعَثُونَ عَلَى نِيَّاتِهِمْ","id":"Telah menceritakan kepada kami [Muhammad bin As Shabah] dan [Nashr bin Ali] serta [Harun bin Abdullah Al Hammal] mereka berkata; telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Muhammad bin Suqah] dia mendengar [Nafi' bin Jubair] telah mengabarkan dari [Ummu Salamah] dia berkata, \"Nabi shallallahu 'alaihi wasallam pernah menyebutkan pasukan yang ditenggelamkan, maka Ummu Salamah bertanya, \"Wahai Rasulullah, bagaimana dengan mereka yang dipaksa?\" beliau menjawab: \"Mereka akan dibangkitkan sesuai dengan niat mereka.\""},"4018":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَلِيِّ بْنِ زَيْدٍ عَنْ أَوْسِ بْنِ خَالِدٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تَخْرُجُ الدَّابَّةُ وَمَعَهَا خَاتَمُ سُلَيْمَانَ بْنِ دَاوُدَ وَعَصَا مُوسَى بْنِ عِمْرَانَ عَلَيْهِمَا السَّلَام فَتَجْلُو وَجْهَ الْمُؤْمِنِ بِالْعَصَا وَتَخْطِمُ أَنْفَ الْكَافِرِ بِالْخَاتِمِ حَتَّى أَنَّ أَهْلَ الْحِوَاءِ لَيَجْتَمِعُونَ فَيَقُولُ هَذَا يَا مُؤْمِنُ وَيَقُولُ هَذَا يَا كَافِرُقَالَ أَبُو الْحَسَنِ الْقَطَّانُ حَدَّثَنَاهُ إِبْرَاهِيمُ بْنُ نَصْرٍ حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ فَذَكَرَ نَحْوَهُ وَقَالَ فِيهِ مَرَّةً فَيَقُولُ هَذَا يَا مُؤْمِنُ وَهَذَا يَا كَافِرُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Yunus bin Muhammad] telah menceritakan kepada kami [Hammad bin Salamah] dari [Ali bin Zaid] dari [Aus bin Khalid] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Binatang melata akan keluar dengan membawa cincinya Sulaiman bin Daud dan tongkatnya Musa bin Imran 'Alaihimas salam, kemudian ia menandai wajah setiap orang mukmin dengan tongkat dan memukul hidung orang kafir dengan cincin. Sehingga orang-orang yang rumahnya berada didekat air berkumpul, lalu binatang tersebut berkata, 'Ini adalah mukmin, ' dan berkata, 'Ini adalah kafir'.\""},"4019":{"ar":"حَدَّثَنَا أَبُو غَسَّانَ مُحَمَّدُ بْنُ عَمْرٍو زُنَيْجٌ حَدَّثَنَا أَبُو تُمَيْلَةَ حَدَّثَنَا خَالِدُ بْنُ عُبَيْدٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بُرَيْدَةَ عَنْ أَبِيهِ قَالَذَهَبَ بِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى مَوْضِعٍ بِالْبَادِيَةِ قَرِيبٍ مِنْ مَكَّةَ فَإِذَا أَرْضٌ يَابِسَةٌ حَوْلَهَا رَمْلٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَخْرُجُ الدَّابَّةُ مِنْ هَذَا الْمَوْضِعِ فَإِذَا فِتْرٌ فِي شِبْرٍقَالَ ابْنُ بُرَيْدَةَ فَحَجَجْتُ بَعْدَ ذَلِكَ بِسِنِينَ فَأَرَانَا عَصًا لَهُ فَإِذَا هُوَ بِعَصَايَ هَذِهِ هَكَذَا وَهَكَذَا","id":"Telah menceritakan kepada kami [Abu Ghassan Muhammad bin 'Amru Zunaij] telah menceritakan kepada kami [Abu Tumailah] telah menceritakan kepada kami [Khalid bin 'Ubaid] telah menceritakan kepada kami [Abdullah bin Buraidah] dari [ayahnya] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah bepergian denganku ke suatu perkampungan dekat kota Makkah -ternyata ia adalah tanah tandus dan di sekitarnya hanya bebatuan kecil-, lantas Rasulullah shallallahu 'alaihi wasallam bersabda: \"Binatang malata akan muncul dari tempat ini yang ternyata (tanahnya) lembek dengan kedalaman sejengkal.\" Ibnu Buraidah berkata, \"Setelah beberapa tahun, saya melaksanakan haji dan kami melihat tongkat milik beliau seperti tongkatku ini seperti ini dan ini.\""},"4020":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ عُمَارَةَ بْنِ الْقَعْقَاعِ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تَقُومُ السَّاعَةُ حَتَّى تَطْلُعَ الشَّمْسُ مِنْ مَغْرِبِهَا فَإِذَا طَلَعَتْ وَرَآهَا النَّاسُ آمَنَ مَنْ عَلَيْهَا فَذَلِكَ حِينَ لَا يَنْفَعُ نَفْسًا إِيمَانُهَا لَمْ تَكُنْ آمَنَتْ مِنْ قَبْلُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Muhammad bin Fudlail] dari ['Umarah bin Al Qa'qa'] dari [Abu Zur'ah] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak akan terjadi hari Kiamat sehingga matahari terbit dari barat, apabila manusia melihat ia telah terbit (dari barat), maka mereka akan beriman semuanya, namun hal itu tidak lagi bermanfaat (keimanan) mereka (karena) mereka sebelumnya tidak beriman.\""},"4021":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي حَيَّانَ التَّيْمِيِّ عَنْ أَبِي زُرْعَةَ بْنِ عَمْرِو بْنِ جَرِيرٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوَّلُ الْآيَاتِ خُرُوجًا طُلُوعُ الشَّمْسِ مِنْ مَغْرِبِهَا وَخُرُوجُ الدَّابَّةِ عَلَى النَّاسِ ضُحًىقَالَ عَبْدُ اللَّهِ فَأَيَّتُهُمَا مَا خَرَجَتْ قَبْلَ الْأُخْرَى فَالْأُخْرَى مِنْهَا قَرِيبٌ قَالَ عَبْدُ اللَّهِ وَلَا أَظُنُّهَا إِلَّا طُلُوعَ الشَّمْسِ مِنْ مَغْرِبِهَا","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Sufyan] dari [Abu Hayyan At Taimi] dari [Abu Zur'ah bin 'Amru bin Jarir] dari [Abdullah bin 'Amru] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tanda-tanda yang pertama kali keluar adalah terbitnya matahari dari barat, keluarnya binatang melata kepada manusia pada waktu pagi.\" Abdullah berkata, \"Tidaklah salah satu dari keduanya muncul lebih awal kecuali yang lain akan menyusul keluar secepatnya.\" Berkata Abdullah, \"Aku tidak mengira kecuali terbitnya matahari dari barat.\""},"4022":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ إِسْرَائِيلَ عَنْ عَاصِمٍ عَنْ زِرٍّ عَنْ صَفْوَانَ بْنِ عَسَّالٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْ قِبَلِ مَغْرِبِ الشَّمْسِ بَابًا مَفْتُوحًا عَرْضُهُ سَبْعُونَ سَنَةً فَلَا يَزَالُ ذَلِكَ الْبَابُ مَفْتُوحًا لِلتَّوْبَةِ حَتَّى تَطْلُعَ الشَّمْسُ مِنْ نَحْوِهِ فَإِذَا طَلَعَتْ مِنْ نَحْوِهِ لَمْ يَنْفَعْ نَفْسًا إِيمَانُهَا لَمْ تَكُنْ آمَنَتْ مِنْ قَبْلُ أَوْ كَسَبَتْ فِي إِيمَانِهَا خَيْرًا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami ['Ubaidullah bin Musa] dari [Israil] dari ['Ashim] dari [Zirr] dari [Shafwan bin 'Assal] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya dari arah tenggelamnya matahari ada suatu pintu yang terbuka, yang luasnya tujuh puluh tahun. Dan pintu itu akan tetap terbuka untuk bertaubat sehingga matahari terbit dari arah itu. Maka jika ia telah terbit dari arah itu, tidaklah berguna lagi keimanan seseorang yang sebelumnya tidak beriman atau yang telah melakukan amal kebaikan dalam keimanannya.\""},"4023":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ شَقِيقٍ عَنْ حُذَيْفَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الدَّجَّالُ أَعْوَرُ عَيْنِ الْيُسْرَى جُفَالُ الشَّعَرِ مَعَهُ جَنَّةٌ وَنَارٌ فَنَارُهُ جَنَّةٌ وَجَنَّتُهُ نَارٌ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Abu Mu'awiyah] telah menceritakan kepada kami [Al A'masy] dari [Syaqiq] dari [Hudzaifah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dajjal itu buta mata kirinya, lebat rambutnya dan bersamanya terdapat surga dan neraka. Namun (pada hakikatnya) nerakanya adalah surga sedangkan surganya adalah neraka.\""},"4024":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ وَمُحَمَّدُ بْنُ بَشَّارٍ وَمُحَمَّدُ بْنُ الْمُثَنَّى قَالُوا حَدَّثَنَا رَوْحُ بْنُ عُبَادَةَ حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ عَنْ أَبِي التَّيَّاحِ عَنْ الْمُغِيرَةِ بْنِ سُبَيْعٍ عَنْ عَمْرِو بْنِ حُرَيْثٍ عَنْ أَبِي بَكْرٍ الصِّدِّيقِ قَالَحَدَّثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ الدَّجَّالَ يَخْرُجُ مِنْ أَرْضٍ بِالْمَشْرِقِ يُقَالُ لَهَا خُرَاسَانُ يَتْبَعُهُ أَقْوَامٌ كَأَنَّ وُجُوهَهُمْ الْمَجَانُّ الْمُطْرَقَةُ","id":"Telah menceritakan kepada kami [Nahsr bin Ali Al Jahdlami] dan [Muhammad bin Basysyar] serta [Muhammad bin Al Mutsanna] mereka berkata; telah menceritakan kepada kami [Rauh bin 'Ubadah] telah menceritakan kepada kami [Sa'id bin Abu 'Arubah] dari [Abu At Tayyah] dari [Al Mughirah bin Subai'] dari ['Amru bin Huraits] dari [Abu Bakar Ash Shiddiq] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam menceritakan kepada kami bahwa Dajjal akan datang dari bumi bagian timur yang di sebut dengan daerah Khurasan, ia di ikuti oleh suatu kaum yang wajah mereka menyerupai tameng (alat) pemukul.\""},"4025":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا إِسْمَعِيلُ بْنُ أَبِي خَالِدٍ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَ قَالَمَا سَأَلَ أَحَدٌ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الدَّجَّالِ أَكْثَرَ مِمَّا سَأَلْتُهُ وَقَالَ ابْنُ نُمَيْرٍ أَشَدَّ سُؤَالًا مِنِّي فَقَالَ لِي مَا تَسْأَلُ عَنْهُ قُلْتُ إِنَّهُمْ يَقُولُونَ إِنَّ مَعَهُ الطَّعَامَ وَالشَّرَابَ قَالَ هُوَ أَهْوَنُ عَلَى اللَّهِ مِنْ ذَلِكَ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Isma'il bin Abu Khalid] dari [Qais bin Abu Hazim] dari [Al Mughirah bin Syu'bah] dia berkata, \"Tidak ada seseorang pun yang bertanya kepada Nabi shallallahu 'alaihi wasallam mengenai peristiwa Dajjal lebih banyak daripada yang pernah aku tanyakan.\" -Ibnu Numair meriwayatkan dengan redaksi; \"Lebih tegas pertanyaannya daripada pertanyaanku.\"- Beliau bersabda kepadaku: \"Apa yang kamu tanyakan?\" Aku menjawab, \"Mereka berkata, \"Dajjal bisa menghadirkan makanan dan minuman?\" beliau menjawab: \"Allah lebih mampu dari itu.\""},"4026":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا إِسْمَعِيلُ بْنُ أَبِي خَالِدٍ عَنْ مُجَالِدٍ عَنْ الشَّعْبِيِّ عَنْ فَاطِمَةَ بِنْتِ قَيْسٍ قَالَتْصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ يَوْمٍ وَصَعِدَ الْمِنْبَرَ وَكَانَ لَا يَصْعَدُ عَلَيْهِ قَبْلَ ذَلِكَ إِلَّا يَوْمَ الْجُمُعَةِ فَاشْتَدَّ ذَلِكَ عَلَى النَّاسِ فَمِنْ بَيْنِ قَائِمٍ وَجَالِسٍ فَأَشَارَ إِلَيْهِمْ بِيَدِهِ أَنْ اقْعُدُوا فَإِنِّي وَاللَّهِ مَا قُمْتُ مَقَامِي هَذَا لِأَمْرٍ يَنْفَعُكُمْ لِرَغْبَةٍ وَلَا لِرَهْبَةٍ وَلَكِنَّ تَمِيمًا الدَّارِيَّ أَتَانِي فَأَخْبَرَنِي خَبَرًا مَنَعَنِي الْقَيْلُولَةَ مِنْ الْفَرَحِ وَقُرَّةِ الْعَيْنِ فَأَحْبَبْتُ أَنْ أَنْشُرَ عَلَيْكُمْ فَرَحَ نَبِيِّكُمْ أَلَا إِنَّ ابْنَ عَمٍّ لِتَمِيمٍ الدَّارِيِّ أَخْبَرَنِي أَنَّ الرِّيحَ أَلْجَأَتْهُمْ إِلَى جَزِيرَةٍ لَا يَعْرِفُونَهَا فَقَعَدُوا فِي قَوَارِبِ السَّفِينَةِ فَخَرَجُوا فِيهَا فَإِذَا هُمْ بِشَيْءٍ أَهْدَبَ أَسْوَدَ قَالُوا لَهُ مَا أَنْتَ قَالَ أَنَا الْجَسَّاسَةُ قَالُوا أَخْبِرِينَا قَالَتْ مَا أَنَا بِمُخْبِرَتِكُمْ شَيْئًا وَلَا سَائِلَتِكُمْ وَلَكِنْ هَذَا الدَّيْرُ قَدْ رَمَقْتُمُوهُ فَأْتُوهُ فَإِنَّ فِيهِ رَجُلًا بِالْأَشْوَاقِ إِلَى أَنْ تُخْبِرُوهُ وَيُخْبِرَكُمْ فَأَتَوْهُ فَدَخَلُوا عَلَيْهِ فَإِذَا هُمْ بِشَيْخٍ مُوثَقٍ شَدِيدِ الْوَثَاقِ يُظْهِرُ الْحُزْنَ شَدِيدِ التَّشَكِّي فَقَالَ لَهُمْ مِنْ أَيْنَ قَالُوا مِنْ الشَّامِ قَالَ مَا فَعَلَتْ الْعَرَبُ قَالُوا نَحْنُ قَوْمٌ مِنْ الْعَرَبِ عَمَّ تَسْأَلُ قَالَ مَا فَعَلَ هَذَا الرَّجُلُ الَّذِي خَرَجَ فِيكُمْ قَالُوا خَيْرًا نَاوَى قَوْمًا فَأَظْهَرَهُ اللَّهُ عَلَيْهِمْ فَأَمْرُهُمْ الْيَوْمَ جَمِيعٌ إِلَهُهُمْ وَاحِدٌ وَدِينُهُمْ وَاحِدٌ قَالَ مَا فَعَلَتْ عَيْنُ زُغَرَ قَالُوا خَيْرًا يَسْقُونَ مِنْهَا زُرُوعَهُمْ وَيَسْتَقُونَ مِنْهَا لِسَقْيِهِمْ قَالَ فَمَا فَعَلَ نَخْلٌ بَيْنَ عَمَّانَ وَبَيْسَانَ قَالُوا يُطْعِمُ ثَمَرَهُ كُلَّ عَامٍ قَالَ فَمَا فَعَلَتْ بُحَيْرَةُ الطَّبَرِيَّةِ قَالُوا تَدَفَّقُ جَنَبَاتُهَا مِنْ كَثْرَةِ الْمَاءِ قَالَ فَزَفَرَ ثَلَاثَ زَفَرَاتٍ ثُمَّ قَالَ لَوْ انْفَلَتُّ مِنْ وَثَاقِي هَذَا لَمْ أَدَعْ أَرْضًا إِلَّا وَطِئْتُهَا بِرِجْلَيَّ هَاتَيْنِ إِلَّا طَيْبَةَ لَيْسَ لِي عَلَيْهَا سَبِيلٌ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى هَذَا يَنْتَهِي فَرَحِي هَذِهِ طَيْبَةُ وَالَّذِي نَفْسِي بِيَدِهِ مَا فِيهَا طَرِيقٌ ضَيِّقٌ وَلَا وَاسِعٌ وَلَا سَهْلٌ وَلَا جَبَلٌ إِلَّا وَعَلَيْهِ مَلَكٌ شَاهِرٌ سَيْفَهُ إِلَى يَوْمِ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [Ayahku] telah menceritakan kepada kami [Isma'il bin Abu Khalid] dari [Mujalid] dari [As Sya'bi] dari [Fatimah binti Qais] dia berkata, \"Suatu hari Rasulullah shallallahu 'alaihi wasallam shalat lalu naik mimbar, padahal biasanya beliau tidak langsung naik mimbar sebelum itu, kecuali pada hari Jum'at. Sehingga hal itu menjadikan suasana tampak serius bagi mereka. Ketika itu ada yang hendak beranjak pergi dan ada pula yang masih duduk, lantas beliau mengisyaratkan dengan tangannya kepada orang-orang supaya mereka duduk kembali. Beliau bersabda: \"Demi Allah, sesungguhnya aku duduk di tempatku ini tidaklah karena ada sesuatu yang bermanfaat buat kalian semua, untuk mengagetkan dan mencemaskan kalian. Akan tetapi Tamim Ad Dari telah datang kepadaku mengabarkan suatu berita yang mencegahku dari tidur siang, karena rasa senang dan gembira. Oleh karena itu, aku ingin sebarkan kepada kalian kebahagiaan Nabi kalian. Ketahuilah bahwa anak paman Tamim Ad Dari mengabariku bahwa angin telah mengarahkan (kapal) mereka menuju pulau yang tidak mereka kenal. Lalu mereka duduk-duduk di sampan kecil miliki perahu induknya. Lalu mereka keluar dengan sampan tersebut. Tiba-tiba mereka berhadapan dengan sosok yang berbulu lebat dan hitam, lantas mereka berkata kepada makhluk itu, 'Siapakah dirimu? ' ia menjawab, 'Aku adalah Al Jasasah.' Mereka bertanya lagi, 'Kabarkanlah kepada kami tentang dirimu! ' ia menjawab, 'Bukankah aku orang yang akan memberitahu kepada kalian dan juga menanyai kalian tentang sesuatu, namun di sana terdapat gua dan kalian telah melihatnya sepintas. Maka datangilah, karena di sana ada seorang laki-laki yang sangat merindukan kabar dari kalian dan ia pun akan mengabari kalian.\" Lantas mereka mendatangi gua tersebut dan menemui laki-laki yang dimaksud. Tiba-tiba mereka melihat seorang yang terbelenggu dengan ikatan yang kuat dan menampakkan kesedihan yang sangat. Orang tersebut berkata kepada mereka, 'Dari manakah kalian? ' mereka menjawab, 'Dari negeri Syam.' Ia bertanya lagi, 'Apa yang telah diperbuat oleh bangsa Arab? ' Mereka menjawab, 'Kami adalah suatu kaum dari bangsa Arab. Lantas apa yang hendak kamu tanyakan? ' Ia berkata, 'Apa yang telah diperbuat oleh seorang laki-laki yang diutus dari lingkungan kalian? mereka menjawab, 'Baiklah, ia telah menentang kaumnya, maka Allah memenangkan dirinya atas mereka. Kini, segala urusan mereka sama (satu), tuhan mereka satu dan agama mereka pun satu.\" laki-laki yang ada dalam gua itu bertanya, 'Apa yang diperbuat oleh 'Ain Zaghar (mata air di negeri Syam)? ' mereka menjawab, 'Mata air tersebut dipergunakan untuk menyirami tumbuh-tumbuhan mereka dan menghilangkan dahaga mereka.' Ia bertanya lagi, 'Apa yang diperbuat terhadap pohon yang terletak antara Amman dan Baisan? ' mereka menjawab, 'Pohon tersebut berbuah setiap tahunnya.' Ia bertanya lagi, 'Bagaimana keadaan danau At Thabariyah? ' mereka menjawab, '(airnya) melimpah sampai ke sisi-sisinya karena banyaknya air. Dan menghembuskan tiga kali semburan.' Lelaki itu berkata, 'Seandainya aku lepas dari ikatanku ini, maka tidaklah akan aku tinggalkan satu daratan pun melainkan akan aku singgahi dengan kedua kakiku ini, kecuali Thayyibah, sebab aku tidak kuasa menyinggahinya.' Nabi shallallahu 'alaihi wasallam bersabda: \"Sampai di sini habislah kegembiraanku. Dan inilah negeri yang baik (suci). Demi dzat yang jiwaku berada di tangan-Nya, di dalamnya tidak ada jalan yang sempit atau luas, dataran atau pun pegunungan melainkan di atasnya terdapat Malaikat yang menghunuskan pedangnya sampai hari Kiamat.\""},"4027":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ يَزِيدَ بْنِ جَابِرٍ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ جُبَيْرِ بْنِ نُفَيْرٍ حَدَّثَنِي أَبِي أَنَّهُ سَمِعَ النَّوَّاسَ بْنَ سَمْعَانَ الْكِلَابِيَّ يَقُولُذَكَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الدَّجَّالَ الْغَدَاةَ فَخَفَضَ فِيهِ وَرَفَعَ حَتَّى ظَنَنَّا أَنَّهُ فِي طَائِفَةِ النَّخْلِ فَلَمَّا رُحْنَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَرَفَ ذَلِكَ فِينَا فَقَالَ مَا شَأْنُكُمْ فَقُلْنَا يَا رَسُولَ اللَّهِ ذَكَرْتَ الدَّجَّالَ الْغَدَاةَ فَخَفَضْتَ فِيهِ ثُمَّ رَفَعْتَ حَتَّى ظَنَنَّا أَنَّهُ فِي طَائِفَةِ النَّخْلِ قَالَ غَيْرُ الدَّجَّالِ أَخْوَفُنِي عَلَيْكُمْ إِنْ يَخْرُجْ وَأَنَا فِيكُمْ فَأَنَا حَجِيجُهُ دُونَكُمْ وَإِنْ يَخْرُجْ وَلَسْتُ فِيكُمْ فَامْرُؤٌ حَجِيجُ نَفْسِهِ وَاللَّهُ خَلِيفَتِي عَلَى كُلِّ مُسْلِمٍ إِنَّهُ شَابٌّ قَطَطٌ عَيْنُهُ قَائِمَةٌ كَأَنِّي أُشَبِّهُهُ بِعَبْدِ الْعُزَّى بْنِ قَطَنٍ فَمَنْ رَآهُ مِنْكُمْ فَلْيَقْرَأْ عَلَيْهِ فَوَاتِحَ سُورَةِ الْكَهْفِ إِنَّهُ يَخْرُجُ مِنْ خَلَّةٍ بَيْنَ الشَّامِ وَالْعِرَاقِ فَعَاثَ يَمِينًا وَعَاثَ شِمَالًا يَا عِبَادَ اللَّهِ اثْبُتُوا قُلْنَا يَا رَسُولَ اللَّهِ وَمَا لُبْثُهُ فِي الْأَرْضِ قَالَ أَرْبَعُونَ يَوْمًا يَوْمٌ كَسَنَةٍ وَيَوْمٌ كَشَهْرٍ وَيَوْمٌ كَجُمُعَةٍ وَسَائِرُ أَيَّامِهِ كَأَيَّامِكُمْ قُلْنَا يَا رَسُولَ اللَّهِ فَذَلِكَ الْيَوْمُ الَّذِي كَسَنَةٍ تَكْفِينَا فِيهِ صَلَاةُ يَوْمٍ قَالَ فَاقْدُرُوا لَهُ قَدْرَهُ قَالَ قُلْنَا فَمَا إِسْرَاعُهُ فِي الْأَرْضِ قَالَ كَالْغَيْثِ اسْتَدْبَرَتْهُ الرِّيحُ قَالَ فَيَأْتِي الْقَوْمَ فَيَدْعُوهُمْ فَيَسْتَجِيبُونَ لَهُ وَيُؤْمِنُونَ بِهِ فَيَأْمُرُ السَّمَاءَ أَنْ تُمْطِرَ فَتُمْطِرَ وَيَأْمُرُ الْأَرْضَ أَنْ تُنْبِتَ فَتُنْبِتَ وَتَرُوحُ عَلَيْهِمْ سَارِحَتُهُمْ أَطْوَلَ مَا كَانَتْ ذُرًى وَأَسْبَغَهُ ضُرُوعًا وَأَمَدَّهُ خَوَاصِرَ ثُمَّ يَأْتِي الْقَوْمَ فَيَدْعُوهُمْ فَيَرُدُّونَ عَلَيْهِ قَوْلَهُ فَيَنْصَرِفُ عَنْهُمْ فَيُصْبِحُونَ مُمْحِلِينَ مَا بِأَيْدِيهِمْ شَيْءٌ ثُمَّ يَمُرَّ بِالْخَرِبَةِ فَيَقُولُ لَهَا أَخْرِجِي كُنُوزَكِ فَيَنْطَلِقُ فَتَتْبَعُهُ كُنُوزُهَا كَيَعَاسِيبِ النَّحْلِ ثُمَّ يَدْعُو رَجُلًا مُمْتَلِئًا شَبَابًا فَيَضْرِبُهُ بِالسَّيْفِ ضَرْبَةً فَيَقْطَعُهُ جِزْلَتَيْنِ رَمْيَةَ الْغَرَضِ ثُمَّ يَدْعُوهُ فَيُقْبِلُ يَتَهَلَّلُ وَجْهُهُ يَضْحَكُ فَبَيْنَمَا هُمْ كَذَلِكَ إِذْ بَعَثَ اللَّهُ عِيسَى ابْنَ مَرْيَمَ فَيَنْزِلُ عِنْدَ الْمَنَارَةِ الْبَيْضَاءِ شَرْقِيَّ دِمَشْقَ بَيْنَ مَهْرُودَتَيْنِ وَاضِعًا كَفَّيْهِ عَلَى أَجْنِحَةِ مَلَكَيْنِ إِذَا طَأْطَأَ رَأْسَهُ قَطَرَ وَإِذَا رَفَعَهُ يَنْحَدِرُ مِنْهُ جُمَانٌ كَاللُّؤْلُؤِ وَلَا يَحِلُّ لِكَافِرٍ يَجِدُ رِيحَ نَفَسِهِ إِلَّا مَاتَ وَنَفَسُهُ يَنْتَهِي حَيْثُ يَنْتَهِي طَرَفُهُ فَيَنْطَلِقُ حَتَّى يُدْرِكَهُ عِنْدَ بَابِ لُدٍّ فَيَقْتُلُهُ ثُمَّ يَأْتِي نَبِيُّ اللَّهِ عِيسَى قَوْمًا قَدْ عَصَمَهُمْ اللَّهُ فَيَمْسَحُ وُجُوهَهُمْ وَيُحَدِّثُهُمْ بِدَرَجَاتِهِمْ فِي الْجَنَّةِ فَبَيْنَمَا هُمْ كَذَلِكَ إِذْ أَوْحَى اللَّهُ إِلَيْهِ يَا عِيسَى إِنِّي قَدْ أَخْرَجْتُ عِبَادًا لِي لَا يَدَانِ لِأَحَدٍ بِقِتَالِهِمْ وَأَحْرِزْ عِبَادِي إِلَى الطُّورِ وَيَبْعَثُ اللَّهُ يَأْجُوجَ وَمَأْجُوجَ وَهُمْ كَمَا قَالَ اللَّهُ{ مِنْ كُلِّ حَدَبٍ يَنْسِلُونَ }فَيَمُرُّ أَوَائِلُهُمْ عَلَى بُحَيْرَةِ الطَّبَرِيَّةِ فَيَشْرَبُونَ مَا فِيهَا ثُمَّ يَمُرُّ آخِرُهُمْ فَيَقُولُونَ لَقَدْ كَانَ فِي هَذَا مَاءٌ مَرَّةً وَيَحْضُرُ نَبِيُّ اللَّهِ وَأَصْحَابُهُ حَتَّى يَكُونَ رَأْسُ الثَّوْرِ لِأَحَدِهِمْ خَيْرًا مِنْ مِائَةِ دِينَارٍ لِأَحَدِكُمْ الْيَوْمَ فَيَرْغَبُ نَبِيُّ اللَّهِ عِيسَى وَأَصْحَابُهُ إِلَى اللَّهِ فَيُرْسِلُ اللَّهُ عَلَيْهِمْ النَّغَفَ فِي رِقَابِهِمْ فَيُصْبِحُونَ فَرْسَى كَمَوْتِ نَفْسٍ وَاحِدَةٍ وَيَهْبِطُ نَبِيُّ اللَّهِ عِيسَى وَأَصْحَابُهُ فَلَا يَجِدُونَ مَوْضِعَ شِبْرٍ إِلَّا قَدْ مَلَأَهُ زَهَمُهُمْ وَنَتْنُهُمْ وَدِمَاؤُهُمْ فَيَرْغَبُونَ إِلَى اللَّهِ فَيُرْسِلُ عَلَيْهِمْ طَيْرًا كَأَعْنَاقِ الْبُخْتِ فَتَحْمِلُهُمْ فَتَطْرَحُهُمْ حَيْثُ شَاءَ اللَّهُ ثُمَّ يُرْسِلُ اللَّهُ عَلَيْهِمْ مَطَرًا لَا يُكِنُّ مِنْهُ بَيْتُ مَدَرٍ وَلَا وَبَرٍ فَيَغْسِلُهُ حَتَّى يَتْرُكَهُ كَالزَّلَقَةِ ثُمَّ يُقَالُ لِلْأَرْضِ أَنْبِتِي ثَمَرَتَكِ وَرُدِّي بَرَكَتَكِ فَيَوْمَئِذٍ تَأْكُلُ الْعِصَابَةُ مِنْ الرِّمَّانَةِ فَتُشْبِعُهُمْ وَيَسْتَظِلُّونَ بِقِحْفِهَا وَيُبَارِكُ اللَّهُ فِي الرِّسْلِ حَتَّى إِنَّ اللِّقْحَةَ مِنْ الْإِبِلِ تَكْفِي الْفِئَامَ مِنْ النَّاسِ وَاللِّقْحَةَ مِنْ الْبَقَرِ تَكْفِي الْقَبِيلَةَ وَاللِّقْحَةَ مِنْ الْغَنَمِ تَكْفِي الْفَخِذَ فَبَيْنَمَا هُمْ كَذَلِكَ إِذْ بَعَثَ اللَّهُ عَلَيْهِمْ رِيحًا طَيِّبَةً فَتَأْخُذُ تَحْتَ آبَاطِهِمْ فَتَقْبِضُ رُوحَ كُلَّ مُسْلِمٍ وَيَبْقَى سَائِرُ النَّاسِ يَتَهَارَجُونَ كَمَا تَتَهَارَجُ الْحُمُرُ فَعَلَيْهِمْ تَقُومُ السَّاعَةُ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Yahya bin Hamzah] telah menceritakan kepada kami [Abdurrahman bin Yazid bin Jabir] telah menceritakan kepadaku [Abdurrahman bin Jubair bin Nufair] telah menceritakan kepadaku [Ayahku] bahwa dia pernah mendengar [An Nawwas bin Sam'an Al Kilabi] berkata, \"Di pagi hari Rasulullah shallallahu 'alaihi wasallam menyebutkan Dajjal, kemudian beliau merendahkan dan meninggikan (suara) sehingga kami mengira bahwa sudah berada di kebun kurma. Tatkala kami mendekat kepada Rasulullah shallallahu 'alaihi wasallam, beliau mengetahui maksud kami, maka beliau pun bertanya: \"Ada apa dengan kalian?\" kami menjawab, \"Wahai Rasulullah, anda menyebutkan Dajjal pada waktu pagi, kemudian anda merendahkan dan meninggikan sehingga kami mengira bahwa dia sudah berada di kebun kurma.\" Beliau bersabda: \"Bukan Dajjal yang aku takuti terhadap kalian, (karena) jika dia keluar sedang aku masih berada di tengah-tengah kalian, maka aku akan menghadangnya hingga ia tidak sampai kepada kalian, dan apabila dia keluar sedang aku tidak ada di tengah-tengah kalian, maka setiap orang harus membentengi dirinya sendiri, dan Allah adalah khalifahku (penggantiku) atas setiap orang muslim. Dajjal adalah seorang pemuda yang rambutnya keriting, matanya juling, seakan-akan kalau aku serupakan dia seperti Abdul 'Uzza bin Qathan. Barangsiapa dari kalian melihatnya, maka bacakanlah kepadanya permulaan surat Al Kahfi, sesungguhnya dia keluar dari celah antara Syam dan Irak, dia berjalan sempoyongan ke kanan dan ke kiri. Wahai hamba Allah, teguhkanlah diri kalian.\" Kami bertanya, \"Wahai Rasulullah, berapa lamakah dia tinggal di bumi?\" Beliau menjawab: \"Empat puluh hari, sehari seperti setahun, sehari seperti sebulan, sehari seperti sepekan dan seluruh hari-harinya seperti hari-hari kalian.\" Kami bertanya, \"Wahai Rasulullah, saat itu yang satu hari sama dengan satu tahun apakah shalat kita sati hari bisa mencukupinya?\" beliau menjawab: \"Perkirakanlah sesuai dengan ukurannya.\" Kami bertanya, \"Bagaimana kecepatannya di bumi?\" beliau menjawab: \"Seperti awan yang tertiup angin.\" Beliau melanjutkan: \"Kemudian dia datang pada suatu kaum dan mengajak mereka, dan mereka pun mengikuti seruannya dan beriman kepadanya. Dajjal lalu memerintahkan langit untuk menurunkan hujan maka langitpun menurunkan hujan, dia juga memerintahkan bumi menumbuhkan tumbuh-tumbuhan, dan bumipun menumbuhkan tumbuihannya, binatang ternak mereka kembali sendiri pada sore hari dengan punggung yang sangat tinggi yang penuh dengan daging dan susu. Kemudian Dajjal mendatangi kaum yang lain dan mengajak mereka, akan tetapi mereka menolak seruannya, lantas dia meninggalkan kaum tersebut. Tiba-tiba mereka jatuh miskin dan lumpuh. Dajjal lalu berkata kepada bumi, \"Keluarkanlah kekayaanmu.\" Maka kekayaan yang di bumi akhirnya keluar dan mengikutinya sebagaimana sekawanan lebah mengikuti ratunya. Kemudian dia memanggil seorang laki-laki dan menebasnya dengan pedang, maka laki-laki tersebut terbelah menjadi dua sejauh lemparan. Kemudian Dajjal memanggil laki-laki yang terbelah tersebut, maka wajah orang tersebut terlihat gembira dan tertawa. Ketika mereka dalam keadaan seperti itu, maka Allah mengutus Isa bin Maryam, ia turun di menara putih yang terletak di negeri Damaskus dengan mengenakan dua pakaian, sambil meletakkan kedua tangannya di atas pundak dua Malaikat. Jika ia menganggukkan kepala, maka akan nampak juman berbentuk mutiara. Tidak ada seorang kafir pun yang menemui angin nafasnya, kecuali ia akan binasa. Lalu Isa bin Maryam mencari Dajjal dan menemukannya di pintu Ludd (suatu tempat di dekat Baitul Maqdis), lalu ia membunuhnya. Kemudian Nabi Allah Isa mendatangi suatu kaum yang telah Allah lindungi. Maka ia mengusap wajah mereka dan menceritakan derajat mereka di surga. Ketika mereka dalam keadaan seperti itu, Allah mewahyukan kepada Isa bin Maryam: 'Wahai Isa, sesungguhnya Aku telah mengeluarkan hamba-hamba-Ku tanpa ada kekuatan manapun yang dapat memeranginya, maka bawalah hamba-hamba-Ku ke bukit Tursina.\" Lalu Allah mengirimkan Ya'juj dan Ma'juj sebagaimana yang disebutkan dalam firman Allah: '(Hingga apabila dibukakan (tembok) Ya'juj dan Ma'juj, dan mereka turun dengan cepat dari seluruh tempat yang Tinggi) ' (Qs. Al Anbiyaa: 96), Orang yang pertama dari mereka berjalan dan melintasi danau At Thabariyah dan meminum semua, kemudian kelompok yang lain datang dan melintasi daerah itu, lalu berkata, 'Dahulu tempat ini pernah mengalirkan airnya'. Nabi Isa dan para sahabatnya lalu datang dan mendapati harga satu kepala lembu lebih berharga bagi mereka daripada seratus dinar yang ada pada kalian hari ini. Maka Nabi Allah Isa dan para sahabatnya dengan sangat memohon kepada Allah, maka Allah mengutus sekawanan naghaf (sejenis ulat yang berada dihidung kambing atau unta) pada leher mereka, maka di pagi harinya mereka mati bergelimpangan seperti matinya satu jiwa. Kemudian Nabi Allah Isa dan para sahabatnya sampai ke suatu tempat, akan tetapi tempat tersebut telah dipenuhi (oleh pengikut Dajjal), bau nafas mereka pun memenuhi tempat tersebut. Lantas mereka (Nabi Isa dan sahabatnya) memohon kepada Allah, maka Allah mengutus sekawanan burung seperti unta yang berleher panjang, supaya melemparkan mereka (pengikut Dajjal) ke berbagai tempat yang dikehendaki Allah. Setelah itu, Allah mengirim hujan kepada mereka sehingga tidak tersisa satu rumahpun yang keras atau tenda-tenda hingga air hujan tersebut membersihkannya sehingga menjadikannya seperti cermin yang bening. Kemudian dikatakan kepada bumi, 'Keluarkanlah tumbuhan-tumbuhanmu dan kembalikanlah keberkahanmu.' Pada hari itu, sekelompok manusia makan buah delima dan dapat berlindung dengan kulitnya. Allah memberikan keberkahan pada susu, sehingga seekor unta yang sebentar lagi beranak dapat mencukupi untuk dimakan orang banyak, seekor lembu yang hendak beranak juga dapat mencukupi untuk dimakan satu kabilah, dan seekor kambing yang hendak beranak juga dapat mencukupi untuk dimakan sekelompok manusia. Dan ketika mereka tengah dalam kondisi demikian, lantas Allah mengirimkan hembusan angin yang baik dan harum, lalu dicabutlah seluruh ruh orang Muslim. Dan yang tersisa adalah orang-orang yang jahat dan berkelakuan seperti keledai, serta kepada merekalah hari Kiamat pun datang.\""},"4028":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ حَدَّثَنَا ابْنُ جَابِرٍ عَنْ يَحْيَى بْنِ جَابِرٍ الطَّائِيِّ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ أَبِيهِ أَنَّهُ سَمِعَ النَّوَّاسَ بْنَ سَمْعَانَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَيُوقِدُ الْمُسْلِمُونَ مِنْ قِسِيِّ يَأْجُوجَ وَمَأْجُوجَ وَنُشَّابِهِمْ وَأَتْرِسَتِهِمْ سَبْعَ سِنِينَ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Yahya bin Hamzah] telah menceritakan kepada kami [Ibnu Jabir] dari [Yahya bin Jabir Ath Thai] telah menceritakan kepadaku [Abdurrahman bin Jubair bin Nufair] dari [Ayahnya] bahwa dia mendengar [An Nawwas bin Sam'an] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kaum Muslimin akan menyalakan uang dirham Ya'juj dan Ma'juj serta anak panah dan perisai mereka selama tujuh tahun.\""},"4029":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ الْمُحَارِبِيُّ عَنْ إِسْمَعِيلَ بْنِ رَافِعٍ أَبِي رَافِعٍ عَنْ أَبِي زُرْعَةَ السَّيْبَانِيِّ يَحْيَى بْنِ أَبِي عَمْرٍو عَنْ عَمْرِو بْنِ عَبْدِ اللَّهِ عَنْ أَبِي أُمَامَةَ الْبَاهِلِيِّ قَالَخَطَبَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَانَ أَكْثَرُ خُطْبَتِهِ حَدِيثًا حَدَّثَنَاهُ عَنْ الدَّجَّالِ وَحَذَّرَنَاهُ فَكَانَ مِنْ قَوْلِهِ أَنْ قَالَ إِنَّهُ لَمْ تَكُنْ فِتْنَةٌ فِي الْأَرْضِ مُنْذُ ذَرَأَ اللَّهُ ذُرِّيَّةَ آدَمَ أَعْظَمَ مِنْ فِتْنَةِ الدَّجَّالِ وَإِنَّ اللَّهَ لَمْ يَبْعَثْ نَبِيًّا إِلَّا حَذَّرَ أُمَّتَهُ الدَّجَّالَ وَأَنَا آخِرُ الْأَنْبِيَاءِ وَأَنْتُمْ آخِرُ الْأُمَمِ وَهُوَ خَارِجٌ فِيكُمْ لَا مَحَالَةَ وَإِنْ يَخْرُجْ وَأَنَا بَيْنَ ظَهْرَانَيْكُمْ فَأَنَا حَجِيجٌ لِكُلِّ مُسْلِمٍ وَإِنْ يَخْرُجْ مِنْ بَعْدِي فَكُلُّ امْرِئٍ حَجِيجُ نَفْسِهِ وَاللَّهُ خَلِيفَتِي عَلَى كُلِّ مُسْلِمٍ وَإِنَّهُ يَخْرُجُ مِنْ خَلَّةٍ بَيْنَ الشَّامِ وَالْعِرَاقِ فَيَعِيثُ يَمِينًا وَيَعِيثُ شِمَالًا يَا عِبَادَ اللَّهِ فَاثْبُتُوا فَإِنِّي سَأَصِفُهُ لَكُمْ صِفَةً لَمْ يَصِفْهَا إِيَّاهُ نَبِيٌّ قَبْلِي إِنَّهُ يَبْدَأُ فَيَقُولُ أَنَا نَبِيٌّ وَلَا نَبِيَّ بَعْدِي ثُمَّ يُثَنِّي فَيَقُولُ أَنَا رَبُّكُمْ وَلَا تَرَوْنَ رَبَّكُمْ حَتَّى تَمُوتُوا وَإِنَّهُ أَعْوَرُ وَإِنَّ رَبَّكُمْ لَيْسَ بِأَعْوَرَ وَإِنَّهُ مَكْتُوبٌ بَيْنَ عَيْنَيْهِ كَافِرٌ يَقْرَؤُهُ كُلُّ مُؤْمِنٍ كَاتِبٍ أَوْ غَيْرِ كَاتِبٍ وَإِنَّ مِنْ فِتْنَتِهِ أَنَّ مَعَهُ جَنَّةً وَنَارًا فَنَارُهُ جَنَّةٌ وَجَنَّتُهُ نَارٌ فَمَنْ ابْتُلِيَ بِنَارِهِ فَلْيَسْتَغِثْ بِاللَّهِ وَلْيَقْرَأْ فَوَاتِحَ الْكَهْفِ فَتَكُونَ عَلَيْهِ بَرْدًا وَسَلَامًا كَمَا كَانَتْ النَّارُ عَلَى إِبْرَاهِيمَ وَإِنَّ مِنْ فِتْنَتِهِ أَنْ يَقُولَ لِأَعْرَابِيٍّ أَرَأَيْتَ إِنْ بَعَثْتُ لَكَ أَبَاكَ وَأُمَّكَ أَتَشْهَدُ أَنِّي رَبُّكَ فَيَقُولُ نَعَمْ فَيَتَمَثَّلُ لَهُ شَيْطَانَانِ فِي صُورَةِ أَبِيهِ وَأُمِّهِ فَيَقُولَانِ يَا بُنَيَّ اتَّبِعْهُ فَإِنَّهُ رَبُّكَ وَإِنَّ مِنْ فِتْنَتِهِ أَنْ يُسَلَّطَ عَلَى نَفْسٍ وَاحِدَةٍ فَيَقْتُلَهَا وَيَنْشُرَهَا بِالْمِنْشَارِ حَتَّى يُلْقَى شِقَّتَيْنِ ثُمَّ يَقُولَ انْظُرُوا إِلَى عَبْدِي هَذَا فَإِنِّي أَبْعَثُهُ الْآنَ ثُمَّ يَزْعُمُ أَنَّ لَهُ رَبًّا غَيْرِي فَيَبْعَثُهُ اللَّهُ وَيَقُولُ لَهُ الْخَبِيثُ مَنْ رَبُّكَ فَيَقُولُ رَبِّيَ اللَّهُ وَأَنْتَ عَدُوُّ اللَّهِ أَنْتَ الدَّجَّالُ وَاللَّهِ مَا كُنْتُ بَعْدُ أَشَدَّ بَصِيرَةً بِكَ مِنِّي الْيَوْمَقَالَ أَبُو الْحَسَنِ الطَّنَافِسِيُّ فَحَدَّثَنَا الْمُحَارِبِيُّ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ الْوَلِيدِ الْوَصَّافِيُّ عَنْ عَطِيَّةَ عَنْ أَبِي سَعِيدٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَلِكَ الرَّجُلُ أَرْفَعُ أُمَّتِي دَرَجَةً فِي الْجَنَّةِ قَالَ قَالَ أَبُو سَعِيدٍ وَاللَّهِ مَا كُنَّا نُرَى ذَلِكَ الرَّجُلَ إِلَّا عُمَرَ بْنَ الْخَطَّابِ حَتَّى مَضَى لِسَبِيلِهِ قَالَ الْمُحَارِبِيُّ ثُمَّ رَجَعْنَا إِلَى حَدِيثِ أَبِي رَافِعٍ قَالَ وَإِنَّ مِنْ فِتْنَتِهِ أَنْ يَأْمُرَ السَّمَاءَ أَنْ تُمْطِرَ فَتُمْطِرَ وَيَأْمُرَ الْأَرْضَ أَنْ تُنْبِتَ فَتُنْبِتَ وَإِنَّ مِنْ فِتْنَتِهِ أَنْ يَمُرَّ بِالْحَيِّ فَيُكَذِّبُونَهُ فَلَا تَبْقَى لَهُمْ سَائِمَةٌ إِلَّا هَلَكَتْ وَإِنَّ مِنْ فِتْنَتِهِ أَنْ يَمُرَّ بِالْحَيِّ فَيُصَدِّقُونَهُ فَيَأْمُرَ السَّمَاءَ أَنْ تُمْطِرَ فَتُمْطِرَ وَيَأْمُرَ الْأَرْضَ أَنْ تُنْبِتَ فَتُنْبِتَ حَتَّى تَرُوحَ مَوَاشِيهِمْ مِنْ يَوْمِهِمْ ذَلِكَ أَسْمَنَ مَا كَانَتْ وَأَعْظَمَهُ وَأَمَدَّهُ خَوَاصِرَ وَأَدَرَّهُ ضُرُوعًا وَإِنَّهُ لَا يَبْقَى شَيْءٌ مِنْ الْأَرْضِ إِلَّا وَطِئَهُ وَظَهَرَ عَلَيْهِ إِلَّا مَكَّةَ وَالْمَدِينَةَ لَا يَأْتِيهِمَا مِنْ نَقْبٍ مِنْ نِقَابِهِمَا إِلَّا لَقِيَتْهُ الْمَلَائِكَةُ بِالسُّيُوفِ صَلْتَةً حَتَّى يَنْزِلَ عِنْدَ الظُّرَيْبِ الْأَحْمَرِ عِنْدَ مُنْقَطَعِ السَّبَخَةِ فَتَرْجُفُ الْمَدِينَةُ بِأَهْلِهَا ثَلَاثَ رَجَفَاتٍ فَلَا يَبْقَى مُنَافِقٌ وَلَا مُنَافِقَةٌ إِلَّا خَرَجَ إِلَيْهِ فَتَنْفِي الْخَبَثَ مِنْهَا كَمَا يَنْفِي الْكِيرُ خَبَثَ الْحَدِيدِ وَيُدْعَى ذَلِكَ الْيَوْمُ يَوْمَ الْخَلَاصِ فَقَالَتْ أُمُّ شَرِيكٍ بِنْتُ أَبِي الْعَكَرِ يَا رَسُولَ اللَّهِ فَأَيْنَ الْعَرَبُ يَوْمَئِذٍ قَالَ هُمْ يَوْمَئِذٍ قَلِيلٌ وَجُلُّهُمْ بِبَيْتِ الْمَقْدِسِ وَإِمَامُهُمْ رَجُلٌ صَالِحٌ فَبَيْنَمَا إِمَامُهُمْ قَدْ تَقَدَّمَ يُصَلِّي بِهِمْ الصُّبْحَ إِذْ نَزَلَ عَلَيْهِمْ عِيسَى ابْنُ مَرْيَمَ الصُّبْحَ فَرَجَعَ ذَلِكَ الْإِمَامُ يَنْكُصُ يَمْشِي الْقَهْقَرَى لِيَتَقَدَّمَ عِيسَى يُصَلِّي بِالنَّاسِ فَيَضَعُ عِيسَى يَدَهُ بَيْنَ كَتِفَيْهِ ثُمَّ يَقُولُ لَهُ تَقَدَّمْ فَصَلِّ فَإِنَّهَا لَكَ أُقِيمَتْ فَيُصَلِّي بِهِمْ إِمَامُهُمْ فَإِذَا انْصَرَفَ قَالَ عِيسَى عَلَيْهِ السَّلَام افْتَحُوا الْبَابَ فَيُفْتَحُ وَوَرَاءَهُ الدَّجَّالُ مَعَهُ سَبْعُونَ أَلْفَ يَهُودِيٍّ كُلُّهُمْ ذُو سَيْفٍ مُحَلًّى وَسَاجٍ فَإِذَا نَظَرَ إِلَيْهِ الدَّجَّالُ ذَابَ كَمَا يَذُوبُ الْمِلْحُ فِي الْمَاءِ وَيَنْطَلِقُ هَارِبًا وَيَقُولُ عِيسَى عَلَيْهِ السَّلَام إِنَّ لِي فِيكَ ضَرْبَةً لَنْ تَسْبِقَنِي بِهَا فَيُدْرِكُهُ عِنْدَ بَابِ اللُّدِّ الشَّرْقِيِّ فَيَقْتُلُهُ فَيَهْزِمُ اللَّهُ الْيَهُودَ فَلَا يَبْقَى شَيْءٌ مِمَّا خَلَقَ اللَّهُ يَتَوَارَى بِهِ يَهُودِيٌّ إِلَّا أَنْطَقَ اللَّهُ ذَلِكَ الشَّيْءَ لَا حَجَرَ وَلَا شَجَرَ وَلَا حَائِطَ وَلَا دَابَّةَ إِلَّا الْغَرْقَدَةَ فَإِنَّهَا مِنْ شَجَرِهِمْ لَا تَنْطِقُ إِلَّا قَالَ يَا عَبْدَ اللَّهِ الْمُسْلِمَ هَذَا يَهُودِيٌّ فَتَعَالَ اقْتُلْهُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَإِنَّ أَيَّامَهُ أَرْبَعُونَ سَنَةً السَّنَةُ كَنِصْفِ السَّنَةِ وَالسَّنَةُ كَالشَّهْرِ وَالشَّهْرُ كَالْجُمُعَةِ وَآخِرُ أَيَّامِهِ كَالشَّرَرَةِ يُصْبِحُ أَحَدُكُمْ عَلَى بَابِ الْمَدِينَةِ فَلَا يَبْلُغُ بَابَهَا الْآخَرَ حَتَّى يُمْسِيَ فَقِيلَ لَهُ يَا رَسُولَ اللَّهِ كَيْفَ نُصَلِّي فِي تِلْكَ الْأَيَّامِ الْقِصَارِ قَالَ تَقْدُرُونَ فِيهَا الصَّلَاةَ كَمَا تَقْدُرُونَهَا فِي هَذِهِ الْأَيَّامِ الطِّوَالِ ثُمَّ صَلُّوا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَكُونُ عِيسَى ابْنُ مَرْيَمَ عَلَيْهِ السَّلَام فِي أُمَّتِي حَكَمًا عَدْلًا وَإِمَامًا مُقْسِطًا يَدُقُّ الصَّلِيبَ وَيَذْبَحُ الْخِنْزِيرَ وَيَضَعُ الْجِزْيَةَ وَيَتْرُكُ الصَّدَقَةَ فَلَا يُسْعَى عَلَى شَاةٍ و��لَا بَعِيرٍ وَتُرْفَعُ الشَّحْنَاءُ وَالتَّبَاغُضُ وَتُنْزَعُ حُمَةُ كُلِّ ذَاتِ حُمَةٍ حَتَّى يُدْخِلَ الْوَلِيدُ يَدَهُ فِي فِي الْحَيَّةِ فَلَا تَضُرَّهُ وَتُفِرَّ الْوَلِيدَةُ الْأَسَدَ فَلَا يَضُرُّهَا وَيَكُونَ الذِّئْبُ فِي الْغَنَمِ كَأَنَّهُ كَلْبُهَا وَتُمْلَأُ الْأَرْضُ مِنْ السِّلْمِ كَمَا يُمْلَأُ الْإِنَاءُ مِنْ الْمَاءِ وَتَكُونُ الْكَلِمَةُ وَاحِدَةً فَلَا يُعْبَدُ إِلَّا اللَّهُ وَتَضَعُ الْحَرْبُ أَوْزَارَهَا وَتُسْلَبُ قُرَيْشٌ مُلْكَهَا وَتَكُونُ الْأَرْضُ كَفَاثُورِ الْفِضَّةِ تُنْبِتُ نَبَاتَهَا بِعَهْدِ آدَمَ حَتَّى يَجْتَمِعَ النَّفَرُ عَلَى الْقِطْفِ مِنْ الْعِنَبِ فَيُشْبِعَهُمْ وَيَجْتَمِعَ النَّفَرُ عَلَى الرُّمَّانَةِ فَتُشْبِعَهُمْ وَيَكُونَ الثَّوْرُ بِكَذَا وَكَذَا مِنْ الْمَالِ وَتَكُونَ الْفَرَسُ بِالدُّرَيْهِمَاتِ قَالُوا يَا رَسُولَ اللَّهِ وَمَا يُرْخِصُ الْفَرَسَ قَالَ لَا تُرْكَبُ لِحَرْبٍ أَبَدًا قِيلَ لَهُ فَمَا يُغْلِي الثَّوْرَ قَالَ تُحْرَثُ الْأَرْضُ كُلُّهَا وَإِنَّ قَبْلَ خُرُوجِ الدَّجَّالِ ثَلَاثَ سَنَوَاتٍ شِدَادٍ يُصِيبُ النَّاسَ فِيهَا جُوعٌ شَدِيدٌ يَأْمُرُ اللَّهُ السَّمَاءَ فِي السَّنَةِ الْأُولَى أَنْ تَحْبِسَ ثُلُثَ مَطَرِهَا وَيَأْمُرُ الْأَرْضَ فَتَحْبِسُ ثُلُثَ نَبَاتِهَا ثُمَّ يَأْمُرُ السَّمَاءَ فِي الثَّانِيَةِ فَتَحْبِسُ ثُلُثَيْ مَطَرِهَا وَيَأْمُرُ الْأَرْضَ فَتَحْبِسُ ثُلُثَيْ نَبَاتِهَا ثُمَّ يَأْمُرُ اللَّهُ السَّمَاءَ فِي السَّنَةِ الثَّالِثَةِ فَتَحْبِسُ مَطَرَهَا كُلَّهُ فَلَا تُقْطِرُ قَطْرَةً وَيَأْمُرُ الْأَرْضَ فَتَحْبِسُ نَبَاتَهَا كُلَّهُ فَلَا تُنْبِتُ خَضْرَاءَ فَلَا تَبْقَى ذَاتُ ظِلْفٍ إِلَّا هَلَكَتْ إِلَّا مَا شَاءَ اللَّهُ قِيلَ فَمَا يُعِيشُ النَّاسُ فِي ذَلِكَ الزَّمَانِ قَالَ التَّهْلِيلُ وَالتَّكْبِيرُ وَالتَّسْبِيحُ وَالتَّحْمِيدُ وَيُجْرَى ذَلِكَ عَلَيْهِمْ مُجْرَى الطَّعَامِ قَالَ أَبُو عَبْد اللَّهِ سَمِعْت أَبَا الْحَسَنِ الطَّنَافِسِيَّ يَقُولُ سَمِعْتُ عَبْدَ الرَّحْمَنِ الْمُحَارِبِيَّ يَقُولُ يَنْبَغِي أَنْ يُدْفَعَ هَذَا الْحَدِيثُ إِلَى الْمُؤَدِّبِ حَتَّى يُعَلِّمَهُ الصِّبْيَانَ فِي الْكُتَّابِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Abdurrahman Al Muharibi] dari [Isma'il bin Rafi' Abu Rafi'] dari [Abu Zur'ah As Saibani] -yaitu Yahya bin Abu 'Amru- dari ['Amru bin Abdullah] dari [Abu Umamah Al Bahili] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah berkhutbah di hadapan kami, dan kebanyakan isi khutbah beliau selalu menceritakan kepada kami tentang Dajjal supaya kami berhati-hati. dan di antara isi khutbah beliau adalah: \"Sungguh, semenjak Allah menciptakan anak cucu Adam, tidak ada fitnah yang lebih besar dari Dajjal, dan tidak ada satu Nabi pun yang diutus oleh Allah melainkan ia akan memperingatkan kepada umatnya mengenai fitnah Dajjal. Sedangkan Aku adalah Nabi yang paling terakhir dan kamu juga ummat yang paling terakhir, maka tidak dapat dipungkiri lagi bahwa Dajjal akan keluar di tengah-tengah kalian. Sekiranya ia keluar, sedang aku masih berada di tengah-tengah kalian, maka Aku adalah pembela setiap orang muslim. Namun jika ia keluar setelah (kematian) ku, maka tiap-tiap kalian adalah penyelamat bagi dirinya sendiri, dan Allah sebagai penggantiku dalam menyelamatkan setiap muslim. Sesungguhnya ia akan keluar dari suatu celah yang terletak antara Syam dan Irak. Lalu ia akan berbuat kerusakan di sebelah kirinya dan kanannya. Wahai hamba Allah, wahai para manusia, teguhkanlah diri kalian, karena aku akan menerangkan sifat-sifatnya yang belum pernah diterangkan oleh seorang Nabi pun sebelumku. Pertama kali ia akan mendakwakan dirinya dengan mengatakan, 'Aku adalah seorang Nabi.' Padahal tidak ada Nabi setelahku, kemudian ia juga akan mendakwakan dirinya dengan mengataka, 'Aku adalah Rabb kalian.' Sedangkan kalian tidak akan bisa melihat Allah kecuali setelah kalian meninggal. Dan ia hanya memiliki satu mata, padahal Allah tidaklah bermata sebelah. Dan diantara kedua matanya tertulis kata 'kafir' yang hanya dapat dibaca oleh setiap muslim baik yang dapat menulis maupun yang tidak dapat menulis. Diantara fitnah-fitnahnya adalah, bahwa bersamanya ada surga dan neraka, namun pada hakekatnya nerakanya adalah surga dan surganya adalah neraka. Barangsiapa mendapatkan cobaan dengan nerakanya, hendaklah ia berlindung kepada Allah dan hendaklah ia membaca ayat di awal-awal surat Al Kahfi. Dan diantara fitnahnya juga adalah, ia akan berkata kepada seorang Arab, 'Pikirkanlah olehmu, sekiranya aku dapat membangkitkan ayah dan ibumu yang telah mati, apakah kamu akan bersaksi bahwa aku adalah Rabbmu? ' Laki-laki arab tersebut menjawab, 'Ya.' Kemudian muncullah setan yang menjelma di hadapannya dalam bentuk ayah dan ibunya, maka keduanya berkata, 'Wahai anakku, ikutilah ia, sesungguhnya dia adalah Rabbmu.' Dan di antara firnah-fitnahnya adalah ia akan memaksa manusia lalu membunuhnya dan memotongnya dengan gergaji. Maka terbelahlah orang tersebut menjadi dua bagian. Kemudian Dajjal berkata, 'Lihatlah oleh kalian kepada hamabku ini, sesungguhnya aku akan membangkitkannya, lalu dia akan mendakwakan bahwa Rabbnya adalah selain aku.' Maka Allah pun membangkitkan orang yang terbelah tersebut. Lalu Dajjal berkata kepadanya, 'Siapakah Rabbmu? ' ia menjawab, 'Rabbku adalah Allah, dan kamu adalah musuh Allah. Kamu adalah Dajjal. Demi Allah, mulai hari ini, tidak ada hal yang lebih aku yakini selain dari (kedustaan) mu'.\" [Abu Hasan Ath Thanafisi] berkata; telah menceritakan kepada kami [Al Muharibi] telah menceritakan kepada kami ['Ubaidullah bin Al Walid Al Washafi] dari ['Athiyah] dari [Abu Sa'id] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Laki-laki itu adalah dari ummatku yang mendapatkan derajat yang paling tinggi di surga.\" Perawi berkata; Abu Sa'id berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Demi Allah, kami tidak melihat laki-laki tersebut melainkan Umar bin Khattab sehingga dia menyelesaikan segala urusannya.\" Al Muharibi berkata, \"Kemudian kembali ke hadits riwayat Abu Rafi', dia berkata, \"Dan termasuk dari fitnahnya (Dajjal) adalah memerintahkan langit supaya menurunkan air hujan, maka turunkah hujan, dan memerintahkan bumi supaya menumbuhkan tumbuhannya, maka bumi pun menumbuhkan tumbuhannya. Termasuk dari fitnahnya adalah ia melintasi suatu negeri, namun penduduknya mendustakannya, maka tidak satu binatang ternak pun yang tersisa melainkan akan binasa. Dan diantara fitnah-fitnahnya adalah bahwa ia akan melintasi suatu negeri, kemudian penduduknya membenarkannya, maka ia memerintahkan langit untuk menurunkan hujan, maka turunkah hujan dan memerintahkan bumi supaya menumbuhkan tumbuhannya, maka tumbuhlah tumbuhannya. Sehingga binatang pada saat itu menjadi lebih besar dan lebih gemuk dibanding dengan masa-masa yang telah lalu, paling besar lambungnya dan paling banyak air susunya. Sungguh, tidak ada satu negeri pun di muka bumi ini yang tidak dimasuki dan dikuasai oleh Dajjal kecuali Makkah dan Madinah, dan dia tidak akan mampu memasukinya dari setiap celah-celah itu melainkan ia akan bertemu dengan menjaga tempat tersebut dengan pedang yang terhunus, sehingga ia akan singgah di suatu tempat yang kosong dan belum pernah diolah. Maka kota Madinah bergetar dengan tiga kali guncangan, sehingga tidak akan tersisa dalam kota tersebut seorang munafik baik laki-laki maupun perempuan kecuali keluar menemui Dajjal, kota Madinah pun terbebas dari orang-orang keji sebagaimana alat pompa besi menghilangkan karat pada besi, dan hari itu disebut dengan hari pembersihan.\" Ummu Syuraik binti Abu Al 'Akr berkata, \"Wahai Rasulullah, dimanakah orang-orang Arab saat itu?\" beliau menjawab: \"Pada saat itu jumlah mereka sangatlah sedikit dan mereka berada di Baitul Maqdis sedangkan imam mereka adalah seorang laki-laki yang shalih. Ketika pemimpin mereka hendak maju ke hadapan untuk mengimami dalam shalat subuh, tiba-tiba turunlah Isa bin Maryam, maka mundurlah imam merka ke belakang supaya Isa maju untuk mengimami shalat. Isa lalu meletakkan tangannya di antara dua bahunya (pemimpin mereka) sambil berkata, 'Majulah kamu dan pimpinlah shalat, karena sesungguhnya ia ditegakkan untuk kamu.' Akhirnya pemimpin mereka pun mengimami mereka shalat, dan ketika shalat telah usai, Isa berkata, 'Bukalah pintu.' Mereka pun membukakan pintu, ternyata di belakangnya Dajjal telah menunggu bersama dengan tujuh puluh ribu orang Yahudi, masing-masig dari mereka memiliki pedang terhunus yang terbuat dari emas dan berjubah besar berwarna hijau. Ketika ia (Isa) memandang Dajjal, Dajjal pun meleleh (hancur) sebagaimana garam yang meleleh di dalam air. Kemudian dia lari dan dihadang oleh Isa di pintu timur kota Lud, kemudian Isa membunuhnya. Maka Allah menjadikan kekalahan terhadap orang-orang Yahudi, dimana tidak ada satu makhlukpun yang diciptakan Allah yang dijadikan perlindungan oleh mereka melainkan Allah akan menjadikannya berbicara, mulai dari batu, pohon, dinding dan binatang ternak kecuali pohon Gharqadah. Sebab ia termasuk dari pohonnya mereka yang tidak mau bicara. Lalu makhluk Allah yang lain angkat bicara, \"Wahai hamba Allah yang Muslim, di sini ada orang Yahudi, kemarilah dan bunuhlah dia.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya hari-harinya (Dajjal hidup) ialah selama empat puluh tahun, setahun bagaikan setengah tahun, dan setahun berikutnya seperti sebulan, dan sebulan seperti sepekan dan sisa hari-hari tersebut seperti percikan api (yang cepat terbangnya), salah seorang berada di pintu Madinah di pagi hari, maka belum sampai pintu yang lain ia telah berada di sore hari.\" Lalu dikatakan kepada beliau, \"Wahai Rasulullah, bagaimana kami shalat di hari-hari yang sangat pendek tersebut?\" beliau menjawab: \"Perkirakanlah hari-hari kalian untuk melaksanakan shalat sebagaimana kalian memperkirakan pada hari-hari yang panjang ini, kemudian tunaikanlah shalat.\" Rasulullah shallallahu 'alaihi wasallam bersabda lagi: \"Kemudian Isa bin Maryam akan menjadi seorang hakim yang adil dikalangan ummatku dan seorang pemimpin yang bijaksana, ia akan menghancurkan salib, membunuh babi, menghapus pajak dan membiarkan sedekah, maka ia tidak akan mencari seekor kambing atau seekor unta zakatpun, kedengkian dan permusuhan dihapus, bisa (racun) dari setiap makhluk yang berbisa diangkat sehingga apabila ada seorang bayi perempuan memasukkan tangannya ke dalam mulut ular, maka ular tersebut tidak akan membahayakannya, dan bayi perempuan itu juga dapat menyakiti seekor singa, sedangkan singa tersebut tidak akan membahayakan bayi itu. Dan serigala akan berada di tengah gerombolan kambing seakan-akan ia adalah anjingnya. Dunia akan dipenuhi oleh kedamaian sebagaimana bejana yang bersisi air (karena sangat ratanya), agama akan menjadi satu, maka tidak ada yang disembah selain Allah, terhapusnya seluruh hal yang menyebabkan peperangan, suku Quraiys kembali mengambil kekuasaannya, dan bumi seakan-akan seperti bintangan perak, dan tumbuh-tumbuhannya akan tumbuh seperti zamannya Nabi Adam, sehingga apabila ada sekelompok orang berkumpul untuk makan setangkai anggur, maka hal itu akan membuatnya senang, dan apabila sekelompok orang tersebut berkumpul untuk memakan sebuah delima, maka hal itu juga akan membuat mereka senang. Seekor sapi pada saat itu harganya sangatlah murah dan seekor kuda hanya seharga beberapa dirham.\" Para sahabat berkata, \"Wahai Rasulullah, kenapa kuda menjadi murah?\" beliau bersabda: \"Ia tidak digunakan untuk berperang selamanya.\" Dikatakan kepada beliau, \"Kenapa sapi jantan harganya mahal?\" Beliau bersabda: \"Sebab ia digunakan untuk membajak bumi semuanya. Sesungguhnya tiga tahun sebelum munculnya Dajjal, adalah waktu yang sangat sulit, dimana manusia akan ditimpa oleh kelaparan yang sangat, Allah akan memerintahkan kepada langit pada tahun pertama untuk menahan sepertiga dari hujannya, dan memerintahkan kepada bumi untuk menahan sepertiga dari tanaman-tanamannya. Dan pada tahun kedua Allah akan memerintahkan kepada langit untuk menahan dua pertiga dari hujannya dan memerintahkan kepada bumi untuk menahan duapertiga dari tumbuh-tumbuhannya. Kemudian di tahun yang ketiga, Allah memerintahkan kepada langit untuk menahan semua air hujannya, maka ia tidak meneteskan setetes air pun dan Allah memerintahkan kepada bumi untuk menahan semua tanaman-tanamannya, maka setelah itu tidak dijumpai satu tanaman hijau yang tumbuh dan semua binatang yang berkuku akan mati, kecuali yang tidak dikehendaki oleh Allah.\" kemudian para sahabat bertanya, \"Dengan apakah manusia akan hidup pada saat itu?\" Beliau menjawab: \"Tahlil, takbir dan tahmid akan sama artinya bagi mereka dengan makanan.\" Abu Abdullah berkata; saya mendengar Abu Al Hasan Ath Thanafisi berkata; saya mendengar Abdurrahman Al Muharibi berkata, \"Selayaknya hadits ini diajarkan kepada para pengajar sehingga ia dapat mengajari anak-anak didiknya dalam beberapa kitab.\""},"4030":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا يُونُسُ بْنُ بُكَيْرٍ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ حَدَّثَنِي عَاصِمُ بْنُ عُمَرَ بْنِ قَتَادَةَ عَنْ مَحْمُودِ بْنِ لَبِيدٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تُفْتَحُ يَأْجُوجُ وَمَأْجُوجُ فَيَخْرُجُونَ كَمَا قَالَ اللَّهُ تَعَالَى{ وَهُمْ مِنْ كُلِّ حَدَبٍ يَنْسِلُونَ }فَيَعُمُّونَ الْأَرْضَ وَيَنْحَازُ مِنْهُمْ الْمُسْلِمُونَ حَتَّى تَصِيرَ بَقِيَّةُ الْمُسْلِمِينَ فِي مَدَائِنِهِمْ وَحُصُونِهِمْ وَيَضُمُّونَ إِلَيْهِمْ مَوَاشِيَهُمْ حَتَّى أَنَّهُمْ لَيَمُرُّونَ بِالنَّهَرِ فَيَشْرَبُونَهُ حَتَّى مَا يَذَرُونَ فِيهِ شَيْئًا فَيَمُرُّ آخِرُهُمْ عَلَى أَثَرِهِمْ فَيَقُولُ قَائِلُهُمْ لَقَدْ كَانَ بِهَذَا الْمَكَانِ مَرَّةً مَاءٌ وَيَظْهَرُونَ عَلَى الْأَرْضِ فَيَقُولُ قَائِلُهُمْ هَؤُلَاءِ أَهْلُ الْأَرْضِ قَدْ فَرَغْنَا مِنْهُمْ وَلَنُنَازِلَنَّ أَهْلَ السَّمَاءِ حَتَّى إِنَّ أَحَدَهُمْ لَيَهُزُّ حَرْبَتَهُ إِلَى السَّمَاءِ فَتَرْجِعُ مُخَضَّبَةً بِالدَّمِ فَيَقُولُونَ قَدْ قَتَلْنَا أَهْلَ السَّمَاءِ فَبَيْنَمَا هُمْ كَذَلِكَ إِذْ بَعَثَ اللَّهُ دَوَابَّ كَنَغَفِ الْجَرَادِ فَتَأْخُذُ بِأَعْنَاقِهِمْ فَيَمُوتُونَ مَوْتَ الْجَرَادِ يَرْكَبُ بَعْضُهُمْ بَعْضًا فَيُصْبِحُ الْمُسْلِمُونَ لَا يَسْمَعُونَ لَهُمْ حِسًّا فَيَقُولُونَ مَنْ رَجُلٌ يَشْرِي نَفْسَهُ وَيَنْظُرُ مَا فَعَلُوا فَيَنْزِلُ مِنْهُمْ رَجُلٌ قَدْ وَطَّنَ نَفْسَهُ عَلَى أَنْ يَقْتُلُوهُ فَيَجِدُهُمْ مَوْتَى فَيُنَادِيهِمْ أَلَا أَبْشِرُوا فَقَدْ هَلَكَ عَدُوُّكُمْ فَيَخْرُجُ النَّاسُ وَيَخْلُونَ سَبِيلَ مَوَاشِيهِمْ فَمَا يَكُونُ لَهُمْ رَعْيٌ إِلَّا لُحُومُهُمْ فَتَشْكَرُ عَلَيْهَا كَأَحْسَنِ مَا شَكِرَتْ مِنْ نَبَاتٍ أَصَابَتْهُ قَطُّ","id":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Yunus bin Bukair] dari [Muhammad bin Ishaq] telah menceritakan kepadaku ['Ashim bin Umar bin Qatadah] dari [Mahmud bin Labid] dari [Abu Sa'id Al Khudri], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ya'juj dan Ma'juj akan dibukakan (jalan keluarnya), lantas mereka keluar sebagaimana yang difirmankan oleh Allah: '(Hingga apabila dibukakan (tembok) Ya'juj dan Ma'juj, dan mereka turun dengan cepat dari seluruh tempat yang tinggi) ' (Qs. Al Anbiyaa; 96). Kemudian mereka menguasai bumi seluruhnya dan sebagian kaum Muslimin berpihak ke golongan mereka, sehingga sisanya berada di kota-kota dan benteng-benteng beserta hewan ternak mereka. Ketika mereka melintasi sungai, maka mereka minum dari air sungai tersebut, sehingga mereka tidak menyisakan sesuatu pun di dalamnya. Lalu kelompok yang terakhir dari mereka melintas, maka salah seorang dari kelompok tersebut berkata, 'Sungguh, dahulu tempat ini mengalirkan banyak air! ' Kemudian muncullah seorang dari mereka di atas bumi sambil berkata, 'Mereka semua adalah penguasa bumi, dan kami telah selesai (mengalahkan) mereka, dan sungguh kami akan menantang penduduk langit.' Sehingga seorang dari mereka melemparkan tombaknya ke langit, maka tombak tersebut kembali dengan lumuran darah.\" Lalu mereka berkata, 'Kita telah membunuh penghuni langit.' Ketika mereka dalam keadaan seperti ini, Allah mengutus sekawanan binatang seperti ulat (belatung) pada belalang, lalu menyerang leher-leher mereka sehingga mereka mati bergelimpangan layaknya matinya belalang, dan mereka saling bertumpukan. Pada pagi harinya, kaum muslimin tidak mendengar suara mereka, maka mereka bertanya, 'Siapakah kiranya seorang laki-laki yang menggadaikan dirinya dan melihat apa yang mereka perbuat? ' maka turunlah seorang laki-laki dari mereka yang menyiapkan dirinya untuk mereka bunuh, namun laki-laki itu mendapati mereka telah mati terbunuh, maka ia pun berseru kepada mereka (kaum Muslimin), 'Bergembiralah, musuh kalian telah binasa! ' Maka orang-orang pun keluar dan melepaskan ternak-ternak mereka. Tidaklah mereka memiliki binatang ternak kecuali hanya tersisa daging-dagingnya saja, lantas ia bersyukur atasnya sebagaimana sebaik-baiknya syukur dari tumbuh-tumbuhan yang tidak pernah mendapatkan siraman air.\""},"4031":{"ar":"حَدَّثَنَا أَزْهَرُ بْنُ مَرْوَانَ حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ قَالَ حَدَّثَنَا أَبُو رَافِعٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ يَأْجُوجَ وَمَأْجُوجَ يَحْفِرُونَ كُلَّ يَوْمٍ حَتَّى إِذَا كَادُوا يَرَوْنَ شُعَاعَ الشَّمْسِ قَالَ الَّذِي عَلَيْهِمْ ارْجِعُوا فَسَنَحْفِرُهُ غَدًا فَيُعِيدُهُ اللَّهُ أَشَدَّ مَا كَانَ حَتَّى إِذَا بَلَغَتْ مُدَّتُهُمْ وَأَرَادَ اللَّهُ أَنْ يَبْعَثَهُمْ عَلَى النَّاسِ حَفَرُوا حَتَّى إِذَا كَادُوا يَرَوْنَ شُعَاعَ الشَّمْسِ قَالَ الَّذِي عَلَيْهِمْ ارْجِعُوا فَسَتَحْفِرُونَهُ غَدًا إِنْ شَاءَ اللَّهُ تَعَالَى وَاسْتَثْنَوْا فَيَعُودُونَ إِلَيْهِ وَهُوَ كَهَيْئَتِهِ حِينَ تَرَكُوهُ فَيَحْفِرُونَهُ وَيَخْرُجُونَ عَلَى النَّاسِ فَيُنْشِفُونَ الْمَاءَ وَيَتَحَصَّنُ النَّاسُ مِنْهُمْ فِي حُصُونِهِمْ فَيَرْمُونَ بِسِهَامِهِمْ إِلَى السَّمَاءِ فَتَرْجِعُ عَلَيْهَا الدَّمُ الَّذِي اجْفَظَّ فَيَقُولُونَ قَهَرْنَا أَهْلَ الْأَرْضِ وَعَلَوْنَا أَهْلَ السَّمَاءِ فَيَبْعَثُ اللَّهُ نَغَفًا فِي أَقْفَائِهِمْ فَيَقْتُلُهُمْ بِهَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالَّذِي نَفْسِي بِيَدِهِ إِنَّ دَوَابَّ الْأَرْضِ لَتَسْمَنُ وَتَشْكَرُ شَكَرًا مِنْ لُحُومِهِمْ","id":"Telah menceritakan kepada kami [Azhar bin Marwan] telah menceritakan kepada kami [Abdul A'la] telah menceritakan kepada kami [Sa'id] dari [Qatadah] dia berkata; telah menceritakan kepada kami [Abu Rafi'] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Ya'juj dan Ma'juj menggali lubang setiap harinya. Ketika mereka nyaris melihat cahaya matahari, maka yang mengusai mereka berseru, 'Kembalilah, kita akan menggalinya esok hari.' Maka Allah mengembalikannya melebihi dari yang sebelumnya. Dan ketika masa mereka telah sampai, dan Allah hendak mengirim mereka kepada manusia, maka mereka kembali menggali sampai ketika mereka nyaris melihat cahaya matahari, maka salah satu dari yang mengusai mereka berseru, 'Kembalilah, kalian akan menggalinya esok hari, jika Allah mengizinkan.' Maka mereka menunggu, lalu mereka kembali lagi ke tempat penggalian yang bentuknya masih seperti semula disaat mereka meninggalkannya. Maka mereka terus menggalinya dan akhirnya mereka dapat keluar kepada manusia. Lantas mereka menghirup air, dan manusia pun berlindung dari mereka di benteng-benteng. Lalu mereka melemparkan anak panah mereka ke langit, maka anak panah itu kembali dengan berlumuran darah. Maka mereka berkata, 'Kami telah menundukkan penduduk bumi, dan kami juga telah menguasai penduduk langit.' Setelah itu Allah mengutus sekelompok ulat di kepala mereka, lalu Allah membunuh mereka dengan binatang tersebut.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Demi dzat yang jiwaku berada di tangan-Nya, sesungguhnya bintang-binatang bumi akan menjadi gemuk dan bersyukur berkat daging-daging mereka.\""},"4032":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارِ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا الْعَوَّامُ بْنُ حَوْشَبٍ حَدَّثَنِي جَبَلَةُ بْنُ سُحَيْمٍ عَنْ مُؤْثِرِ بْنِ عَفَازَةَ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَلَمَّا كَانَ لَيْلَةَ أُسْرِيَ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقِيَ إِبْرَاهِيمَ وَمُوسَى وَعِيسَى فَتَذَاكَرُوا السَّاعَةَ فَبَدَءُوا بِإِبْرَاهِيمَ فَسَأَلُوهُ عَنْهَا فَلَمْ يَكُنْ عِنْدَهُ مِنْهَا عِلْمٌ ثُمَّ سَأَلُوا مُوسَى فَلَمْ يَكُنْ عِنْدَهُ مِنْهَا عِلْمٌ فَرُدَّ الْحَدِيثُ إِلَى عِيسَى ابْنِ مَرْيَمَ فَقَالَ قَدْ عُهِدَ إِلَيَّ فِيمَا دُونَ وَجْبَتِهَا فَأَمَّا وَجْبَتُهَا فَلَا يَعْلَمُهَا إِلَّا اللَّهُ فَذَكَرَ خُرُوجَ الدَّجَّالِ قَالَ فَأَنْزِلُ فَأَقْتُلُهُ فَيَرْجِعُ النَّاسُ إِلَى بِلَادِهِمْ فَيَسْتَقْبِلُهُمْ يَأْجُوجُ وَمَأْجُوجُ وَهُمْ مِنْ كُلِّ حَدَبٍ يَنْسِلُونَ فَلَا يَمُرُّونَ بِمَاءٍ إِلَّا شَرِبُوهُ وَلَا بِشَيْءٍ إِلَّا أَفْسَدُوهُ فَيَجْأَرُونَ إِلَى اللَّهِ فَأَدْعُو اللَّهَ أَنْ يُمِيتَهُمْ فَتَنْتُنُ الْأَرْضُ مِنْ رِيحِهِمْ فَيَجْأَرُونَ إِلَى اللَّهِ فَأَدْعُو اللَّهَ فَيُرْسِلُ السَّمَاءَ بِالْمَاءِ فَيَحْمِلُهُمْ فَيُلْقِيهِمْ فِي الْبَحْرِ ثُمَّ تُنْسَفُ الْجِبَالُ وَتُمَدُّ الْأَرْضُ مَدَّ الْأَدِيمِ فَعُهِدَ إِلَيَّ مَتَى كَانَ ذَلِكَ كَانَتْ السَّاعَةُ مِنْ النَّاسِ كَالْحَامِلِ الَّتِي لَا يَدْرِي أَهْلُهَا مَتَى تَفْجَؤُهُمْ بِوِلَادَتِهَاقَالَ الْعَوَّامُ وَوُجِدَ تَصْدِيقُ ذَلِكَ فِي كِتَابِ اللَّهِ تَعَالَى{ حَتَّى إِذَا فُتِحَتْ يَأْجُوجُ وَمَأْجُوجُ وَهُمْ مِنْ كُلِّ حَدَبٍ يَنْسِلُونَ }","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [Al 'Awam bin Hausyab] telah menceritakan kepadaku [Jabalah bin Suhaim] dari [Mu`tsir bin 'Afarah] dari [Abdullah bin Mas'ud] dia berkata, \"Ketika Rasulullah shallallahu 'alaihi wasallam di isra'kan di malam isra'nya, beliau bertemu dengan Ibrahim, Musa dan Isa, lantas mereka menyebutkan mengenai hari Kiamat. Dimulai dari Ibrahim, kemudian mereka bertanya kepadanya mengenai terjadinya hari Kiamat namun Ibrahim tidak mengetahuinya, kemudian mereka bertanya kepada Musa namun Musa juga tidak mengetahuinya, kemudian pembicaraan mereka kembali kepada Isa bin Maryam, maka Isa berkata, \"Sungguh telah diikrarkan kepadaku segala hal selain kejadian Kiamat, adapun kejadiannya maka tidak seorang pun yang mengetahuinya kecuali Allah, setelah itu Isa menyebutkan tentang munculnya Dajjal, dia berkata, \"Kemudian saya diturunkan dan berhasil membunuhnya, sehingga kebanyakan manusia kembali ke negaranya masing-masing. Ternyata mereka bertemu dengan Ya'juj dan Ma'juj, dan mereka (Ya'juj dan Ma'juj) turun dengan cepat dari tempat yang tinggi, mereka tidak melintasi mata air (sungai) melainkan akan meminum habis airnya, dan tidak pula (melintasi) sesuatu melainkan mereka akan membuat kerusakan. Maka saya memohon kepada Allah dengan mengangkat suara supaya mereka dibinasakan, lantas bumi berbau busuk (karena bangkainya), maka saya memohon kepada Allah dengan penuh harap dan mengangkat suara, lantas Allah menurunkan air hujan dan membawa (bangkai) mereka dan melemparkan (bangkai) mereka di lautan. Kemudian gunung-gunung diratakan dan bumi dibentangkan sebagaimana kulit (binatang) sehabis disamak, lalu diberitahukan kepadaku, sekiranya hal itu telah terjadi, maka Kiamat oleh manusia ibarat seorang wanita hamil yang keluarganya tidak mengetahui kapan kelahirannya akan tiba.\" Al 'Awam berkata, \"Ternyata kebenaran hal itu didapati dalam Kitabullah Ta'ala: '(Hingga apabila dibukakan (tembok) Ya'juj dan Ma'juj, dan mereka turun dengan cepat dari seluruh tempat yang tinggi) ' (Qs. Al Anbiyaa; 96)."},"4033":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُعَاوِيَةُ بْنُ هِشَامٍ حَدَّثَنَا عَلِيُّ بْنُ صَالِحٍ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَبَيْنَمَا نَحْنُ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ أَقْبَلَ فِتْيَةٌ مِنْ بَنِي هَاشِمٍ فَلَمَّا رَآهُمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اغْرَوْرَقَتْ عَيْنَاهُ وَتَغَيَّرَ لَوْنُهُ قَالَ فَقُلْتُ مَا نَزَالُ نَرَى فِي وَجْهِكَ شَيْئًا نَكْرَهُهُ فَقَالَ إِنَّا أَهْلُ بَيْتٍ اخْتَارَ اللَّهُ لَنَا الْآخِرَةَ عَلَى الدُّنْيَا وَإِنَّ أَهْلَ بَيْتِي سَيَلْقَوْنَ بَعْدِي بَلَاءً وَتَشْرِيدًا وَتَطْرِيدًا حَتَّى يَأْتِيَ قَوْمٌ مِنْ قِبَلِ الْمَشْرِقِ مَعَهُمْ رَايَاتٌ سُودٌ فَيَسْأَلُونَ الْخَيْرَ فَلَا يُعْطَوْنَهُ فَيُقَاتِلُونَ فَيُنْصَرُونَ فَيُعْطَوْنَ مَا سَأَلُوا فَلَا يَقْبَلُونَهُ حَتَّى يَدْفَعُوهَا إِلَى رَجُلٍ مِنْ أَهْلِ بَيْتِي فَيَمْلَؤُهَا قِسْطًا كَمَا مَلَئُوهَا جَوْرًا فَمَنْ أَدْرَكَ ذَلِكَ مِنْكُمْ فَلْيَأْتِهِمْ وَلَوْ حَبْوًا عَلَى الثَّلْجِ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Mu'awiyah bin Hisyam] telah menceritakan kepada kami [Ali bin Shalih] dari [Yazid bin Abu Ziyad] dari [Ibrahim] dari ['Alqamah] dari [Abdullah] dia berkata, \"Ketika kami berada di sisi Rasulullah shallallahu 'alaihi wasallam, tiba-tiba seorang pemuda dari Bani Hasyim datang, ketika Nabi shallallahu 'alaihi wasallam melihat mereka, maka kedua mata beliau terlihat berbinar-binar dan berubah wajahnya.\" Abdullah berkata, \"Lalu saya bertanya, \"Kenapa kami masih melihat di wajah anda ada sesuatu yang kami benci?\" beliau menjawab: \"Sesungguhnya kami adalah ahli bait yang Allah memilihkan akhirat buat kami atas dunia. Dan sungguh, sepeninggalku nanti ahli baitku akan menemui musibah, bencana dan pengusiran, sehingga suatu kaum dari timur datang dengan membawa bendera-bendera hitam, mereka meminta (diterapkannya) kebaikan namun ditolak. Kemudian mereka berperang dan mendapatkan kemenangan, akhirnya mereka diberi apa yang mereka minta, lalu kaum tersebut tidak mau menerima sehingga mereka menyerahkan urusan tersebut kepada seorang laki-laki dari ahli baitku, lantas ia memenuhinya dengan keadilan sebagaimana (sebelumnya) bumi dipenuhi dengan kejatahan. Barangsiapa dari kalian mendapatinya, maka berbaiatlah walau dalam keadaan merangkak di atas salju.\""},"4034":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ مَرْوَانَ الْعُقَيْلِيُّ حَدَّثَنَا عُمَارَةُ بْنُ أَبِي حَفْصَةَ عَنْ زَيْدٍ الْعَمِّيِّ عَنْ أَبِي صِدِّيقٍ النَّاجِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَكُونُ فِي أُمَّتِي الْمَهْدِيُّ إِنْ قُصِرَ فَسَبْعٌ وَإِلَّا فَتِسْعٌ فَتَنْعَمُ فِيهِ أُمَّتِي نِعْمَةً لَمْ يَنْعَمُوا مِثْلَهَا قَطُّ تُؤْتَى أُكُلَهَا وَلَا تَدَّخِرُ مِنْهُمْ شَيْئًا وَالْمَالُ يَوْمَئِذٍ كُدُوسٌ فَيَقُومُ الرَّجُلُ فَيَقُولُ يَا مَهْدِيُّ أَعْطِنِي فَيَقُولُ خُذْ","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] telah menceritakan kepada kami [Muhammad bin Marwan Al 'Uqaili] telah menceritakan kepada kami ['Umarah bin Abu Hafshah] dari [Zaid Al 'Ammi] dari [Abu Shidiq An Naji] dari [Abu Sa'id Al Khudri], bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Akan ada pada ummatku Al Mahdi, jika dipendekkan (hidupnya bersama kalian) maka menjadi tujuh (tahun), dan jika tidak maka menjadi sembilan (Tahun). Lantas ummatku akan mendapatkan kenikmatan yang belum pernah mereka rasakan sama sekali (sebelumnya). Akan diberikan makanannya, maka janganlah kalian menyimpannya sedikitpun. Dan harta benda pada hari itu begitu melimpah, lalu ada seorang laki-laki berdiri sambil berkata, 'Wahai Al Mahdi, berilah aku.' Ia menjawab, 'Ambillah'.\""},"4035":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى وَأَحْمَدُ بْنُ يُوسُفَ قَالَا حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ سُفْيَانَ الثَّوْرِيِّ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي أَسْمَاءَ الرَّحَبِيِّ عَنْ ثَوْبَانَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْتَتِلُ عِنْدَ كَنْزِكُمْ ثَلَاثَةٌ كُلُّهُمْ ابْنُ خَلِيفَةٍ ثُمَّ لَا يَصِيرُ إِلَى وَاحِدٍ مِنْهُمْ ثُمَّ تَطْلُعُ الرَّايَاتُ السُّودُ مِنْ قِبَلِ الْمَشْرِقِ فَيَقْتُلُونَكُمْ قَتْلًا لَمْ يُقْتَلْهُ قَوْمٌ ثُمَّ ذَكَرَ شَيْئًا لَا أَحْفَظُهُ فَقَالَ فَإِذَا رَأَيْتُمُوهُ فَبَايِعُوهُ وَلَوْ حَبْوًا عَلَى الثَّلْجِ فَإِنَّهُ خَلِيفَةُ اللَّهِ الْمَهْدِيُّ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] dan [Ahmad bin Yusuf] keduanya berkata; telah menceritakan kepada kami [Abdurrazaq] dari [Sufyan At Tsauri] dari [Khalid bin Al Khadza] dari [Abu Qilabah] dari [Abu Asma Ar Rahabi] dari [Tsauban] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kelak tiga orang akan berperang didekat perbendaharaan kalian ini (yaitu Ka'bah), dan kesemuanya adalah anak khalifah. Dan tidak ada yang menang melainkan satu orang, lalu muncullah bendera-bendera hitam dari wilayah timur, mereka lantas memerangi kalian dengan peperangan sengit yang sama sekali belum pernah dilakukan kaum manapun. Jika kalian melihatnya, maka berbaiatlah kepadanya walaupun sambil merangkak di atas salju, karena sesungguhnya dia adalah khalifah Allah Al Mahdi.\""},"4036":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو دَاوُدَ الْحَفَرِيُّ حَدَّثَنَا يَاسِينُ عَنْ إِبْرَاهِيمَ بْنِ مُحَمَّدِ ابْنِ الْحَنَفِيَّةِ عَنْ أَبِيهِ عَنْ عَلِيٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَهْدِيُّ مِنَّا أَهْلَ الْبَيْتِ يُصْلِحُهُ اللَّهُ فِي لَيْلَةٍ","id":"Telah menceritakan kepada kami ['Utsman bin Abu Syaibah] telah menceritakan kepada kami [Abu Daud Al Hafari] telah menceritakan kepada kami [Yasin] dari [Ibrahim bin Muhammad bin Al Hanafiyah] dari [Ayahnya] dari [Ali] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Al Mahdi dari (keturunan) kami, yaitu ahli bait yang Allah memperbaiki (keadaannya) dalam semalam.\""},"4037":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ الْمَلِكِ حَدَّثَنَا أَبُو الْمَلِيحِ الرَّقِّيُّ عَنْ زِيَادِ بْنِ بَيَانٍ عَنْ عَلِيِّ بْنِ نُفَيْلٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ قَالَكُنَّا عِنْدَ أُمِّ سَلَمَةَ فَتَذَاكَرْنَا الْمَهْدِيَّ فَقَالَتْ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْمَهْدِيُّ مِنْ وَلَدِ فَاطِمَةَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Ahmad bin Abdul Malik] telah menceritakan kepada kami [Abu Al Malih Ar Raqqi] dari [Ziyad bin Bayan] dari [Ali bin Nufail] dari [Sa'id bin Al Musayyab] dia berkata, \"Ketika kami berada di samping [Ummu Salamah], tiba-tiba dia menyebutkan kepada kami mengenai perkara Mahdi, katanya, \"Saya pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Al Mahdi berasal dari anak keturunan Fatimah.\""},"4038":{"ar":"حَدَّثَنَا هَدِيَّةُ بْنُ عَبْدِ الْوَهَّابِ حَدَّثَنَا سَعْدُ بْنُ عَبْدِ الْحَمِيدِ بْنِ جَعْفَرٍ عَنْ عَلِيِّ بْنِ زِيَادٍ الْيَمَامِيِّ عَنْ عِكْرِمَةَ بْنِ عَمَّارٍ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ نَحْنُ وَلَدَ عَبْدِ الْمُطَّلِبِ سَادَةُ أَهْلِ الْجَنَّةِ أَنَا وَحَمْزَةُ وَعَلِيٌّ وَجَعْفَرٌ وَالْحَسَنُ وَالْحُسَيْنُ وَالْمَهْدِيُّ","id":"Telah menceritakan kepada kami [Hadiyyah bin Abdul Wahhab] telah menceritakan kepada kami [Sa'd bin Abdul Hamid bin Ja'far] dari ['Ali bin Ziyad Al Yamami] dari ['Ikrimah bin 'Ammar] dari [Ishaq bin Abdullah bin Abu Thalhah] dari [Anas bin Malik] dia berkata, \"Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kami adalah anak keturunan Abdul Muthalib, pemuka penduduk surga, yaitu; Aku, Hamzah, 'Ali, Ja'far, Hasan, Husain dan Al Mahdi.\""},"4039":{"ar":"حَدَّثَنَا حَرْمَلَةُ بْنُ يَحْيَى الْمِصْرِيُّ وَإِبْرَاهِيمُ بْنُ سَعِيدٍ الْجَوْهَرِيُّ قَالَا حَدَّثَنَا أَبُو صَالِحٍ عَبْدُ الْغَفَّارِ بْنُ دَاوُدَ الْحَرَّانِيُّ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ أَبِي زُرْعَةَ عَمْرِو بْنِ جَابِرٍ الْحَضْرَمِيِّ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ بْنَ جَزْءٍ الزَّبِيدِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْرُجُ نَاسٌ مِنْ الْمَشْرِقِ فَيُوَطِّئُونَ لِلْمَهْدِيِّ يَعْنِي سُلْطَانَهُ","id":"Telah menceritakan kepada kami [Harmalah bin Yahya Al Mishri] dan [Ibrahim bin Sa'id Al Jauhari] keduanya berkata; telah menceritakan kepada kami [Abu Shalih Abdul Ghafar bin Daud Al Harrani] telah menceritakan kepada kami [Ibnu Lahi'ah] dari [Abu Zur'ah Amru bin Jabir Al Hadlrami] dari [Abdullah bin Al Harits bin Jaz`I Az Zabidi] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sekelompok manusia datang dari arah timur lalu menyerahkan kekuasaannya kepada Al Mahdi.\""},"4040":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ الْأَوْزَاعِيِّ عَنْ حَسَّانَ بْنِ عَطِيَّةَ قَالَ مَالَ مَكْحُولٌ وَابْنُ أَبِي زَكَرِيَّا إِلَى خَالِدِ بْنِ مَعْدَانَ وَمِلْتُ مَعَهُمَا فَحَدَّثَنَا عَنْ جُبَيْرِ بْنِ نُفَيْرٍ قَالَقَالَ لِي جُبَيْرٌ انْطَلِقْ بِنَا إِلَى ذِي مِخْمَرٍ وَكَانَ رَجُلًا مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَانْطَلَقْتُ مَعَهُمَا فَسَأَلَهُ عَنْ الْهُدْنَةِ فَقَالَ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ سَتُصَالِحُكُمْ الرُّومُ صُلْحًا آمِنًا ثُمَّ تَغْزُونَ أَنْتُمْ وَهُمْ عَدُوًّا فَتَنْتَصِرُونَ وَتَغْنَمُونَ وَتَسْلَمُونَ ثُمَّ تَنْصَرِفُونَ حَتَّى تَنْزِلُوا بِمَرْجٍ ذِي تُلُولٍ فَيَرْفَعُ رَجُلٌ مِنْ أَهْلِ الصَّلِيبِ الصَّلِيبَ فَيَقُولُ غَلَبَ الصَّلِيبُ فَيَغْضَبُ رَجُلٌ مِنْ الْمُسْلِمِينَ فَيَقُومُ إِلَيْهِ فَيَدُقُّهُ فَعِنْدَ ذَلِكَ تَغْدِرُ الرُّومُ وَيَجْتَمِعُونَ لِلْمَلْحَمَةِحَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ حَسَّانَ بْنِ عَطِيَّةَ بِإِسْنَادِهِ نَحْوَهُ وَزَادَ فِيهِ فَيَجْتَمِعُونَ لِلْمَلْحَمَةِ فَيَأْتُونَ حِينَئِذٍ تَحْتَ ثَمَانِينَ غَايَةٍ تَحْتَ كُلِّ غَايَةٍ اثْنَا عَشَرَ أَلْفًا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Isa bin Yunus] dari [Al Auza'i] dari [Al Hasan bin 'Athiyah] dia berkata, \"Makhul dan Ibnu Abu Zakaria pergi menemui Khalid bin Ma'dan, dan aku pun ikut bersama mereka berdua, lantas [Khalid bin Ma'dan] menceritakan kepada kami dari [Jubair bin Nufair] ia berkata, \"Jubair bin Nufair pernah berkata kepadaku, \"Mari kita pergi menemui [Dzul Mikhmar] -salah seorang dari sahabat Nabi shallallahu 'alaihi wasallam-, maka aku pun pergi bersamanya. Aku lalu bertanya kepadanya tentang kejadian malahim (peperangan yang besar). Dia menjawab, \"Aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bangsa Romawi akan berdamai dengan kalian, setelah itu mereka bersama kalian akan berperang melawan musuh hingga kalian menang dan mendapatkan harta rampasan, dan mereka akhirnya menyerah. Setelah itu, kalian akan pergi menuju padang rumput yang berbukit. Lalu ada seorang tentara salib mengangkat salib sambil berkata, '(Tentara) salib telah menang.' Maka salah seorang Muslim marah ketika mendengarnya, lalu ia mendekati laki-laki tersebut dan memukulnya. Maka saat itulah bangsa Romawi berkhianat (dari perdamaian), hingga mereka berkumpul untuk melakukan peperangan besar-besaran.\" Telah menceritakan kepada kami [Abdurrahman bin Ibrahim Ad Dimasyqi] telah menceritakan kepada kami [Al Walid bin Muslim] telah menceritakan kepada kami [Al Auza'i] dari [Hasan bin 'Athiyah] dengan isnad seperti hadits di atas, namun dia menambahkan, \"Lantas mereka berkumpul untuk melakukan peperangan besar-besaran, sehingga saat itu mereka datang di bawah delapan puluh bendera (komandan), dan setiap bendera membawahi dua belas ribu tentara.\""},"4041":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا عُثْمَانُ بْنُ أَبِي الْعَاتِكَةِ عَنْ سُلَيْمَانَ بْنِ حَبِيبٍ الْمُحَارِبِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا وَقَعَتْ الْمَلَاحِمُ بَعَثَ اللَّهُ بَعْثًا مِنْ الْمَوَالِي هُمْ أَكْرَمُ الْعَرَبِ فَرَسًا وَأَجْوَدُهُ سِلَاحًا يُؤَيِّدُ اللَّهُ بِهِمْ الدِّينَ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Al Walid bin Muslim] telah menceritakan kepada kami ['Utsman bin Abu Al 'Atikah] dari [Sulaiman bin Habib Al Muharibi] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika terjadi peperangan yang besar maka Allah akan mengutus para penolong-Nya, mereka adalah tentara Arab yang paling mulia dan yang paling bagus senjatanya. Dan dengan merekalah Allah memuliakan Islam.\""},"4042":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا الْحُسَيْنُ بْنُ عَلِيٍّ عَنْ زَائِدَةَ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ جَابِرِ بْنِ سَمُرَةَ عَنْ نَافِعِ بْنِ عُتْبَةَ بْنِ أَبِي وَقَّاصٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ سَتُقَاتِلُونَ جَزِيرَةَ الْعَرَبِ فَيَفْتَحُهَا اللَّهُ ثُمَّ تُقَاتِلُونَ الرُّومَ فَيَفْتَحُهَا اللَّهُ ثُمَّ تُقَاتِلُونَ الدَّجَّالَ فَيَفْتَحُهَا اللَّهُقَالَ جَابِرٌ فَمَا يَخْرُجُ الدَّجَّالُ حَتَّى تُفْتَحَ الرُّومُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Al Husain bin 'Ali] dari [Zaidah] dari [Abdul Malik bin 'Umair] dari [Jabir bin Samurah] dari [Nafi' bin 'Utbah bin Abu Waqash] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Kalian akan berperang melawan Jazirah Arab, kemudian Allah menaklukkan buat kalian. Setelah itu kalian akan berperang melawan orang-orang Romawi, lalu Allah menaklukkannya. Setelah itu kalian akan berperang melawan Dajjal, kemudian Allah akan menaklukkannya.\" Jabir berkata, \"Dajjal tidak akan keluar hingga bangsa Romawi dapat dikalahkan.\""},"4043":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ وَإِسْمَعِيلُ بْنُ عَيَّاشٍ قَالَا حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي مَرْيَمَ عَنْ الْوَلِيدِ بْنِ سُفْيَانَ بْنِ أَبِي مَرْيَمَ عَنْ يَزِيدَ بْنِ قُطَيْبٍ السَّكُونِيِّ وَقَالَ الْوَلِيدُ يَزِيدُ بْنُ قُطْبَةَ عَنْ أَبِي بَحْرِيَّةَ عَنْ مُعَاذِ بْنِ جَبَلٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمَلْحَمَةُ الْكُبْرَى وَفَتْحُ الْقُسْطَنْطِينِيَّةِ وَخُرُوجُ الدَّجَّالِ فِي سَبْعَةِ أَشْهُرٍ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Al Walid bin Muslim] dan [Isma'il bin 'Ayyasy] keduanya berkata; telah menceritakan kepada kami [Abu Bakar bin Abu Maryam] dari [Al Walid bin Sufyan bin Abu Maryam] dari [Yazid bin Quthaib As Sakuni], dan Al Walid berkata; Yazid bin Quthbah dari [Abu Bahriyah] dari [Mu'adz bin Jabal] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Peperangan yang besar, penaklukan Kostantinopel dan keluarnya Dajjal muncul selama tujuh bulan.\""},"4044":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا بَقِيَّةُ عَنْ بَحِيرِ بْنِ سَعْدٍ عَنْ خَالِدٍ عَنْ ابْنِ أَبِي بِلَالٍ عَنْ عَبْدِ اللَّهِ بْنِ بُسْرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ الْمَلْحَمَةِ وَفَتْحِ الْمَدِينَةِ سِتُّ سِنِينَ وَيَخْرُجُ الدَّجَّالُ فِي السَّابِعَةِ","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] telah menceritakan kepada kami [Baqiyah] dari [Bahir bin Sa'd] dari [Khalid] dari [Ibnu Abu Bilal] dari [Abdullah bin Busr] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Antara Malhamah (peperangan yang besar) dan penaklukan Madinah berjarak enam tahun, kemudian Dajjal muncul ditahun yang Ketujuh.\""},"4045":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مَيْمُونٍ الرَّقِّيُّ حَدَّثَنَا أَبُو يَعْقُوبَ الْحُنَيْنِيُّ عَنْ كَثِيرِ بْنِ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ عَوْفٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَقُومُ السَّاعَةُ حَتَّى تَكُونَ أَدْنَى مَسَالِحِ الْمُسْلِمِينَ بِبَوْلَاءَ ثُمَّ قَالَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا عَلِيُّ يَا عَلِيُّ يَا عَلِيُّ قَالَ بِأَبِي وَأُمِّي قَالَ إِنَّكُمْ سَتُقَاتِلُونَ بَنِي الْأَصْفَرِ وَيُقَاتِلُهُمْ الَّذِينَ مِنْ بَعْدِكُمْ حَتَّى تَخْرُجَ إِلَيْهِمْ رُوقَةُ الْإِسْلَامِ أَهْلُ الْحِجَازِ الَّذِينَ لَا يَخَافُونَ فِي اللَّهِ لَوْمَةَ لَائِمٍ فَيَفْتَتِحُونَ الْقُسْطَنْطِينِيَّةَ بِالتَّسْبِيحِ وَالتَّكْبِيرِ فَيُصِيبُونَ غَنَائِمَ لَمْ يُصِيبُوا مِثْلَهَا حَتَّى يَقْتَسِمُوا بِالْأَتْرِسَةِ وَيَأْتِي آتٍ فَيَقُولُ إِنَّ الْمَسِيحَ قَدْ خَرَجَ فِي بِلَادِكُمْ أَلَا وَهِيَ كِذْبَةٌ فَالْآخِذُ نَادِمٌ وَالتَّارِكُ نَادِمٌ","id":"Telah menceritakan kepada kami [Ali bin Maimun Ar Raqqi] telah menceritakan kepada kami [Abu Ya'qub Al Hunaini] dari [Katsir bin Abdullah bin 'Amru bin 'Auf] dari [Ayahnya] dari [Kakeknya] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak akan terjadi hari Kiamat sehingga kalian dengan Bani Ashfar akan terjadi genjatan senjata, kemudian mereka mengkhianati kalian dan menyerang kalian di bawah delapan puluh bendera (kelompok pasukan), dan setiap kelompok pasukan terdiri dari dua belas ribu pasukan.\""},"4046":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْعَلَاءِ حَدَّثَنِي بُسْرُ بْنُ عُبَيْدِ اللَّهِ حَدَّثَنِي أَبُو إِدْرِيسَ الْخَوْلَانِيُّ حَدَّثَنِي عَوْفُ بْنُ مَالِكٍ الْأَشْجَعِيُّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَكُونُ بَيْنَكُمْ وَبَيْنَ بَنِي الْأَصْفَرِ هُدْنَةٌ فَيَغْدِرُونَ بِكُمْ فَيَسِيرُونَ إِلَيْكُمْ فِي ثَمَانِينَ غَايَةً تَحْتَ كُلِّ غَايَةٍ اثْنَا عَشَرَ أَلْفًا","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibrahim] telah menceritakan kepada kami [Al Walid bin Muslim] telah menceritakan kepada kami [Abdullah bin Al 'Ala] telah menceritakan kepadaku [Busr bin 'Ubaidullah] telah menceritakan kepadaku [Abu Idris Al Khaulani] telah menceritakan kepadaku ['Auf bin Malik Al Asyja'i] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Akan terjadi antara kalian dengan Bani Ashfar (bangsa berkulit kuning) genjatan senjata (perdamaian), lalu mereka mengkhianati kalian. Setelah itu mereka akan mendatangi kalian (menyerang) di bawah delapan puluh bendera (kelompok pasukan), dan setiap kelompok pasukan terdiri dari dua belas ribu pasukan.\""},"4047":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَيَبْلُغُ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَقُومُ السَّاعَةُ حَتَّى تُقَاتِلُوا قَوْمًا نِعَالُهُمْ الشَّعَرُ وَلَا تَقُومُ السَّاعَةُ حَتَّى تُقَاتِلُوا قَوْمًا صِغَارَ الْأَعْيُنِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Az Zuhri] dari [Sa'id bin Musayyab] dari [Abu Hurairah] dan sampai kepada Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak akan terjadi hari Kiamat sehingga kalian memerangi suatu kaum yang sandal-sandal mereka terbuat dari bulu, dan tidak akan terjadi hari Kiamat sehingga kalian memerangi suatu kaum yang bermata sipit.\""},"4048":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَقُومُ السَّاعَةُ حَتَّى تُقَاتِلُوا قَوْمًا صِغَارَ الْأَعْيُنِ ذُلْفَ الْأُنُوفِ كَأَنَّ وُجُوهَهُمْ الْمَجَانُّ الْمُطْرَقَةُ وَلَا تَقُومُ السَّاعَةُ حَتَّى تُقَاتِلُوا قَوْمًا نِعَالُهُمْ الشَّعَرُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kiamat tidak akan terjadi sehingga kalian berperang melawan suatu kaum yang bermata sipit, berhidung pesek, seakan-akan wajah mereka tameng yang terbuat dari kulit yang berlapis-lapis. Dan tidak akan terjadi hari Kiamat hingga kalian memerangi kaum bersepatu bulu.\""},"4049":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَسْوَدُ بْنُ عَامِرٍ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ حَدَّثَنَا الْحَسَنُ عَنْ عَمْرِو بْنِ تَغْلِبَ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ مِنْ أَشْرَاطِ السَّاعَةِ أَنْ تُقَاتِلُوا قَوْمًا عِرَاضَ الْوُجُوهِ كَأَنَّ وُجُوهَهُمْ الْمَجَانُّ الْمُطْرَقَةُ وَإِنَّ مِنْ أَشْرَاطِ السَّاعَةِ أَنْ تُقَاتِلُوا قَوْمًا يَنْتَعِلُونَ الشَّعَرَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Aswad bin 'Amir] telah menceritakan kepada kami [Jarir bin Hazim] telah menceritakan kepada kami [Al Hasan] dari ['Amru bin Taghlab] dia berkata, \"Saya mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya diantara tanda-tanda hari Kiamat adalah kalian memerangi suatu kaum yang berwajah lebar, seakan-akan wajah mereka seperti tameng yang terbuat dari kulit yang berlapis-lapis. Dan sesungguhnya dari tanda-tanda datangnya hari Kiamat adalah kalian akan berperang melawan kaum yang memakai sepatu berbulu.\""},"4050":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَرَفَةَ حَدَّثَنَا عَمَّارُ بْنُ مُحَمَّدٍ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّقَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَقُومُ السَّاعَةُ حَتَّى تُقَاتِلُوا قَوْمًا صِغَارَ الْأَعْيُنِ عِرَاضَ الْوُجُوهِ كَأَنَّ أَعْيُنَهُمْ حَدَقُ الْجَرَادِ كَأَنَّ وُجُوهَهُمْ الْمَجَانُّ الْمُطْرَقَةُ يَنْتَعِلُونَ الشَّعَرَ وَيَتَّخِذُونَ الدَّرَقَ يَرْبُطُونَ خَيْلَهُمْ بِالنَّخْلِ","id":"Telah menceritakan kepada kami [Al Hasan bin 'Arafah] telah menceritakan kepada kami ['Ammar bin Muhammad] dari [Al A'masy] dari [Abu As Shalih] dari [Abu Sa'id Al Khudri] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak akan terjadi hari Kiamat hingga kalian berperang melawan kaum yang bermata sipit dan berwajah lebar, seakan-akan mata mereka seperti tameng yang terbuat dari kulit yang berlapis-lapis. Mereka memakai sepatu dari wool dan membawa perisai dari kulit, dan mereka mengikat kudanya di bawah pohon kurma.\""},"4051":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا عَمْرُو بْنُ وَاقِدٍ الْقُرَشِيُّ حَدَّثَنَا يُونُسُ بْنُ مَيْسَرَةَ بْنِ حَلْبَسٍ عَنْ أَبِي إِدْرِيسَ الْخَوْلَانِيِّ عَنْ أَبِي ذَرٍّ الْغِفَارِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ الزَّهَادَةُ فِي الدُّنْيَا بِتَحْرِيمِ الْحَلَالِ وَلَا فِي إِضَاعَةِ الْمَالِ وَلَكِنْ الزَّهَادَةُ فِي الدُّنْيَا أَنْ لَا تَكُونَ بِمَا فِي يَدَيْكَ أَوْثَقَ مِنْكَ بِمَا فِي يَدِ اللَّهِ وَأَنْ تَكُونَ فِي ثَوَابِ الْمُصِيبَةِ إِذَا أُصِبْتَ بِهَا أَرْغَبَ مِنْكَ فِيهَا لَوْ أَنَّهَا أُبْقِيَتْ لَكَقَالَ هِشَامٌ كَانَ أَبُو إِدْرِيسَ الْخَوْلَانِيُّ يَقُولُ مِثْلُ هَذَا الْحَدِيثِ فِي الْأَحَادِيثِ كَمِثْلِ الْإِبْرِيزِ فِي الذَّهَبِ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami ['Amru bin Waqid Al Qurasyi] telah menceritakan kepada kami [Yunus bin Maisarah bin Halbas] dari [Abu Idris Al Khaulani] dari [Abu Dzar Al Ghifari] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak dikatakan zuhud terhadap dunia mengharamkan sesuatu yang halal dan tidak menghambur-hamburkan harta, tetapi zuhud terhadap dunia adalah apa yang kamu miliki tidak lebih kamu sukai dari apa yang ada di tangan Allah, dan hendaknya pahala karena sabar terhadap Musibah yang menimpamu lebih kamu sukai, dari (sekiranya) benda tersebut berada di tanganmu.\" Hisyam berkata, \"Abu Idris Al Khaulani berkata, \"Permisalan hadits ini dengan beberapa hadits lainnya ibarat emas murni di dalam emas biasa.\""},"4052":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا الْحَكَمُ بْنُ هِشَامٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ أَبِي فَرْوَةَ عَنْ أَبِي خَلَّادٍ وَكَانَتْ لَهُ صُحْبَةٌ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَأَيْتُمْ الرَّجُلَ قَدْ أُعْطِيَ زُهْدًا فِي الدُّنْيَا وَقِلَّةَ مَنْطِقٍ فَاقْتَرِبُوا مِنْهُ فَإِنَّهُ يُلْقِي الْحِكْمَةَ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Al Hakam bin Hisyam] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Abu Farwah] dari [Abu Khallad] salah seorang sahabat Nabi, ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika kalian melihat ada seseorang yang diberi sikap zuhud terhadap dunia dan sedikit berbicara, maka dekatilah sebab ia telah di beri hikmah.\""},"4053":{"ar":"حَدَّثَنَا أَبُو عُبَيْدَةَ بْنُ أَبِي السَّفَرِ حَدَّثَنَا شِهَابُ بْنُ عَبَّادٍ حَدَّثَنَا خَالِدُ بْنُ عَمْرٍو الْقُرَشِيُّ عَنْ سُفْيَانَ الثَّوْرِيِّ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ السَّاعِدِيِّ قَالَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ دُلَّنِي عَلَى عَمَلٍ إِذَا أَنَا عَمِلْتُهُ أَحَبَّنِي اللَّهُ وَأَحَبَّنِي النَّاسُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ازْهَدْ فِي الدُّنْيَا يُحِبَّكَ اللَّهُ وَازْهَدْ فِيمَا فِي أَيْدِي النَّاسِ يُحِبُّوكَ","id":"Telah menceritakan kepada kami [Abu 'Ubaidah bin Abu As Safar] telah menceritakan kepada kami [Syihab bin 'Abbad] telah menceritakan kepada kami [Khalid bin 'Amru Al Qurasyi] dari [Sufyan Ats Tsauri] dari [Abu Hazim] dari [Sahl bin Sa'd As Sa'idi] dia berkata, \"Seorang laki-laki datang kepada Nabi shallallahu 'alaihi wasallam seraya berkata, \"Wahai Rasulullah, tunjukkanlah kepadaku suatu amalan yang jika aku kerjakan maka Allah dan seluruh manusia akan mencintaiku.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berlakulah zuhud dalam urusan dunia niscaya kamu akan dicintai Allah, dan zuhudlah kamu terhadap apa yang dimiliki orang lain niscaya kamu akan dicintai orang-orang.\""},"4054":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ أَبِي وَائِلٍ عَنْ سَمُرَةَ بْنِ سَهْمٍ رَجُلٍ مِنْ قَوْمِهِ قَالَنَزَلْتُ عَلَى أَبِي هَاشِمِ بْنِ عُتْبَةَ وَهُوَ طَعِينٌ فَأَتَاهُ مُعَاوِيَةُ يَعُودُهُ فَبَكَى أَبُو هَاشِمٍ فَقَالَ مُعَاوِيَةُ مَا يُبْكِيكَ أَيْ خَالِ أَوَجَعٌ يُشْئِزُكَ أَمْ عَلَى الدُّنْيَا فَقَدْ ذَهَبَ صَفْوُهَا قَالَ عَلَى كُلٍّ لَا وَلَكِنْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَهِدَ إِلَيَّ عَهْدًا وَدِدْتُ أَنِّي كُنْتُ تَبِعْتُهُ قَالَ إِنَّكَ لَعَلَّكَ تُدْرِكُ أَمْوَالًا تُقْسَمُ بَيْنَ أَقْوَامٍ وَإِنَّمَا يَكْفِيكَ مِنْ ذَلِكَ خَادِمٌ وَمَرْكَبٌ فِي سَبِيلِ اللَّهِ فَأَدْرَكْتُ فَجَمَعْتُ","id":"Telah menceritakan kepada kami [Muhammad bin As Shabah] telah memberitakan kepada kami [Jarir] dari [Manshur] dari [Abu Wail] dari [Samurah bin Sahm] seorang laki-laki dari kaumnya, dia berkata, \"Saya pernah menginap di rumah Abu Hasyim bin 'Utbah ketika ia sedang sakit, lalu Mu'awiyah juga datang menjenguknya. Lantas Abu Hasyim menangis, maka Mu'awiyah pun bertanya, \"Wahai paman, apa yang membuatmu menangis? Apakah kamu merasakan sakit ataukah karena urusan dunia yang telah pergi kesuciannya?\" [Abu Hasyim] menjawab, \"Bukan karena dua-duanya, akan tetapi Rasulullah shallallahu 'alaihi wasallam pernah memberiku amanah, andai saja dulu saya dapat melaksanakannya. Beliau pernah bersabda: \"Sesungguhnya kamu akan memiliki harta yang akan kamu berikan kepada orang-orang. Meski demikian, cukuplah bagimu seorang pembantu dan kendaraan di jalan Allah.\" Setelah itu, akupun mendapatkannya dan berhasil mengumpulkannya.\""},"4055":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ أَبِي الرَّبِيعِ حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا جَعْفَرُ بْنُ سُلَيْمَانَ عَنْ ثَابِتٍ عَنْ أَنَسٍ قَالَاشْتَكَى سَلْمَانُ فَعَادَهُ سَعْدٌ فَرَآهُ يَبْكِي فَقَالَ لَهُ سَعْدٌ مَا يُبْكِيكَ يَا أَخِي أَلَيْسَ قَدْ صَحِبْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَيْسَ أَلَيْسَ قَالَ سَلْمَانُ مَا أَبْكِي وَاحِدَةً مِنْ اثْنَتَيْنِ مَا أَبْكِي ضِنًّا لِلدُّنْيَا وَلَا كَرَاهِيَةً لِلْآخِرَةِ وَلَكِنْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَهِدَ إِلَيَّ عَهْدًا فَمَا أُرَانِي إِلَّا قَدْ تَعَدَّيْتُ قَالَ وَمَا عَهِدَ إِلَيْكَ قَالَ عَهِدَ إِلَيَّ أَنَّهُ يَكْفِي أَحَدَكُمْ مِثْلُ زَادِ الرَّاكِبِ وَلَا أُرَانِي إِلَّا قَدْ تَعَدَّيْتُ وَأَمَّا أَنْتَ يَا سَعْدُ فَاتَّقِ اللَّهَ عِنْدَ حُكْمِكَ إِذَا حَكَمْتَ وَعِنْدَ قَسْمِكَ إِذَا قَسَمْتَ وَعِنْدَ هَمِّكَ إِذَا هَمَمْتَقَالَ ثَابِتٌ فَبَلَغَنِي أَنَّهُ مَا تَرَكَ إِلَّا بِضْعَةً وَعِشْرِينَ دِرْهَمًا مِنْ نَفَقَةٍ كَانَتْ عِنْدَهُ","id":"Telah menceritakan kepada kami [Al Hasan bin Abu Ar Rabi'] telah menceritakan kepada kami [Abdurrazaq] telah menceritakan kepada kami [Ja'far bin Sulaiman] dari [Tsabit] dari [Anas] dia berkata, \"Salman pernah mengeluh sakit, maka Sa'd datang menjenguknya. Ketika ia melihat Salman menangis, Sa'd bertanya, \"Apa yang membuatmu menangis wahai saudaraku? Tidakkah kamu telah menemani Rasulullah shallallahu 'alaihi wasallam? Bukankah…? Dan bukankah …? [Salman] menjawab, \"Tidaklah aku menangis karena rakus terhadap dunia dan tidak pula karena benci (akan pergi) ke akhirat, akan tetapi dahulu Rasulullah shallallahu 'alaihi wasallam pernah memberikan amanat kepadaku, dan menurutku aku telah melanggar amanah tersebut.\" Sa'd bertanya, \"Apakah yang beliau amanatkan kepadamu?\" Salman menjawab, \"Beliau memberiku amanah, bahwa cukuplah bekal salah seorang dari kalian sebagaimana (bekal) orang yang hendak bepergian. Dan menurutku aku telah melampaui batas. Adapun kamu wahai Sa'd, takutlah kamu kepada Allah dalam setiap keputusanmu ketika kamu memutuskan suatu hukum, atau dalam pembagianmu saat kamu membagikan, dan dalam keinginanmu ketika kamu berkeinginan.\" Tsabit berkata, \"Telah sampai berita kepadaku bahwa ketika meninggal dunia, Sa'd hanya meninggalkan dua puluh dirham dari harta yang ia miliki.\""},"4056":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عُمَرَ بْنِ سُلَيْمَانَ قَالَ سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ أَبَانَ بْنِ عُثْمَانَ بْنِ عَفَّانَ عَنْ أَبِيهِ قَالَخَرَجَ زَيْدُ بْنُ ثَابِتٍ مِنْ عِنْدِ مَرْوَانَ بِنِصْفِ النَّهَارِ قُلْتُ مَا بَعَثَ إِلَيْهِ هَذِهِ السَّاعَةَ إِلَّا لِشَيْءٍ سَأَلَ عَنْهُ فَسَأَلْتُهُ فَقَالَ سَأَلَنَا عَنْ أَشْيَاءَ سَمِعْنَاهَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ كَانَتْ الدُّنْيَا هَمَّهُ فَرَّقَ اللَّهُ عَلَيْهِ أَمْرَهُ وَجَعَلَ فَقْرَهُ بَيْنَ عَيْنَيْهِ وَلَمْ يَأْتِهِ مِنْ الدُّنْيَا إِلَّا مَا كُتِبَ لَهُ وَمَنْ كَانَتْ الْآخِرَةُ نِيَّتَهُ جَمَعَ اللَّهُ لَهُ أَمْرَهُ وَجَعَلَ غِنَاهُ فِي قَلْبِهِ وَأَتَتْهُ الدُّنْيَا وَهِيَ رَاغِمَةٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Umar bin Sulaiman] dia berkata; saya mendengar [Abdurrahman bin Aban bin 'Utsman bin 'Affan] dari [Ayahnya] dia berkata, \" [Zaid bin Tsabit] keluar dari sisi Marwan saat siang hari, aku pun berkata, \"Tidaklah ia mengutus seseorang kepadanya di waktu seperti ini kecuali untuk menanyakan sesuatu kepadanya. Lalu aku tanyakan kepadanya dan ia pun menjawab, \"Sesungguhnya kami menanyakan tentang sesuatu yang pernah kami dengar dari Rasulullah shallallahu 'alaihi wasallam, aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menjadikan dunia sebagai ambisinya, maka Allah akan mencerai-beraikan urusannya, dan Allah akan menjadikannya miskin. Tidaklah ia akan mendapatkan dunia kecuali apa yang telah di tetapkan baginya. Dan barangsiapa menjadikan akhirat sebagai niatannya, maka Allah akan menyatakan urusannya dan membuatnya kaya hati, serta ia akan di beri dunia sekalipun dunia memaksanya.\""},"4057":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ وَالْحُسَيْنُ بْنُ عَبْدِ الرَّحْمَنِ قَالَا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ مُعَاوِيَةَ النَّصْرِيِّ عَنْ نَهْشَلٍ عَنْ الضَّحَّاكِ عَنْ الْأَسْوَدِ بْنِ يَزِيدَ قَالَ قَالَ عَبْدُ اللَّهِسَمِعْتُ نَبِيَّكُمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ جَعَلَ الْهُمُومَ هَمًّا وَاحِدًا هَمَّ الْمَعَادِ كَفَاهُ اللَّهُ هَمَّ دُنْيَاهُ وَمَنْ تَشَعَّبَتْ بِهِ الْهُمُومُ فِي أَحْوَالِ الدُّنْيَا لَمْ يُبَالِ اللَّهُ فِي أَيِّ أَوْدِيَتِهِ هَلَكَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] dan [Al Husain bin Abdurrahman] keduanya berkata; telah menceritakan kepada kami [Abdullah bin Numair] dari [Mu'awiyah An Nashri] dari [Nahsyal] dari [Ad Dlahak] dari [Al Aswad bin Yazid] dia berkata; [Abdullah] berkata, \"Saya pernah mendengar Nabi kalian shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menjadikan segala macam keinginannya hanya satu, yaitu keinginan tempat kembali (negeri Akhirat), niscaya Allah akan mencukupkan baginya keinginan dunianya. Dan barangsiapa yang keinginannya beraneka ragam pada urusan dunia, maka Allah tidak akan memperdulikan dimanapun ia binasa.\""},"4058":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ دَاوُدَ عَنْ عِمْرَانَ بْنِ زَائِدَةَ عَنْ أَبِيهِ عَنْ أَبِي خَالِدٍ الْوَالِبِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَ وَلَا أَعْلَمُهُ إِلَّا قَدْ رَفَعَهُ قَالَيَقُولُ اللَّهُ سُبْحَانَهُ يَا ابْنَ آدَمَ تَفَرَّغْ لِعِبَادَتِي أَمْلَأْ صَدْرَكَ غِنًى وَأَسُدَّ فَقْرَكَ وَإِنْ لَمْ تَفْعَلْ مَلَأْتُ صَدْرَكَ شُغْلًا وَلَمْ أَسُدَّ فَقْرَكَ","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] telah menceritakan kepada kami [Abdullah bin Daud] dari [Imran bin Zaidah] dari [Ayahnya] dari [Abu Khalid Al Walibi] dari [Abu Hurairah] dia berkata, \"Saya tidak mengetahui hadits ini melainkan ia telah memarfu'kannya (kepada Nabi), beliau bersabda, \"Allah berfirman: \"Wahai anak Adam, luangkanlah waktumu untuk beribadah kepada-Ku, niscaya Aku akan penuhi dadamu dengan kekayaan (batin). Akan Aku tutupi kemiskinanmu. Dan jika kamu tidak melakukannya, maka Aku akan masuki hatimu dengan kesibukan dan tidak akan Aku tutupi kemiskinanmu.\""},"4059":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبِي وَمُحَمَّدُ بْنُ بِشْرٍ قَالَا حَدَّثَنَا إِسْمَعِيلُ بْنُ أَبِي خَالِدٍ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ قَالَ سَمِعْتُ الْمُسْتَوْرِدَ أَخَا بَنِي فِهْرٍ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا مَثَلُ الدُّنْيَا فِي الْآخِرَةِ إِلَّا مَثَلُ مَا يَجْعَلُ أَحَدُكُمْ إِصْبَعَهُ فِي الْيَمِّ فَلْيَنْظُرْ بِمَ يَرْجِعُ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [Ayahku] dan [Muhammad bin Bisyr] keduanya berkata; telah menceritakan kepada kami [Isma'il bin Abu Khalid] dari [Qais bin Abu Hazim] dia berkata; saya mendengar [Al Mustaurida] saudara Bani Fihr berkata, \"Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah permisalan dunia dengan akhirat melainkan seperti ketika seorang dari kalian memasukkan jarinya ke dalam lautan, maka lihatlah berapa teteskah yang masih tersisa (di jari tangan).\""},"4060":{"ar":"حَدَّثَنَا يَحْيَى بْنُ حَكِيمٍ حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا الْمَسْعُودِيُّ أَخْبَرَنِي عَمْرُو بْنُ مُرَّةَ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَاضْطَجَعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى حَصِيرٍ فَأَثَّرَ فِي جِلْدِهِ فَقُلْتُ بِأَبِي وَأُمِّي يَا رَسُولَ اللَّهِ لَوْ كُنْتَ آذَنْتَنَا فَفَرَشْنَا لَكَ عَلَيْهِ شَيْئًا يَقِيكَ مِنْهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أَنَا وَالدُّنْيَا إِنَّمَا أَنَا وَالدُّنْيَا كَرَاكِبٍ اسْتَظَلَّ تَحْتَ شَجَرَةٍ ثُمَّ رَاحَ وَتَرَكَهَا","id":"Telah menceritakan kepada kami [Yahya bin Hakim] telah menceritakan kepada kami [Abu Daud] telah menceritakan kepada kami [Al Mas'udi] telah mengabarkan kepadaku ['Amru bin Murrah] dari [Ibrahim] dari ['Alqamah] dari [Abdullah] dia berkata, \"Nabi shallallahu 'alaihi wasallam pernah berbaring di atas tikar hingga membekas dikulitnya. Lalu aku bertanya, \"Demi ayah dan ibuku, wahai Rasulullah! Jika anda mengizinkan kami, maka kami akan menghamparkan sesuatu yang dapat menjagamu.\" Namun Rasulullah shallallahu 'alaihi wasallam menjawab: \"Apa urusanku dengan dunia ini? Sesungguhnya diriku dan dunia ini bagaikan seseorang yang tengah berjalan kemudian berteduh di bawah pohon, lalu aku pergi meninggalkan (pohon tersebut).\""},"4061":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ وَإِبْرَاهِيمُ بْنُ الْمُنْذِرِ الْحِزَامِيُّ وَمُحَمَّدٌ الصَّبَّاحُ قَالُوا حَدَّثَنَا أَبُو يَحْيَى زَكَرِيَّا بْنُ مَنْظُورٍ حَدَّثَنَا أَبُو حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِذِي الْحُلَيْفَةِ فَإِذَا هُوَ بِشَاةٍ مَيِّتَةٍ شَائِلَةٍ بِرِجْلِهَا فَقَالَ أَتُرَوْنَ هَذِهِ هَيِّنَةً عَلَى صَاحِبِهَا فَوَالَّذِي نَفْسِي بِيَدِهِ لَلدُّنْيَا أَهْوَنُ عَلَى اللَّهِ مِنْ هَذِهِ عَلَى صَاحِبِهَا وَلَوْ كَانَتْ الدُّنْيَا تَزِنُ عِنْدَ اللَّهِ جَنَاحَ بَعُوضَةٍ مَا سَقَى كَافِرًا مِنْهَا قَطْرَةً أَبَدًا","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] dan [Ibrahim bin Al Mundzir Al Hizami] serta [Muhammad As Shabah] mereka berkata; telah menceritakan kepada kami [Abu Yahya Zakaria bin Mandzur] telah menceritakan kepada kami [Abu Hazim] dari [Sahl bin Sa'd] dia berkata, \"Kami pernah bersama Rasulullah shallallahu 'alaihi wasallam di Dzul Khulaifah, tiba-tiba ada seekor kambing mati dengan kaki terangkat, maka beliau pun bersabda: \"Bukankah kalian melihat bahwa hal ini merupakan suatu yang hina bagi pemiliknya? Demi dzat yang jiwaku berada di tangan-Nya, sungguh dunia itu lebih hina di hadapan Allah daripada (bangkai) ini atas pemiliknya, sekiranya dunia itu memiliki nilai seberat sayap nyamuk di sisi Allah, niscaya Dia tidak akan memberikan setetes pun terhadap orang kafir.\""},"4062":{"ar":"حَدَّثَنَا يَحْيَى بْنُ حَبِيبِ بْنِ عَرَبِيٍّ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ مُجَالِدِ بْنِ سَعِيدٍ الْهَمْدَانِيِّ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ الْهَمْدَانِيِّ قَالَ حَدَّثَنَا الْمُسْتَوْرِدُ بْنُ شَدَّادٍ قَالَإِنِّي لَفِي الرَّكْبِ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ أَتَى عَلَى سَخْلَةٍ مَنْبُوذَةٍ قَالَ فَقَالَ أَتُرَوْنَ هَذِهِ هَانَتْ عَلَى أَهْلِهَا قَالَ قِيلَ يَا رَسُولَ اللَّهِ مِنْ هَوَانِهَا أَلْقَوْهَا أَوْ كَمَا قَالَ قَالَ فَوَالَّذِي نَفْسِي بِيَدِهِ لَلدُّنْيَا أَهْوَنُ عَلَى اللَّهِ مِنْ هَذِهِ عَلَى أَهْلِهَا","id":"Telah menceritakan kepada kami [Yahya bin Habib bin 'Arabi] telah menceritakan kepada kami [Hammad bin Zaid] dari [Mujalid bin Sa'id Al Hamdani] dari [Qais bin Abu Hazim Al Hamdani] dia berkata; telah menceritakan kepada kami [Al Mustaurid bin Syaddad] dia berkata, \"Sesungguhnya saya pernah berjalan bersama Rasulullah shallallahu 'alaihi wasallam, tiba-tiba beliau melewati seekor anak kambing yang terbuang.\" Mustaurid berkata, \"Kemudian beliau bersabda: \"Apakah kalian berfikir bahwa hal ini adalah barang hina bagi pemiliknya?\" Mustaurid berkata, \"Beliau ditanya, \"Wahai Rasulullah, karena hinanya itulah pemiliknya membuangnya.\" Atau sebagaimana yang dikatakan. Beliau bersabda: \"Demi dzat yang jiwaku berada di tangan-Nya, sungguh dunia ini lebih hina dari pada (bangkai) ini atas pemiliknya.\""},"4063":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مَيْمُونٍ الرَّقِّيُّ حَدَّثَنَا أَبُو خُلَيْدٍ عُتْبَةُ بْنُ حَمَّادٍ الدِّمَشْقِيُّ عَنْ ابْنِ ثَوْبَانَ عَنْ عَطَاءِ بْنِ قُرَّةَ عَنْ عَبْدِ اللَّهِ بْنِ ضَمْرَةَ السَّلُولِيِّ قَالَ حَدَّثَنَا أَبُو هُرَيْرَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَقُولُ الدُّنْيَا مَلْعُونَةٌ مَلْعُونٌ مَا فِيهَا إِلَّا ذِكْرَ اللَّهِ وَمَا وَالَاهُ أَوْ عَالِمًا أَوْ مُتَعَلِّمًا","id":"Telah menceritakan kepada kami [Ali bin Maimun Ar Raqqi] telah menceritakan kepada kami [Abu Khulaid 'Utbah bin Hammad Ad Dimasyqi] dari [Ibnu Tsauban] dari ['Atha bin Qurrah] dari [Abdullah bin Dlamrah As Saluli] dia berkata; telah menceritakan kepada kami [Abu Hurairah] dia berkata, \"Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dunia itu terlaknat dan terlaknat pula apa yang ada di dalamnya, kecuali dzikir kepada Allah dan yang berhubungan dengannya, atau seorang yang 'alim dan mengajarkan ilmunya.\""},"4064":{"ar":"حَدَّثَنَا أَبُو مَرْوَانَ مُحَمَّدُ بْنُ عُثْمَانَ الْعُثْمَانِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الدُّنْيَا سِجْنُ الْمُؤْمِنِ وَجَنَّةُ الْكَافِرِ","id":"Telah menceritakan kepada kami [Abu Marwan Muhammad bin 'Utsman Al 'Utsmani] telah menceritakan kepada kami [Abdul Aziz bin Abu Hazim] dari [Al 'Ala bin Abdurrahman] dari [Ayahnya] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dunia ibarat penjara orang-orang mukmin dan surganya orang-orang kafir.\""},"4065":{"ar":"حَدَّثَنَا يَحْيَى بْنُ حَبِيبِ بْنِ عَرَبِيٍّ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ لَيْثٍ عَنْ مُجَاهِدٍ عَنْ ابْنِ عُمَرَ قَالَأَخَذَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِبَعْضِ جَسَدِي فَقَالَ يَا عَبْدَ اللَّهِ كُنْ فِي الدُّنْيَا كَأَنَّكَ غَرِيبٌ أَوْ كَأَنَّكَ عَابِرُ سَبِيلٍ وَعُدَّ نَفْسَكَ مِنْ أَهْلِ الْقُبُورِ","id":"Telah menceritakan kepada kami [Yahya bin Habib bin 'Arabi] telah menceritakan kepada kami [Hammad bin Zaid] dari [Laits] dari [Mujahid] dari [Ibnu Umar] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah memegang sebagian dari tubuhku seraya bersabda: \"Wahai Abdullah, jadilah kamu di dunia ini seakan-akan orang asing atau seorang pengembara, dan persiapkanlah dirimu sebagai calon penghuni kubur.\""},"4066":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُوَيْدُ بْنُ عَبْدِ الْعَزِيزِ عَنْ زَيْدِ بْنِ وَاقِدٍ عَنْ بُسْرِ بْنِ عُبَيْدِ اللَّهِ عَنْ أَبِي إِدْرِيسَ الْخَوْلَانِيِّ عَنْ مُعَاذِ بْنِ جَبَلٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا أُخْبِرُكَ عَنْ مُلُوكِ الْجَنَّةِ قُلْتُ بَلَى قَالَ رَجُلٌ ضَعِيفٌ مُسْتَضْعِفٌ ذُو طِمْرَيْنِ لَا يُؤْبَهُ لَهُ لَوْ أَقْسَمَ عَلَى اللَّهِ لَأَبَرَّهُ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Suwaid bin Abdul 'Aziz] dari [Zaid bin Waqid] dari [Busyr bin 'Ubaidullah] dari [Abu Idris Al Khaulani] dari [Mu'adz bin Jabal] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Maukah aku beritahukan kepada kalian raja-raja di surga?\" Aku menjawab, \"Tentu.\" Beliau bersabda: \"Yaitu seorang yang lemah lagi tertindas, ia hanya memiliki dua kain yang telah usang dan tidak di kenal. Sekiranya ia bersumpah kepada Allah, niscaya akan dikabulkan.\""},"4067":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ مَعْبَدِ بْنِ خَالِدٍ قَالَ سَمِعْتُ حَارِثَةَ بْنَ وَهْبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا أُنَبِّئُكُمْ بِأَهْلِ الْجَنَّةِ كُلُّ ضَعِيفٍ مُتَضَعِّفٍ أَلَا أُنَبِّئُكُمْ بِأَهْلِ النَّارِ كُلُّ عُتُلٍّ جَوَّاظٍ مُسْتَكْبِرٍ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Sufyan] dari [Ma'bad bin Khalid] dia berkata; saya mendengar [Haritsah bin Wahb] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Maukah aku beritahukan kepada kalian para penghuni surga? Yaitu setiap orang yang lemah dan tertindas. Dan maukah aku beritahukan kepada kalian penghuni neraka? Yaitu orang yang berlaku keras dan kasar serta sombong.\""},"4068":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَمْرُو بْنُ أَبِي سَلَمَةَ عَنْ صَدَقَةَ بْنِ عَبْدِ اللَّهِ عَنْ إِبْرَاهِيمَ بْنِ مُرَّةَ عَنْ أَيُّوبَ بْنِ سُلَيْمَانَ عَنْ أَبِي أُمَامَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ أَغْبَطَ النَّاسِ عِنْدِي مُؤْمِنٌ خَفِيفُ الْحَاذِ ذُو حَظٍّ مِنْ صَلَاةٍ غَامِضٌ فِي النَّاسِ لَا يُؤْبَهُ لَهُ كَانَ رِزْقُهُ كَفَافًا وَصَبَرَ عَلَيْهِ عَجِلَتْ مَنِيَّتُهُ وَقَلَّ تُرَاثُهُ وَقَلَّتْ بَوَاكِيهِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] telah menceritakan kepada kami ['Amru bin Abu Salamah] dari [Shadaqah bin Abdullah] dari [Ibrahim bin Murrah] dari [Ayyub bin Sulaiman] dari [Abu Umamah] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya orang yang aku paling merasa iri kepadanya adalah orang mukmin yang miskin, gemar mendirikan shalat, beribadah kepada Rabbnya dengan baik, tidak dikenal orang, selalu merasa cukup dengan rizki (yang telah di berikan), selalu bersabar, kematiannya dipercepat, warisannya sedikit dan tidak banyak orang yang menangisi saat kematiannya.\""},"4069":{"ar":"حَدَّثَنَا كَثِيرُ بْنُ عُبَيْدٍ الْحِمْصِيُّ حَدَّثَنَا أَيُّوبُ بْنُ سُوَيْدٍ عَنْ أُسَامَةَ بْنِ زَيْدٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي أُمَامَةَ الْحَارِثِيِّ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْبَذَاذَةُ مِنْ الْإِيمَانِ قَالَ الْبَذَاذَةُ الْقَشَافَةُ يَعْنِي التَّقَشُّفَ","id":"Telah menceritakan kepada kami [Katsir bin 'Ubaid Al Himshi] telah menceritakan kepada kami [Ayyub bin Suwaid] dari [Usamah bin Zaid] dari [Abdullah bin Abu Umamah Al Haritsi] dari [Ayahnya] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kelusuhan itu bagian dari Iman.\" Abu Umamah berkata, \"lusuh maksudnya adalah sederhana dalam berpakaian (tidak sombong).\""},"4070":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا يَحْيَى بْنُ سُلَيْمٍ عَنْ ابْنِ خُثَيْمٍ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أَسْمَاءَ بِنْتِ يَزِيدَأَنَّهَا سَمِعَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَلَا أُنَبِّئُكُمْ بِخِيَارِكُمْ قَالُوا بَلَى يَا رَسُولَ اللَّهِ قَالَ خِيَارُكُمْ الَّذِينَ إِذَا رُءُوا ذُكِرَ اللَّهُ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] telah menceritakan kepada kami [Yahya bin Sulaim] dari [Ibnu Khutsaim] dari [Syahr bin Hausab] dari [Asma binti Yazid], bahwa dia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Maukah aku beritahukan kepada kalian orang yang terbaik dari kalian?\" mereka menjawab, \"Tentu, wahai Rasulullah.\" Beliau bersabda: \"Sebaik-sebaik kalian adalah orang yang jika takut, maka ia akan selalu berdzikir kepada Allah 'azza wajalla.\""},"4071":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ حَدَّثَنِي أَبِي عَنْ سَهْلِ بْنِ سَعْدٍ السَّاعِدِيِّ قَالَمَرَّ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلٌ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا تَقُولُونَ فِي هَذَا الرَّجُلِ قَالُوا رَأْيَكَ فِي هَذَا نَقُولُ هَذَا مِنْ أَشْرَفِ النَّاسِ هَذَا حَرِيٌّ إِنْ خَطَبَ أَنْ يُخَطَّبَ وَإِنْ شَفَعَ أَنْ يُشَفَّعَ وَإِنْ قَالَ أَنْ يُسْمَعَ لِقَوْلِهِ فَسَكَتَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَرَّ رَجُلٌ آخَرُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا تَقُولُونَ فِي هَذَا قَالُوا نَقُولُ وَاللَّهِ يَا رَسُولَ اللَّهِ هَذَا مِنْ فُقَرَاءِ الْمُسْلِمِينَ هَذَا حَرِيٌّ إِنْ خَطَبَ لَمْ يُنْكَحْ وَإِنْ شَفَعَ لَا يُشَفَّعْ وَإِنْ قَالَ لَا يُسْمَعْ لِقَوْلِهِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَهَذَا خَيْرٌ مِنْ مِلْءِ الْأَرْضِ مِثْلَ هَذَا","id":"Telah menceritakan kepada kami [Muhammad bin As Shabah] telah menceritakan kepada kami [Abdul Aziz bin Abu Hazim] telah menceritakan kepadaku [Ayahku] dari [Sahl bin Sa'd As Sa'idi] dia berkata, \"Seorang laki-laki melintasi Rasulullah shallallahu 'alaihi wasallam, lantas Nabi shallallahu 'alaihi wasallam bersabda: \"Apa pendapat kalian dengan laki-laki ini?\" mereka menjawab, \"Pendapat kami bahwa dia dari bangsawan, apabila meminang pasti akan di terima, dan bila dimintai bantuan pasti akan membantu, dan jika berkata pasti perkataannya akan di dengar.\" Nabi shallallahu 'alaihi wasallam diam. Beberapa saat kemudian lewatlah seorang laki-laki di hadapan beliau, lalu Nabi shallallahu 'alaihi wasallam bertanya: \"Apa pendapat kalian dengan orang ini?\" Mereka menjawab, \"Menurut kami, demi Allah, wahai Rasulullah… orang ini adalah orang termiskin dari kalangan kaum Muslimin, apabila ia meminang pasti pinangannya akan di tolak, jika dimintai pertolongan dia tidak akan menolong, dan apabila berkata maka perkataannya tidak akan di dengar.\" Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh, orang ini (orang yang terlihat miskin) lebih baik dari dunia dan seisinya daripada orang yang ini (yaitu orang yang kelihatanya bangsawan).\""},"4072":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ يُوسُفَ الْجُبَيْرِيُّ حَدَّثَنَا حَمَّادُ بْنُ عِيسَى حَدَّثَنَا مُوسَى بْنُ عُبَيْدَةَ أَخْبَرَنِي الْقَاسِمُ بْنُ مِهْرَانَ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ يُحِبُّ عَبْدَهُ الْمُؤْمِنَ الْفَقِيرَ الْمُتَعَفِّفَ أَبَا الْعِيَالِ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Yusuf Al Jubairi] telah menceritakan kepada kami [Hammad bin Isa] telah menceritakan kepada kami [Musa bin 'Ubaidah] telah mengabarkan kepadaku [Al Qasim bin Mihran] dari ['Imran bin Hushain] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah mencintai hamba-Nya yang mukmin, fakir dan dapat menjaga kehormatan keluarga.\""},"4073":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدْخُلُ فُقَرَاءُ الْمُؤْمِنِينَ الْجَنَّةَ قَبْلَ الْأَغْنِيَاءِ بِنِصْفِ يَوْمٍ خَمْسِ مِائَةِ عَامٍ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Muhammad bin Bisyr] dari [Muhammad bin 'Amru] dari [Abu Salamah] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang-orang fakir dari kaum mukminin akan masuk surga sebelum orang-orang kaya dengan jarak setengah hari yang setara dengan lima ratus tahun.\""},"4074":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا بَكْرُ بْنُ عَبْدِ الرَّحْمَنِ حَدَّثَنَا عِيسَى بْنُ الْمُخْتَارِ عَنْ مُحَمَّدِ بْنِ أَبِي لَيْلَى عَنْ عَطِيَّةَ الْعَوْفِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ فُقَرَاءَ الْمُهَاجِرِينَ يَدْخُلُونَ الْجَنَّةَ قَبْلَ أَغْنِيَائِهِمْ بِمِقْدَارِ خَمْسِ مِائَةِ سَنَةٍ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Bakr bin Abdurrahman] telah menceritakan kepada kami [Isa bin Al Muhtar] dari [Muhammad bin Abu Laila] dari ['Athiyah Al 'Aufi] dari [Abu Sa'id Al Khudri] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya orang-orang fakir miskin dari kaum Mukminin akan masuk surga sebelum orang-orang kaya dengan jarak setengah hari yang setara dengan lima ratus tahun.\""},"4075":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ أَنْبَأَنَا أَبُو غَسَّانَ بَهْلُولٌ حَدَّثَنَا مُوسَى بْنُ عُبَيْدَةَ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَاشْتَكَى فُقَرَاءُ الْمُهَاجِرِينَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا فَضَّلَ اللَّهُ بِهِ عَلَيْهِمْ أَغْنِيَاءَهُمْ فَقَالَ يَا مَعْشَرَ الْفُقَرَاءِ أَلَا أُبَشِّرُكُمْ أَنَّ فُقَرَاءَ الْمُؤْمِنِينَ يَدْخُلُونَ الْجَنَّةَ قَبْلَ أَغْنِيَائِهِمْ بِنِصْفِ يَوْمٍ خَمْسِ مِائَةِ عَامٍ ثُمَّ تَلَا مُوسَى هَذِهِ الْآيَةَ{ وَإِنَّ يَوْمًا عِنْدَ رَبِّكَ كَأَلْفِ سَنَةٍ مِمَّا تَعُدُّونَ }","id":"Telah menceritakan kepada kami [Ishaq bin Manshur] telah memberitakan kepada kami [Abu Ghasan Bahlul] telah menceritakan kepada kami [Musa bin 'Ubaidah] dari [Abdullah bin Dinar] dari [Abdullah bin Umar] dia berkata, \"Orang-orang fakir Muhajirin mengadu kepada Rasulullah shallallahu 'alaihi wasallam atas karunia Allah yang diberikan kepada orang-orang kaya, beliau bersabda: \"Wahai orang-orang miskin, maukah aku beri kabar gembira kepada kalian? Sesungguhnya orang-orang fakir miskin dari kaum Mukminin akan masuk surga sebelum orang-orang kaya dengan jarak setengah hari yang setara dengan lima ratus tahun.\" Kemudian Musa membaca ayat ini: '(Sesungguhnya sehari di sisi Tuhanmu adalah seperti seribu menurut perhitunganmu) ' (Qs. Al Hajj: 47)."},"4076":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ الْكِنْدِيُّ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ التَّيْمِيُّ أَبُو يَحْيَى حَدَّثَنَا إِبْرَاهِيمُ أَبُو إِسْحَقَ الْمَخْزُومِيُّ عَنْ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ جَعْفَرُ بْنُ أَبِي طَالِبٍ يُحِبُّ الْمَسَاكِينَ وَيَجْلِسُ إِلَيْهِمْ وَيُحَدِّثُهُمْ وَيُحَدِّثُونَهُ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَكْنِيهِ أَبَا الْمَسَاكِينِ","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id Al Kindi] telah menceritakan kepada kami [Isma'il bin Ibrahim At Taimi Abu Yahya] telah menceritakan kepada kami [Ibrahim Abu Ishaq Al Mahzumi] dari [Al Maqburi] dari [Abu Hurairah] dia berkata, \"Ja'far bin Abu Thalib sangat menyukai orang-orang miskin dan sering duduk bermajlis bersama mereka, ia menceritakan kepada mereka dan mereka pun bercerita kepadanya. Oleh karena itu, Rasulullah shallallahu 'alaihi wasallam menjulukinya dengan Abu Al Masakin (Bapaknya orang-orang miskin).\""},"4077":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَبْدُ اللَّهِ بْنُ سَعِيدٍ قَالَا حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ عَنْ يَزِيدَ بْنِ سِنَانٍ عَنْ أَبِي الْمُبَارَكِ عَنْ عَطَاءٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَأَحِبُّوا الْمَسَاكِينَ فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي دُعَائِهِ اللَّهُمَّ أَحْيِنِي مِسْكِينًا وَأَمِتْنِي مِسْكِينًا وَاحْشُرْنِي فِي زُمْرَةِ الْمَسَاكِينِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Abdullah bin Sa'id] keduanya berkata; telah menceritakan kepada kami [Abu Khalid Al Ahmar] dari [Yazid bin Sinan] dari [Abu Al Mubarak] dari ['Atha] dari [Abu Sa'id Al Khudri] dia berkata: \"Cintailah oleh kalian kaum fakir miskin. Karena sesungguhnya aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda dalam doanya: 'Ya Allah, wahai Rabbku, hidupkanlah aku dalam keadaan miskin, dan matikan aku dalam keadaan miskin serta kumpulkan aku dalam keadaan miskin'.\""},"4078":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ يَحْيَى بْنِ سَعِيدٍ الْقَطَّانُ حَدَّثَنَا عَمْرُو بْنُ مُحَمَّدٍ الْعَنْقَزِيُّ حَدَّثَنَا أَسْبَاطُ بْنُ نَصْرٍ عَنْ السُّدِّيِّ عَنْ أَبِي سَعْدٍ الْأَزْدِيِّ وَكَانَ قَارِئَ الْأَزْدِ عَنْ أَبِي الْكَنُودِ عَنْ خَبَّابٍفِي قَوْلِهِ تَعَالَى{ وَلَا تَطْرُدْ الَّذِينَ يَدْعُونَ رَبَّهُمْ بِالْغَدَاةِ وَالْعَشِيِّ إِلَى قَوْلِهِ فَتَكُونَ مِنْ الظَّالِمِينَ }قَالَ جَاءَ الْأَقْرَعُ بْنُ حَابِسٍ التَّمِيمِيُّ وَعُيَيْنَةُ بْنُ حِصْنٍ الْفَزَارِيُّ فَوَجَدَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَعَ صُهَيْبٍ وَبِلَالٍ وَعَمَّارٍ وَخَبَّابٍ قَاعِدًا فِي نَاسٍ مِنْ الضُّعَفَاءِ مِنْ الْمُؤْمِنِينَ فَلَمَّا رَأَوْهُمْ حَوْلَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَقَرُوهُمْ فَأَتَوْهُ فَخَلَوْا بِهِ وَقَالُوا إِنَّا نُرِيدُ أَنْ تَجْعَلَ لَنَا مِنْكَ مَجْلِسًا تَعْرِفُ لَنَا بِهِ الْعَرَبُ فَضْلَنَا فَإِنَّ وُفُودَ الْعَرَبِ تَأْتِيكَ فَنَسْتَحْيِي أَنْ تَرَانَا الْعَرَبُ مَعَ هَذِهِ الْأَعْبُدِ فَإِذَا نَحْنُ جِئْنَاكَ فَأَقِمْهُمْ عَنْكَ فَإِذَا نَحْنُ فَرَغْنَا فَاقْعُدْ مَعَهُمْ إِنْ شِئْتَ قَالَ نَعَمْ قَالُوا فَاكْتُبْ لَنَا عَلَيْكَ كِتَابًا قَالَ فَدَعَا بِصَحِيفَةٍ وَدَعَا عَلِيًّا لِيَكْتُبَ وَنَحْنُ قُعُودٌ فِي نَاحِيَةٍ فَنَزَلَ جِبْرَائِيلُ عَلَيْهِ السَّلَام فَقَالَ{ وَلَا تَطْرُدْ الَّذِينَ يَدْعُونَ رَبَّهُمْ بِالْغَدَاةِ وَالْعَشِيِّ يُرِيدُونَ وَجْهَهُ مَا عَلَيْكَ مِنْ حِسَابِهِمْ مِنْ شَيْءٍ وَمَا مِنْ حِسَابِكَ عَلَيْهِمْ مِنْ شَيْءٍ فَتَطْرُدَهُمْ فَتَكُونَ مِنْ الظَّالِمِينَ }ثُمَّ ذَكَرَ الْأَقْرَعَ بْنَ حَابِسٍ وَعُيَيْنَةَ بْنَ حِصْنٍ فَقَالَ{ وَكَذَلِكَ فَتَنَّا بَعْضَهُمْ بِبَعْضٍ لِيَقُولُوا أَهَؤُلَاءِ مَنَّ اللَّهُ عَلَيْهِمْ مِنْ بَيْنِنَا أَلَيْسَ اللَّهُ بِأَعْلَمَ بِالشَّاكِرِينَ }ثُمَّ قَالَ{ وَإِذَا جَاءَكَ الَّذِينَ يُؤْمِنُونَ بِآيَاتِنَا فَقُلْ سَلَامٌ عَلَيْكُمْ كَتَبَ رَبُّكُمْ عَلَى نَفْسِهِ الرَّحْمَةَ }قَالَ فَدَنَوْنَا مِنْهُ حَتَّى وَضَعْنَا رُكَبَنَا عَلَى رُكْبَتِهِ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَجْلِسُ مَعَنَا فَإِذَا أَرَادَ أَنْ يَقُومَ قَامَ وَتَرَكَنَا فَأَنْزَلَ اللَّهُ{ وَاصْبِرْ نَفْسَكَ مَعَ الَّذِينَ يَدْعُونَ رَبَّهُمْ بِالْغَدَاةِ وَالْعَشِيِّ يُرِيدُونَ وَجْهَهُ وَلَا تَعْدُ عَيْنَاكَ عَنْهُمْ }وَلَا تُجَالِسْ الْأَشْرَافَ{ تُرِيدُ زِينَةَ الْحَيَاةِ الدُّنْيَا وَلَا تُطِعْ مَنْ أَغْفَلْنَا قَلْبَهُ عَنْ ذِكْرِنَا }يَعْنِي عُيَيْنَةَ وَالْأَقْرَعَ{ وَاتَّبَعَ هَوَاهُ وَكَانَ أَمْرُهُ فُرُطًا }قَالَ هَلَاكًا قَالَ أَمْرُ عُيَيْنَةَ وَالْأَقْرَعِ ثُمَّ ضَرَبَ لَهُمْ مَثَلَ الرَّجُلَيْنِ وَمَثَلَ الْحَيَاةِ الدُّنْيَاقَالَ خَبَّابٌ فَكُنَّا نَقْعُدُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِذَا بَلَغْنَا السَّاعَةَ الَّتِي يَقُومُ فِيهَا قُمْنَا وَتَرَكْنَاهُ حَتَّى يَقُومَ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad bin Yahya bin Sa'id Al Qatthan] telah menceritakan kepada kami ['Amru bin Muhammad Al 'Anqazi] telah menceritakan kepada kami [Asbath bin Nashr] dari [As Suddi] dari [Abu Sa'd Al Azdi] salah seorang ahli Qira'ah penduduk Azad, dari [Abu Al Kanud] dari [Khabbab] tentang firman Allah Ta'ala: '(Dan janganlah kamu mengusir orang-orang yang menyeru Tuhannya di pagi dan petang hari) ' hingga firman-Nya, '(sehingga kamu termasuk orang-orang yang zalim) ' (Qs. Al An'aam: 52). Khabbab berkata, \"Al Aqra' bin Habis At Tamimi dan 'Uyainah bin Hishn Al Fazari datang dan keduanya mendapati Rasulullah shallallahu 'alaihi wasallam sedang duduk bermajlis bersama-sama dengan Shuhaib, Bilal, 'Ammar dan Khabbab dari kalangan orang-orang mukmin yang lemah. Ketika keduanya melihat mereka berada di sekeliling Nabi shallallahu 'alaihi wasallam, maka keduanya mendatanginya seraya mencela beliau, katanya, \"Sesungguhnya kami ingin agar kamu membuat majlis khusus buat kami, supaya orang-orang Arab tahu keutamaan yang kami miliki, karena delegasi Arab akan datang kepadamu, dan mereka malu jika orang-orang Arab tahu mereka bermajlis dengan para hamba sahaya. Oleh karena itu, apabila kami datang kepadamu, maka halaulah mereka dari kami, jika kami telah selesai barulah kamu bermajlis dengan mereka sekehendakmu.\" Beliau menjawab: \"Ya.\" Mereka berkata, \"Tulislah perjanjian terhadap kami atas kamu.\" Perawi berkata, \"Kemudian beliau meminta lembaran kertas dan menyuruh Ali supaya menulisnya, sementara itu kami duduk di pojok masjid. Maka Jibril 'Alaihi salam datang dan berkata menyampaikan firman Allah: '(Dan janganlah kamu mengusir orang-orang yang menyeru Tuhannya di pagi dan petang hari, sedang mereka menghendaki keridlaan-Nya, kamu tidak memikul tanggung jawab sedikitpun terhadap perbuatan mereka dan merekapun tidak memikul tanggung jawab sedikitpun terhadap perbuatanmu, yang menyebabkan kamu (berhak) mengusir mereka, (sehingga kamu termasuk orang-orang yang zalim) ' (Qs. Al An'aam; 52). Kemudian Jibril menyebutkan mengenai diri Al Aqra' bin Habis dan 'Uyainah bin Hishn, katanya: '(Dan Demikianlah Telah kami uji sebahagian mereka (orang-orang kaya) dengan sebahagian mereka (orang-orang miskin), supaya (orang-orang yang Kaya itu) berkata: \"Orang-orang semacam inikah di antara kita yang diberi anugerah Allah kepada mereka?\" (Allah berfirman): \"Tidakkah Allah lebih mengetahui tentang orang-orang yang bersyukur (kepadaNya)?\" QS Al An'am; 63. kemudian dia juga berkata; \"Apabila orang-orang yang beriman kepada ayat-ayat kami itu datang kepadamu, Maka Katakanlah: \"Salaamun alaikum. Tuhanmu telah menetapkan atas Diri-Nya kasih sayang, …) ' (Qs. Al An'aam; 54). Khabab berkata, \"Setelah itu kami mendekati beliau sehingga lutut kami dengan lutut beliau saling bersentuhan, dan saat itu Rasulullah shallallahu 'alaihi wasallam duduk bermajlis bersama kami, ketika beliau hendak berdiri dan meninggalkan kami, maka Allah menurunkan: '(Dan bersabarlah kamu bersama-sama dengan orang-orang yang menyeru Tuhannya di pagi dan senja hari dengan mengharap keridhaan-Nya; dan janganlah kedua matamu berpaling dari mereka…) ' (Qs. Al Kahfi: 28). Yakni, janganlah kamu bermajlis dengan orang-orang kaya (di antara mereka). '(karena) mengharapkan perhiasan dunia ini; dan janganlah kamu mengikuti orang yang hatinya telah kami lalaikan dari mengingati kami…) ' (Qs. Al Kahfi: 28), yaitu 'Uyainah dan Al Aqra' '(…Serta menuruti hawa nafsunya dan adalah keadaannya itu melewati batas) ' (Qs. Al Kahfi: 28). Khabab berkata, \"Yaitu kebinasaan.\" Khabab berkata lagi, \"Sungguh buruk perkara Al Aqra' dan 'Uyainah ini. Kemudian Allah membuat sebuah permisalan atas mereka dua orang dan kehidupan dunia dan akhirat.\" Khabbab berkata, \"Maka kami duduk bermajlis bersama Nabi shallallahu 'alaihi wasallam, ketika telah sampai waktunya beliau hendak berdiri, maka kami pun berdiri meninggalkan beliau, sebelum beliau berdiri.\""},"4079":{"ar":"حَدَّثَنَا يَحْيَى بْنُ حَكِيمٍ حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا قَيْسُ بْنُ الرَّبِيعِ عَنْ الْمِقْدَامِ بْنِ شُرَيْحٍ عَنْ أَبِيهِ عَنْ سَعْدٍ قَالَنَزَلَتْ هَذِهِ الْآيَةُ فِينَا سِتَّةٍ فِيَّ وَفِي ابْنِ مَسْعُودٍ وَصُهَيْبٍ وَعَمَّارٍ وَالْمِقْدَادِ وَبِلَالٍ قَالَ قَالَتْ قُرَيْشٌ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّا لَا نَرْضَى أَنْ نَكُونَ أَتْبَاعًا لَهُمْ فَاطْرُدْهُمْ عَنْكَ قَالَ فَدَخَلَ قَلْبَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ ذَلِكَ مَا شَاءَ اللَّهُ أَنْ يَدْخُلَ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ وَلَا تَطْرُدْ الَّذِينَ يَدْعُونَ رَبَّهُمْ بِالْغَدَاةِ وَالْعَشِيِّ يُرِيدُونَ وَجْهَهُ }الْآيَةَ","id":"Telah menceritakan kepada kami [Yahya bin Hakim] telah menceritakan kepada kami [Abu Daud] telah menceritakan kepada kami [Qais bin Ar Rabi'] dari [Al Miqdam bin Syuraih] dari [Ayahnya] dari [Sa'd] dia berkata, \"Ayat ini turun berkenaan dengan kami berenam, yaitu aku sendiri, Ibnu Mas'ud, Shuhaib, Ammar, Al Miqdad dan Bilal.\" Sa'd berkata, \"Orang-orang Quraisy berkata kepada Rasulullah shallallahu 'alaihi wasallam, \"Sesungguhnya kami tidak suka menjadi pengikut mereka, karena itu usirlah mereka darimu! \" Sa'd berkata, \"Ternyata kata-kata orang Quraisy masuk ke hati Rasulullah shallallahu 'alaihi wasallam atas yang Allah kehendaki untuk masuk, Allah Allah 'azza wajalla lalu menurunkan ayat: '(Dan janganlah kamu mengusir orang-orang yang menyeru Tuhannya di pagi dan petang hari, sedang mereka menghendaki keridlaan-Nya) ' (Qs. Al An'aam; 52)."},"4080":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ قَالَا حَدَّثَنَا بَكْرُ بْنُ عَبْدِ الرَّحْمَنِ حَدَّثَنَا عِيسَى بْنُ الْمُخْتَارِ عَنْ مُحَمَّدِ بْنِ أَبِي لَيْلَى عَنْ عَطِيَّةَ الْعَوْفِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ وَيْلٌ لِلْمُكْثِرِينَ إِلَّا مَنْ قَالَ بِالْمَالِ هَكَذَا وَهَكَذَا وَهَكَذَا وَهَكَذَا أَرْبَعٌ عَنْ يَمِينِهِ وَعَنْ شِمَالِهِ وَمِنْ قُدَّامِهِ وَمِنْ وَرَائِهِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Abu Kuraib] keduanya berkata; telah menceritakan kepada kami [Bakr bin Abdurrahman] telah menceritakan kepada kami [Isa bin Al Mukhtar] dari [Muhammad bin Abu Laila] dari ['Athiyah Al 'Aufi] dari [Abu Sa'id Al Khudri] dari Rasulullah shallallahu 'alaihi wasallam, bahwa beliau bersabda: 'Celakalah orang yang banyak harta, kecuali orang yang berkata dengan hartanya, 'Seperti ini, seperti ini, seperti ini dan seperti ini.' Beliau lakukan sebanyak empat kali, ke sebelah kanannya, kiri depan dan belakang.\""},"4081":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ عَبْدِ الْعَظِيمِ الْعَنْبَرِيُّ حَدَّثَنَا النَّضْرُ بْنُ مُحَمَّدٍ حَدَّثَنَا عِكْرِمَةُ بْنُ عَمَّارٍ حَدَّثَنِي أَبُو زُمَيْلٍ هُوَ سِمَاكٌ عَنْ مَالِكِ بْنِ مَرْثَدٍ عَنْ أَبِيهِ عَنْ أَبِي ذَرٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْأَكْثَرُونَ هُمْ الْأَسْفَلُونَ يَوْمَ الْقِيَامَةِ إِلَّا مَنْ قَالَ بِالْمَالِ هَكَذَا وَهَكَذَا وَكَسَبَهُ مِنْ طَيِّبٍ","id":"Telah menceritakan kepada kami [Al 'Abbas bin Abdul 'Azhim Al Anbari] telah menceritakan kepada kami [An Nadlr bin Muhammad] telah menceritakan kepada kami [Ikrimah bin 'Ammar] telah menceritakan kepadaku [Abu Zumail] -yaitu Simak- dari [Malik bin Martsad] dari [Ayahnya] dari [Abu Dzar] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang banyak harta adalah yang paling rendah kedudukannya di hari Kiamat kelak, kecuali orang yang berkata dengan hartanya, 'Seperti ini dan seperti ini, ' dan ia memperoleh hartanya dengan baik.\""},"4082":{"ar":"حَدَّثَنَا يَحْيَى بْنُ حَكِيمٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ عَنْ مُحَمَّدِ بْنِ عَجْلَانَ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْأَكْثَرُونَ هُمْ الْأَسْفَلُونَ إِلَّا مَنْ قَالَ هَكَذَا وَهَكَذَا وَهَكَذَا ثَلَاثًا","id":"Telah menceritakan kepada kami [Yahya bin Hakim] telah menceritakan kepada kami [Yahya bin Sa'id Al Qatthan] dari [Muhammad bin 'Ajlan] dari [Ayahnya] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang memiliki banyak harta adalah orang yang berada paling bawah derajatnya, kecuali orang yang mengatakan, 'Seperti ini, seperti ini dan seperti ini.\" Beliau mengucapkan hingga tiga kali."},"4083":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ أَبِي سُهَيْلِ بْنِ مَالِكٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا أُحِبُّ أَنَّ أُحُدًا عِنْدِي ذَهَبًا فَتَأْتِي عَلَيَّ ثَالِثَةٌ وَعِنْدِي مِنْهُ شَيْءٌ إِلَّا شَيْءٌ أَرْصُدُهُ فِي قَضَاءِ دَيْنٍ","id":"Telah menceritakan kepada kami [Ya'qub bin Humaid bin Kasib] telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Abu Suhail bin Malik] dari [Ayahnya] dari [Abu Hurairah], bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Sungguh, aku tidak menginginkan sekiranya emas sebesar gunung Uhud menjadi milikku, kemudian datang lagi yang ketiga, sedangkan aku memiliki sesuatu darinya, kecuali sesuatu yang memang aku persiapkan untuk sekedar membayar hutang.\""},"4084":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا صَدَقَةُ بْنُ خَالِدٍ حَدَّثَنَا يَزِيدُ بْنُ أَبِي مَرْيَمَ عَنْ أَبِي عُبَيْدِ اللَّهِ مُسْلِمِ بْنِ مِشْكَمٍ عَنْ عَمْرِو بْنِ غَيْلَانَ الثَّقَفِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ مَنْ آمَنَ بِي وَصَدَّقَنِي وَعَلِمَ أَنَّ مَا جِئْتُ بِهِ هُوَ الْحَقُّ مِنْ عِنْدِكَ فَأَقْلِلْ مَالَهُ وَوَلَدَهُ وَحَبِّبْ إِلَيْهِ لِقَاءَكَ وَعَجِّلْ لَهُ الْقَضَاءَ وَمَنْ لَمْ يُؤْمِنْ بِي وَلَمْ يُصَدِّقْنِي وَلَمْ يَعْلَمْ أَنَّ مَا جِئْتُ بِهِ هُوَ الْحَقُّ مِنْ عِنْدِكَ فَأَكْثِرْ مَالَهُ وَوَلَدَهُ وَأَطِلْ عُمُرَهُ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Shadaqah bin Khalid] telah menceritakan kepada kami [Yazid bin Abu Maryam] dari [Abu 'Ubidullah Muslim bin Misykam] dari ['Amru bin Ghailan At Tsaqafi] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam berdo'a: \"Ya Allah, barangsiapa beriman kepadaku dan meyakiniku serta mengetahui bahwa apa yang aku bawa adalah benar dari sisi-Mu, maka sedikitkanlah harta bendanya dan anaknya, dan berilah kecintaan supaya bertemu dengan-Mu dan cepatkanlah keputusan-Mu. Dan barangsiapa tidak beriman terhadapku, tidak membenarkan aku serta tidak mengetahui bahwa yang aku bawa adalah kebenaran yang datang dari sisi-Mu, maka perbanyaklah harta bendanya, anak-anaknya dan panjangkanlah umurnya.\""},"4085":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَفَّانُ حَدَّثَنَا غَسَّانُ بْنُ بُرْزِينَ ح و حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُعَاوِيَةَ الْجُمَحِيُّ حَدَّثَنَا غَسَّانُ بْنُ بُرْزِينَ حَدَّثَنَا سَيَّارُ بْنُ سَلَامَةَ عَنْ الْبَرَاءِ السَّلِيطِيِّ عَنْ نُقَادَةَ الْأَسَدِيِّ قَالَبَعَثَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى رَجُلٍ يَسْتَمْنِحُهُ نَاقَةً فَرَدَّهُ ثُمَّ بَعَثَنِي إِلَى رَجُلٍ آخَرَ فَأَرْسَلَ إِلَيْهِ بِنَاقَةٍ فَلَمَّا أَبْصَرَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اللَّهُمَّ بَارِكْ فِيهَا وَفِيمَنْ بَعَثَ بِهَا قَالَ نُقَادَةُ فَقُلْتُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَفِيمَنْ جَاءَ بِهَا قَالَ وَفِيمَنْ جَاءَ بِهَا ثُمَّ أَمَرَ بِهَا فَحُلِبَتْ فَدَرَّتْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ أَكْثِرْ مَالَ فُلَانٍ لِلْمَانِعِ الْأَوَّلِ وَاجْعَلْ رِزْقَ فُلَانٍ يَوْمًا بِيَوْمٍ لِلَّذِي بَعَثَ بِالنَّاقَةِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Ghassan bin Burzin]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Abdullah bin Mu'awiyah Al Jumahi] telah menceritakan kepada kami [Ghassan bin Burzin] telah menceritakan kepada kami [Sayyar bin Salamah] dari [Al Barra As Salithi] dari [Nuqadah Al Asadi] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam mengutusku menemui seorang laki-laki untuk meminta seekor unta (sebagai zakatnya), namun laki-laki itu menolaknya. Beliau kemudian mengutusku untuk menemui laki-laki yang lain, lantas laki-laki (yang kedua) mengirim seekor unta kepada beliau, ketika Rasulullah shallallahu 'alaihi wasallam melihat unta tersebut, beliau berdo'a: \"Ya Allah, berkahilah ia dan orang yang diutus dengannya.\" Nuqadah berkata, \"Lalu saya berkata kepada Rasulullah shallallahu 'alaihi wasallam, \"Begitu juga dengan orang yang datang bersamanya.\" Setelah itu beliau memerintahkan supaya air susunya diperah hingga melimpah, Rasulullah shallallahu 'alaihi wasallam berdo'a: \"Ya Allah, perbanyaklah harta si fulan -yaitu seseorang yang pertama menolak- dan jadikanlah rizki si fulan itu disetiap harinya (beralih) kepada orang yang telah memberi unta.\""},"4086":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ حَمَّادٍ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ أَبِي حَصِينٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَعِسَ عَبْدُ الدِّينَارِ وَعَبْدُ الدِّرْهَمِ وَعَبْدُ الْقَطِيفَةِ وَعَبْدُ الْخَمِيصَةِ إِنْ أُعْطِيَ رَضِيَ وَإِنْ لَمْ يُعْطَ لَمْ يَفِ","id":"Telah menceritakan kepada kami [Al Hasan bin Hammad] telah menceritakan kepada kami [Abu Bakar bin 'Ayasy] dari [Abu Hashin] dari [Abu Shalih] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Binasalah budak dinar, budak dirham, budak sutera dan budak pakaian (beludru), jika diberi ia ridla dan jika tidak diberi ia tidak taat.\""},"4087":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ حُمَيْدٍ حَدَّثَنَا إِسْحَقُ بْنُ سَعِيدٍ عَنْ صَفْوَانَ بْنِ سُلَيْمٍ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَقَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَعِسَ عَبْدُ الدِّينَارِ وَعَبْدُ الدِّرْهَمِ وَعَبْدُ الْخَمِيصَةِ تَعِسَ وَانْتَكَسَ وَإِذَا شِيكَ فَلَا انْتَقَشَ","id":"Telah menceritakan kepada kami [Ya'qub bin Humaid] telah menceritakan kepada kami [Ishaq bin Sa'id] dari [Shofwan bin Sulaim] dari [Abdullah bin Dinar] dari [Abu Shalih] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Celakalah budak dinar, budak dirham dan budak pakaian (sutra), binasalah ia dan merugilah ia, jika ia kemasukan duri maka ia tidak dapat mengeluarkannya.\""},"4088":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ الْغِنَى عَنْ كَثْرَةِ الْعَرَضِ وَلَكِنَّ الْغِنَى غِنَى النَّفْسِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bukanlah kekayaan itu karena banyaknya harta, akan tetapi kekayaan itu adalah kaya hati.\""},"4089":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ لَهِيعَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي جَعْفَرٍ وَحُمَيْدِ بْنِ هَانِئٍ الْخَوْلَانِيِّ أَنَّهُمَا سَمِعَا أَبَا عَبْدِ الرَّحْمَنِ الْحُبُلِيَّ يُخْبِرُ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ قَدْ أَفْلَحَ مَنْ هُدِيَ إِلَى الْإِسْلَامِ وَرُزِقَ الْكَفَافَ وَقَنَعَ بِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] telah menceritakan kepada kami [Abdullah bin Lahi'ah] dari ['Ubaidullah bin Abu Ja'far] dan [Humaid bin Hani` Al Khaulani] bahwa keduanya mendengar [Abu Abdurrahman Al Hubuli] mengabarkan dari [Abdullah bin 'Amru bin Al 'Ash] dari Rasulullah shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Sungguh beruntung orang yang telah diberikan petunjuk Islam, diberi rizki yang sekedar mencukupinya, dan ia pun ridla menerimanya.\""},"4090":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الْأَعْمَشُ عَنْ عُمَارَةَ بْنِ الْقَعْقَاعِ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ اجْعَلْ رِزْقَ آلِ مُحَمَّدٍ قُوتًا","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Al A'masy] dari ['Umarah bin Al Qa'qa'] dari [Abu Zur'ah] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ya Allah, jadikanlah rizki keluarga Muhammad hanya sebatas makanan pokok saja.\""},"4091":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبِي وَيَعْلَى عَنْ إِسْمَعِيلَ بْنِ أَبِي خَالِدٍ عَنْ نُفَيْعٍ عَنْ أَنَسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ غَنِيٍّ وَلَا فَقِيرٍ إِلَّا وَدَّ يَوْمَ الْقِيَامَةِ أَنَّهُ أُتِيَ مِنْ الدُّنْيَا قُوتًا","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [ayahku] dan [Ya'la] dari [Isma'il bin Abu Khalid] dari [Nufai'] dari [Anas] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak seorang pun di hari kiamat kelak, baik orang kaya ataupun orang miskin kecuali dia menginginkan sekiranya di dunia dulu ia hanya diberikan makanan pokok saja.\""},"4092":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ وَمُجَاهِدُ بْنُ مُوسَى قَالَا حَدَّثَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي شُمَيْلَةَ عَنْ سَلَمَةَ بْنِ عُبَيْدِ اللَّهِ بْنِ مِحْصَنٍ الْأَنْصَارِيِّ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَصْبَحَ مِنْكُمْ مُعَافًى فِي جَسَدِهِ آمِنًا فِي سِرْبِهِ عِنْدَهُ قُوتُ يَوْمِهِ فَكَأَنَّمَا حِيزَتْ لَهُ الدُّنْيَا","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] dan [Mujahid bin Musa] keduanya berkata; telah menceritakan kepada kami [Marwan bin Mu'awiyah] telah menceritakan kepada kami [Abdurrahman bin Abu Syumailah] dari [Salamah bin 'Ubaidullah bin Mihshan Al Anshari] dari [Ayahnya] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa di pagi hari tubuhnya sehat, aman jiwanya dan memiliki makanan pokok pada hari itu, maka seolah-olah dunia telah dihimpun untuknya.\""},"4093":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا وَكِيعٌ وَأَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْظُرُوا إِلَى مَنْ هُوَ أَسْفَلَ مِنْكُمْ وَلَا تَنْظُرُوا إِلَى مَنْ هُوَ فَوْقَكُمْ فَإِنَّهُ أَجْدَرُ أَنْ لَا تَزْدَرُوا نِعْمَةَ اللَّهِ قَالَ أَبُو مُعَاوِيَةَ عَلَيْكُمْ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Waki'] dan [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Lihatlah kepada orang yang lebih rendah dari kalian, dan janganlah kalian melihat orang yang lebih tinggi dari kalian, sesungguhnya hal itu lebih baik agar kalian tidak meremehkan nikmat Allah.\" Abu Mu'awiyah menyebutkan dengan redaksi, \"(nikmat Allah) atas kalian.\" "},"4094":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ سِنَانٍ حَدَّثَنَا كَثِيرُ بْنُ هِشَامٍ حَدَّثَنَا جَعْفَرُ بْنُ بُرْقَانَ حَدَّثَنَا يَزِيدُ بْنُ الْأَصَمِّ عَنْ أَبِي هُرَيْرَةَرَفَعَهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ لَا يَنْظُرُ إِلَى صُوَرِكُمْ وَأَمْوَالِكُمْ وَلَكِنْ إِنَّمَا يَنْظُرُ إِلَى أَعْمَالِكُمْ وَقُلُوبِكُمْ","id":"Telah menceritakan kepada kami [Ahmad bin Sinan] telah menceritakan kepada kami [Katsir bin Hisyam] telah menceritakan kepada kami [Ja'far bin Burqan] telah menceritakan kepada kami [Yazid bin Al Asham] dari [Abu Hurairah] yang dimarfu'kan kepada Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya Allah tidak melihat kepada rupa dan harta benda kalian, tetapi Dia hanya memandang kepada amal dan hati kalian.\""},"4095":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ وَأَبُو أُسَامَةَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْإِنْ كُنَّا آلَ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَنَمْكُثُ شَهْرًا مَا نُوقِدُ فِيهِ بِنَارٍ مَا هُوَ إِلَّا التَّمْرُ وَالْمَاءُ إِلَّا أَنَّ ابْنَ نُمَيْرٍ قَالَ نَلْبَثُ شَهْرًا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdullah bin Numair] dan [Abu Usamah] dari [Hisyam bin 'Urwah] dari [Ayahnya] dari ['Aisyah] dia berkata, \"Sungguh, kami pernah tinggal selama sebulan lamanya tanpa menghidupkan api (tidak memasak), yang kami makan hanyalah kurma dan air.\""},"4096":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَ قَالَتْلَقَدْ كَانَ يَأْتِي عَلَى آلِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الشَّهْرُ مَا يُرَى فِي بَيْتٍ مِنْ بُيُوتِهِ الدُّخَانُ قُلْتُ فَمَا كَانَ طَعَامُهُمْ قَالَتْ الْأَسْوَدَانِ التَّمْرُ وَالْمَاءُ غَيْرَ أَنَّهُ كَانَ لَنَا جِيرَانٌ مِنْ الْأَنْصَارِ جِيرَانُ صِدْقٍ وَكَانَتْ لَهُمْ رَبَائِبُ فَكَانُوا يَبْعَثُونَ إِلَيْهِ أَلْبَانَهَاقَالَ مُحَمَّدٌ وَكَانُوا تِسْعَةَ أَبْيَاتٍ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [Muhammad bin 'Amru] dari [Abu Salamah] dari ['Aisyah] dia berkata, \"Sungguh telah lewat satu bulan dalam keluarga Muhammad tidak terlihat asap di rumah-rumah keluarga Muhammad sedikit pun.\" Muhammad bin 'Amru bertanya, \"Jadi apa yang mereka makan?\" 'Aisyah menjawab, \"Al Aswadain; kurma dan air, namun kami memiliki tetangga dari kalangan Anshar -dan mereka adalah tetangga yang baik- yang memiliki hewan ternak, mereka kerap sekali mengirimkan susunya kepada beliau.\" Muhammad berkata, \"Keluarga mereka (Rasulullah) ada dalam sembilan rumah.\""},"4097":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ حَدَّثَنَا بِشْرُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ سِمَاكٍ عَنْ النُّعْمَانِ بْنِ بَشِيرٍ قَالَ سَمِعْتُ عُمَرَ بْنَ الْخَطَّابِ يَقُولُرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَلْتَوِي فِي الْيَوْمِ مِنْ الْجُوعِ مَا يَجِدُ مِنْ الدَّقَلِ مَا يَمْلَأُ بِهِ بَطْنَهُ","id":"Telah menceritakan kepada kami [Nashr bin Ali] telah menceritakan kepada kami [Bisyr bin Umar] telah menceritakan kepada kami [Syu'bah] dari [Simak] dari [An Nu'man bin Basyir] dia berkata; saya mendengar [Umar bin Khaththab] berkata, \"Suatu hari saya pernah melihat Rasulullah shallallahu 'alaihi wasallam membungkuk karena kelaparan, beliau tidak mendapatkan kurma (yang telah rusak) yang dapat di masukkan dalam perutnya.\""},"4098":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا الْحَسَنُ بْنُ مُوسَى أَنْبَأَنَا شَيْبَانُ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مِرَارًا وَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ مَا أَصْبَحَ عِنْدَ آلِ مُحَمَّدٍ صَاعُ حَبٍّ وَلَا صَاعُ تَمْرٍ وَإِنَّ لَهُ يَوْمَئِذٍ تِسْعَ نِسْوَةٍ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Al Hasan bin Musa] telah memberitakan kepada kami [Syaiban] dari [Qatadah] dari [Anas bin Malik] dia berkata, \"Sering kali Rasulullah shallallahu 'alaihi wasallam bersabda: 'Demi dzat yang jiwa Muhammad berada di tangan-Nya, pernah disuatu pagi keluarga Muhammad tidak mendapatkan satu sha' gandum dan tidak pula satu sha' kurma.' Padahal ketika itu beliau memiliki sembilan isteri.\""},"4099":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ الْمَسْعُودِيُّ عَنْ عَلِيِّ بْنِ بَذِيمَةَ عَنْ أَبِي عُبَيْدَةَ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أَصْبَحَ فِي آلِ مُحَمَّدٍ إِلَّا مُدٌّ مِنْ طَعَامٍ أَوْ مَا أَصْبَحَ فِي آلِ مُحَمَّدٍ مُدٌّ مِنْ طَعَامٍ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] telah menceritakan kepada kami [Abu Al Mughirah] telah menceritakan kepada kami [Abdurrahman bin Abdullah Al Mas'udi] dari [Ali bin Badzimah] dari [Abu 'Ubaidah] dari [Abdullah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pernah suatu pagi keluarga Muhammad tidak mendapatkan makanan melainkan hanya satu mud.\" Atau, \"Pernah suatu pagi tidak didapatkan dalam keluarga Muhammad kecuali satu mud makanan.\""},"4100":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ أَخْبَرَنِي أَبِي عَنْ شُعْبَةَ عَنْ عَبْدِ الْأَكْرَمِ رَجُلٌ مِنْ أَهْلِ الْكُوفَةِ عَنْ أَبِيهِ عَنْ سُلَيْمَانَ بْنِ صُرَدٍ قَالَأَتَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَكَثْنَا ثَلَاثَ لَيَالٍ لَا نَقْدِرُ أَوْ لَا يَقْدِرُ عَلَى طَعَامٍ","id":"Telah menceritakan kepada kami [Nashr bin Ali] telah mengabarkan kepadaku [Ayahku] dari [Syu'bah] dari [Abdul Akram] seorang laki-laki dari penduduk Kufah, dari [Ayahnya] dari [Sulaiman bin Shurad] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah datang kepada kami kemudian kami tinggal selama tiga hari, selama itu kami tidak mendapatkan makanan sedikit pun.\""},"4101":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَأُتِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا بِطَعَامٍ سُخْنٍ فَأَكَلَ فَلَمَّا فَرَغَ قَالَ الْحَمْدُ لِلَّهِ مَا دَخَلَ بَطْنِي طَعَامٌ سُخْنٌ مُنْذُ كَذَا وَكَذَا","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] telah menceritakan kepada kami [Ali bin Mushir] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dia berkata, \"Suatu hari Rasulullah shallallahu 'alaihi wasallam pernah diberi makanan yang masih hangat lalu beliau memakannya, selesai makan beliau mengucapkan: \"Segala puji bagi Allah, perutku tidak pernah kemasukan makanan yang hangat sejak ini dan ini.\""},"4102":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ وَأَبُو خَالِدٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْكَانَ ضِجَاعُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَدَمًا حَشْوُهُ لِيفٌ","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id] telah menceritakan kepada kami [Abdullah bin Numair] dan [Abu Khalid] dari [Hisyam bin 'Urwah] dari [Ayahnya] dari ['Aisyah] dia berkata, \"Tempat tidur Rasulullah shallallahu 'alaihi wasallam terbuat dari kulit yang berisi jerami (serabut).\""},"4103":{"ar":"حَدَّثَنَا وَاصِلُ بْنُ عَبْدِ الْأَعْلَى حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ أَبِيهِ عَنْ عَلِيٍّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَى عَلِيًّا وَفَاطِمَةَ وَهُمَا فِي خَمِيلٍ لَهُمَا وَالْخَمِيلُ الْقَطِيفَةُ الْبَيْضَاءُ مِنْ الصُّوفِ قَدْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَهَّزَهُمَا بِهَا وَوِسَادَةٍ مَحْشُوَّةٍ إِذْخِرًا وَقِرْبَةٍ","id":"Telah menceritakan kepada kami [Washil bin Abdul A'la] telah menceritakan kepada kami [Muhammad bin Fudlail] dari ['Atha bin As Saib] dari [Ayahnya] dari [Ali], bahwa Rasulullah shallallahu 'alaihi wasallam pernah menemui Ali dan Fatimah, sementara keduanya sedang berada di dalam selimut mereka yang terbuat dari kain wool. Dan Rasulullah shallallahu 'alaihi wasallam sendiri yang menyiapkan kain wool, bantal dan tempat minum dari kulit untuk keduanya.\""},"4104":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عُمَرُ بْنُ يُونُسَ حَدَّثَنَا عِكْرِمَةُ بْنُ عَمَّارٍ حَدَّثَنِي سِمَاكٌ الْحَنَفِيُّ أَبُو زُمَيْلٍ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ الْعَبَّاسِ حَدَّثَنِي عُمَرُ بْنُ الْخَطَّابِ قَالَدَخَلْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ عَلَى حَصِيرٍ قَالَ فَجَلَسْتُ فَإِذَا عَلَيْهِ إِزَارٌ وَلَيْسَ عَلَيْهِ غَيْرُهُ وَإِذَا الْحَصِيرُ قَدْ أَثَّرَ فِي جَنْبهِ وَإِذَا أَنَا بِقَبْضَةٍ مِنْ شَعِيرٍ نَحْوِ الصَّاعِ وَقَرَظٍ فِي نَاحِيَةٍ فِي الْغُرْفَةِ وَإِذَا إِهَابٌ مُعَلَّقٌ فَابْتَدَرَتْ عَيْنَايَ فَقَالَ مَا يُبْكِيكَ يَا ابْنَ الْخَطَّابِ فَقُلْتُ يَا نَبِيَّ اللَّهِ وَمَالِي لَا أَبْكِي وَهَذَا الْحَصِيرُ قَدْ أَثَّرَ فِي جَنْبِكَ وَهَذِهِ خِزَانَتُكَ لَا أَرَى فِيهَا إِلَّا مَا أَرَى وَذَلِكَ كِسْرَى وَقَيْصَرُ فِي الثِّمَارِ وَالْأَنْهَارِ وَأَنْتَ نَبِيُّ اللَّهِ وَصَفْوَتُهُ وَهَذِهِ خِزَانَتُكَ قَالَ يَا ابْنَ الْخَطَّابِ أَلَا تَرْضَى أَنْ تَكُونَ لَنَا الْآخِرَةُ وَلَهُمْ الدُّنْيَا قُلْتُ بَلَى","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Umar bin Yunus] telah menceritakan kepada kami ['Ikrimah bin 'Ammar] telah menceritakan kepadaku [Simak Al Hanafi Abu Zumail] telah menceritakan kepadaku [Abdullah bin Al 'Abbas] telah menceritakan kepadaku [Umar bin Khattab] dia berkata, \"Saya pernah menemui Rasulullah shallallahu 'alaihi wasallam saat beliau berada di atas tikar.\" Umar melanjutkan, \"Lalu aku duduk, ternyata saya dapati beliau hanya mengenakan selembar kain dan tidak ada kain lain selain yang dipakainya, sementara tikar itu telah membekas pada sisi beliau. Saya juga (melihat) segenggam gandum sekitar satu sha' dan daun yang dipergunakan untuk menyamak yang terletak di sudut kamar dan kulit yang menggantung. Tak terasa kedua mataku berlinang air mata. Beliau bertanya: \"Apa yang membuatmu menangis wahai Ibnul Khattab?\" aku menjawab, \"Wahai Nabi Allah, bagaimana aku tidak meneteskan air mata, sementara tikar ini membekas di sisimu, dan aku tidak melihat dalam ruanganmu kecuali apa aku lihat. Sedangkan raja Kisra dan Kaisar Romawi dipenuhi buah-buahan dan sungai-sungai, engkau adalah Nabi Allah dan pilihan-Nya, namun ruanganmu hanya seperti ini!.\" Beliau menjawab: \"Wahai Ibnul Khattab, tidakkah kamu ridla kita mendapatkan akhirat dan mereka mendapatkan dunia?\" Aku menjawab, \"Tentu.\""},"4105":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ طَرِيفٍ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ بْنِ حَبِيبٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ مُجَالِدٍ عَنْ عَامِرٍ عَنْ الْحَارِثِ عَنْ عَلِيٍّ قَالَأُهْدِيَتْ ابْنَةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَيَّ فَمَا كَانَ فِرَاشُنَا لَيْل��ةَ أُهْدِيَتْ إِلَّا مَسْكَ كَبْشٍ","id":"Telah menceritakan kepada kami [Muhammad bin Tharif] dan [Ishaq bin Ibrahim bin Habib] keduanya berkata; telah menceritakan kepada kami [Muhammad bin Fudlail] dari [Mujalid] dari ['Amir] dari [Al Harits] dari ['Ali] dia berkata, \"Puteri Rasulullah shallallahu 'alaihi wasallam telah diberikan kepadaku, ketika malam di hari ia diberikannya padaku, kami tidak memiliki kasur melainkan hanya terbuat dari kain wool.\""},"4106":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ وَأَبُو كُرَيْبٍ قَالَا حَدَّثَنَا أَبُو أُسَامَةَ عَنْ زَائِدَةَ عَنْ الْأَعْمَشِ عَنْ شَقِيقٍ عَنْ أَبِي مَسْعُودٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْمُرُ بِالصَّدَقَةِ فَيَنْطَلِقُ أَحَدُنَا يَتَحَامَلُ حَتَّى يَجِيءَ بِالْمُدِّ وَإِنَّ لِأَحَدِهِمْ الْيَوْمَ مِائَةَ أَلْفٍقَالَ شَقِيقٌ كَأَنَّهُ يُعَرِّضُ بِنَفْسِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] dan [Abu Kuraib] keduanya berkata; telah menceritakan kepada kami [Abu Usamah] dari [Zaidah] dari [Al A'masy] dari [Syaqiq] dari [Abu Mas'ud] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam memerintahkan kepada kami untuk sedekah. Lalu salah seorang dari kami berlalu (berusaha) hingga ia bisa kembali dengan (sedekah) satu mud, bagi salah seorang dari mereka, untuk hari ini, bisa sebanding dengan seratus ribu dirham.\" Syaqiq berkata, \"Seakan-akan ia memaksakan dirinya.\""},"4107":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ أَبِي نَعَامَةَ سَمِعَهُ مِنْ خَالِدِ بْنِ عُمَيْرٍ قَالَخَطَبَنَا عُتْبَةُ بْنُ غَزْوَانَ عَلَى الْمِنْبَرِ فَقَالَ لَقَدْ رَأَيْتُنِي سَابِعَ سَبْعَةٍ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا لَنَا طَعَامٌ نَأْكُلُهُ إِلَّا وَرَقُ الشَّجَرِ حَتَّى قَرِحَتْ أَشْدَاقُنَا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Waki'] dari [Abu Na'amah] dan dia mendengar dari [Khalid bin 'Umair] dia berkata, \" ['Utbah bin Ghazwan] pernah berkhutbah di atas mimbar di hadapan kami, katanya, \"Sungguh diriku adalah orang ketujuh dari tujuh orang yang pernah bersama Rasulullah shallallahu 'alaihi wasallam, dan kami tidak mendapati makanan yang layak kami makan kecuali dedaunan, sehingga sudut mulut kami banyak yang terluka.\""},"4108":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا غُنْدَرٌ عَنْ شُعْبَةَ عَنْ عَبَّاسٍ الْجُرَيْرِيِّ قَالَ سَمِعْتُ أَبَا عُثْمَانَ يُحَدِّثُ عَنْ أَبِي هُرَيْرَةَأَنَّهُمْ أَصَابَهُمْ جُوعٌ وَهُمْ سَبْعَةٌ قَالَ فَأَعْطَانِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَبْعَ تَمَرَاتٍ لِكُلِّ إِنْسَانٍ تَمْرَةٌ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Ghundar] dari [Syu'bah] dari ['Abbas Al Jurairi] dia berkata; saya mendengar [Abu Utsman] menceritakan dari [Abu Hurairah], bahwa mereka pernah mengalami rasa lapar, dan saat itu mereka berjumlah tujuh orang, maka nabi shallallahu 'alaihi wasallam memberiku tujuh butir kurma dan setiap kami mendapatkan satu butir kurma.\""},"4109":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ أَبِي عُمَرَ الْعَدَنِيُّ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ يَحْيَى بْنِ عَبْدِ الرَّحْمَنِ بْنِ حَاطِبٍ عَنْ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ بْنِ الْعَوَّامِ عَنْ أَبِيهِ قَالَلَمَّا نَزَلَتْ{ ثُمَّ لَتُسْأَلُنَّ يَوْمَئِذٍ عَنْ النَّعِيمِ }قَالَ الزُّبَيْرُ وَأَيُّ نَعِيمٍ نُسْأَلُ عَنْهُ وَإِنَّمَا هُوَ الْأَسْوَدَانِ التَّمْرُ وَالْمَاءُ قَالَ أَمَا إِنَّهُ سَيَكُونُ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya bin Abu Umar Al 'Adani] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Muhammad bin 'Amru] dari [Yahya bin Abdurrahman bin Hathib] dari [Abdullah bin Az Zubair bin Al 'Awam] dari [Ayahnya] dia berkata, \"Ketika turun ayat: '(Kemudian kamu pasti akan ditanyai pada hari itu tentang kenikmatan (yang kamu megah-megahkan di dunia itu) ' (Qs. At Takaatsur: 8), Zubair bertanya, \"Nikmat apakah yang kiranya akan dimintai pertanggung jawaban dari kami? Sedangkan nikmat kami tidak lain hanya terdiri dari al aswadain (kurma dan air)?\" beliau bersabda: \"Dan itu pasti akan terjadi.\""},"4110":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ وَهْبِ بْنِ كَيْسَانَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَبَعَثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ ثَلَاثُ مِائَةٍ نَحْمِلُ أَزْوَادَنَا عَلَى رِقَابِنَا فَفَنِيَ أَزْوَادُنَا حَتَّى كَانَ يَكُونُ لِلرَّجُلِ مِنَّا تَمْرَةٌ فَقِيلَ يَا أَبَا عَبْدِ اللَّهِ وَأَيْنَ تَقَعُ التَّمْرَةُ مِنْ الرَّجُلِ فَقَالَ لَقَدْ وَجَدْنَا فَقْدَهَا حِينَ فَقَدْنَاهَا وَأَتَيْنَا الْبَحْرَ فَإِذَا نَحْنُ بِحُوتٍ قَدْ قَذَفَهُ الْبَحْرُ فَأَكَلْنَا مِنْهُ ثَمَانِيَةَ عَشَرَ يَوْمًا","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami ['Abdah bin Sulaiman] dari [Hisyam bin 'Urwah] dari [Wahb bin Kaisan] dari [Jabir bin Abdullah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah mengutus kami sejumlah tiga ratus orang. Kami membawa bekal di atas leher kami. Lalu bekal kami habis sehingga seorang dari kami hanya memiliki sebuah kurma. Maka Jabir ditanya, \"Wahai Abu Abdullah, bisa apa satu butir kurma untuk seorang laki-laki?\" Jabir berkata, \"Di hari kami kehabisan bekal, kami menemukan ikan besar yang terhempas oleh air laut, lalu kami pun memakannya selama delapan belas hari lamanya.\""},"4111":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي السَّفَرِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَمَرَّ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ نُعَالِجُ خُصًّا لَنَا فَقَالَ مَا هَذَا فَقُلْتُ خُصٌّ لَنَا وَهَى نَحْنُ نُصْلِحُهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أُرَى الْأَمْرَ إِلَّا أَعْجَلَ مِنْ ذَلِكَ","id":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu As Safar] dari [Abdullah bin 'Amru] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah melintasi kami ketika kami sedang mengurusi bilik kami yang terbuat dari pelepah dan kayu, maka beliau bersabda: \"Apakah ini?\" Aku menjawab, \"Ini adalah bilik kami yang sedang kami perbaiki.\" Beliau bersabda: \"Kurasa datangnya kematian lebih cepat dari itu.\""},"4112":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ عُثْمَانَ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا عِيسَى بْنُ عَبْدِ الْأَعْلَى بْنِ أَبِي فَرْوَةَ حَدَّثَنِي إِسْحَقُ بْنُ أَبِي طَلْحَةَ عَنْ أَنَسٍ قَالَمَرَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِقُبَّةٍ عَلَى بَابِ رَجُلٍ مِنْ الْأَنْصَارِ فَقَالَ مَا هَذِهِ قَالُوا قُبَّةٌ بَنَاهَا فُلَانٌ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُّ مَالٍ يَكُونُ هَكَذَا فَهُوَ وَبَالٌ عَلَى صَاحِبِهِ يَوْمَ الْقِيَامَةِ فَبَلَغَ الْأَنْصَارِيَّ ذَلِكَ فَوَضَعَهَا فَمَرَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدُ فَلَمْ يَرَهَا فَسَأَلَ عَنْهَا فَأُخْبِرَ أَنَّهُ وَضَعَهَا لِمَا بَلَغَهُ عَنْكَ فَقَالَ يَرْحَمُهُ اللَّهُ يَرْحَمُهُ اللَّهُ","id":"Telah menceritakan kepada kami [Al 'Abbas bin Utsman Ad Dimasyqi] telah menceritakan kepada kami [Al Walid bin Muslim] telah menceritakan kepada kami [Isa bin Abdul A'la bin Abu Farwah] telah menceritakan kepadaku [Ishaq bin Abu Thalhah] dari [Anas] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah lewat dekat kubbah milik orang Anshar, maka beliau bertanya: \"Apa ini?\" mereka menjawab, \"Kubah yang dibangun oleh si Fulan.\" Rasulullah shallallahu 'alaihi wasallam kemudian bersabda: \"Setiap harta (yang digunakan) seperti ini, maka akan menjadi bencana bagi pemiliknya kelak di hari Kiamat.\" Ternyata ucapan beliau sampai kepada laki-laki Anshar tersebut, maka ia langsung merobohkannya. Selang beberapa saat, beliau kembali dan melewati tempat tersebut, namun beliau tidak melihatnya lagi, maka beliau pun menanyakannya. Lalu beliau diberitahu, \"Pemiliknya telah merobohkannya setelah mendengar ucapanmu.\" Beliau bersabda: \"Semoga Allah merahmatinya, semoga Allah merahmatinya.\""},"4113":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا إِسْحَقُ بْنُ سَعِيدِ بِنِ عَمْرِو بْنِ سَعِيدِ بْنِ الْعَاصِ عَنْ أَبِيهِ سَعِيدٍ عَنْ ابْنِ عُمَرَ قَالَلَقَدْ رَأَيْتُنِي مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَنَيْتُ بَيْتًا يُكِنُّنِي مِنْ الْمَطَرِ وَيُكِنُّنِي مِنْ الشَّمْسِ مَا أَعَانَنِي عَلَيْهِ خَلْقُ اللَّهِ تَعَالَى","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Ishaq bin Sa'id bin 'Amru bin Sa'id bin Al 'Ash] dari [ayahnya yaitu Sa'id] dari [Ibnu Umar] dia berkata; \"Aku pernah bermimpi membangun suatu rumah bersama Rasulullah shallallahu 'alaihi wasallam yang dapat melindungiku dari hujan dan dari terik Matahari, dan tidak ada satupun dari Makhluk Allah yang membantuku (selain Rasulullah shallallahu 'alaihi wasallam).\""},"4114":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ مُوسَى حَدَّثَنَا شَرِيكٌ عَنْ أَبِي إِسْحَقَ عَنْ حَارِثَةَ بْنِ مُضَرِّبٍ قَالَأَتَيْنَا خَبَّابًا نَعُودُهُ فَقَالَ لَقَدْ طَالَ سَقْمِي وَلَوْلَا أَنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تَتَمَنَّوْا الْمَوْتَ لَتَمَنَّيْتُهُ وَقَالَ إِنَّ الْعَبْدَ لَيُؤْجَرُ فِي نَفَقَتِهِ كُلِّهَا إِلَّا فِي التُّرَابِ أَوْ قَالَ فِي الْبِنَاءِ","id":"Telah menceritakan kepada kami [Isma'il bin Musa] telah menceritakan kepada kami [Syarik] dari [Abu Ishaq] dari [Haritsah bin Mudlarib] dia berkata, \"Kami mendatangi [Khabbab] untuk menjenguknya, lantas dia berkata, \"Sakitku telah cukup lama, seandainya aku tidak mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: 'Janganlah kalian mengharapkan kematian'. Tentu aku telah mengharapkannya. Dan beliau juga bersabda: \"Sesungguhnya seorang hamba akan di beri pahala dalam semua nafkah kehidupannya kecuali pembiayaan dalam urusan tanah.\" Atau beliau bersabda: \"Dalam urusan bangunan.\""},"4115":{"ar":"حَدَّثَنَا حَرْمَلَةُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي ابْنُ لَهِيعَةَ عَنْ ابْنِ هُبَيْرَةَ عَنْ أَبِي تَمِيمٍ الْجَيْشَانِيِّ قَالَ سَمِعْتُ عُمَرَ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَوْ أَنَّكُمْ تَوَكَّلْتُمْ عَلَى اللَّهِ حَقَّ تَوَكُّلِهِ لَرَزَقَكُمْ كَمَا يَرْزُقُ الطَّيْرَ تَغْدُو خِمَاصًا وَتَرُوحُ بِطَانًا","id":"Telah menceritakan kepada kami [Harmalah bin Yahya] telah menceritakan kepada kami [Abdullah bin Wahb] telah mengabarkan kepadaku [Ibnu Lahi'ah] dari [Ibnu Hubairah] dari [Abu Tamim Al Jaisyani] dia berkata; saya mendengar [Umar] berkata, \"Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sekiranya kalian bertawakkal kepada Allah dengan sebenar-benarnya tawakkal, niscaya Dia akan memberi rizki kepada kalian sebagaimana Dia memberi rizki terhadap burung, ia pergi dalam keadaan lapar dan pulang dalam keadaan kenyang.\""},"4116":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ سَلَّامِ بْنِ شُرَحْبِيلَ أَبِي شُرَحْبِيلَ عَنْ حَبَّةَ وَسَوَاءٍ ابْنَيْ خَالِدٍ قَالَادَخَلْنَا عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يُعَالِجُ شَيْئًا فَأَعَنَّاهُ عَلَيْهِ فَقَالَ لَا تَيْئَسَا مِنْ الرِّزْقِ مَا تَهَزَّزَتْ رُءُوسُكُمَا فَإِنَّ الْإِنْسَانَ تَلِدُهُ أُمُّهُ أَحْمَرَ لَيْسَ عَلَيْهِ قِشْرٌ ثُمَّ يَرْزُقُهُ اللَّهُ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Sallam bin Syurahbil Abu Syurahbil] dari [Habbah] dan [Sawwa] anaknya Khalid, keduanya berkata, \"Kami pernah menemui Nabi shallallahu 'alaihi wasallam saat beliau sedang memperbaiki sesuatu, kami lalu berkeluh kesah kepadanya, maka beliau pun bersabda: \"Janganlah kalian berputus asa dari rizki Allah selama kepala kalian masih bergerak. Karena sesungguhnya manusia itu dilahirkan oleh ibunya dalam keadaan merah, tidak memiliki suatu apapun, lalu Allah 'azza wajalla memberinya rizki.\""},"4117":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ أَنْبَأَنَا أَبُو شُعَيْبٍ صَالِحُ بْنُ زُرَيْقٍ الْعَطَّارُ حَدَّثَنَا سَعِيدُ بْنُ عَبْدِ الرَّحْمَنِ الْجُمَحِيُّ عَنْ مُوسَى بْنِ عُلَيِّ بْنِ رَبَاحٍ عَنْ أَبِيهِ عَنْ عَمْرِو بْنِ الْعَاصِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْ قَلْبِ ابْنِ آدَمَ بِكُلِّ وَادٍ شُعْبَةً فَمَنْ اتَّبَعَ قَلْبُهُ الشُّعَبَ كُلَّهَا لَمْ يُبَالِ اللَّهُ بِأَيِّ وَادٍ أَهْلَكَهُ وَمَنْ تَوَكَّلَ عَلَى اللَّهِ كَفَاهُ التَّشَعُّبَ","id":"Telah menceritakan kepada kami [Ishaq bin Manshur] telah memberitakan kepada kami [Abu Syu'aib Shalih bin Zuraiq Al 'Atthar] telah menceritakan kepada kami [Sa'id bin Abdurrahman Al Jumahi] dari [Musa bin Ali bin Rabah] dari [Ayahnya] dari ['Amru bin Al 'Ash] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya dalam rongga hati seorang anak Adam terdapat kecenderungan untuk mengumpulkan harta kekayaan, barangsiapa yang mengikuti kecenderungan tersebut maka Allah membiarkannya binasa dengan itu, namun siapa yang bertawakkal kepada Allah maka Allah akan mencukupkannya.\""},"4118":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ طَرِيفٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَمُوتَنَّ أَحَدٌ مِنْكُمْ إِلَّا وَهُوَ يُحْسِنُ الظَّنَّ بِاللَّهِ","id":"Telah menceritakan kepada kami [Muhammad bin Tharif] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Sufyan] dari [Jabir] dia berkata, \"Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah salah seorang dari kalian mati melainkan dalam kondisi berbaik sangka terhadap Allah.\""},"4119":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ ابْنِ عَجْلَانَ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَيَبْلُغُ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمُؤْمِنُ الْقَوِيُّ خَيْرٌ وَأَحَبُّ إِلَى اللَّهِ مِنْ الْمُؤْمِنِ الضَّعِيفِ وَفِي كُلٍّ خَيْرٌ احْرِصْ عَلَى مَا يَنْفَعُكَ وَلَا تَعْجِزْ فَإِنْ غَلَبَكَ أَمْرٌ فَقُلْ قَدَرُ اللَّهِ وَمَا شَاءَ فَعَلَ وَإِيَّاكَ وَاللَّوْ فَإِنَّ اللَّوْ تَفْتَحُ عَمَلَ الشَّيْطَانِ","id":"Telah menceritakan kepada kami [Muhammad bin As Shabah] telah memberitakan kepada kami [Sufyan bin 'Uyainah] dari [Ibnu 'Ajlan] dari [Al A'raj] dari [Abu Hurairah] dan sampai kepada Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Seorang mukmin yang kuat itu lebih baik dari lebih dicintai oleh Allah daripada seorang mukmin yang lemah, dan dalam masing-masing keduanya itu terdapat kebaikan. Bersungguh-sungguhlah terhadap sesuatu yang bermanfaat bagimu dan jangan lemah semangat. Jika suatu perkara mengalahkanmu maka katakanlah, 'Ketentuan Allah telah ditetapkan, dan suatu yang telah Dia kehendaki maka akan terjadi. Dan jauhilah olehmu dari ucapan 'Seandainya', karena sesungguhnya ungkapan 'Seandainya' membuka peluang masuknya setan.\""},"4120":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ الْوَهَّابِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ إِبْرَاهِيمَ بْنِ الْفَضْلِ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْكَلِمَةُ الْحِكْمَةُ ضَالَّةُ الْمُؤْمِنِ حَيْثُمَا وَجَدَهَا فَهُوَ أَحَقُّ بِهَا","id":"Telah menceritakan kepada kami [Abdurrahman bin Abdul Wahhab] telah menceritakan kepada kami [Abdullah bin Numair] dari [Ibrahim bin Al Fadll] dari [Sa'id Al Maqburi] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kalimat hikmah adalah barang seorang mukmin yang hilang, maka dimana saja ia menemukannya ia lebih berhak untuk mengambilnya.\""},"4121":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ عَبْدِ الْعَظِيمِ الْعَنْبَرِيُّ حَدَّثَنَا صَفْوَانُ بْنُ عِيسَى عَنْ عَبْدِ اللَّهِ بْنِ سَعِيدِ بْنِ أَبِي هِنْدٍ عَنْ أَبِيهِ قَالَ سَمِعْتُ ابْنَ عَبَّاسٍ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نِعْمَتَانِ مَغْبُونٌ فِيهِمَا كَثِيرٌ مِنْ النَّاسِ الصِّحَّةُ وَالْفَرَاغُ","id":"Telah menceritakan kepada kami [Al 'Abbas bin Abdul 'Azhim Al 'Anbari] telah menceritakan kepada kami [Shafwan bin Isa] dari [Abdullah bin Sa'id bin Abu Hind] dari [Ayahnya] dia berkata; saya mendengar [Ibnu Abbas] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dua kenikmatan yang sering dilupakan oleh kebanyakan manusia adalah kesehatan dan waktu luang.\""},"4122":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ زِيَادٍ حَدَّثَنَا الْفُضَيْلُ بْنُ سُلَيْمَانَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُثْمَانَ بْنِ خُثَيْمٍ حَدَّثَنِي عُثْمَانُ بْنُ جُبَيْرٍ مَوْلَى أَبِي أَيُّوبَ عَنْ أَبِي أَيُّوبَ قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ عَلِّمْنِي وَأَوْجِزْ قَالَ إِذَا قُمْتَ فِي صَلَاتِكَ فَصَلِّ صَلَاةَ مُوَدِّعٍ وَلَا تَكَلَّمْ بِكَلَامٍ تَعْتَذِرُ مِنْهُ وَأَجْمِعْ الْيَأْسَ عَمَّا فِي أَيْدِي النَّاسِ","id":"Telah menceritakan kepada kami [Muhammad bin Ziyad] telah menceritakan kepada kami [Al Fudlail bin Sulaiman] telah menceritakan kepada kami [Abdullah bin Utsman bin Haitsam] telah menceritakan kepadaku [Utsman bin Jubair] bekas budak Abu Ayyub, dari [Abu Ayyub] dia berkata, \"Seorang laki-laki datang kepada Nabi shallallahu 'alaihi wasallam seraya berkata, \"Wahai Rasulullah, ajarkanlah kepadaku (ilmu) yang singkat padat.\" Beliau bersabda: \"Apabila kamu (hendak) mendirikan shalat maka shalatlah seperti shalatnya orang yang hendak berpisah. Janganlah kamu mengatakan suatu perkataan yang akan kamu sesali. Dan kumpulkan rasa keputus asaan dari apa yang di miliki orang lain.\""},"4123":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا الْحَسَنُ بْنُ مُوسَى عَنْ حَمَّادِ بْنِ سَلَمَةَ عَنْ عَلِيِّ بْنِ زَيْدٍ عَنْ أَوْسِ بْنِ خَالِدٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَثَلُ الَّذِي يَجْلِسُ يَسْمَعُ الْحِكْمَةَ ثُمَّ لَا يُحَدِّثُ عَنْ صَاحِبِهِ إِلَّا بِشَرِّ مَا يَسْمَعُ كَمَثَلِ رَجُلٍ أَتَى رَاعِيًا فَقَالَ يَا رَاعِي أَجْزِرْنِي شَاةً مِنْ غَنَمِكَ قَالَ اذْهَبْ فَخُذْ بِأُذُنِ خَيْرِهَا فَذَهَبَ فَأَخَذَ بِأُذُنِ كَلْبِ الْغَنَمِقَالَ أَبُو الْحَسَنِ بْنُ سَلَمَةَ حَدَّثَنَاهُ إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا مُوسَى حَدَّثَنَا حَمَّادٌ فَذَكَرَ نَحْوَهُ وَقَالَ فِيهِ بِأُذُنِ خَيْرِهَا شَاةً","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Al Hasan bin Musa] dari [Hammad bin Salamah] dari [Ali bin Zaid] dari [Aus bin Khalid] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Permisalan orang yang duduk dan mendengarkan hikmah kemudian ia tidak berbicara tentang sahabatnya kecuali yang jelek dari apa yang ia dengar, seperti seorang laki-laki yang datang kepada penggembala dan berkata, 'Hai pengembala sembelihkan untukku satu kambingmu.' Maka si pengembala berkata, 'Pergi dan ambillah dengan kambing yang paling bagus, ' namun ia pergi dengan membawa kambing yang paling jelek.\" Abu Al Hasan bin Salamah berkata, \"Telah menceritakan kepada kami Isma'il bin Ibrahim, telah menceritakan kepada kami Musa, telah menceritakan kepada kami Hammad, kemudian ia menyebutkan hadits seperti di atas, namun dia menyebutkan, \"(Ambillah) kambing yang paling bagus.\""},"4124":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ ح و حَدَّثَنَا عَلِيُّ بْنُ مَيْمُونٍ الرَّقِّيُّ حَدَّثَنَا سَعِيدُ بْنُ مَسْلَمَةَ جَمِيعًا عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَدْخُلُ الْجَنَّةَ مَنْ كَانَ فِي قَلْبِهِ مِثْقَالُ حَبَّةٍ مِنْ خَرْدَلٍ مِنْ كِبْرٍ وَلَا يَدْخُلُ النَّارَ مَنْ كَانَ فِي قَلْبِهِ مِثْقَالُ حَبَّةٍ مِنْ خَرْدَلٍ مِنْ إِيمَانٍ","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] telah menceritakan kepada kami [Ali bin Mushir]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ali bin Maimun Ar Raqi] telah menceritakan kepada kami [Sa'id bin Maslamah] semuanya dari [Al A'masy] dari [Ibrahim] dari ['Alqamah] dari [Abdullah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak akan masuk surga orang yang dalam hatinya terdapat kesombongan (walau) sebiji sawi, dan tidak akan masuk neraka seorang yang di dalam hatinya terdapat keimanan (walau) sebiji sawi.\""},"4125":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ الْأَغَرِّ أَبِي مُسْلِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُ سُبْحَانَهُ الْكِبْرِيَاءُ رِدَائِي وَالْعَظَمَةُ إِزَارِي مَنْ نَازَعَنِي وَاحِدًا مِنْهُمَا أَلْقَيْتُهُ فِي جَهَنَّمَ","id":"Telah menceritakan kepada kami [Hannad bin As Sari] telah menceritakan kepada kami [Abu Al Ahwash] dari ['Atha bin As Saib] dari [Al Aghar Abu Muslim] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah Subhanahu berfirman: 'Kesombongan adalah pakaian-Ku, dan kebesaran adalah selendang-Ku, siapa saja yang mencabut salah satu dari keduanya dari-Ku, maka akan Aku lemparkan ia ke neraka Jahannam.\""},"4126":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ وَهَارُونُ بْنُ إِسْحَقَ قَالَا حَدَّثَنَا عَبْدُ الرَّحْمَنِ الْمُحَارِبِيُّ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُ سُبْحَانَهُ الْكِبْرِيَاءُ رِدَائِي وَالْعَظَمَةُ إِزَارِي فَمَنْ نَازَعَنِي وَاحِدًا مِنْهُمَا أَلْقَيْتُهُ فِي النَّارِ","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id] dan [Harun bin Ishaq] keduanya berkata; telah menceritakan kepada kami [Abdurrahman Al Muharibi] dari ['Atha bin As Saib] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah 'azza wajalla berfirman: 'Kesombongan adalah pakaian-Ku, sedangkan kebesaran adalah selendang-Ku, maka siapa saja yang mencabut salah satu dari dua hal, itu maka ia akan Aku lemparkan ke neraka.\""},"4127":{"ar":"حَدَّثَنَا حَرْمَلَةُ بْنُ يَحْيَى حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ أَنَّ دَرَّاجًا حَدَّثَهُ عَنْ أَبِي الْهَيْثَمِ عَنْ أَبِي سَعِيدٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ يَتَوَاضَعُ لِلَّهِ سُبْحَانَهُ دَرَجَةً يَرْفَعُهُ اللَّهُ بِهِ دَرَجَةً وَمَنْ يَتَكَبَّرُ عَلَى اللَّهِ دَرَجَةً يَضَعُهُ اللَّهُ بِهِ دَرَجَةً حَتَّى يَجْعَلَهُ فِي أَسْفَلِ السَّافِلِينَ","id":"Telah menceritakan kepada kami [Harmalah bin Yahya] telah menceritakan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku ['Amru bin Al Harits] bahwa [Darrajan] telah menceritakan kepadanya dari [Abu Al Haitsam] dari [Abu Sa'id] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa tawadlu' (bersikap rendah diri) kepada Allah Subhanah satu derajat, niscaya Allah akan mengangkatnya satu derajat, dan barangsiapa bersikap sombong kepada Allah satu derajat, maka Allah akan merendahkan satu derajat hingga derajat yang paling hina.\""},"4128":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ الصَّمَدِ وَسَلْمُ بْنُ قُتَيْبَةَ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ عَلِيِّ بْنِ زَيْدٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَإِنْ كَانَتْ الْأَمَةُ مِنْ أَهْلِ الْمَدِينَةِ لَتَأْخُذُ بِيَدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَا يَنْزِعُ يَدَهُ مِنْ يَدِهَا حَتَّى تَذْهَبَ بِهِ حَيْثُ شَاءَتْ مِنْ الْمَدِينَةِ فِي حَاجَتِهَا","id":"Telah menceritakan kepada kami [Nahsr bin Ali] telah menceritakan kepada kami [Abdus Shamad] dan [Salm bin Qutaibah] keduanya berkata; telah menceritakan kepada kami [Syu'bah] dari ['Ali bin Zaid] dari [Anas bin Malik] dia berkata, \"Sekiranya ada seorang budak wanita dari penduduk Madinah yang menggandeng tangan Rasulullah shallallahu 'alaihi wasallam, maka beliau tidak menarik tangan beliau dari tangan budak tersebut sampai ia membawanya ke manapun yang ia kehendaki di Madinah hingga selesai hajatnya.\""},"4129":{"ar":"حَدَّثَنَا عَمْرُو بْنُ رَافِعٍ حَدَّثَنَا جَرِيرٌ عَنْ مُسْلِمٍ الْأَعْوَرِ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعُودُ الْمَرِيضَ وَيُشَيِّعُ الْجِنَازَةَ وَيُجِيبُ دَعْوَةَ الْمَمْلُوكِ وَيَرْكَبُ الْحِمَارَ وَكَانَ يَوْمَ قُرَيْظَةَ وَالنَّضِيرِ عَلَى حِمَارٍ وَيَوْمَ خَيْبَرَ عَلَى حِمَارٍ مَخْطُومٍ بِرَسَنٍ مِنْ لِيفٍ وَتَحْتَهُ إِكَافٌ مِنْ لِيفٍ","id":"Telah menceritakan kepada kami ['Amru bin Rafi'] telah menceritakan kepada kami [Jarir] dari [Muslim Al A'war] dari [Anas bin Malik] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam adalah sosok orang yang suka menjenguk orang yang sakit, mengantarkan jenazah, memenuhi ajakan seorang hamba sahaya, dan menaiki seekor keledai. Ketika hari (pengusiran) Bani Quraidlah dan Nadlir beliau menaiki seekor keledai, dan ketika hari (penaklukan) Khaibar, beliau juga menaiki seekor keledai yang tali kekangnya dan pelananya terbuat dari kulit.\""},"4130":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ سَعِيدٍ حَدَّثَنَا عَلِيُّ بْنُ الْحُسَيْنِ بْنِ وَاقِدٍ حَدَّثَنَا أَبِي عَنْ مَطَرٍ عَنْ قَتَادَةَ عَنْ مُطَرِّفٍ عَنْ عِيَاضِ بْنِ حِمَارٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ خَطَبَهُمْ فَقَالَ إِنَّ اللَّهَ عَزَّ وَجَلَّ أَوْحَى إِلَيَّ أَنْ تَوَاضَعُوا حَتَّى لَا يَفْخَرَ أَحَدٌ عَلَى أَحَدٍ","id":"Telah menceritakan kepada kami [Ahmad bin Sa'id] telah menceritakan kepada kami [Ali bin Al Husain bin Waqid] telah menceritakan kepada kami [Ayahku] dari [Mathar] dari [Qatadah] dari [Mutharif] dari ['Iyadl bin Himar] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau berkhutbah di hadapan para sahabat dengan mengatakan: \"Sesungguhnya Allah 'azza wajalla telah mewahyukan kepadaku supaya kalian bersikap rendah diri, sampai tidak ada lagi salah seorang dari kalian saling berbangga diri kepada yang lainnya.\""},"4131":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ وَعَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي عُتْبَةَ مَوْلًى لِأَنَسِ بْنِ مَالِكٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَشَدَّ حَيَاءً مِنْ عَذْرَاءَ فِي خِدْرِهَا وَكَانَ إِذَا كَرِهَ شَيْئًا رُئِيَ ذَلِكَ فِي وَجْهِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Yahya bin Sa'id] dan [Abdurrahman bin Mahdi] keduanya berkata; telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Abdullah bin Abu 'Utbah] bekas budak Anas bin Malik, dari [Abu Sa'id Al Khudri] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam adalah seorang yang pemalu, dan lebih malu daripada seorang perawan yang dipingit di kamarnya. Dan jika beliau membenci sesuatu maka itu akan terlihat dari mimik wajahnya.\""},"4132":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ عَبْدِ اللَّهِ الرَّقِّيُّ حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ مُعَاوِيَةَ بْنِ يَحْيَى عَنْ الزُّهْرِيِّ عَنْ أَنَسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ لِكُلِّ دِينٍ خُلُقًا وَخُلُقُ الْإِسْلَامِ الْحَيَاءُ","id":"Telah menceritakan kepada kami [Isma'il bin Abdullah Ar Raqi] telah menceritakan kepada kami [Isa bin Yunus] dari [Mu'awiyah bin Yahya] dari [Az Zuhri] dari [Anas] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya setiap agama itu memliki etika, sedangkan akhlak (etika) Islam adalah rasa malu.\""},"4133":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا سَعِيدُ بْنُ مُحَمَّدٍ الْوَرَّاقُ حَدَّثَنَا صَالِحُ بْنُ حَسَّانَ عَنْ مُحَمَّدِ بْنِ كَعْبٍ الْقُرَظِيِّ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ لِكُلِّ دِينٍ خُلُقًا وَإِنَّ خُلُقَ الْإِسْلَامِ الْحَيَاءُ","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id] telah menceritakan kepada kami [Sa'id bin Muhammad Al Warraq] telah menceritakan kepada kami [Shalih bin Hasan] dari [Muhammad bin Ka'b Al Quradli] dari [Ibnu Abbas] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya setiap agama itu memliki etika, sedangkan akhlak (etika) Islam adalah rasa malu.\""},"4134":{"ar":"حَدَّثَنَا عَمْرُو بْنُ رَافِعٍ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ رِبْعِيِّ بْنِ حِرَاشٍ عَنْ عُقْبَةَ بْنِ عَمْرٍو أَبِي مَسْعُودٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِمَّا أَدْرَكَ النَّاسُ مِنْ كَلَامِ النُّبُوَّةِ الْأُولَى إِذَا لَمْ تَسْتَحْيِ فَاصْنَعْ مَا شِئْتَ","id":"Telah menceritakan kepada kami ['Amru bin Rafi'] telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Rib'I bin Hirasy] dari ['Uqbah bin 'Amru Abu Mas'ud] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Yang pertama kali diketahui oleh manusia dari perkara kenabian adalah 'Jika kamu tidak punya rasa malu maka berbuatlah sesukamu'.\""},"4135":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ مُوسَى حَدَّثَنَا هُشَيْمٌ عَنْ مَنْصُورٍ عَنْ الْحَسَنِ عَنْ أَبِي بَكْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْحَيَاءُ مِنْ الْإِيمَانِ وَالْإِيمَانُ فِي الْجَنَّةِ وَالْبَذَاءُ مِنْ الْجَفَاءِ وَالْجَفَاءُ فِي النَّارِ","id":"Telah menceritakan kepada kami [Isma'il bin Musa] telah menceritakan kepada kami [Husyaim] dari [Manshur] dari [Al Hasan] dari [Abu Bakrah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Malu itu sebagian dari iman, dan iman akan berada di surga. Sedangkan perkataan kotor termasuk dari perangai buruk, dan perangai buruk akan berada di neraka.\""},"4136":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا مَعْمَرٌ عَنْ ثَابِتٍ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا كَانَ الْفُحْشُ فِي شَيْءٍ قَطُّ إِلَّا شَانَهُ وَلَا كَانَ الْحَيَاءُ فِي شَيْءٍ قَطُّ إِلَّا زَانَهُ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali Al Khallal] telah menceritakan kepada kami [Abdurrazaq] telah memberitakan kepada kami [Ma'mar] dari [Tsabit] dari [Anas], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah kekejian terhadap sesuatu apapun kecuali ia akan membuatnya buruk. Dan tidaklah malu kepada sesuatu apapun kecuali ia akan menghiasinya.\""},"4137":{"ar":"حَدَّثَنَا حَرْمَلَةُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ حَدَّثَنِي سَعِيدُ بْنُ أَبِي أَيُّوبَ عَنْ أَبِي مَرْحُومٍ عَنْ سَهْلِ بْنِ مُعَاذِ بْنِ أَنَسٍ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ كَظَمَ غَيْظًا وَهُوَ قَادِرٌ عَلَى أَنْ يُنْفِذَهُ دَعَاهُ اللَّهُ عَلَى رُءُوسِ الْخَلَائِقِ يَوْمَ الْقِيَامَةِ حَتَّى يُخَيِّرَهُ فِي أَيِّ الْحُورِ شَاءَ","id":"Telah menceritakan kepada kami [Harmalah bin Yahya] telah menceritakan kepada kami [Abdullah bin Wahb] telah menceritakan kepadaku [Sa'id bin Abu Ayyub] dari [Abu Marhum] dari [Sahl bin Mu'adz bin Anas] dari [Ayahnya], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mampu menahan amarahnya sedangkan ia mampu melampiaskannya, maka Allah akan memanggilnya di hadapan seluruh makhluk pada hari Kiamat hingga Dia memberinya (kebebasan) memilih bidadari yang ia suka.\""},"4138":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ مُحَمَّدُ بْنُ الْعَلَاءِ الْهَمْدَانِيُّ حَدَّثَنَا يُونُسُ بْنُ بُكَيْرٍ حَدَّثَنَا خَالِدُ بْنُ دِينَارٍ الشَّيْبَانِيُّ عَنْ عُمَارَةَ الْعَبْدِيِّ حَدَّثَنَا أَبُو سَعِيدٍ الْخُدْرِيُّ قَالَكُنَّا جُلُوسًا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَتَتْكُمْ وُفُودُ عَبْدِ الْقَيْسِ وَمَا يَرَى أَحَدٌ فِينَا نَحْنُ كَذَلِكَ إِذْ جَاءُوا فَنَزَلُوا فَأَتَوْا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبَقِيَ الْأَشَجُّ الْعَصَرِيُّ فَجَاءَ بَعْدُ فَنَزَلَ مَنْزِلًا فَأَنَاخَ رَاحِلَتَهُ وَوَضَعَ ثِيَابَهُ جَانِبًا ثُمَّ جَاءَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أَشَجُّ إِنَّ فِيكَ لَخَصْلَتَيْنِ يُحِبُّهُمَا اللَّهُ الْحِلْمَ وَالتُّؤَدَةَ قَالَ يَا رَسُولَ اللَّهِ أَشَيْءٌ جُبِلْتُ عَلَيْهِ أَمْ شَيْءٌ حَدَثَ لِي قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَلْ شَيْءٌ جُبِلْتَ عَلَيْهِ","id":"Telah menceritakan kepada kami [Abu Kuraib Muhammad bin Al 'Ala Al Hamdani] telah menceritakan kepada kami [Yunus bin Bukair] telah menceritakan kepada kami [Khalid bin Dinar As Syaibani] dari ['Umarah Al 'Abdi] telah menceritakan kepada kami [Abu Sa'id Al Khudri] dia berkata, \"Kami pernah duduk-duduk bersama Rasulullah shallallahu 'alaihi wasallam, beliau lalu bersabda: \"Delegasi Abdul Qais telah datang kepada kalian.\" Namun tidak seorang pun dari kami yang melihatnya, ketika kami masih seperti itu tiba-tiba mereka datang dan datang menemui Rasulullah shallallahu 'alaihi wasallam, kecuali Al Asyaj Al 'Ashri yang masih di belakang (tertinggal). Lalu ia pun datang, setelah menambatkan unta dan meletakkan pakaiannya ia datang menemui Rasulullah shallallahu 'alaihi wasallam. Rasulullah shallallahu 'alaihi wasallam lalu bersabda kepadanya: \"Wahai Asyaj, sesungguhnya dalam dirimu terdapat dua sikap yang dicintai Allah; sikap santun dan tidak tergesa-gesa.\" Asyaj berkata, \"Wahai Rasulullah, itu sifat yang telah ditetapkan untukku, atau sesuatu yang bermula dariku?\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Itu sifat yang ditetapkan untukmu.\""},"4139":{"ar":"حَدَّثَنَا أَبُو إِسْحَقَ الْهَرَوِيُّ حَدَّثَنَا الْعَبَّاسُ بْنُ الْفَضْلِ الْأَنْصَارِيُّ حَدَّثَنَا قُرَّةُ بْنُ خَالِدٍ حَدَّثَنَا أَبُو جَمْرَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِلْأَشَجِّ الْعَصَرِيِّ إِنَّ فِيكَ خَصْلَتَيْنِ يُحِبُّهُمَا اللَّهُ الْحِلْمَ وَالْحَيَاءَ","id":"Telah menceritakan kepada kami [Abu Ishaq Al Harawi] telah menceritakan kepada kami [Al 'Abbas bin Al Fadl Al Anshari] telah menceritakan kepada kami [Qurrah bin Khalid] telah menceritakan kepada kami [Abu Jamrah] dari [Ibnu Abbas], bahwa Nabi shallallahu 'alaihi wasallam bersabda kepada Al Asyaj Al 'Ashri: \"Sesungguhnya dalam dirimu terdapat dua sikap yang dicintai oleh Allah; sifat santun dan malu.\""},"4140":{"ar":"حَدَّثَنَا زَيْدُ بْنُ أَخْزَمَ حَدَّثَنَا بِشْرُ بْنُ عُمَرَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ يُونُسَ بْنِ عُبَيْدٍ عَنْ الْحَسَنِ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ جُرْعَةٍ أَعْظَمُ أَجْرًا عِنْدَ اللَّهِ مِنْ جُرْعَةِ غَيْظٍ كَظَمَهَا عَبْدٌ ابْتِغَاءَ وَجْهِ اللَّهِ","id":"Telah menceritakan kepada kami [Zaid bin Akhzam] telah menceritakan kepada kami [Bisyr bin Umar] telah menceritakan kepada kami [Hammad bin Salamah] dari [Yunus bin 'Ubaid] dari [Al Hasan] dari [Ibnu Umar] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada tegukan yang lebih besar pahalanya di sisi Allah daripada tegukan amarah yang ditahan dari seorang hamba karena mencari keridlaan Allah.\""},"4141":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ أَنْبَأَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى أَنْبَأَنَا إِسْرَائِيلُ عَنْ إِبْرَاهِيمَ بْنِ مُهَاجِرٍ عَنْ مُجَاهِدٍ عَنْ مُوَرِّقٍ الْعِجْلِيِّ عَنْ أَبِي ذَرٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي أَرَى مَا لَا تَرَوْنَ وَأَسْمَعُ مَا لَا تَسْمَعُونَ إِنَّ السَّمَاءَ أَطَّتْ وَحَقَّ لَهَا أَنْ تَئِطَّ مَا فِيهَا مَوْضِعُ أَرْبَعِ أَصَابِعَ إِلَّا وَمَلَكٌ وَاضِعٌ جَبْهَتَهُ سَاجِدًا لِلَّهِ وَاللَّهِ لَوْ تَعْلَمُونَ مَا أَعْلَمُ لَضَحِكْتُمْ قَلِيلًا وَلَبَكَيْتُمْ كَثِيرًا وَمَا تَلَذَّذْتُمْ بِالنِّسَاءِ عَلَى الْفُرُشَاتِ وَلَخَرَجْتُمْ إِلَى الصُّعُدَاتِ تَجْأَرُونَ إِلَى اللَّهِ وَاللَّهِ لَوَدِدْتُ أَنِّي كُنْتُ شَجَرَةً تُعْضَدُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah memberitakan kepada kami ['Ubaidullah bin Musa] telah memberitakan kepada kami [Israil] dari [Ibrahim bin Muhajir] dari [Mujahid] dari [Muwariq Al 'Ijli] dari [Abu Dzar] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya saya mengetahui sesuatu yang tidak kalian ketahui, dan mendengar apa yang tidak kalian dengar. Sesungguhnya langit merintih dan diberikan kepadanya hak untuk merintih. Karena tidaklah dalam posisi empat jari kecuali ada Malaikat yang meletakkan keningnya bersujud kepada Allah. Demi Allah, seandainya kalian mengetahui apa yang aku ketahui, niscaya kalian akan sedikit tertawa dan banyak menangis, dan kalian tidak akan merasakan enaknya di atas kasur bersama isteri, dan kalian akan keluar menuju bukit-bukit untuk berdo'a dengan suara keras kepada Allah. Demi Allah, aku sangat ingin seandainya aku menjadi sebatang pohon yang ditebang.\""},"4142":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ تَعْلَمُونَ مَا أَعْلَمُ لَضَحِكْتُمْ قَلِيلًا وَلَبَكَيْتُمْ كَثِيرًا","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Abdus Shamad bin Abdul Warits] telah menceritakan kepada kami [Hammam] dari [Qatadah] dari [Anas bin Malik] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sekiranya kalian mengetahui apa yang aku ketahui, sungguh kalian akan sedikit tertawa dan banyak menangis.\""},"4143":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي فُدَيْكٍ عَنْ مُوسَى بْنِ يَعْقُوبَ الزَّمْعِيِّ عَنْ أَبِي حَازِمٍ أَنَّ عَامِرَ بْنَ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ أَخْبَرَهُ أَنَّ أَبَاهُ أَخْبَرَهُأَنَّهُ لَمْ يَكُنْ بَيْنَ إِسْلَامِهِمْ وَبَيْنَ أَنْ نَزَلَتْ هَذِهِ الْآيَةُ يُعَاتِبُهُمْ اللَّهُ بِهَا إِلَّا أَرْبَعُ سِنِينَ{ وَلَا يَكُونُوا كَالَّذِينَ أُوتُوا الْكِتَابَ مِنْ قَبْلُ فَطَالَ عَلَيْهِمْ الْأَمَدُ فَقَسَتْ قُلُوبُهُمْ وَكَثِيرٌ مِنْهُمْ فَاسِقُونَ }","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibrahim] telah menceritakan kepada kami [Muhammad bin Abu Fudaik] dari [Musa bin Ya'qub Az Zam'i] dari [Abu Hazim] bahwa ['Amir bin Abdullah bin Az Zubair] mengabarkan kepadanya, bahwa [Ayahnya] telah mengabarkan kepadanya, bahwa jarak antara keIslaman mereka dan turunnya ayat yang dengannya Allah mencela mereka kecuali hanya empat tahun, yaitu: '(…dan janganlah mereka seperti orang-orang yang sebelumnya telah diturunkan Al Kitab kepadanya, Kemudian berlalulah masa yang panjang atas mereka lalu hati mereka menjadi keras. dan kebanyakan di antara mereka adalah orang-orang yang fasik) ' (Qs. Al Hadiid: 16)."},"4144":{"ar":"حَدَّثَنَا بَكْرُ بْنُ خَلَفٍ حَدَّثَنَا أَبُو بَكْرٍ الْحَنَفِيُّ حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ جَعْفَرٍ عَنْ إِبْرَاهِيمَ بْنِ عَبْدِ اللَّهِ بْنِ حُنَيْنٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُكْثِرُوا الضَّحِكَ فَإِنَّ كَثْرَةَ الضَّحِكِ تُمِيتُ الْقَلْبَ","id":"Telah menceritakan kepada kami [Bakar bin Khalaf] telah menceritakan kepada kami [Abu Bakar Al Hanafi] telah menceritakan kepada kami [Abdul Hamid bin Ja'far] dari [Ibrahim bin Abdullah bin Hunain] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian banyak tertawa, karena banyak tertawa akan mematikan hati.\""},"4145":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَقَالَ لِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْرَأْ عَلَيَّ فَقَرَأْتُ عَلَيْهِ بِسُورَةِ النِّسَاءِ حَتَّى إِذَا بَلَغْتُ{ فَكَيْفَ إِذَا جِئْنَا مِنْ كُلِّ أُمَّةٍ بِشَهِيدٍ وَجِئْنَا بِكَ عَلَى هَؤُلَاءِ شَهِيدًا }فَنَظَرْتُ إِلَيْهِ فَإِذَا عَيْنَاهُ تَدْمَعَانِ","id":"Telah menceritakan kepada kami [Al Hannad bin As Sarri] telah menceritakan kepada kami [Abu Al Ahwash] dari [Al A'masy] dari [Ibrahim] dari ['Alqamah] dari [Abdullah] dia berkata, \"Nabi shallallahu 'alaihi wasallam pernah bersabda kepadaku: \"Bacakanlah (ayat) untukku! \" Maka saya membaca surat An Nisaa, ketika sampai ayat: '(Maka bagaimanakah (halnya orang kafir nanti), apabila kami mendatangkan seseorang saksi (rasul) dari tiap-tiap umat dan kami mendatangkan kamu (Muhammad) sebagai saksi atas mereka itu (sebagai umatmu) ' (Qs. An Nisaa: 41), maka saya melihat kedua air mata beliau meneteskan air mata.\""},"4146":{"ar":"حَدَّثَنَا الْقَاسِمُ بْنُ زَكَرِيَّا بْنِ دِينَارٍ حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ حَدَّثَنَا أَبُو رَجَاءٍ الْخُرَاسَانِيُّ عَنْ مُحَمَّدِ بْنِ مَالِكٍ عَنْ الْبَرَاءِ قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي جِنَازَةٍ فَجَلَسَ عَلَى شَفِيرِ الْقَبْرِ فَبَكَى حَتَّى بَلَّ الثَّرَى ثُمَّ قَالَ يَا إِخْوَانِي لِمِثْلِ هَذَا فَأَعِدُّوا","id":"Telah menceritakan kepada kami [Al Qasim bin Zakaria bin Dinar] telah menceritakan kepada kami [Ishaq bin Manshur] telah menceritakan kepada kami [Abu Raja Al Khurasani] dari [Muhammad bin Malik] dari [Al Barra] dia berkata, \"Kami pernah mengantar jenazah bersama Rasulullah shallallahu 'alaihi wasallam, kemudian beliau duduk di sisi kuburan dan menangis hingga membasahi tanah. Beliau bersabda: \"Wahai saudaraku, bersiap-siaplah untuk hal seperti ini.\""},"4147":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَحْمَدَ بْنِ بَشِيرِ بْنِ ذَكْوَانَ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا أَبُو رَافِعٍ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ السَّائِبِ عَنْ سَعْدِ بْنِ أَبِي وَقَّاصٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ابْكُوا فَإِنْ لَمْ تَبْكُوا فَتَبَاكَوْا","id":"Telah menceritakan kepada kami [Abdullah bin Ahmad bin Basyir bin Dzakwan Ad Dimasyqi] telah menceritakan kepada kami [Al Walid bin Muslim] telah menceritakan kepada kami [Abu Rafi'] dari [Ibnu Abu Mulaikah] dari [Abdurrahman bin As Saib] dari [Sa'd bin Abu Waqash] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Menagislah kalian, jika tidak bisa menangis maka berusalah untuk menangis.\""},"4148":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ وَإِبْرَاهِيمُ بْنُ الْمُنْذِرِ قَالَا حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ حَدَّثَنِي حَمَّادُ بْنُ أَبِي حُمَيْدٍ الزُّرَقِيُّ عَنْ عَوْنِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ بْنِ مَسْعُودٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ عَبْدٍ مُؤْمِنٍ يَخْرُجُ مِنْ عَيْنَيْهِ دُمُوعٌ وَإِنْ كَانَ مِثْلَ رَأْسِ الذُّبَابِ مِنْ خَشْيَةِ اللَّهِ ثُمَّ تُصِيبُ شَيْئًا مِنْ حُرِّ وَجْهِهِ إِلَّا حَرَّمَهُ اللَّهُ عَلَى النَّارِ","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibrahim Ad Dimasyqi] dan [Ibrahim bin Al Mundzir] keduanya berkata; telah menceritakan kepada kami [Ibnu Abu Fudaik] telah menceritakan kepadaku [Hammad bin Abu Humaid Az Zuraqi] dari ['Aun bin Abdullah bin 'Utbah bin Mas'ud] dari [Ayahnya] dari [Abdullah bin Mas'ud] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang mukmin mengeluarkan air mata dari kedua matanya walaupun sebesar kepala ekor lalat karena takut kepada Allah, kemudian ia mengenai wajahnya melainkan Allah akan membaskannya dari neraka.\""},"4149":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ مَالِكِ بْنِ مِغْوَلٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ سَعِيدٍ الْهَمْدَانِيِّ عَنْ عَائِشَةَ قَالَتْقُلْتُ يَا رَسُولَ اللَّهِ{ وَالَّذِينَ يُؤْتُونَ مَا آتَوْا وَقُلُوبُهُمْ وَجِلَةٌ }أَهُوَ الَّذِي يَزْنِي وَيَسْرِقُ وَيَشْرَبُ الْخَمْرَ قَالَ لَا يَا بِنْتَ أَبِي بَكْرٍ أَوْ يَا بِنْتَ الصِّدِّيقِ وَلَكِنَّهُ الرَّجُلُ يَصُومُ وَيَتَصَدَّقُ وَيُصَلِّي وَهُوَ يَخَافُ أَنْ لَا يُتَقَبَّلَ مِنْهُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Waki'] dari [Malik bin Mighwal] dari [Abdurrahman bin Sa'id Al Hamdani] dari ['Aisyah] dia berkata, \"Saya bertanya, \"Wahai Rasulullah, apakah firman Allah: '(Dan orang-orang yang memberikan apa yang telah mereka berikan, dengan hati yang takut…) ' (Qs. Al Mukminuun: 60), ditujukan kepada orang-orang berzina, mencuri dan minum minuman keras saja?\" Beliau menjawab: \"Tidak wahai puteri Abu Bakar -atau wahai puteri As Shiddiq-, tetapi (ayat tersebut) ditujukan kepada seseorang yang berpuasa, bersedekah dan shalat, sedangkan ia takut jika amalannya tidak di terima.\""},"4150":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ إِسْمَعِيلَ بْنِ عِمْرَانَ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ يَزِيدَ بْنِ جَابِرٍ حَدَّثَنِي أَبُو عَبْدِ رَبٍّ قَالَ سَمِعْتُ مُعَاوِيَةَ بْنَ أَبِي سُفْيَانَ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّمَا الْأَعْمَالُ كَالْوِعَاءِ إِذَا طَابَ أَسْفَلُهُ طَابَ أَعْلَاهُ وَإِذَا فَسَدَ أَسْفَلُهُ فَسَدَ أَعْلَاهُ","id":"Telah menceritakan kepada kami ['Utsman bin Isma'il bin 'Imran Ad Dimasyqi] telah menceritakan kepada kami [Al Walid bin Muslim] telah menceritakan kepada kami [Abdurrahman bin Yazid bin Jabir] telah menceritakan kepadaku [Abu 'Abd Rabb] dia berkata; saya mendengar [Mu'awiyah bin Abu Sufyan] berkata, \"Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya amalan seseorang itu bagaikan tempat minum, jika bawahnya jernih maka atasnya pun ikut jernih, namun jika bawahnya keruh maka permukaannya pun ikut keruh.\""},"4151":{"ar":"حَدَّثَنَا كَثِيرُ بْنُ عُبَيْدٍ الْحِمْصِيُّ حَدَّثَنَا بَقِيَّةُ عَنْ وَرْقَاءَ بْنِ عُمَرَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ ذَكْوَانَ أَبُو الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْعَبْدَ إِذَا صَلَّى فِي الْعَلَانِيَةِ فَأَحْسَنَ وَصَلَّى فِي السِّرِّ فَأَحْسَنَ قَالَ اللَّهُ عَزَّ وَجَلَّ هَذَا عَبْدِي حَقًّا","id":"Telah menceritakan kepada kami [Katsir bin 'Ubaid Al Himshi] telah menceritakan kepada kami [Baqiyah] dari [Warqa bin 'Umar] telah menceritakan kepada kami [Abdullah bin Dzakwan Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya jika ada seorang hamba yang shalat dalam kondisi terang-terangan kemudian ia membaguskan shalatnya, begitu juga ketika ia shalat dalam kondisi sembunyi-sembunyi dan membaguskan shalatnya, maka Allah 'azza wajalla akan berfirman, 'Ini benar-benar hamba-Ku'.\""},"4152":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَامِرِ بْنِ زُرَارَةَ وَإِسْمَعِيلُ بْنُ مُوسَى قَالَا حَدَّثَنَا شَرِيكُ بْنُ عَبْدِ اللَّهِ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَارِبُوا وَسَدِّدُوا فَإِنَّهُ لَيْسَ أَحَدٌ مِنْكُمْ بِمُنْجِيهِ عَمَلُهُ قَالُوا وَلَا أَنْتَ يَا رَسُولَ اللَّهِ قَالَ وَلَا أَنَا إِلَّا أَنْ يَتَغَمَّدَنِي اللَّهُ بِرَحْمَةٍ مِنْهُ وَفَضْلٍ","id":"Telah menceritakan kepada kami [Abdullah bin 'Amir bin Zurarah] dan [Isma'il bin Musa] keduanya berkata; telah menceritakan kepada kami [Syarik bin Abdullah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bertaqarublah kalian dan bersungguh-sungguhlah (dalam beribadah), sebab sesungguhnya tidak ada seorangpun dari kalian yang selamat karena amalnya.\" Mereka berkata, \"Begitu juga dengan anda wahai Rasulullah! \" Beliau menjawab: \"Begitu juga dengan saya, hanya saja Allah meliputiku dengan rahmat dan kemuliaan-Nya.\""},"4153":{"ar":"حَدَّثَنَا أَبُو مَرْوَانَ الْعُثْمَانِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قَالَ اللَّهُ عَزَّ وَجَلَّ أَنَا أَغْنَى الشُّرَكَاءِ عَنْ الشِّرْكِ فَمَنْ عَمِلَ لِي عَمَلًا أَشْرَكَ فِيهِ غَيْرِي فَأَنَا مِنْهُ بَرِيءٌ وَهُوَ لِلَّذِي أَشْرَكَ","id":"Telah menceritakan kepada kami [Abu Marwan Al 'Utsmani] telah menceritakan kepada kami [Abdul Aziz bin Abu Hazim] dari [Al 'Ala bin Abdurrahman] dari [Ayahnya] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah 'azza wajalla berfirman; 'Aku adalah dzat yang tidak membutuhkan sekutu, maka barangsiapa mengerjakan suatu amalan dengan menyertakan sekutu selain diri-Ku, maka Aku berlepas diri darinya, dan ia milik sekutu yang disertakannya itu.\""},"4154":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ وَهَارُونُ بْنُ عَبْدِ اللَّهِ الْحَمَّالُ وَإِسْحَقُ بْنُ مَنْصُورٍ حَدَّثَنَا مُحَمَّدُ بْنُ بَكْرٍ الْبُرْسَانِيُّ أَنْبَأَنَا عَبْدُ الْحَمِيدِ بْنُ جَعْفَرٍ أَخْبَرَنِي أَبِي عَنْ زِيَادِ بْنِ مِينَاءَ عَنْ أَبِي سَعْدِ بْنِ أَبِي فَضَالَةَ الْأَنْصَارِيِّ وَكَانَ مِنْ الصَّحَابَةِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا جَمَعَ اللَّهُ الْأَوَّلِينَ وَالْآخِرِينَ يَوْمَ الْقِيَامَةِ لِيَوْمٍ لَا رَيْبَ فِيهِ نَادَى مُنَادٍ مَنْ كَانَ أَشْرَكَ فِي عَمَلٍ عَمِلَهُ لِلَّهِ فَلْيَطْلُبْ ثَوَابَهُ مِنْ عِنْدِ غَيْرِ اللَّهِ فَإِنَّ اللَّهَ أَغْنَى الشُّرَكَاءِ عَنْ الشِّرْكِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] dan [Harun bin Abdullah Al Hammal] serta [Ishaq bin Manshur] telah menceritakan kepada kami [Muhammad bin Bakar Al Bursani] telah memberitakan kepada kami [Abdul Hamid bin Ja'far] telah mengabarkan kepadaku [Ayahku] dari [Ziyad bin Mina] dari [Abu Sa'd bin Abu Fadlalah Al Anshari] salah seorang sahabat Nabi, ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila Allah mengumpulkan orang-orang yang terdahulu dan orang-orang yang terakhir pada hari Kiamat -di hari yang tidak ada keraguan dalamnya-, maka akan ada seorang penyeru yang menyeru, \"Barangsiapa berbuat syirik yang ia kerjakan untuk selain Allah, hendaknya ia meminta balasan kepada selain Allah tersebut, sesungguhnya Allah tidak membutuhkan sekutu.\""},"4155":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ عَنْ كَثِيرِ بْنِ زَيْدٍ عَنْ رُبَيْحِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي سَعِيدٍ الْخُدْرِيِّ عَنْ أَبِيهِ عَنْ أَبِي سَعِيدٍ قَالَخَرَجَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ نَتَذَاكَرُ الْمَسِيحَ الدَّجَّالَ فَقَالَ أَلَا أُخْبِرُكُمْ بِمَا هُوَ أَخْوَفُ عَلَيْكُمْ عِنْدِي مِنْ الْمَسِيحِ الدَّجَّالِ قَالَ قُلْنَا بَلَى فَقَالَ الشِّرْكُ الْخَفِيُّ أَنْ يَقُومَ الرَّجُلُ يُصَلِّي فَيُزَيِّنُ صَلَاتَهُ لِمَا يَرَى مِنْ نَظَرِ رَجُلٍ","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id] telah menceritakan kepada kami [Abu Khalid Al Ahmar] dari [Katsir bin Zaid] dari [Rubaih bin Abdurrahman bi Abu Sa'id Al Khudri] dari [Ayahnya] dari [Abu Sa'id] dia berkata, 'Rasulullah shallallahu 'alaihi wasallam pernah keluar bersama kami, sementara kami saling mengingatkan tentang Al Masih Ad Dajjal, maka beliau bersabda: \"Maukah aku beritahukan kepada kalian tentang sesuatu yang lebih aku khawatirkan terhadap diri kalian daripada Al Masih Ad Dajjal?\" Abu Sa'id berkata, \"Kami menjawab, \"Tentu.\" Beliau bersabda: \"Syirik yang tersembunyi, yaitu seseorang mengerjakan shalat dan membaguskan shalatnya dengan harapan agar ada seseorang yang memperhatikannya.\""},"4156":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ خَلَفٍ الْعَسْقَلَانِيُّ حَدَّثَنَا رَوَّادُ بْنُ الْجَرَّاحِ عَنْ عَامِرِ بْنِ عَبْدِ اللَّهِ عَنْ الْحَسَنِ بْنِ ذَكْوَانَ عَنْ عُبَادَةَ بْنِ نُسَيٍّ عَنْ شَدَّادِ بْنِ أَوْسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَخْوَفَ مَا أَتَخَوَّفُ عَلَى أُمَّتِي الْإِشْرَاكُ بِاللَّهِ أَمَا إِنِّي لَسْتُ أَقُولُ يَعْبُدُونَ شَمْسًا وَلَا قَمَرًا وَلَا وَثَنًا وَلَكِنْ أَعْمَالًا لِغَيْرِ اللَّهِ وَشَهْوَةً خَفِيَّةً","id":"Telah menceritakan kepada kami [Muhammad bin Khalaf Al 'Asqalani] telah menceritakan kepada kami [Rawwad bin Al Jarrah] dari ['Amir bin Abdullah] dari [Al Hasan bin Dzakwan] dari ['Ubadah bin Nusai] dari [Syaddad bin Aus] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya sesuatu yang paling saya khawatirkan atas ummatku adalah syirik kepada Allah, saya tidak mengatakan bahwa mereka menyembah matahari dan juga rembulan, tidak pula menyembah berhala, akan tetapi mereka beramal untuk selain Allah dan syahwat yang tersembunyi.\""},"4157":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ قَالَا حَدَّثَنَا بَكْرُ بْنُ عَبْدِ الرَّحْمَنِ حَدَّثَنَا عِيسَى بْنُ الْمُخْتَارِ عَنْ مُحَمَّدِ بْنِ أَبِي لَيْلَى عَنْ عَطِيَّةَ الْعَوْفِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ يُسَمِّعْ يُسَمِّعْ اللَّهُ بِهِ وَمَنْ يُرَاءِ يُرَاءِ اللَّهُ بِهِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Abu Kuraib] keduanya berkata; telah menceritakan kepada kami [Bakr bin Abdurrahman] telah menceritakan kepada kami [Isa bin Al Mukhtar] dari [Muhammad bin Abu Laila] dari ['Athiyah Al 'Aufi] dari [Abu Sa'id Al Khudri] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa ingin didengar (orang lain) maka Allah akan memperdengarkannya (untuk orang lain), dan barangsiapa ingin dilihat (orang lain) maka Allah akan memperlihatkannya.\""},"4158":{"ar":"حَدَّثَنَا هَارُونُ بْنُ إِسْحَقَ حَدَّثَنِي مُحَمَّدُ بْنُ عَبْدِ الْوَهَّابِ عَنْ سُفْيَانَ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ جُنْدَبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ يُرَاءِ يُرَاءِ اللَّهُ بِهِ وَمَنْ يُسَمِّعْ يُسَمِّعْ اللَّهُ بِهِ","id":"Telah menceritakan kepada kami [Harun bin Ishaq] telah menceritakan kepadaku [Muhammad bin Abdul Wahhab] dari [Sufyan] dari [Salamah bin Kuhail] dari [Jundab] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa melakukan riya' niscaya Allah akan mengabulkannya, dan barangsiapa melakukan sum'ah (ingin di dengar) niscaya Allah akan mengabulkannya (akan didengar orang).\""},"4159":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبِي وَمُحَمَّدُ ابْنُ بِشْرٍ قَالَا حَدَّثَنَا إِسْمَعِيلُ بْنُ أَبِي خَالِدٍ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا حَسَدَ إِلَّا فِي اثْنَتَيْنِ رَجُلٌ آتَاهُ اللَّهُ مَالًا فَسَلَّطَهُ عَلَى هَلَكَتِهِ فِي الْحَقِّ وَرَجُلٌ آتَاهُ اللَّهُ حِكْمَةً فَهُوَ يَقْضِي بِهَا وَيُعَلِّمُهَا","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [Ayahku] dan [Muhammad bin Bisyr] keduanya berkata; telah menceritakan kepada kami [Isma'il bin Abu Khalid] dari [Qais bin Abu Hazim] dari [Abdullah bin Mas'ud] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada kedengkian kecuali dalam dua perkara; seseorang yang dikaruniai Allah harta kekayaan kemudian ia habiskan dalam jalan kebenaran, dan seseorang yang dikaruniai Allah Al Hikmah (ilmu) lalu ia mengamalkannya.\""},"4160":{"ar":"حَدَّثَنَا يَحْيَى بْنُ حَكِيمٍ وَمُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ يَزِيدَ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا حَسَدَ إِلَّا فِي اثْنَتَيْنِ رَجُلٌ آتَاهُ اللَّهُ الْقُرْآنَ فَهُوَ يَقُومُ بِهِ آنَاءَ اللَّيْلِ وَآنَاءَ النَّهَارِ وَرَجُلٌ آتَاهُ اللَّهُ مَالًا فَهُوَ يُنْفِقُهُ آنَاءَ اللَّيْلِ وَآنَاءَ النَّهَارِ","id":"Telah menceritakan kepada kami [Yahya bin Hakim] dan [Muhammad bin Abdullah bin Yazid] keduanya berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Salim] dari [Ayahnya] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada hasad (dengki) kecuali dalam dua perkara; seseorang yang diberi Allah Al Quran (Hikmah) kemudian ia mengamalkannya sepanjang siang dan malam, dan seseorang yang diberi Allah harta kekayaan, lalu ia menginfakkannya sepanjang siang dan malam.\""},"4161":{"ar":"حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ الْحَمَّالُ وَأَحْمَدُ بْنُ الْأَزْهَر قَالَا حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ عَنْ عِيسَى بْنِ أَبِي عِيسَى الْحَنَّاطِ عَنْ أَبِي الزِّنَادِ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْحَسَدُ يَأْكُلُ الْحَسَنَاتِ كَمَا تَأْكُلُ النَّارُ الْحَطَبَ وَالصَّدَقَةُ تُطْفِئُ الْخَطِيئَةَ كَمَا يُطْفِئُ الْمَاءُ النَّارَ وَالصَّلَاةُ نُورُ الْمُؤْمِنِ وَالصِّيَامُ جُنَّةٌ مِنْ النَّارِ","id":"Telah menceritakan kepada kami [Harun bin Abdullah Al Hammal] dan [Ahmad bin Al Azhar] keduanya berkata; telah menceritakan kepada kami [Ibnu Abu Fudaik] dari [Isa bin Abu Isa Al Hannath] dari [Abu Az Zinad] dari [Anas], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kedengkian akan memakan kebaikan sebagaimana api memakan kayu bakar, dan sedekah akan menghapus kesalahan sebagaimana air dapat mematikan api. Shalat adalah cahaya seorang mukmin, sedangkan puasa adalah perisai dari api neraka.\""},"4162":{"ar":"حَدَّثَنَا الْحُسَيْنُ بْنُ الْحَسَنِ الْمَرْوَزِيُّ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ وَابْنُ عُلَيَّةَ عَنْ عُيَيْنَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي بَكْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ ذَنْبٍ أَجْدَرُ أَنْ يُعَجِّلَ اللَّهُ لِصَاحِبِهِ الْعُقُوبَةَ فِي الدُّنْيَا مَعَ مَا يَدَّخِرُ لَهُ فِي الْآخِرَةِ مِنْ الْبَغْيِ وَقَطِيعَةِ الرَّحِمِ","id":"Telah menceritakan kepada kami [Al Husain bin Al Hasan Al Mawarzi] telah memberitakan kepada kami [Abdullah bin Mubarak] dan [Ibnu 'Ulayyah] dari ['Uyainah bin Abdurrahman] dari [ayahnya] dari [Abu Bakrah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada perbuatan dosa yang akan di segerakan siksanya bagi pelakunya oleh Allah di dunia dan di sisakan baginya di akhirat melainkan berbuat aniaya dan memutuskan tali silaturrahmi.\""},"4163":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا صَالِحُ بْنُ مُوسَى عَنْ مُعَاوِيَةَ بْنِ إِسْحَقَ عَنْ عَائِشَةَ بِنْتِ طَلْحَةَ عَنْ عَائِشَةَ أُمِّ الْمُؤْمِنِينَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسْرَعُ الْخَيْرِ ثَوَابًا الْبِرُّ وَصِلَةُ الرَّحِمِ وَأَسْرَعُ الشَّرِّ عُقُوبَةً الْبَغْيُ وَقَطِيعَةُ الرَّحِمِ","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] telah menceritakan kepada kami [Shalih bin Musa] dari [Mu'awiyah bin Ishaq] dari ['Aisyah binti Thalhah] dari ['Aisyah Ummul Mukminin] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perbuatan baik yang akan di segerakan pahalanya adalah berbuat baik dan menyambung silaturrahim, sedangkan perbuatan dosa yang akan di segerakan siksanya adalah kezhaliman dan memutus tali silaturrahim.\""},"4164":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ حُمَيْدٍ الْمَدَنِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ دَاوُدَ بْنِ قَيْسٍ عَنْ أَبِي سَعِيدٍ مَوْلَى بَنِي عَامِرٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ حَسْبُ امْرِئٍ مِنْ الشَّرِّ أَنْ يَحْقِرَ أَخَاهُ الْمُسْلِمَ","id":"Telah menceritakan kepada kami [Ya'qub bin Humaid Al Madani] telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Daud bin Qais] dari [Abu Sa'id bekas budak 'Amir] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Cukuplah seseorang dikatakan telah berbuat jahat jika ia merendahkan saudaranya muslim.\""},"4165":{"ar":"حَدَّثَنَا حَرْمَلَةُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَنْبَأَنَا عَمْرُو بْنُ الْحَارِثِ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ سِنَانِ بْنِ سَعْدٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ أَوْحَى إِلَيَّ أَنْ تَوَاضَعُوا وَلَا يَبْغِي بَعْضُكُمْ عَلَى بَعْضٍ","id":"Telah menceritakan kepada kami [Harmalah bin Yahya] telah menceritakan kepada kami [Abdullah bin Wahb] telah memberitakan kepada kami ['Amru bin Al Harit] dari [Yazid bin Abu Habib] dari [Sinan bin Sa'd] dari [Anas bin Malik] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah telah mewahyukan kepadaku supaya kalian bersikap rendah hati, dan janganlah sebagian kalian berbuat aniaya terhadap sebagian yang lain.\""},"4166":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا أَبُو عَقِيلٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ حَدَّثَنِي رَبِيعَةُ بْنُ يَزِيدَ وَعَطِيَّةُ بْنُ قَيْسٍ عَنْ عَطِيَّةَ السَّعْدِيِّ وَكَانَ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَبْلُغُ الْعَبْدُ أَنْ يَكُونَ مِنْ الْمُتَّقِينَ حَتَّى يَدَعَ مَا لَا بَأْسَ بِهِ حَذَرًا لِمَا بِهِ الْبَأْسُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Hasyim bin Al Qasim] telah menceritakan kepada kami [Abu 'Aqil] telah menceritakan kepada kami [Abdullah bin Yazid] telah menceritakan kepadaku [Rabi'ah bin Yazid] dan ['Athiyah bin Qais] dari ['Athiyah As Sa'di] -dan dia termasuk dari salah seorang sahabat Nabi shallallahu 'alaihi wasallam- dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang hamba belum mencapai derajat takwa sehingga ia meninggalkan sesuatu yang mubah (boleh) sebagai bentuk kehati-hatian dari sesuatu yang dilarang.\""},"4167":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ حَدَّثَنَا زَيْدُ بْنُ وَاقِدٍ حَدَّثَنَا مُغِيثُ بْنُ سُمَيٍّ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَقِيلَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّ النَّاسِ أَفْضَلُ قَالَ كُلُّ مَخْمُومِ الْقَلْبِ صَدُوقِ اللِّسَانِ قَالُوا صَدُوقُ اللِّسَانِ نَعْرِفُهُ فَمَا مَخْمُومُ الْقَلْبِ قَالَ هُوَ التَّقِيُّ النَّقِيُّ لَا إِثْمَ فِيهِ وَلَا بَغْيَ وَلَا غِلَّ وَلَا حَسَدَ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Yahya bin Hamzah] telah menceritakan kepada kami [Zaid bin Waqid] telah menceritakan kepada kami [Mughits bin Sumay] dari [Abdullah bin 'Amru] dia berkata; Ditanyakan kepada Rasulullah shallallahu 'alaihi wasallam; \"Manusia bagaimanakah yang paling mulia?\" Beliau menjawab: \"Senua (orang) yang hatinya bersedih dan lisan (ucapannya) benar.\" Mereka berkata; \"Perkataannya yang benar telah kami ketahui, lantas apakah maksud dari hati yang bersedirh?\" Beliau bersabda: \"Hati yang bertakwa dan bersih, tidak ada kedurhakaan dan kelaliman padanya, serta kedengkian dan hasad.\""},"4168":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ أَبِي رَجَاءٍ عَنْ بُرْدِ بْنِ سِنَانٍ عَنْ مَكْحُولٍ عَنْ وَاثِلَةَ بْنِ الْأَسْقَعِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أَبَا هُرَيْرَةَ كُنْ وَرِعًا تَكُنْ أَعْبَدَ النَّاسِ وَكُنْ قَنِعًا تَكُنْ أَشْكَرَ النَّاسِ وَأَحِبَّ لِلنَّاسِ مَا تُحِبُّ لِنَفْسِكَ تَكُنْ مُؤْمِنًا وَأَحْسِنْ جِوَارَ مَنْ جَاوَرَكَ تَكُنْ مُسْلِمًا وَأَقِلَّ الضَّحِكَ فَإِنَّ كَثْرَةَ الضَّحِكِ تُمِيتُ الْقَلْبَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Abu Raja`] dari [Burd bin Sinan] dari [Makhul] dari [Watsilah bin Al Asqa'] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai Abu Hurairah, Jadilah kamu seorang yang wara`, niscaya kamu menjadi manusia yang paling beriabadah. Jadilah kamu menjadi seorang yang merasa kecukupan, niscaya kamu menjadi manusia yang paling bersyukur. Cintailah mmanusia seperti kamu mencintai dirimu sendiri, niscaya kamu akan menja di seorang mukmin. Perbaikilah hubungan dalam bertetangga dengan tetanggamu, niscaya kamu akan menjadi seorang yang berserah diri. Dan sedikitkanlah tertawa, karena banyak tertawa akan mematikan hati.\""},"4169":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ رُمْحٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ عَنْ الْمَاضِي بْنِ مُحَمَّدٍ عَنْ عَلِيِّ بْنِ سُلَيْمَانَ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ أَبِي إِدْرِيسَ الْخَوْلَانِيِّ عَنْ أَبِي ذَرٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا عَقْلَ كَالتَّدْبِيرِ وَلَا وَرَعَ كَالْكَفِّ وَلَا حَسَبَ كَحُسْنِ الْخُلُقِ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad bin Rumh] telah menceritakan kepada kami [Abdullah bin Wahb] dari [Al Madli bin Muhammad] dari ['Ali bin Sulaiman] dari [Al Qasim bin Muhammad] dari [Abu Idris Al Khaulani] dari [Abu Dzar] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bahwasanya kesederhanaan itu bagian dari iman, dikatakan bahwa al-badzadzah itu adalah sikap sederhana."},"4170":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ خَلَفٍ الْعَسْقَلَانِيُّ حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ حَدَّثَنَا سَلَّامُ بْنُ أَبِي مُطِيعٍ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَمُرَةَ بْنِ جُنْدَبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْحَسَبُ الْمَالُ وَالْكَرَمُ التَّقْوَى","id":"Telah menceritakan kepada kami [Muhammad bin Khalaf Al 'Asqalani] telah menceritakan kepada kami [Yunus bin Muhammad] telah menceritakan kepada kami [Sallam bin Abu Muthi'] dari [Qatadah] dari [Al Hasan] dari [Samurah bin Jundab] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kehormatan adalah (dengan) harta sedangkan kemuliaan adalah (dengan) ketakwaan.\""},"4171":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ وَعُثْمَانُ بْنُ أَبِي شَيْبَةَ قَالَا حَدَّثَنَا الْمُعْتَمِرُ بْنُ سُلَيْمَانَ عَنْ كَهْمَسِ بْنِ الْحَسَنِ عَنْ أَبِي السَّلِيلِ ضُرَيْبِ بْنِ نُفَيْرٍ عَنْ أَبِي ذَرٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي لَأَعْرِفُ كَلِمَةً وَقَالَ عُثْمَانُ آيَةً لَوْ أَخَذَ النَّاسُ كُلُّهُمْ بِهَا لَكَفَتْهُمْ قَالُوا يَا رَسُولَ اللَّهِ أَيَّةُ آيَةٍ قَالَ{ وَمَنْ يَتَّقِ اللَّهَ يَجْعَلْ لَهُ مَخْرَجًا }","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] dan [Utsman bin Abu Syaibah] keduanya berkata; telah menceritakan kepada kami [Al Mu'tamir bin Sulaiman] dari [Kahmas bin Al Hasan] dari [Abu As Salil Dluraib bin Nufair] dari [Abu Dzar] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya saya mengetahui satu kalimat. \" sedangkan Utsman mengatakan; \"Satu ayat, sekiranya semua manusia mengambilnya niscaya ayat tersebut dapat menncukupi mereka.\" Mereka bertanya; \"Wahai Rasulullah, ayat apakah itu?\" Beliau menjawab: \"Barangsiapa bertakwa kepada Allah, niscaya Dia akan memberikan jalan keluar baginya.\""},"4172":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا نَافِعُ بْنُ عُمَرَ الْجُمَحِيُّ عَنْ أُمَيَّةَ بْنِ صَفْوَانَ عَنْ أَبِي بَكْرِ بْنِ أَبِي زُهَيْرٍ الثَّقَفِيِّ عَنْ أَبِيهِ قَالَخَطَبَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالنَّبَاوَةِ أَوْ الْبَنَاوَةِ قَالَ وَالنَّبَاوَةُ مِنْ الطَّائِفِ قَالَ يُوشِكُ أَنْ تَعْرِفُوا أَهْلَ الْجَنَّةِ مِنْ أَهْلِ النَّارِ قَالُوا بِمَ ذَاكَ يَا رَسُولَ اللَّهِ قَالَ بِالثَّنَاءِ الْحَسَنِ وَالثَّنَاءِ السَّيِّئِ أَنْتُمْ شُهَدَاءُ اللَّهِ بَعْضُكُمْ عَلَى بَعْضٍ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Yazid bin Harun] telah memberitakan kepada kami [Nafi' bin Umar Al Jumahi] dari [Umayyah bin Shafwan] dari [Abu Bakar bin Abu Zuhair At Tsaqafi] dari [ayahnya] dia berkata; Rasulullah shallallahu 'alaihi wasallam berkhotbah di hadapan kami ketika berada di Nabwah atau Banawah -Abu Zuhair mengatakan; \"Nabawah adalah bagian dati daerah Tha`if.\"- sabdanya: 'Hampir-hampir saja kalian dapat mengetahui (beda antara) ahli surga dan ahli neraka.\" Mereka bertanya; \"Wahai Rasulullah, bagaimanakah hal itu dapat di ketahui?\" beliau menjawab: \"Dengan pujian yang baik dan caci maki yang buruk. Kalian adalah para saksi Allah (yang akan mempersaksikan) antara sebagian dengan sebagian yang lain.\""},"4173":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ جَامِعِ بْنِ شَدَّادٍ عَنْ كُلْثُومٍ الْخُزَاعِيِّ قَالَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ كَيْفَ لِي أَنْ أَعْلَمَ إِذَا أَحْسَنْتُ أَنِّي قَدْ أَحْسَنْتُ وَإِذَا أَسَأْتُ أَنِّي قَدْ أَسَأْتُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَالَ جِيرَانُكَ قَدْ أَحْسَنْتَ فَقَدْ أَحْسَنْتَ وَإِذَا قَالُوا إِنَّكَ قَدْ أَسَأْتَ فَقَدْ أَسَأْتَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Mu'awiyah] dari [All A'masy] dari [Jami' bin Syaddad] dari [Kultsum Al Khuza'i] dia berkata; \"Nabi shallallahu 'alaihi wasallam pernah di datangi seorang laki-laki seraya berkata; \"Wahai Rasulullah, bagaimanakah saya bisa mengetahui diriku jika telah berbuat baik atau berbuat jahat?\" maka beliau menjawab: \"Jika tetanggamu mengatakan bahwa kamu telah berbuat baik, berarti kamu telah berbuat baik. Namun jika tetanggamu mengatakan bahwa kamu berbuat jahat, berarti kamu telah berbuat jahat.\""},"4174":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا مَعْمَرٌ عَنْ مَنْصُورٍ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَجُلٌ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَيْفَ لِي أَنْ أَعْلَمَ إِذَا أَحْسَنْتُ وَإِذَا أَسَأْتُ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سَمِعْتَ جِيرَانَكَ يَقُولُونَ أَنْ قَدْ أَحْسَنْتَ فَقَدْ أَحْسَنْتَ وَإِذَا سَمِعْتَهُمْ يَقُولُونَ قَدْ أَسَأْتَ فَقَدْ أَسَأْتَ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] telah menceritakan kepada kami [Abdurrazaq] telah memberitakan kepada kami [Ma'mar] dari [Manshur] dari [Abu Wa`il] dari [Abdullah] dia berkata; seorang laki-laki bertanya kepada Rasulullah shallallahu 'alaihi wasallam; \"Bagaimanakah seharusnya aku dapat mengetahui bahwa aku telah berbuat baik dan telah berbuat jahat?\" Beliau menjawab: \"Apabila kamu mendengar bahwa tetanggamu mengatakan bahwa kamu telah berbuat baik, maka kamu adalah orang baik. Namun jika kamu mendengar tetanggamu mengatakan bahwa kamu telah berbuat jahat, maka kamu adalah orang jahat.\""},"4175":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى وَزَيْدُ بْنُ أَخْزَمَ قَالَا حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبُو هِلَالٍ حَدَّثَنَا عُقْبَةُ بْنُ أَبِي ثُبَيْتٍ عَنْ أَبِي الْجَوْزَاءِ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَهْلُ الْجَنَّةِ مَنْ مَلَأَ اللَّهَ أُذُنَيْهِ مِنْ ثَنَاءِ النَّاسِ خَيْرًا وَهُوَ يَسْمَعُ وَأَهْلُ النَّارِ مَنْ مَلَأَ أُذُنَيْهِ مِنْ ثَنَاءِ النَّاسِ شَرًّا وَهُوَ يَسْمَعُ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] dan [Ziad bin Ahzam] keduanya berkata; telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Abu Hilal] telah menceritakan kepada kami ['Uqbah bin Abu Tsubait] dari [Abu Al Jauzza`] dari [Ibnu Abbas] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Penghuni surga adalah orang yang di penuhi kedua telinganya oleh Allah dengan pujian yang baik dari manusia, dan ia pun mendengarnya. Sedangkan penghuni neraka adalah orang yang kedua telionganya di penuhi oleh Allah dengan cacian yang buruk dari manusia dan dia pun mendengarnya.\""},"4176":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي عِمْرَانَ الْجَوْنِيِّ عَنْ عَبْدِ اللَّهِ بْنِ الصَّامِتِ عَنْ أَبِي ذَرٍّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قُلْتُ لَهُ الرَّجُلُ يَعْمَلُ الْعَمَلَ لِلَّهِ فَيُحِبُّهُ النَّاسُ عَلَيْهِ قَالَ ذَلِكَ عَاجِلُ بُشْرَى الْمُؤْمِنِ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Abu 'Imran Al Jauni] dari [Abdullah bin As Shamit] dari [Abu Dzar] dari Nabi shallallahu 'alaihi wasallam, Abu Dzar berkata; saya bertanya kepada beliau; \"Seorang laki-laki beramal karena Allah, maka manusia menjadi cinta dengan amalan laki-laki tersebut.\" Beliau bersabda: \"Itu adalah kabar gembira yang di segerakan untuk orang Mukmin.\""},"4177":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا سَعِيدُ بْنُ سِنَانٍ أَبُو سِنَانٍ الشَّيْبَانِيُّ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ إِنِّي أَعْمَلُ الْعَمَلَ فَيُطَّلَعُ عَلَيْهِ فَيُعْجِبُنِي قَالَ لَكَ أَجْرَانِ أَجْرُ السِّرِّ وَأَجْرُ الْعَلَانِيَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Abu Daud] telah menceritakan kepada kami [Sa'id bin Sinan Abu Sinan As Syaibani] dari [Habib bin Abu Tsabit] dari [Abu Shalih] dari [Abu Hurairah] dia berkata; seorang laki-laki bertanya; \"Wahai Rasulullah, sesungguhnya saya telah melakukan suatu amalan, lantas amalan tersebut di perlihatkan kepadaku hingga saya kagum dengan amalan tersebut.\" Beliau bersabda: \"Bagimu dua pahala, pahala ketika sembunyi-sembunyi dan ketika di tampakkan.\""},"4178":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ ح و حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ قَالَا أَنْبَأَنَا يَحْيَى بْنُ سَعِيدٍ أَنَّ مُحَمَّدَ بْنَ إِبْرَاهِيمَ التَّيْمِيَّ أَخْبَرَهُ أَنَّهُ سَمِعَ عَلْقَمَةَ بْنَ وَقَّاصٍ أَنَّهُ سَمِعَ عُمَرَ بْنَ الْخَطَّابِ وَهُوَ يَخْطُبُ النَّاسَ فَقَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّمَا الْأَعْمَالُ بِالنِّيَّاتِ وَلِكُلِّ امْرِئٍ مَا نَوَى فَمَنْ كَانَتْ هِجْرَتُهُ إِلَى اللَّهِ وَإِلَى رَسُولِهِ فَهِجْرَتُهُ إِلَى اللَّهِ وَإِلَى رَسُولِهِ وَمَنْ كَانَتْ هِجْرَتُهُ لِدُنْيَا يُصِيبُهَا أَوْ امْرَأَةٍ يَتَزَوَّجُهَا فَهِجْرَتُهُ إِلَى مَا هَاجَرَ إِلَيْهِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Yazid bin Harun]. Dan diriwayatkan dari jalur lain, telah menceritakan kepada kami [Muhammad bin Rumh] telah memberitakan kepada kami [Al Laits bin Sa'd] keduanya berkata; telah memberitakan kepada kami [Yahya bin Sa'id] bahwa [Muhammad bin Ibrahim At Taimi] telah mengabarkan bahwa dia pernah mendengar ['Alqamah bin Waqash] bahwa dia mendengar [Umar bin Khatthab] sedang berkhotbah di hadapan manusia, katanya;; \"saya pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya setiap amalan sesuai dengan niat, dan balasan bagi seseorang itu sesuai dengan apa yang di niatkannya. Maka barangsiapa hijrahnya untuk Allah dan Rasul-Nya maka pahala hijrahnya karena Allah dan Rasul-Nya, dan barangsiapa hijrahnya untuk dunia atau wanita yang akan di nikahinya, maka balasan hijrahnya sesuai dengan tujuan hijrahnya tersebut.\""},"4179":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الْأَعْمَشُ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ أَبِي كَبْشَةَ الْأَنْمَارِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَثَلُ هَذِهِ الْأُمَّةِ كَمَثَلِ أَرْبَعَةِ نَفَرٍ رَجُلٌ آتَاهُ اللَّهُ مَالًا وَعِلْمًا فَهُوَ يَعْمَلُ بِعِلْمِهِ فِي مَالِهِ يُنْفِقُهُ فِي حَقِّهِ وَرَجُلٌ آتَاهُ اللَّهُ عِلْمًا وَلَمْ يُؤْتِهِ مَالًا فَهُوَ يَقُولُ لَوْ كَانَ لِي مِثْلُ هَذَا عَمِلْتُ فِيهِ مِثْلَ الَّذِي يَعْمَلُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَهُمَا فِي الْأَجْرِ سَوَاءٌ وَرَجُلٌ آتَاهُ اللَّهُ مَالًا وَلَمْ يُؤْتِهِ عِلْمًا فَهُوَ يَخْبِطُ فِي مَالِهِ يُنْفِقُهُ فِي غَيْرِ حَقِّهِ وَرَجُلٌ لَمْ يُؤْتِهِ اللَّهُ عِلْمًا وَلَا مَالًا فَهُوَ يَقُولُ لَوْ كَانَ لِي مِثْلُ هَذَا عَمِلْتُ فِيهِ مِثْلَ الَّذِي يَعْمَلُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَهُمَا فِي الْوِزْرِ سَوَاءٌحَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ الْمَرْوَزِيُّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا مَعْمَرٌ عَنْ مَنْصُورٍ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ ابْنِ أَبِي كَبْشَةَ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ح و حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ سَمُرَةَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ مُفَضَّلٍ عَنْ مَنْصُورٍ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ ابْنِ أَبِي كَبْشَةَ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Al A'masy] dari [Salim bin Abu Ja'd] dari [Abu Kabsyah Al Anmari] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Permisalan ummat ini bagaikan empat orang laki-laki, yaitu; seorang laki-laki yang di berikan oleh Allah berupa harta dan ilmu, kemudian dia membelanjakan hartanya sesuai dengan ilmunya. Seseorang yang diberi oleh Allah berupa ilmu dan tidak di berikan harta, lalu dia berkata; \"Seandainya saya memiliki seperti yang di miliki orang ini, niscaya saya akan berbuat seperti yang ia perbuat.\" Maka dalam urusan pahala, mereka berdua sama. Dan seorang laki-laki yang diberi oleh Allah berupa harta dan tidak diberi ilmu, maka ia menyia-nyiakan hartanya dan tidak membelanjakannya bukan kepada jalan yang benar. Serta seorang laki-laki yang tidak di beri oleh Allah berupa harta dan juga ilmu, lalu dia berkata; \"Seandainya aku memiliki seperti yang di miliki orang ini, niscaya aku akan berbuat seperti yang ia perbuat.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Maka dalam urusan dosa, mereka berdua sama.\" Telah menceritakan kepada kami [Ishaq bin Manshur Al Mawarzi] telah menceritakan kepada kami [Abdurrazaq] telah memberitakan kepada kami [Ma'mar] dari [Manshur] dari [Salim bin Abu Al Ja'd] dari [Ibnu Abu Kabsyah] dari [ayahnya] dari Nabi shallallahu 'alaihi wasallam. Dan dan diriwayatkan dari jalur lain, telah menceritakan kepada kami [Muhammad bin Isma'il bin Samurah] telah menceritakan kepada kami [Abu Usamah] dari [Mufadlal] dari [Manshur] dari [Salim bin Abu Al Ja'd] dari [Ibnu Abu Kabsyah] dari [ayahnya] dari Nabi shallallahu 'alaihi wasallam seperti hadits di atas."},"4180":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ سِنَانٍ وَمُحَمَّدُ بْنُ يَحْيَى قَالَا حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ عَنْ شَرِيكٍ عَنْ لَيْثٍ عَنْ طَاوُسٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا يُبْعَثُ النَّاسُ عَلَى نِيَّاتِهِمْ","id":"Telah menceritakan kepada kami [Ahmad bin Sinan] dan [Muhammad bin Yahya] keduanya berkata; telah menceritakan kepada kami [Yazid bin Harun] dari [Syarik] dari [Laits] dari [Thawus] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hanyasanya manusia akan dikumpulkan sesuai dengan niat mereka masing-masing.\""},"4181":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ مُحَمَّدٍ أَنْبَأَنَا زَكَرِيَّا بْنُ عَدِيٍّ أَنْبَأَنَا شَرِيكٌ عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُحْشَرُ النَّاسُ عَلَى نِيَّاتِهِمْ","id":"Telah menceritakan kepada kami [Zuhair bin Muhammad] telah memberitakan kepada kami [Zakariya bin 'Adi] telah memberitakan kepada kami [Syarik] dari [Al A'masy] dari [Abu Sufyan] dari [Jabir] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Manusia akan di kumpulkan sesuai dengan niat mereka masing-masing.\""},"4182":{"ar":"حَدَّثَنَا أَبُو بِشْرٍ بَكْرُ بْنُ خَلَفٍ وَأَبُو بَكْرِ بْنُ خَلَّادٍ الْبَاهِلِيُّ قَالَا حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا سُفْيَانُ حَدَّثَنِي أَبِي عَنْ أَبِي يَعْلَى عَنْ الرَّبِيعِ بْنِ خُثَيْمٍ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ خَطَّ خَطًّا مُرَبَّعًا وَخَطًّا وَسَطَ الْخَطِّ الْمُرَبَّعِ وَخُطُوطًا إِلَى جَانِبِ الْخَطِّ الَّذِي وَسَطَ الْخَطِّ الْمُرَبَّعِ وَخَطًّا خَارِجًا مِنْ الْخَطِّ الْمُرَبَّعِ فَقَالَ أَتَدْرُونَ مَا هَذَا قَالُوا اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ هَذَا الْإِنْسَانُ الْخَطُّ الْأَوْسَطُ وَهَذِهِ الْخُطُوطُ إِلَى جَنْبِهِ الْأَعْرَاضُ تَنْهَشُهُ أَوْ تَنْهَسُهُ مِنْ كُلِّ مَكَانٍ فَإِنْ أَخْطَأَهُ هَذَا أَصَابَهُ هَذَا وَالْخَطُّ الْمُرَبَّعُ الْأَجَلُ الْمُحِيطُ وَالْخَطُّ الْخَارِجُ الْأَمَلُ","id":"Telah menceritakan kepada kami [Abu Bisyir Bakar bin Khalaf] dan [Abu Bakar bin Khallad Al Bahili] keduanya berkata; telah menceritakan kepada kami [Yahya bin Sa'id] telah menceritakan kepada kami [Sufyan] telah menceritakan kepadaku [ayahku] dari [Abu Ya'la] dari [Ar Rabi' bin Hutsaim] dari [Abdullah bin Mas'ud] dari Nabi shallallahu 'alaihi wasallam bahwa beliau membuat garis persegi empat dan menggaris tengah di persegi empat tersebut, dan membuat beberapa garis pada sisi garis tengah dari tengah garis tersebut serta satu garis di luar garis segi empat tersebut. Lalu beliau bersabda: \"Tahukah kalian apakah ini?\" para sahabat menjawab; \"Allah dan Rasul-Nya yang lebih mengetahui.\" Beliau bersabda: \"Ini adalah manusia berada di garis tengah, sementara garis-garis ini (yang berada di sisinya) adalah rintangan-rintangan yang menghimpit -atau yang menggigitnya- dari segala tempat. Jika ia berbuat salah, maka ia akan terkena garis ini. Adapun garis segi empat yang mengitarinya adalah ajal yang mengelilinya. Dan garis yang berada di luar adalah cita-citanya.\""},"4183":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ حَدَّثَنَا النَّضْرُ بْنُ شُمَيْلٍ أَنْبَأَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي بَكْرٍ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذَا ابْنُ آدَمَ وَهَذَا أَجَلُهُ عِنْدَ قَفَاهُ وَبَسَطَ يَدَهُ أَمَامَهُ ثُمَّ قَالَ وَثَمَّ أَمَلُهُ","id":"Telah menceritakan kepada kami [Ishaq bin Manshur] telah menceritakan kepada kami [An Nadlr bin Syumail] telah memberitakan kepada kami [Hammad bin Salamah] dari ['Ubaidillah bin Abu Bakar] dia berkata; saya mendengar [Anas bin Malik] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ini adalah anak Adam dan ini adalah ajalnya terletak di tengkuknya.\" Sambil merentangkan tangan beliau di hadapannya sambil bersabda: \"Dan kemudian (ini) adalah cita-citanya.\""},"4184":{"ar":"حَدَّثَنَا أَبُو مَرْوَانَ مُحَمَّدُ بْنُ عُثْمَانَ الْعُثْمَانِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قَلْبُ الشَّيْخِ شَابٌّ فِي حُبِّ اثْنَتَيْنِ فِي حُبِّ الْحَيَاةِ وَكَثْرَةِ الْمَالِ","id":"Telah menceritakan kepada kami [Abu Marwan Muhammad bin Utsman Al 'Utsmani] telah menceritakan kepada kami [Abdul Aziz bin Abu Hazim] dari [Al 'Ala` bin Abdurrahman] dari [ayahnya] dari [Abu Hurairah] dia berkata; sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hati orang tua masih akan tetap muda dalam mencintai dua perkara, yaitu; cinta dunia dan banyaknya harta kekayaan.\""},"4185":{"ar":"حَدَّثَنَا بِشْرُ بْنُ مُعَاذٍ الضَّرِيرُ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَهْرَمُ ابْنُ آدَمَ وَيَشِبُّ مِنْهُ اثْنَتَانِ الْحِرْصُ عَلَى الْمَالِ وَالْحِرْصُ عَلَى الْعُمُرِ","id":"Telah menceritakan kepada kami [Bisyr bin Mu'adz Ad Dlarir] telah menceritakan kepada kami [Abu 'Awanah] dari [Qatadah] dari [Anas] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Anak Adam akan menua, namun ia masih tetap berjiwa muda dalam dua hal, yaitu; rakus terhadap harta kekayaan dan umur yang panjang.\""},"4186":{"ar":"حَدَّثَنَا أَبُو مَرْوَانَ الْعُثْمَانِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَوْ أَنَّ لِابْنِ آدَمَ وَادِيَيْنِ مِنْ مَالٍ لَأَحَبَّ أَنْ يَكُونَ مَعَهُمَا ثَالِثٌ وَلَا يَمْلَأُ نَفْسَهُ إِلَّا التُّرَابُ وَيَتُوبُ اللَّهُ عَلَى مَنْ تَابَ","id":"Telah menceritakan kepada kami [Abu Marwan Al 'Utsmani] telah menceritakan kepada kami [Abdul Aziz bin Abu Hazim] dari [Al 'Ala` bin Abdurrahman] dari [ayahnya] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sekiranya anak adam memiliki dua lembah yang berisikan harta kekayaan, niscaya ia akan sangat berharap memiliki lembah ketiganya. Dan tidaklah ia memenuhi dirinya melainkan hanya dengan debu, dan Allah hanya mengampuni orang-orang yang bertaubat.\""},"4187":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَرَفَةَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ مُحَمَّدٍ الْمُحَارِبِيُّ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَعْمَارُ أُمَّتِي مَا بَيْنَ السِّتِّينَ إِلَى السَّبْعِينَ وَأَقَلُّهُمْ مَنْ يَجُوزُ ذَلِكَ","id":"Telah menceritakan kepada kami [Al Hasan bin 'Arafah] telah menceritakan kepadaku [Abdurrahman bin Muhammad Al Muharibi] dari [Muhammad bin 'Amru] dari [Abu Salamah] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Usia ummatku berkisar antara enam puluh sampai tujuh puluh tahun, dan sedikit sekali mereka yang melebihi (usia) tersebut.\""},"4188":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي سَلَمَةَ عَنْ أُمِّ سَلَمَةَ قَالَتْوَالَّذِي ذَهَبَ بِنَفْسِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مَاتَ حَتَّى كَانَ أَكْثَرُ صَلَاتِهِ وَهُوَ جَالِسٌ وَكَانَ أَحَبَّ الْأَعْمَالِ إِلَيْهِ الْعَمَلُ الصَّالِحُ الَّذِي يَدُومُ عَلَيْهِ الْعَبْدُ وَإِنْ كَانَ يَسِيرًا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Al Ahwash] dari [Abu Ishaq] dari [Abu Salamah] dari [Ummu Salamah] dia berkata; \"Demi dzat yang telah mengambil jiwa beliau shallallahu 'alaihi wasallam, tidaklah beliau meninggal dunia hingga kebanyakan shalat yang di kerjakannya dengan posisi duduk, dan amalan yang paling di cintai oleh beliau adalah amal Shalih yang di kerjakan seorang hamba secara terus menerus walaupun sedikit.\""},"4189":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْكَانَتْ عِنْدِي امْرَأَةٌ فَدَخَلَ عَلَيَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَنْ هَذِهِ قُلْتُ فُلَانَةُ لَا تَنَامُ تَذْكُرُ مِنْ صَلَاتِهَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَهْ عَلَيْكُمْ بِمَا تُطِيقُونَ فَوَاللَّهِ لَا يَمَلُّ اللَّهُ حَتَّى تَمَلُّوا قَالَتْ وَكَانَ أَحَبَّ الدِّينَ إِلَيْهِ الَّذِي يَدُومُ عَلَيْهِ صَاحِبُهُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Usamah] dari [Hisyam bin 'Urwah] dari [ayahnya] dari ['Aisyah] dia berkata; seorang wanita tengah bersamaku, lalu Nabi shallallahu 'alaihi wasallam menemuiku seraya bertanya: \"Siapakah wanita ini?\" Jawabku; \"Fulanah. Yang tidak pernah tidur. -'Aisyah menyebutkan tentang kebiasaan shalatnya- Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Tinggalkanlah (perbuatan itu), kerjakanlah amalan semampu kalian, demi Allah, Allah tidak akan merasa bosan hingga kalian sendirilah yang merasa bosan.\" 'Aisyah berkata; \"Sesungguhnya (pelaksanaan) agama yang paling beliau cintai adalah yang selalu di kerjakan terus menerus oleh pelakunya.\""},"4190":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا الْفَضْلُ بْنُ دُكَيْنٍ عَنْ سُفْيَانَ عَنْ الْجُرَيْرِيِّ عَنْ أَبِي عُثْمَانَ عَنْ حَنْظَلَةَ الْكَاتِبِ التَّمِيمِيِّ الْأُسَيِّدِيِّ قَالَكُنَّا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْنَا الْجَنَّةَ وَالنَّارَ حَتَّى كَأَنَّا رَأْيَ الْعَيْنِ فَقُمْتُ إِلَى أَهْلِي وَوَلَدِي فَضَحِكْتُ وَلَعِبْتُ قَالَ فَذَكَرْتُ الَّذِي كُنَّا فِيهِ فَخَرَجْتُ فَلَقِيتُ أَبَا بَكْرٍ فَقُلْتُ نَافَقْتُ نَافَقْتُ فَقَالَ أَبُو بَكْرٍ إِنَّا لَنَفْعَلُهُ فَذَهَبَ حَنْظَلَةُ فَذَكَرَهُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا حَنْظَلَةُ لَوْ كُنْتُمْ كَمَا تَكُونُونَ عِنْدِي لَصَافَحَتْكُمْ الْمَلَائِكَةُ عَلَى فُرُشِكُمْ أَوْ عَلَى طُرُقِكُمْ يَا حَنْظَلَةُ سَاعَةً وَسَاعَةً","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Al Fadl bin Dukain] dari [Sufyan] dari [Al Jurairi] dari [Abu 'Utsman] dari [Handlalah Al Katib At Tamimi Al Usaiyidi] dia berkata; \"Kami pernah berada di sisi Rasulullah shallallahu 'alaihi wasallam, beliau pun menceritakan kepada kami tentang surga dan neraka sehingga seakan-akan kamui melihatnya dengan mata kepala saya sendiri. Namun setelah kami menemui istri dan anak-anakku, maka akupun kembali tertawa dan bercanda.\" Handlalah berkata; Lalu kuingat suasana ketika kami bersama Nabi shallallahu 'alaihi wasallam, lantas aku segera keluar dan bertemu dengan Abu Bakar, saya berkata; \"Aku telah berbuat kemunafikan, aku telah berbuat kemunafikan.\" Abu Bakar berkata; \"Sungguh kita memang pernah melakukannya.\" Kemudian Handlalah pergi dan menceritakan hal itu kepada Nabi shallallahu 'alaihi wasallam, maka beliau bersabda: \"Wahai Handlalah, seandainya kamu dapat terus berada pada kondisimu seperti saat kamu berada di sisiku, niscara para Malaikat akan selalu menyalamimu di setiap jalanmu -atau di setiap jalan-jalanmu- wahai Handlalah, sedikit demi sedikitlah (dalam beramal).\""},"4191":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ عُثْمَانَ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا ابْنُ لَهِيعَةَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ الْأَعْرَجُ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اكْلَفُوا مِنْ الْعَمَلِ مَا تُطِيقُونَ فَإِنَّ خَيْرَ الْعَمَلِ أَدْوَمُهُ وَإِنْ قَلَّ","id":"Telah menceritakan kepada kami [Al 'Abbas bin 'Ustman Ad Dimasyqi] telah menceritakan kepada kami [Al Walid bin Muslim] telah menceritakan kepada kami [Ibnu Lahi'ah] telah menceritakan kepada kami [Abdurrahman Al A'raj] saya mendengar [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Laksanakanlah oleh kalian amalan semampu kalian, sesungguhnya sebaik-baik amalan adalah yang di kerjakan secara terus menerus walaupun sedikit.\""},"4192":{"ar":"حَدَّثَنَا عَمْرُو بْنُ رَافِعٍ حَدَّثَنَا يَعْقُوبُ بْنُ عَبْدِ اللَّهِ الْأَشْعَرِيُّ عَنْ عِيسَى بْنِ جَارِيَةَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَمَرَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى رَجُلٍ يُصَلِّي عَلَى صَخْرَةٍ فَأَتَى نَاحِيَةَ مَكَّةَ فَمَكَثَ مَلِيًّا ثُمَّ انْصَرَفَ فَوَجَدَ الرَّجُلَ يُصَلِّي عَلَى حَالِهِ فَقَامَ فَجَمَعَ يَدَيْهِ ثُمَّ قَالَ يَا أَيُّهَا النَّاسُ عَلَيْكُمْ بِالْقَصْدِ ثَلَاثًا فَإِنَّ اللَّهَ لَا يَمَلُّ حَتَّى تَمَلُّوا","id":"Telah menceritakan kepada kami [Amru bin Rafi'] telah menceritakan kepada kami [Ya'qub bin Abdullah Al Asy'ari] dari [Isa bin Jariyah] dari [Jabir bin Abdullah] dia berkata; Rasulullah shallallahu 'alaihi wasallam melewati seseorang yang sedang shalat di atas batu, lalu beliau pergi ke arah Makkah dan berdiam diri cukup lama di sana, lalu beliau kembali dan mendapatkan laki-laki tersebut masih shalat seperti sebelumnya, maka beliau bangkit dan menggabungkan kedua tangannya seraya bersabda: \"Wahai sekalian manusia, bersikaplah pertengahan -beliau mengatakannya hingga tiga kali- sesungguhnya Allah tidak akan merasa bosan, sampai kalian sendiri yang merasa bosan.\""},"4193":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا وَكِيعٌ وَأَبِي عَنْ الْأَعْمَشِ عَنْ شَقِيقٍ عَنْ عَبْدِ اللَّهِ قَالَقُلْنَا يَا رَسُولَ اللَّهِ أَنُؤَاخَذُ بِمَا كُنَّا نَعْمَلُ فِي الْجَاهِلِيَّةِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَحْسَنَ فِي الْإِسْلَامِ لَمْ يُؤَاخَذْ بِمَا كَانَ فِي الْجَاهِلِيَّةِ وَمَنْ أَسَاءَ أُخِذَ بِالْأَوَّلِ وَالْآخِرِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [Waki'] dan [ayahku] dari [Al A'masy] dari [Syaqiq] dari [Abdullah] dia berkata; kami bertanya; \"Wahai Rasulullah, apakah kami juga akan di siksa atas apa yang pernah kami lakukan di masa Jahiliyah?\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa berbuat kebaikan setelah masuk Islam, maka ia tidak akan disiksa atas apa yang pernah di perbuatnya di masa Jahiliyah, namun jika di berbuat kejelekan (setelah masuk Islam), maka ia akan disiksa baik sebelumnya dan juga sesudahnya.\""},"4194":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنِي سَعِيدُ بْنُ مُسْلِمِ بْنِ بَانَكَ سَمِعْتُ عَامِرَ بْنَ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ يَقُولُ حَدَّثَنِي عَوْفُ بْنُ الْحَارِثِ عَنْ عَائِشَةَ قَالَتْقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا عَائِشَةُ إِيَّاكِ وَمُحَقَّرَاتِ الْأَعْمَالِ فَإِنَّ لَهَا مِنْ اللَّهِ طَالِبًا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Khalid bin Makhlad] telah menceritakan kepadaku [Sa'id bin Muslim bin Banak] saya mendengar ['Amir bin Abdullah bin Az Zubair] berkata; telah menceritakan kepadaku ['Auf bin Al Harits] dari ['Aisyah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: Wahai 'Aisyah, jauhilah olehmu perbuatan-pebuatan tercela, karena sesungguhnya perbuatan-perbuatan itu akan di tuntut oleh Allah.\""},"4195":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ وَالْوَلِيدُ بْنُ مُسْلِمٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ عَجْلَانَ عَنْ الْقَعْقَاعِ بْنِ حَكِيمٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْمُؤْمِنَ إِذَا أَذْنَبَ كَانَتْ نُكْتَةٌ سَوْدَاءُ فِي قَلْبِهِ فَإِنْ تَابَ وَنَزَعَ وَاسْتَغْفَرَ صُقِلَ قَلْبُهُ فَإِنْ زَادَ زَادَتْ فَذَلِكَ الرَّانُ الَّذِي ذَكَرَهُ اللَّهُ فِي كِتَابِهِ{ كَلَّا بَلْ رَانَ عَلَى قُلُوبِهِمْ مَا كَانُوا يَكْسِبُونَ }","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Hatim bin Isma'il] dan [Walid bin Muslim] keduanya berkata; telah menceritakan kepada kami [Muhammad bin 'Ajlan] dari [Al Qa'qa' bin Hakim] dari [Abu Shalih] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya apabila seorang mukmin berbuat dosa, maka akan ada titik hitam di dalam hatinya, jika ia bertaubat, meninggalkannya serta meminta ampun naka hatinya akan kembali putih, namun jika ia menambah (dosanya) maka akan bertambah (titik hitam), maka itulah penutup (hati) yang di sebutkan dalam firman Allah dalam kitab-Nya; \"Sekali-kali tidak (demikian), Sebenarnya apa yang selalu mereka usahakan itu menutupi hati mereka.\" (QS Al Muthafifin; 14)."},"4196":{"ar":"حَدَّثَنَا عِيسَى بْنُ يُونُسَ الرَّمْلِيُّ حَدَّثَنَا عُقْبَةُ بْنُ عَلْقَمَةَ بْنِ خَدِيجٍ الْمَعَافِرِيُّ عَنْ أَرْطَاةَ بْنِ الْمُنْذِرِ عَنْ أَبِي عَامِرٍ الْأَلْهَانِيِّ عَنْ ثَوْبَانَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ لَأَعْلَمَنَّ أَقْوَامًا مِنْ أُمَّتِي يَأْتُونَ يَوْمَ الْقِيَامَةِ بِحَسَنَاتٍ أَمْثَالِ جِبَالِ تِهَامَةَ بِيضًا فَيَجْعَلُهَا اللَّهُ عَزَّ وَجَلَّ هَبَاءً مَنْثُورًا قَالَ ثَوْبَانُ يَا رَسُولَ اللَّهِ صِفْهُمْ لَنَا جَلِّهِمْ لَنَا أَنْ لَا نَكُونَ مِنْهُمْ وَنَحْنُ لَا نَعْلَمُ قَالَ أَمَا إِنَّهُمْ إِخْوَانُكُمْ وَمِنْ جِلْدَتِكُمْ وَيَأْخُذُونَ مِنْ اللَّيْلِ كَمَا تَأْخُذُونَ وَلَكِنَّهُمْ أَقْوَامٌ إِذَا خَلَوْا بِمَحَارِمِ اللَّهِ انْتَهَكُوهَا","id":"Telah menceritakan kepada kami [Isa bin Yunus Ar Ramli] telah menceritakan kepada kami ['Uqbah bin 'Alqamah bin Khadij Al Mu'afiri] dari [Arthah bin Al Mundzir] dari [Abu 'Amir Al Hani] dari [Tsauban] dari Nabi shallallahu 'alaihi wasallam bahwa beliau bersabda: \"Sungguh saya telah mengetahui bahwa ada suatu kaum dari ummatku yang datang pada hari Kiamat dengan membawa kebaikan sebesar gunung Tihamah yang putih, lantas Allah menjadikannya sia-sia.\" Tsauban berkata; \"Wahai Rasulullah, sebutkanlah ciri-ciri mereka kepada kami, dan jelaskanlah tentang mereka kepada kami, supaya kami tidak menjadi seperti mereka sementara kami tidak mengetahuinya.\" Beliau bersabda: \"Sesungguhnya mereka adalah saudara-saudara kalian dan dari golongan kalian, mereka shalat malam sebagaimana kalian mengerjakannya, tetapi mereka adalah kaum yang jika kembali kepada apa yang di haramkan Allah, maka mereka terus mengerjakannya.\""},"4197":{"ar":"حَدَّثَنَا هَارُونُ بْنُ إِسْحَقَ وَعَبْدُ اللَّهِ بْنُ سَعِيدٍ قَالَا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ أَبِيهِ وَعَمِّهِ عَنْ جَدِّهِ عَنْ أَبِي هُرَيْرَةَ قَالَسُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أَكْثَرُ مَا يُدْخِلُ الْجَنَّةَ قَالَ التَّقْوَى وَحُسْنُ الْخُلُقِ وَسُئِلَ مَا أَكْثَرُ مَا يُدْخِلُ النَّارَ قَالَ الْأَجْوَفَانِ الْفَمُ وَالْفَرْجُ","id":"Telah menceritakan kepada kami [Harun bin Ishaq] dan [Abdullah bin Sa'id] keduanya berkata; telah menceritakan kepada kami [Abdullah bin Idris] dari [ayahnya] dan [pamannya] dari [kakeknya] dari [Abu Hurairah] dia berkata; Nabi shallallahu 'alaihi wasallam pernah di tanya; \"perkara apa yang banyak menyebabkan masuk surga?\" beliau menjawab: \"Takwa kepada Allah dan akhlak yang mulia.\" Dan beliau di tanya; \"Perkara apa yang banyak menyebabkan masuk neraka?\" beliau menjawab: \"Dua rongga yang terbuka yaitu mulut dan kemaluan.\""},"4198":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا شَبَابَةُ حَدَّثَنَا وَرْقَاءُ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ عَزَّ وَجَلَّ أَفْرَحُ بِتَوْبَةِ أَحَدِكُمْ مِنْهُ بِضَالَّتِهِ إِذَا وَجَدَهَا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Syababah] telah menceritakan kepada kami [Warqa`] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Sesungguhnya Allah 'azza wajalla lebih bergembira dengan taubat salah seorang dari kalian, daripada seseorang dari kalian menemukan barang bawaannya yang telah lama hilang.\""},"4199":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ الْمَدِينِيُّ حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا جَعْفَرُ بْنُ بُرْقَانَ عَنْ يَزِيدَ بْنِ الْأَصَمِّ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَوْ أَخْطَأْتُمْ حَتَّى تَبْلُغَ خَطَايَاكُمْ السَّمَاءَ ثُمَّ تُبْتُمْ لَتَابَ عَلَيْكُمْ","id":"Telah menceritakan kepada kami [Ya'qub bin Humaid bin Kasib Al Madini] telah menceritakan kepada kami [Abu Mu'awiyah] telah menceritakan kepada kami [Ja'far bin Burqan] dari [Yazid bin Al Asham] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Sekiranya kalian melakukan kesalahan hingga kesalahan kalian mencapai langit dan bumi, kemudian kalian bertaubat, niscaya taubat kalian akan di terima.\""},"4200":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ وَكِيعٍ حَدَّثَنَا أَبِي عَنْ فُضَيْلِ بْنِ مَرْزُوقٍ عَنْ عَطِيَّةَ عَنْ أَبِي سَعِيدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَلَّهُ أَفْرَحُ بِتَوْبَةِ عَبْدِهِ مِنْ رَجُلٍ أَضَلَّ رَاحِلَتَهُ بِفَلَاةٍ مِنْ الْأَرْضِ فَالْتَمَسَهَا حَتَّى إِذَا أَعْيَى تَسَجَّى بِثَوْبِهِ فَبَيْنَا هُوَ كَذَلِكَ إِذْ سَمِعَ وَجْبَةَ الرَّاحِلَةِ حَيْثُ فَقَدَهَا فَكَشَفَ الثَّوْبَ عَنْ وَجْهِهِ فَإِذَا هُوَ بِرَاحِلَتِهِ","id":"Telah menceritakan kepada kami [Sufyan bin Waki'] telah menceritakan kepada kami [ayahku] dari [Fudlail bin Marzuq] dari ['Athiyah] dari [Abu Sa'id] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah lebih berbahagia dengan taubat hamba-Nya dari bahagianya seseorang yang kehilangan kendaraan (unta) yang membawa seluruh kebutuhan hidupnya dalam perjalanan di padang pasir yang sangat luas, ketika dia sudah berusaha mencari kemana-mana, dan berhenti dengan menutup pakaiannya, tiba-tiba dia mendengar suara, setelah menyingkap pakaiannya tiba-tiba ia mendapatkan kendaraannya berada di hadapannya.\""},"4201":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ سَعِيدٍ الدَّارِمِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الرَّقَاشِيُّ حَدَّثَنَا وُهَيْبُ بْنُ خَالِدٍ حَدَّثَنَا مَعْمَرٌ عَنْ عَبْدِ الْكَرِيمِ عَنْ أَبِي عُبَيْدَةَ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ التَّائِبُ مِنْ الذَّنْبِ كَمَنْ لَا ذَنْبَ لَهُ","id":"Telah menceritakan kepada kami [Ahmad bin Sa'id Ad Darimi] telah menceritakan kepada kami [Muhammad bin Abdullah Ar Raqasy] telah menceritakan kepada kami [Wuhaib bin Khalid] telah menceritakan kepada kami [Ma'mar] dari [Abdul Karim] dari [Abu 'Ubaidah bin Abdullah] dari [ayahnya] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang bertaubat dari dosa, bagaikan seorang yang tidak berdosa.\""},"4202":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ حَدَّثَنَا عَلِيُّ بْنُ مَسْعَدَةَ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُّ بَنِي آدَمَ خَطَّاءٌ وَخَيْرُ الْخَطَّائِينَ التَّوَّابُونَ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Zaid bin Hubab] telah menceritakan kepada kami [Ali bin Mas'adah] dari [Qatadah] dari [Anas] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Semua bani Adam pernah melakukan kesalahan, dan sebaik-baik orang yang salah adalah yang segera bertaubat.\""},"4203":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ الْكَرِيمِ الْجَزَرِيِّ عَنْ زِيَادِ بْنِ أَبِي مَرْيَمَ عَنْ ابْنِ مَعْقِلٍ قَالَ دَخَلْتُ مَعَ أَبِي عَلَى عَبْدِ اللَّهِ فَسَمِعْتُهُ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النَّدَمُ تَوْبَةٌ فَقَالَ لَهُ أَبِي أَنْتَ سَمِعْتَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ النَّدَمُ تَوْبَةٌ قَالَ نَعَمْ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Sufyan] dari [Abdul Karim Al Jazari] dari [Ziyad bin Abu Maryam] dari [Ibnu Ma'qil] dia berkata; saya bersama ayahku menemui [Abdullah], maka saya mendengar dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Penyesalan adalah bentuk taubat.\" Maka ayahku bertanya kepadanya; \"Apakah kamu mendengarnya dari Rasulullah shallallahu 'alaihi wasallam bahwa penyesalan adalah taubat?\" dia menjawab; \"Ya.\""},"4204":{"ar":"حَدَّثَنَا رَاشِدُ بْنُ سَعِيدٍ الرَّمْلِيُّ أَنْبَأَنَا الْوَلِيدُ بْنُ مُسْلِمٍ عَنْ ابْنِ ثَوْبَانَ عَنْ أَبِيهِ عَنْ مَكْحُولٍ عَنْ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ عَزَّ وَجَلَّ لَيَقْبَلُ تَوْبَةَ الْعَبْدِ مَا لَمْ يُغَرْغِرْ","id":"Telah menceritakan kepada kami [Rasyid bin Sa'id Ar Ramli] telah memberitakan kepada kami [Al Walid bin Muslim] dari [Ibnu Tsauban] dari [ayahnya] dari [Makhul] dari [Jubair bin Nufair] dari [Abdullah bin Umar] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Sesungguhnya Allah 'azza wajalla akan menerima taubat seorang hamba, selagi ia belum sakaratul maut.\""},"4205":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى وَإِسْحَقُ بْنُ مَنْصُورٍ قَالَا حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا مَعْمَرٌ قَالَ قَالَ الزُّهْرِيُّ أَلَا أُحَدِّثُكَ بِحَدِيثَيْنِ عَجِيبَيْنِ أَخْبَرَنِي حُمَيْدُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَسْرَفَ رَجُلٌ عَلَى نَفْسِهِ فَلَمَّا حَضَرَهُ الْمَوْتُ أَوْصَى بَنِيهِ فَقَالَ إِذَا أَنَا مِتُّ فَأَحْرِقُونِي ثُمَّ اسْحَقُونِي ثُمَّ ذَرُّونِي فِي الرِّيحِ فِي الْبَحْرِ فَوَاللَّهِ لَئِنْ قَدَرَ عَلَيَّ رَبِّي لَيُعَذِّبُنِي عَذَابًا مَا عَذَّبَهُ أَحَدًا قَالَ فَفَعَلُوا بِهِ ذَلِكَ فَقَالَ لِلْأَرْضِ أَدِّي مَا أَخَذْتِ فَإِذَا هُوَ قَائِمٌ فَقَالَ لَهُ مَا حَمَلَكَ عَلَى مَا صَنَعْتَ قَالَ خَشْيَتُكَ أَوْ مَخَافَتُكَ يَا رَبِّ فَغَفَرَ لَهُ لِذَلِكَ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] dan [Ishaq bin Manshur] keduanya berkata; telah menceritakan kepada kami [Abdurrazaq] telah memberitakan kepada kami [Ma'mar] dia berkata; [Az Zuhri] berkata; \"Maukah aku ceritakan kepadamu dua hadits yang menakjubkan? Telah mengabarkan kepadaku [Humaid bin Abdurrahman] dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam beliau bersabda: \"Seorang laki-laki telah berbuat aniaya terhadap dirinya sendiri, ketika kematian telah tiba, ia berwasiat kepada anaknya seraya berkata; \"Apabila aku mati, maka bakarlah jasadku, kemudian jadikanlah aku debu, dan tebarkanlah debu itu biar di terpa angin laut. Demi Allah, seandainya Rabbku telah menentukan adzabku, tidaklah akan ada yang dapat mengadzabku.\" Beliau kembali bersabda: \"Kemudian mereka melaksanakannya, lantas di katakanlah kepada bumi; \"Kembalikanlah apa yang telah kamu ambil.\" Maka tiba-tiba orang tersebut telah berdiri, lalu di tanyakan kepadanya; \"Apa yang mendorongmu melakukan perbuatan itu?\" lelaki itu menjawab; \"Karena takut kepada-Mu wahai Rabbku.\" Maka ia pun di ampuni.\""},"4206":{"ar":"قَالَ الزُّهْرِيُّ وَحَدَّثَنِي حُمَيْدُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ دَخَلَتْ امْرَأَةٌ النَّارَ فِي هِرَّةٍ رَبَطَتْهَا فَلَا هِيَ أَطْعَمَتْهَا وَلَا هِيَ أَرْسَلَتْهَا تَأْكُلُ مِنْ خَشَاشِ الْأَرْضِ حَتَّى مَاتَتْقَالَ الزُّهْرِيُّ لِئَلَّا يَتَّكِلَ رَجُلٌ وَلَا يَيْئَسَ رَجُلٌ","id":"(Masih dari jalur periwayatan yang sama dengan hadits sebelumnya) [Az Zuhri] berkata; dan telah menceritakan kepadaku [Humaid bin Abdurrahman] dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam beliau bersabda: \"Seorang wanita masuk neraka karena seekor kucing yang di karungnya, ia tidak memberinya makan dan tidak juga melepasnya hingga ia dapat mencari makan dari hewan bumi sampai mati.\" Az Zuhri berkata; \"Supaya seseorang itu tidak hanya bertawakkal dan tidak berputus asa.\""},"4207":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ عَنْ مُوسَى بْنِ الْمُسَيَّبِ الثَّقَفِيِّ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ غَنْمٍ عَنْ أَبِي ذَرٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ تَبَارَكَ وَتَعَالَى يَقُولُ يَا عِبَادِي كُلُّكُمْ مُذْنِبٌ إِلَّا مَنْ عَافَيْتُ فَسَلُونِي الْمَغْفِرَةَ فَأَغْفِرَ لَكُمْ وَمَنْ عَلِمَ مِنْكُمْ أَنِّي ذُو قُدْرَةٍ عَلَى الْمَغْفِرَةِ فَاسْتَغْفَرَنِي بِقُدْرَتِي غَفَرْتُ لَهُ وَكُلُّكُمْ ضَالٌّ إِلَّا مَنْ هَدَيْتُ فَسَلُونِي الْهُدَى أَهْدِكُمْ وَكُلُّكُمْ فَقِيرٌ إِلَّا مَنْ أَغْنَيْتُ فَسَلُونِي أَرْزُقْكُمْ وَلَوْ أَنَّ حَيَّكُمْ وَمَيِّتَكُمْ وَأَوَّلَكُمْ وَآخِرَكُمْ وَرَطْبَكُمْ وَيَابِسَكُمْ اجْتَمَعُوا فَكَانُوا عَلَى قَلْبِ أَتْقَى عَبْدٍ مِنْ عِبَادِي لَمْ يَزِدْ فِي مُلْكِي جَنَاحُ بَعُوضَةٍ وَلَوْ اجْتَمَعُوا فَكَانُوا عَلَى قَلْبِ أَشْقَى عَبْدٍ مِنْ عِبَادِي لَمْ يَنْقُصْ مِنْ مُلْكِي جَنَاحُ بَعُوضَةٍ وَلَوْ أَنَّ حَيَّكُمْ وَمَيِّتَكُمْ وَأَوَّلَكُمْ وَآخِرَكُمْ وَرَطْبَكُمْ وَيَابِسَكُمْ اجْتَمَعُوا فَسَأَلَ كُلُّ سَائِلٍ مِنْهُمْ مَا بَلَغَتْ أُمْنِيَّتُهُ مَا نَقَصَ مِنْ مُلْكِي إِلَّا كَمَا لَوْ أَنَّ أَحَدَكُمْ مَرَّ بِشَفَةِ الْبَحْرِ فَغَمَسَ فِيهَا إِبْرَةً ثُمَّ نَزَعَهَا ذَلِكَ بِأَنِّي جَوَادٌ مَاجِدٌ عَطَائِي كَلَامٌ إِذَا أَرَدْتُ شَيْئًا فَإِنَّمَا أَقُولُ لَهُ كُنْ فَيَكُونُ","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id] telah menceritakan kepada kami ['Abdah bin Sulaiman] dari [Musa bin Al Musayyab At Tsaqafi] dari [Shar bin Hausyab] dari [Abdurrahman bin Ghanmin] dari [Abu Dzar] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah Tabaraka wa Ta'ala berfriman: \"Wahai hamba-Ku, sesungguhnya kalian bersalah kecuali orang yang Aku maafkan maka mintalah kepadaKu ampunan niscaya Aku akan mengampuni kalian semua dan barang siapa yang mengetahui bahwasanya Aku mempunyai kemampuan untuk mengampuni lalu dia memohon ampunan dengan kekuasaanKu itu maka Aku akan mengampuninya, kalian semuanya sesat kecuali orang yang Aku berikan hidayah maka mintalah hidayah kepadaku niscaya Aku akan memberikan hidayah kalian, setiap kalian adalah fakir kecuali orang yang Aku cukupkan maka mintalah kepadaKu niscaya Aku akan melimpahkan rizki kalian, seandainya orang yang hidup dan yang mati diantara kalian, juga orang yang pertama dan terakhir diantara kalian baik yang di laut atau yang di darat mereka semua berkumpul di atas seorang yang paling bertakwa diantara hambaKu maka hal itu tidak akan menambah dalam kekuasaanKu meskipun sebesar sayap nyamuk demikian pula kalau mereka berkumpul atas seorang yang paling jahat diantara hambaKu maka hal itu tidak akan mengurangi sedikitpun dari kekuasaanKu seandainya orang yang hidup dan yang mati diantara kalian, juga orang yang pertama dan terakhir diantara kalian baik yang di laut atau yang di darat semua berkumpul lalu setiap orang meminta apa yang dia inginkan maka hal itu tidak akan mengurangi dari kekuasaanKu kecuali bagaikan orang yang mencelupkan jarum ke lautan kemudian mengangkat jarum itu kembali (tidak berpengaruh) hal itu karena Aku adalah Maha dermawan dan Maha mulia terhadap pemberianKu dan apabila Aku menginginkan sesuatu maka Aku akan mengatakan: \"Jadilah\" maka hal itu akan terjadi."},"4208":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا الْفَضْلُ بْنُ مُوسَى عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَكْثِرُوا ذِكْرَ هَاذِمِ اللَّذَّاتِ يَعْنِي الْمَوْتَ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Al Fadl bin Musa] dari [Muhammad bin 'Amru] dari [Abu Salamah] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perbanyaklah mengingat sesuatu yang dapat menghancurkan kenikmatan, yaitu kematian.\""},"4209":{"ar":"حَدَّثَنَا الزُّبَيْرُ بْنُ بَكَّارٍ حَدَّثَنَا أَنَسُ بْنُ عِيَاضٍ حَدَّثَنَا نَافِعُ بْنُ عَبْدِ اللَّهِ عَنْ فَرْوَةَ بْنِ قَيْسٍ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ عَنْ ابْنِ عُمَرَ أَنَّهُ قَالَكُنْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَهُ رَجُلٌ مِنْ الْأَنْصَارِ فَسَلَّمَ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ يَا رَسُولَ اللَّهِ أَيُّ الْمُؤْمِنِينَ أَفْضَلُ قَالَ أَحْسَنُهُمْ خُلُقًا قَالَ فَأَيُّ الْمُؤْمِنِينَ أَكْيَسُ قَالَ أَكْثَرُهُمْ لِلْمَوْتِ ذِكْرًا وَأَحْسَنُهُمْ لِمَا بَعْدَهُ اسْتِعْدَادًا أُولَئِكَ الْأَكْيَاسُ","id":"Telah mengabarkan kepada kami [Az Zubair bin Bakkar] telah mengabarkan kepada kami [Anas bin 'Iyadl] telah mengabarkan kepada kami [Nafi' bin Abdullah] dari [Farwah bin Qais] dari ['Atha` bin Abu Rabah] dari [Ibnu Umar] bahwa dia berkata; Saya bersama dengan Rasulullah shallallahu 'alaihi wasallam, tiba-tiba datang seorang laki-laki Anshar kepada beliau, lalu dia mengucapkan salam kepada Nabi shallallahu 'alaihi wasallam dan bertanya; \"Ya Rasulullah, bagaimanakah orang mukmin yang utama?\" beliau menjawab: \"Orang yang paling baik akhlaknya.\" Dia bertanya lagi; \"Orang mukmin yang bagaimanakah yang paling bijak?\" beliau menjawab: \"Orang yang paling banyak mengingat kematian, dan yang paling baik persiapannya setelah kematian, merekalah orang-orang yang bijak.\""},"4210":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَبْدِ الْمَلِكِ الْحِمْصِيُّ حَدَّثَنَا بَقِيَّةُ بْنُ الْوَلِيدِ حَدَّثَنِي ابْنُ أَبِي مَرْيَمَ عَنْ ضَمْرَةَ بْنِ حَبِيبٍ عَنْ أَبِي يَعْلَى شَدَّادِ بْنِ أَوْسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْكَيِّسُ مَنْ دَانَ نَفْسَهُ وَعَمِلَ لِمَا بَعْدَ الْمَوْتِ وَالْعَاجِزُ مَنْ أَتْبَعَ نَفْسَهُ هَوَاهَا ثُمَّ تَمَنَّى عَلَى اللَّهِ","id":"Telah mengabarkan kepada kami [Hisyam bin Abdul Malik Al Himshi] telah mengabarkan kepada kami [Baqiyah bin Al Walid] telah mengabarkan kepadaku [Ibnu Abu Maryam] dari [Dlamrah bin Habib] dari [Abu Ya'la Syaddad bin Aus] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang berakal (bijak) adalah orang yang bisa menahan nafsunya dan beramal untuk setelah kematian, dan orang yang lemah adalah orang yang mengikuti hawa nafsunya dan selalu berangan-angan (kosong) atas Allah.\""},"4211":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْحَكَمِ بْنِ أَبِي زِيَادٍ حَدَّثَنَا سَيَّارٌ حَدَّثَنَا جَعْفَرٌ عَنْ ثَابِتٍ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَى شَابٍّ وَهُوَ فِي الْمَوْتِ فَقَالَ كَيْفَ تَجِدُكَ قَالَ أَرْجُو اللَّهَ يَا رَسُولَ اللَّهِ وَأَخَافُ ذُنُوبِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَجْتَمِعَانِ فِي قَلْبِ عَبْدٍ فِي مِثْلِ هَذَا الْمَوْطِنِ إِلَّا أَعْطَاهُ اللَّهُ مَا يَرْجُو وَآمَنَهُ مِمَّا يَخَافُ","id":"Telah menceritakan kepada kami [Abdullah bin Al Hakam bin Abu Ziyad] telah menceritakan kepada kami [Sayyar] telah menceritakan kepada kami [Ja'far] dari [Tsabit] dari [Anas] bahwa Nabi shallallahu 'alaihi wasallam menemui seorang pemuda yang sedang sekaratul maut, beliau bertanya: \"Bagaimana keadaanmu?\" dia menjawab; \"Aku sangat mengharapkan Allah, wahai Rasulullah, dan aku sangat takut akan dosa-dosaku.\" maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah berkumpul di dalam hati seorang hamba saat keadaan seperti ini, melainkan Allah akan memberikan kepadanya apa yang di harapkannya, dan akan di berikan rasa aman akan apa yang ia takuti.\""},"4212":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا شَبَابَةُ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ عَطَاءٍ عَنْ سَعِيدِ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمَيِّتُ تَحْضُرُهُ الْمَلَائِكَةُ فَإِذَا كَانَ الرَّجُلُ صَالِحًا قَالُوا اخْرُجِي أَيَّتُهَا النَّفْسُ الطَّيِّبَةُ كَانَتْ فِي الْجَسَدِ الطَّيِّبِ اخْرُجِي حَمِيدَةً وَأَبْشِرِي بِرَوْحٍ وَرَيْحَانٍ وَرَبٍّ غَيْرِ غَضْبَانَ فَلَا يَزَالُ يُقَالُ لَهَا ذَلِكَ حَتَّى تَخْرُجَ ثُمَّ يُعْرَجُ بِهَا إِلَى السَّمَاءِ فَيُفْتَحُ لَهَا فَيُقَالُ مَنْ هَذَا فَيَقُولُونَ فُلَانٌ فَيُقَالُ مَرْحَبًا بِالنَّفْسِ الطَّيِّبَةِ كَانَتْ فِي الْجَسَدِ الطَّيِّبِ ادْخُلِي حَمِيدَةً وَأَبْشِرِي بِرَوْحٍ وَرَيْحَانٍ وَرَبٍّ غَيْرِ غَضْبَانَ فَلَا يَزَالُ يُقَالُ لَهَا ذَلِكَ حَتَّى يُنْتَهَى بِهَا إِلَى السَّمَاءِ الَّتِي فِيهَا اللَّهُ عَزَّ وَجَلَّ وَإِذَا كَانَ الرَّجُلُ السُّوءُ قَالَ اخْرُجِي أَيَّتُهَا النَّفْسُ الْخَبِيثَةُ كَانَتْ فِي الْجَسَدِ الْخَبِيثِ اخْرُجِي ذَمِيمَةً وَأَبْشِرِي بِحَمِيمٍ وَغَسَّاقٍ وَآخَرَ مِنْ شَكْلِهِ أَزْوَاجٌ فَلَا يَزَالُ يُقَالُ لَهَا ذَلِكَ حَتَّى تَخْرُجَ ثُمَّ يُعْرَجُ بِهَا إِلَى السَّمَاءِ فَلَا يُفْتَحُ لَهَا فَيُقَالُ مَنْ هَذَا فَيُقَالُ فُلَانٌ فَيُقَالُ لَا مَرْحَبًا بِالنَّفْسِ الْخَبِيثَةِ كَانَتْ فِي الْجَسَدِ الْخَبِيثِ ارْجِعِي ذَمِيمَةً فَإِنَّهَا لَا تُفْتَحُ لَكِ أَبْوَابُ السَّمَاءِ فَيُرْسَلُ بِهَا مِنْ السَّمَاءِ ثُمَّ تَصِيرُ إِلَى الْقَبْرِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Syababah] dari [Ibnu Abu Dzi`b] dari [Muhammad bin 'Amru bin 'Atha`] dari [Sa'id bin Yasar] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Mayit akan didatangi Malaikat, jika ia seorang yang shalih, maka para Malaikat akan berkata; \"Keluarlah wahai jiwa yang baik yang berada dalam tubuh yang baik. Keluarlah dengan terpuji dan bergembiralah dengan kenyamanan serta wewangian, dan dengan Rabb yang tidak akan murka.\" dan seruan itu terus di serukan kepadanya sampai jiwanya keluar. Kemudian dia akan diangkat ke langit dan ditanya; \"Siapakah orang ini? Mereka (para Malaikat) menjawab; \"Fulan.\" maka di katakan kepadanya; \"Selamat datang wahai jiwa yang baik, yang berada dalam tubuh yang baik Keluarlah dengan terpuji dan bergembiralah dengan kenyamanan serta wewangian, dan dengan Rabb yang tidak akan murka.\" dan seruan itu terus di serukan kepadanya sampai ia tiba di langit yang terdapat Allah 'azza wajalla di sana. Namun jika mayit tersebut dari orang yang jahat, maka akan di katakan (kepadanya); \"Keluarlan wahai jiwa yang jahat yang ada dalam tubuh yang jahat, keluarlah dengan tercela dan terimalah air yang panas dan bau yang busuk, serta siksaan lainnya yang berlipat ganda.\" seruan itu terus saja di serukan sampai jiwanya keluar. Kemudian dia akan di angkat ke langit, maka (pintu langit) tidak akan di bukakan untuknya. Di tanyakan kepadanya; \"Siapakah orang ini?\" di jawab; \"Fulan.\" lalu di katakan; \"Tidak ada ucapan selamat untuk jiwa yang jawat yang terdapat pada tubuh yang jahat, kembalilah dengan tercela, karena tidak akan di bukakan pintu-pintu langit untukmu.\" kemudian dia di turunkan dari langit, maka ia kembali ke dalam kubur.\""},"4213":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ ثَابِتٍ الْجَحْدَرِيُّ وَعُمَرُ بْنُ شَبَّةَ بْنِ عَبِيدَةَ قَالَا حَدَّثَنَا عُمَرُ بْنُ عَلِيٍّ أَخْبَرَنِي إِسْمَعِيلُ بْنُ أَبِي خَالِدٍ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا كَانَ أَجَلُ أَحَدِكُمْ بِأَرْضٍ أَوْثَبَتْهُ إِلَيْهَا الْحَاجَةُ فَإِذَا بَلَغَ أَقْصَى أَثَرِهِ قَبَضَهُ اللَّهُ سُبْحَانَهُ فَتَقُولُ الْأَرْضُ يَوْمَ الْقِيَامَةِ رَبِّ هَذَا مَا اسْتَوْدَعْتَنِي","id":"Telah menceritakan kepada kami [Ahmad bin Tsabit Al Jahdari] dan [Umar bin Syabbah bin 'Abidah] keduanya berkata; telah menceritakan kepada kami ['Umar bin Ali] telah mengabarkanku [Isma'il bin Abu Khalid] dari [Qais bin Abu Hazim] dari [Abdullah bin Mas'ud] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Apabila ajal salah seorang dari kalian telah di tentukan di suatu tempat di muka bumi, maka ia akan di berikan kebutuhannya untuk pergi ke tempat tersebut. Dan jika telah sampai pada batas akhir perjalanannya, maka Allah Subhanahu akan mencabut (nyawanya), dan bumi akan berkata pada hari Kiamat; \"Wahai Rabbku, inilah yang telah Engkau titipkan kepadaku.\""},"4214":{"ar":"حَدَّثَنَا يَحْيَى بْنُ خَلَفٍ أَبُو سَلَمَةَ حَدَّثَنَا عَبْدُ الْأَعْلَى عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ سَعْدِ بْنِ هِشَامٍ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَحَبَّ لِقَاءَ اللَّهِ أَحَبَّ اللَّهُ لِقَاءَهُ وَمَنْ كَرِهَ لِقَاءَ اللَّهِ كَرِهَ اللَّهُ لِقَاءَهُ فَقِيلَ يَا رَسُولَ اللَّهِ كَرَاهِيَةُ لِقَاءِ اللَّهِ فِي كَرَاهِيَةِ لِقَاءِ الْمَوْتِ فَكُلُّنَا يَكْرَهُ الْمَوْتَ قَالَ لَا إِنَّمَا ذَاكَ عِنْدَ مَوْتِهِ إِذَا بُشِّرَ بِرَحْمَةِ اللَّهِ وَمَغْفِرَتِهِ أَحَبَّ لِقَاءَ اللَّهِ فَأَحَبَّ اللَّهُ لِقَاءَهُ وَإِذَا بُشِّرَ بِعَذَابِ اللَّهِ كَرِهَ لِقَاءَ اللَّهِ وَكَرِهَ اللَّهُ لِقَاءَهُ","id":"Telah menceritakan kepada kami [Yahya bin Khalaf Abu Salamah] telah menceritakan kepada kami [Abdul A'la] dari [Sa'id] dari [Qatadah] dari [Zurarah bin Aufa] dari [Sa'id bin Hisyam] dari ['Aisyah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa cinta bertemu Allah, maka Allah pun cinta bertemu dengannya, dan barangsiapa benci bertemu dengan Allah, maka Allah pun benci bertemu dengannya.\" Maka di tanyakan; \"Wahai Rasulullah, kalau begitu kebencian terhadap perjumpaan dengan Allah, berarti benci terhadap kematian? Padahal kami benci terhadap kematian.\" Beliau bersabda: \"Bukan, akan tetapi hal itu saat kematiannya tiba. Jika ia dikabarkan akan mendapatkan rahmat Allah dan ampunan-Nya, lalu ia cinta berjumpa dengan Allah, maka Allah pun cinta berjumpa dengannya, dan jika di kabarkan ia akan mendapatkan adzab Allah, lalu ia benci berjumpa dengan Allah, maka Allah pun benci berjumpa dengannya.\""},"4215":{"ar":"حَدَّثَنَا عِمْرَانُ بْنُ مُوسَى حَدَّثَنَا عَبْدُ الْوَارِثِ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ صُهَيْبٍ عَنْ أَنَسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَتَمَنَّى أَحَدُكُمْ الْمَوْتَ لِضُرٍّ نَزَلَ بِهِ فَإِنْ كَانَ لَا بُدَّ مُتَمَنِّيًا الْمَوْتَ فَلْيَقُلْ اللَّهُمَّ أَحْيِنِي مَا كَانَتْ الْحَيَاةُ خَيْرًا لِي وَتَوَفَّنِي إِذَا كَانَتْ الْوَفَاةُ خَيْرًا لِي","id":"Telah menceritakan kepada kami ['Imran bin Musa] telah menceritakan kepada kami [Abdul Warits bin Sa'id] telah menceritakan kepada kami [Abdul Aziz bin Shuhaib] dari [Anas] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah salah seorang dari kalian berangan-angan ingin mati karena musibah yang menimpanya. Namun jika terpaksa berangan-angan kematian, hendaknya ia berdo'a: \"Ya Allah, hidupkkanlah aku selama kehidupan itu baik untukku, dan matikanlah aku selama kematian itu baik untukku.\""},"4216":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ شَيْءٌ مِنْ الْإِنْسَانِ إِلَّا يَبْلَى إِلَّا عَظْمًا وَاحِدًا وَهُوَ عَجْبُ الذَّنَبِ وَمِنْهُ يُرَكَّبُ الْخَلْقُ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada sesuatu pada diri manusia akan usang dan hanya menyisakan sebatang tulang, yaitu pangkal ekor. Dan darinya pula semua makluk akan disusun kembali kelak di hari Kiamat.\""},"4217":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ حَدَّثَنِي يَحْيَى بْنُ مَعِينٍ حَدَّثَنَا هِشَامُ بْنُ يُوسُفَ عَنْ عَبْدِ اللَّهِ بْنِ بَحِيرٍ عَنْ هَانِئٍ مَوْلَى عُثْمَانَ قَالَكَانَ عُثْمَانُ بْنُ عَفَّانَ إِذَا وَقَفَ عَلَى قَبْرٍ يَبْكِي حَتَّى يَبُلَّ لِحْيَتَهُ فَقِيلَ لَهُ تَذْكُرُ الْجَنَّةَ وَالنَّارَ وَلَا تَبْكِي وَتَبْكِي مِنْ هَذَا قَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْقَبْرَ أَوَّلُ مَنَازِلِ الْآخِرَةِ فَإِنْ نَجَا مِنْهُ فَمَا بَعْدَهُ أَيْسَرُ مِنْهُ وَإِنْ لَمْ يَنْجُ مِنْهُ فَمَا بَعْدَهُ أَشَدُّ مِنْهُ قَالَ وَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا رَأَيْتُ مَنْظَرًا قَطُّ إِلَّا وَالْقَبْرُ أَفْظَعُ مِنْهُ","id":"Telah menceritakan kepada kami [Muhammad bin Ishaq] telah menceritakan kepadaku [Yahya bin Ma'in] telah menceritakan kepada kami [Hisyam bin Yusuf] dari [Abdullah bin Bahir] dari [Hani` bekas budak 'Utsman] dia berkata; \"Jika [Utsman bin 'Affan] berhenti di suatu kuburan, dia menangis sehingga jenggotnya basah. Di tanyakan kepadanya; \"Apakah kamu ingat surga dan neraka?, janganlah kamu menangis, apakah kamu menangis hanya karena ini?\" dia menjawab; \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya kuburan adalah tempat singgah pertama akhirat. Jika selamat darinya, maka setelahnya pun ia akan lebih mudah (urusannya) namun jika ia tidak selamat darinya, maka sesudahnya pun ia akan lebih sulit lagi.\" Utsman berkata; Rasulullah shallallahu 'alaihi wasallam juga bersabda: \"Aku tidak pernah melihat suatu pemandangan melainkan kuburan itu lebih buruk dari dari segalanya.\""},"4218":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا شَبَابَةُ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ عَطَاءٍ عَنْ سَعِيدِ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْمَيِّتَ يَصِيرُ إِلَى الْقَبْرِ فَيُجْلَسُ الرَّجُلُ الصَّالِحُ فِي قَبْرِهِ غَيْرَ فَزِعٍ وَلَا مَشْعُوفٍ ثُمَّ يُقَالُ لَهُ فِيمَ كُنْتَ فَيَقُولُ كُنْتُ فِي الْإِسْلَامِ فَيُقَالُ لَهُ مَا هَذَا الرَّجُلُ فَيَقُولُ مُحَمَّدٌ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَاءَنَا بِالْبَيِّنَاتِ مِنْ عِنْدِ اللَّهِ فَصَدَّقْنَاهُ فَيُقَالُ لَهُ هَلْ رَأَيْتَ اللَّهَ فَيَقُولُ مَا يَنْبَغِي لِأَحَدٍ أَنْ يَرَى اللَّهَ فَيُفْرَجُ لَهُ فُرْجَةٌ قِبَلَ النَّارِ فَيَنْظُرُ إِلَيْهَا يَحْطِمُ بَعْضُهَا بَعْضًا فَيُقَالُ لَهُ انْظُرْ إِلَى مَا وَقَاكَ اللَّهُ ثُمَّ يُفْرَجُ لَهُ قِبَلَ الْجَنَّةِ فَيَنْظُرُ إِلَى زَهْرَتِهَا وَمَا فِيهَا فَيُقَالُ لَهُ هَذَا مَقْعَدُكَ وَيُقَالُ لَهُ عَلَى الْيَقِينِ كُنْتَ وَعَلَيْهِ مُتَّ وَعَلَيْهِ تُبْعَثُ إِنْ شَاءَ اللَّهُ وَيُجْلَسُ الرَّجُلُ السُّوءُ فِي قَبْرِهِ فَزِعًا مَشْعُوفًا فَيُقَالُ لَهُ فِيمَ كُنْتَ فَيَقُولُ لَا أَدْرِي فَيُقَالُ لَهُ مَا هَذَا الرَّجُلُ فَيَقُولُ سَمِعْتُ النَّاسَ يَقُولُونَ قَوْلًا فَقُلْتُهُ فَيُفْرَجُ لَهُ قِبَلَ الْجَنَّةِ فَيَنْظُرُ إِلَى زَهْرَتِهَا وَمَا فِيهَا فَيُقَالُ لَهُ انْظُرْ إِلَى مَا صَرَفَ اللَّهُ عَنْكَ ثُمَّ يُفْرَجُ لَهُ فُرْجَةٌ قِبَلَ النَّارِ فَيَنْظُرُ إِلَيْهَا يَحْطِمُ بَعْضُهَا بَعْضًا فَيُقَالُ لَهُ هَذَا مَقْعَدُكَ عَلَى الشَّكِّ كُنْتَ وَعَلَيْهِ مُتَّ وَعَلَيْهِ تُبْعَثُ إِنْ شَاءَ اللَّهُ تَعَالَى","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Syababah] dari [Ibnu Abu Dzi`b] dari [Muhammad bin 'Amru bin Al 'Atha`] dari [Sa'id bin Yasar] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Sesungguhnya (ketika) mayit masuk ke dalam kuburnya, maka seorang yang shalih akan di di dudukkan dalam kuburnya tanpa rasa takut dan rasa kekhawatiran. Lalu akan di katakan kepadanya; \"Bagaimana keadaan akhir hayatmu?\" maka ia akan menjawab; \"Aku dalam keadaan Islam (berserah diri).\" kemudian ditanyakan lagi; \"siapakah lelaki ini?\" ia akan menjawab; \"Muhammad Rasulullah shallallahu 'alaihi wasallam, dia telah datang kepada kami dengan membawa keterangan-keterangan dari sisi Allah, lalu kami membenarkannya.\" di tanyakan lagi kepadanya; \"Apakah kamu melihat Allah?\" Ia menjawab; \"Tidak layak bagi seseorang untuk melihat Allah.\" maka di singkapkanlah baginya celah yang membatasi neraka, ia melihat gejolak apinya yang saling menghantam satu sama lainnya. Dan di katakan kepadanya; \"Lihatlah apa yang telah Allah perbuat untuk menyelamatkanmu.\" kemudian di singkapkan baginya celah yang menghalangi surga dan ia melihat hiasan dan seluruh keindahan yang terdapat di dalamnya. Maka di katakan kepadanya; \"Inilah tempatmu.\" dan di katakan kepadanya; \"atas keyakinan yang kamu jalankan, dan karenanya kamu di matikan serta dengannya pula kamu di bangkitkan Insya Allah.\" Dan seorang yang jahat akan didudukkan di dalam kuburnya dengan penuuh rasa takut dan kekhawatiran. Lalu di tanyakan kepadanya; \"Bagaimana keadaan akhir hayatmu?\" ia menjawab; \"Aku tidak tahu.\" di tanyakan kepadanya; \"Siapakah laki-laki ini?\" ia menjawab; \"Aku mendengar orang-orang membicarakan sesuatu dan aku pun mengikutinya.\" lalu di bukakan celah yang membatasi surga, dan ia melihat keindahan yang terdapat di dalamnya, maka di katakan kepadanya; \"Lihatlah kepada orang-orang yang Allah jauhkan dirimu darinya.\" kemudian di bukakan celah yang membatasi neraka dan ia melihat apinya saling menghantam satu sama lain, maka di katakan kepadanya; \"Inilah tempatmu, atas keraguan yang ada pada dirimu. Karenanya pula kamu mati dan dengannya pula kamu di bangkitkan Insya Allah Ta'ala.\""},"4219":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ الْبَرَاءِ بْنِ عَازِبٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ{ يُثَبِّتُ اللَّهُ الَّذِينَ آمَنُوا بِالْقَوْلِ الثَّابِتِ }قَالَ نَزَلَتْ فِي عَذَابِ الْقَبْرِ يُقَالُ لَهُ مَنْ رَبُّكَ فَيَقُولُ رَبِّيَ اللَّهُ وَنَبِيِّي مُحَمَّدٌ فَذَلِكَ قَوْلُهُ{ يُثَبِّتُ اللَّهُ الَّذِينَ آمَنُوا بِالْقَوْلِ الثَّابِتِ فِي الْحَيَاةِ الدُّنْيَا وَفِي الْآخِرَةِ }","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari ['Alqamah bin Martsad] dari [Sa'd bin 'Ubaidah] darii [Al Barra` bin 'Azib] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Allah meneguhkan (iman) orang-orang yang beriman dengan Ucapan yang teguh itu dalam kehidupan di dunia dan di akhirat; (QS Ibrahim; 27). Beliau bersabda: \"Ayat ini di turunkan mengenai adzab kubur, di katakan kepada mayit; \"Siapa Rabbmu? Maka ia akan menjawab; \"Rabb adalah Allah, dan Nabiku adalah Muhammad.\" dan itulah maksud dari firman-Nya; \" \"Allah meneguhkan (iman) orang-orang yang beriman dengan Ucapan yang teguh itu dalam kehidupan di dunia dan di akhirat; (QS Ibrahim; 27).\""},"4220":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا مَاتَ أَحَدُكُمْ عُرِضَ عَلَى مَقْعَدِهِ بِالْغَدَاةِ وَالْعَشِيِّ إِنْ كَانَ مِنْ أَهْلِ الْجَنَّةِ فَمِنْ أَهْلِ الْجَنَّةِ وَإِنْ كَانَ مِنْ أَهْلِ النَّارِ فَمِنْ أَهْلِ النَّارِ يُقَالُ هَذَا مَقْعَدُكَ حَتَّى تُبْعَثَ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdullah bin Numair] telah menceritakan kepada kami ['Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Jika salah seorang dari kalian meninggal dunia, maka akan di tampakkan tempat tinggalnya pada saat pagi hari dan sore hari. Jika ia termasuk penduduk surga, maka ia akan menjadi penduduk surga, dan jika ia dari penghuni neraka, maka ia akan menjadi penghuni neraka, di katakan; \"Ini adalah tempat tinggalmu, \" sampai dia di bangkitkan pada hari Kiamat.\""},"4221":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ أَنْبَأَنَا مَالِكُ بْنُ أَنَسٍ عَنْ ابْنِ شِهَابٍ عَنْ عَبْدِ اللَّهِ بْنِ كَعْبٍ الْأَنْصَارِيِّ أَنَّهُ أَخْبَرَهُ أَنَّ أَبَاهُ كَانَ يُحَدِّثُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّمَا نَسَمَةُ الْمُؤْمِنِ طَائِرٌ يَعْلُقُ فِي شَجَرِ الْجَنَّةِ حَتَّى يَرْجِعَ إِلَى جَسَدِهِ يَوْمَ يُبْعَثُ","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] telah memberitakan kepada kami [Mlaik bin Anas] dari [Ibnu Syihab] dari [Abdulla bin Ka'ab Al Anshari] bahwa dirinya telah mengabarkan kepadanya, bahwa [ayahnya] pernah bercerita bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya jiwa seorang mukmin bagaikan burung yang bergelayutan di pohon surga sampai ia kembali ke jasadnya pada hari Kiamat.\""},"4222":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ حَفْصٍ الْأُبُلِّيُّ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا دَخَلَ الْمَيِّتُ الْقَبْرَ مُثِّلَتْ الشَّمْسُ عِنْدَ غُرُوبِهَا فَيَجْلِسُ يَمْسَحُ عَيْنَيْهِ وَيَقُولُ دَعُونِي أُصَلِّي","id":"Telah menceritakan kepada kami [Isma'il bin Hafhs Al Uballi] telah menceritakan kepada kami [Abu Bakar bin 'Ayyasy] dari [Al A'masy] dari [Abu Sufyan] dari [Jabir] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Jika mayit masuk ke dalam kubur, maka di perlihatkannya matahari ketika akan tenggelam, kemudian ia akan mengusap kedua matanya seraya berkata; \"Biarkanlah aku shalat.\""},"4223":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبَّادُ بْنُ الْعَوَّامِ عَنْ حَجَّاجٍ عَنْ عَطِيَّةَ عَنْ أَبِي سَعِيدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ صَاحِبَيْ الصُّورِ بِأَيْدِيهِمَا أَوْ فِي أَيْدِيهِمَا قَرْنَانِ يُلَاحِظَانِ النَّظَرَ مَتَى يُؤْمَرَانِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami ['Abbad bin Al 'Awam] dari [Hajjaj] dari ['Athiyah] dari [Abu Sa'id] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya kedua sahabatku (Malaikat) pembawa sangkala selalu membawa sangkakala di kedua tangannya atau di kedua tangannya memegang sangkala, keduanya bersiap-siap kapan saja di perintahkan (meniupkannya).\""},"4224":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَجُلٌ مِنْ الْيَهُودِ بِسُوقِ الْمَدِينَةِ وَالَّذِي اصْطَفَى مُوسَى عَلَى الْبَشَرِ فَرَفَعَ رَجُلٌ مِنْ الْأَنْصَارِ يَدَهُ فَلَطَمَهُ قَالَ تَقُولُ هَذَا وَفِينَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذُكِرَ ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ قَالَ اللَّهُ عَزَّ وَجَلَّ{ وَنُفِخَ فِي الصُّورِ فَصَعِقَ مَنْ فِي السَّمَاوَاتِ وَمَنْ فِي الْأَرْضِ إِلَّا مَنْ شَاءَ اللَّهُ ثُمَّ نُفِخَ فِيهِ أُخْرَى فَإِذَا هُمْ قِيَامٌ يَنْظُرُونَ }فَأَكُونُ أَوَّلَ مَنْ رَفَعَ رَأْسَهُ فَإِذَا أَنَا بِمُوسَى آخِذٌ بِقَائِمَةٍ مِنْ قَوَائِمِ الْعَرْشِ فَلَا أَدْرِي أَرَفَعَ رَأْسَهُ قَبْلِي أَوْ كَانَ مِمَّنْ اسْتَثْنَى اللَّهُ عَزَّ وَجَلَّ وَمَنْ قَالَ أَنَا خَيْرٌ مِنْ يُونُسَ بْنِ مَتَّى فَقَدْ كَذَبَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Ali bin Mushir] dari [Muhammad bin 'Amru] dari [Abu Salamah] dari [Abu Hurairah] dia berkata; saat berada di pasar Madinah, seorang laki-laki Yahudi berkata; \"Demi dzat yang telah menyucikan Musa dari seluruh manusia.\" (mendengar itu) seorang laki-laki Anshar mengangkat tangannya dan menamparnya seraya berkata; \"Kamu berani mengatakan ini, sedangkan Rasulullah shallallahu 'alaihi wasallam berada di tengah-tengah kami!.\" kemudian hal itu di beritahukan kepada Rasulullah shallallahu 'alaihi wasallam, lalu beliau bersabda: \"Allah Azza wa Jalla berfirman: \"Dan ditiuplah sangkakala, Maka matilah siapa yang di langit dan di bumi kecuali siapa yang dikehendaki Allah. Kemudian ditiup sangkakala itu sekali lagi Maka tiba-tiba mereka berdiri menunggu (putusannya masing-masing). (QS Az Zumar; 68).\" (beliau bersabda): \"Aku adalah orang yang pertama-tama mengangkat kepala, tiba-tiba saya melihat Musa mengambil tiang dari tiang-tiang 'Arsy, aku tidak tahu apakah ia mengangkat kepalanya sebulumku ataukah ia yang di kecualikan oleh Allah 'azza wajalla, dan barang siapa yang mengatakan Aku lebih baik daripada Yunus bin Matta, maka ia telah berdusta.\""},"4225":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ وَمُحَمَّدُ بْنُ الصَّبَّاحِ قَالَا حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ حَدَّثَنِي أَبِي عَنْ عُبَيْدِ اللَّهِ بْنِ مِقْسَمٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ عَلَى الْمِنْبَرِ يَقُولُ يَأْخُذُ الْجَبَّارُ سَمَاوَاتِهِ وَأَرَضِيهِ بِيَدِهِ وَقَبَضَ يَدَهُ فَجَعَلَ يَقْبِضُهَا وَيَبْسُطُهَا ثُمَّ يَقُولُ أَنَا الْجَبَّارُ أَنَا الْمَلِكُ أَيْنَ الْجَبَّارُونَ أَيْنَ الْمُتَكَبِّرُونَ قَالَ وَيَتَمَايَلُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ يَمِينِهِ وَعَنْ شِمَالِهِ حَتَّى نَظَرْتُ إِلَى الْمِنْبَرِ يَتَحَرَّكُ مِنْ أَسْفَلِ شَيْءٍ مِنْهُ حَتَّى إِنِّي لَأَقُولُ أَسَاقِطٌ هُوَ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] dan [Muhammad bin As Shabah] keduanya berkata; telah menceritakan kepada kami [Abdul Aziz Abu Abu Hazim] telah menceritakan kepadaku [ayahku] dari [Abdullah bin Miqsam] dari [Abdullah bin Umar] dia berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda di atas mimbar: \"Alla Al Jabbar akan mengambil langit dan bumi-Nya dengan tangan-Nya, Dia menggenggam dan mengepalkannya kemudian melebarkannya, lalu Dia berfirman: \"Aku adalah Al Jabbar (Yang Maha Perkasa), dan Akulah raja. Di manakah orang-orang (yang pernah) mengaku perkasa? Di manaka orang-orang yang sombong?\" Abdullah bin Umar berkata; \"Rasulullah shallallahu 'alaihi wasallam menoleh ke kanan dan ke kiri, hingga ku lihat mimbar itu bawahnya bergoyang, sampai saya berkata apakah ia akan roboh bersama dengan Rasulullah shallallahu 'alaihi wasallam.\""},"4226":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ عَنْ حَاتِمِ بْنِ أَبِي صَغِيرَةَ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ الْقَاسِمِ قَالَ قَالَتْ عَائِشَةُقُلْتُ يَا رَسُولَ اللَّهِ كَيْفَ يُحْشَرُ النَّاسُ يَوْمَ الْقِيَامَةِ قَالَ حُفَاةً عُرَاةً قُلْتُ وَالنِّسَاءُ قَالَ وَالنِّسَاءُ قُلْتُ يَا رَسُولَ اللَّهِ فَمَا يُسْتَحْيَا قَالَ يَا عَائِشَةُ الْأَمْرُ أَهَمُّ مِنْ أَنْ يَنْظُرَ بَعْضُهُمْ إِلَى بَعْضٍ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Khalid Al Ahmar] dari [Hatim bin Abu Shaghirah] dari [Ibnu Abu Mulaikah] dari [Qasim] dia berkata; ['Asiyah] berkata; saya bertanya; \"Wahai Rasulullah, bagaimanakah keadaan manusia ketika mereka di padang mahsyar?\" Beliau menjawab: \"Mereka telanjang tanpa pakaian.\" saya bertanya; \"Begitu juga dengan para wanita?\" Beliau menjawab: \"Begitu juga dengan wanita.\" saya bertanya; \"Wahai Rasulullah, apakah mereka tidak merasa malu?\" Beliau menjawab: \"Wahai 'Aisyah, perkara pada hari itu lebih penting daripada saling pandang di antara sesama mereka.\""},"4227":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ قَالَ حَدَّثَنَا وَكِيعٌ عَنْ عَلِيِّ بْنِ عَلِيِّ بْنِ رِفَاعَةَ عَنْ الْحَسَنِ عَنْ أَبِي مُوسَى الْأَشْعَرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعْرَضُ النَّاسُ يَوْمَ الْقِيَامَةِ ثَلَاثَ عَرَضَاتٍ فَأَمَّا عَرْضَتَانِ فَجِدَالٌ وَمَعَاذِيرُ وَأَمَّا الثَّالِثَةُ فَعِنْدَ ذَلِكَ تَطِيرُ الصُّحُفُ فِي الْأَيْدِي فَآخِذٌ بِيَمِينِهِ وَآخِذٌ بِشِمَالِهِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dia berkata; telah menceritakan kepada kami [Waki'] dari [Ali bin Ali bin Rifa'ah] dari [Al Hasan] dari [Abu Musa Al Asy'ari] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pada hari Kiamat, manusia akan diperlihatkan tiga tontonan, dua tontonan mengenai perdebatan dan alasan-alasan yang dikemukakan adapun tontonan yang ketiga akan dibagikan buku catatan amalan (hamba) dimana ada yang mengambil dengan tangan kanannya ada pula yang mengambil dengan tangan kirinya."},"4228":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عِيسَى بْنُ يُونُسَ وَأَبُو خَالِدٍ الْأَحْمَرُ عَنْ ابْنِ عَوْنٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ يَوْمَ يَقُومُ النَّاسُ لِرَبِّ الْعَالَمِينَ }قَالَ يَقُومُ أَحَدُهُمْ فِي رَشْحِهِ إِلَى أَنْصَافِ أُذُنَيْهِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Isa bin Yunus] dan [Abu Khalid Al Ahmar] dari [Ibnu 'Aun] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam mengenai (firman Allah): (Yaitu) Ketika manusia berdiri menghadap Rabb semesta alam.\" (QS Al Muthafifin; 6). Beliau bersabda: \"Setiap orang dari mereka akan berdiri dengan keringat yang mencapai kedua telinganya.\""},"4229":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ دَاوُدَ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ يَوْمَ تُبَدَّلُ الْأَرْضُ غَيْرَ الْأَرْضِ وَالسَّمَاوَاتُ }فَأَيْنَ تَكُونُ النَّاسُ يَوْمَئِذٍ قَالَ عَلَى الصِّرَاطِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Ali bin Mushir] dari [Daud] dari [Asy Sya'bi] dari [Masruq] dari ['Aisyah] dia berkata; saya bertanya kepada Rasulullah shallallahu 'alaihi wasallam (mengenai firman Allah): \"(yaitu) pada hari (ketika) bumi diganti dengan bumi yang lain dan (demikian pula) langit, (QS Ibrahim; 49), lantas di manakah manusia ketika itu?\" Beliau menjawab: \"Di atas shirath.\""},"4230":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ قَالَ حَدَّثَنَا عَبْدُ الْأَعْلَى عَنْ مُحَمَّدِ بْنِ إِسْحَقَ حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ الْمُغِيرَةِ عَنْ سُلَيْمَانَ بْنِ عَمْرِو بْنِ عَبْدِ بْنِ الْعُتْوَارِيِّ أَحَدِ بَنِي لَيْثٍ قَالَ وَكَانَ فِي حَجْرِ أَبِي سَعِيدٍ قَالَ سَمِعْتُهُ يَعْنِي أَبَا سَعِيدٍ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يُوضَعُ الصِّرَاطُ بَيْنَ ظَهْرَانَيْ جَهَنَّمَ عَلَى حَسَكٍ كَحَسَكِ السَّعْدَانِ ثُمَّ يَسْتَجِيزُ النَّاسُ فَنَاجٍ مُسَلَّمٌ وَمَخْدُوجٌ بِهِ ثُمَّ نَاجٍ وَمُحْتَبَسٌ بِهِ وَمَنْكُوسٌ فِيهَا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dia berkata; telah menceritakan kepada kami [Abdul A'la] dari [Muhammad bin Ishaq], telah menceritakan kepadaku ['Ubaidillah bin Mughirah] dari [Sulaiman bin 'Amru bin Abd bin Al 'Utwari] salah seorang dari Bani Laits, dia berkata; -dan dia berada di kamarnya Abu Sa'id- saya mendengar [Abu Sa'id] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Shirath akan di letakkan di punggung Neraka Jahannam di atas pohon berduri seperti pohon sa'dan, kemudian para manusia melintasinya, maka ada di antara manusia ada yang selamat dan ada juga yang selamat sedang ia tertahan dan ada pula yang terbalik.\""},"4231":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ عَنْ أُمِّ مُبَشِّرٍ عَنْ حَفْصَةَ قَالَتْقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي لَأَرْجُو أَلَّا يَدْخُلَ النَّارَ أَحَدٌ إِنْ شَاءَ اللَّهُ تَعَالَى مِمَّنْ شَهِدَ بَدْرًا وَالْحُدَيْبِيَةَ قَالَتْ قُلْتُ يَا رَسُولَ اللَّهِ أَلَيْسَ قَدْ قَالَ اللَّهُ{ وَإِنْ مِنْكُمْ إِلَّا وَارِدُهَا كَانَ عَلَى رَبِّكَ حَتْمًا مَقْضِيًّا }قَالَ أَلَمْ تَسْمَعِيهِ يَقُولُ{ ثُمَّ نُنَجِّي الَّذِينَ اتَّقَوْا وَنَذَرُ الظَّالِمِينَ فِيهَا جِثِيًّا }","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Aal A'masy] dari [Sufyan] dari [Jabir] dari [Ummu Mubasyir] dari [Hafshah] dia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya saya berharap tidak ada seorang pun dari kalangan orang-orang yang ikut serta dalam perang Badar dan Hudaibiyyah yang masuk neraka, Insya Allah Ta'ala.\" Hafshah berkata; Saya bertanya; \"Wahai Rasulullah, tidakkah Allah telah berfirman: \"Dan tidak ada seorangpun dari padamu, melainkan mendatangi neraka itu. hal itu bagi Tuhanmu adalah suatu kemestian yang sudah ditetapkan? (QS Maryam; 71).\" beliau bersabda: \"Apakah kamu tidak mendengar bahwa Dia juga berfirman: \"Kemudian kami akan menyelamatkan orang-orang yang bertakwa dan membiarkan orang-orang yang zalim di dalam neraka dalam keadaan berlutut.\" (QS Maryam; 72)."},"4232":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ قَالَ حَدَّثَنَا يَحْيَى بْنُ زَكَرِيَّا بْنِ أَبِي زَائِدَةَ عَنْ أَبِي مَالِكٍ الْأَشْجَعِيِّ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَرِدُونَ عَلَيَّ غُرًّا مُحَجَّلِينَ مِنْ الْوُضُوءِ سِيمَاءُ أُمَّتِي لَيْسَ لِأَحَدٍ غَيْرِهَا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dia berkata; telah menceritakan kepada kami [Yahya bin Zakariya bin Abu Za`idah] dari [Abu Malik Al Asyja'i] dari [Abu Hazim] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Di perlihatkan kepadaku muka-muka dan kedua tangan tangan serta kaki yang putih bersinar karena wudlu', sebagai tanda dari ummatku, dan tidak ada yang seperti itu selain dari ummatku.\""},"4233":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ عَنْ عَمْرِو بْنِ مَيْمُونٍ عَنْ عَبْدِ اللَّهِ قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي قُبَّةٍ فَقَالَ أَتَرْضَوْنَ أَنْ تَكُونُوا رُبُعَ أَهْلِ الْجَنَّةِ قُلْنَا بَلَى قَالَ أَتَرْضَوْنَ أَنْ تَكُونُوا ثُلُثَ أَهْلِ الْجَنَّةِ قُلْنَا نَعَمْ قَالَ وَالَّذِي نَفْسِي بِيَدِهِ إِنِّي لَأَرْجُو أَنْ تَكُونُوا نِصْفَ أَهْلِ الْجَنَّةِ وَذَلِكَ أَنَّ الْجَنَّةَ لَا يَدْخُلُهَا إِلَّا نَفْسٌ مُسْلِمَةٌ وَمَا أَنْتُمْ فِي أَهْلِ الشِّرْكِ إِلَّا كَالشَّعَرَةِ الْبَيْضَاءِ فِي جِلْدِ الثَّوْرِ الْأَسْوَدِ أَوْ كَالشَّعَرَةِ السَّوْدَاءِ فِي جِلْدِ الثَّوْرِ الْأَحْمَرِ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dari ['Amru bin Maimun] dari [Abdullah] dia berkata; \"Kami pernah bersama-sama dengan Rasulullah shallallahu 'alaihi wasallam di Quba, maka beliau bersabda: \"Maukah kalian menjadi seperempat dari penghuni surga?\" Kami menjawab; \"Tentu.\" Beliau bersabda: \"Maukah kalian menjadi sepertiga dari penduduk surga?\" kami menjawab; \"Ya.\" Beliau bersabda: \"Demi dzat yang jiwaku berada di tangan-Nya sesungguhnya saya berharap kalian menjadi setengah dari penghuni surga, dan yang demikian itu surga tidak akan dimasuki melainkan oleh orang-orang yang muslim, adapun kalian di bandingkan dengan orang-orang Musyrik hanyalah bagaikan bulu putih berada di atas kulit lembu yang hitam, atau begaikan bulu hitam berada di atas kulit lembu yang merah.\""},"4234":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ وَأَحْمَدُ بْنُ سِنَانٍ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي سَعِيدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَجِيءُ النَّبِيُّ وَمَعَهُ الرَّجُلَانِ وَيَجِيءُ النَّبِيُّ وَمَعَهُ الثَّلَاثَةُ وَأَكْثَرُ مِنْ ذَلِكَ وَأَقَلُّ فَيُقَالُ لَهُ هَلْ بَلَّغْتَ قَوْمَكَ فَيَقُولُ نَعَمْ فَيُدْعَى قَوْمُهُ فَيُقَالُ هَلْ بَلَّغَكُمْ فَيَقُولُونَ لَا فَيُقَالُ مَنْ يَشْهَدُ لَكَ فَيَقُولُ مُحَمَّدٌ وَأُمَّتُهُ فَتُدْعَى أُمَّةُ مُحَمَّدٍ فَيُقَالُ هَلْ بَلَّغَ هَذَا فَيَقُولُونَ نَعَمْ فَيَقُولُ وَمَا عِلْمُكُمْ بِذَلِكَ فَيَقُولُونَ أَخْبَرَنَا نَبِيُّنَا بِذَلِكَ أَنَّ الرُّسُلَ قَدْ بَلَّغُوا فَصَدَّقْنَاهُ قَالَ فَذَلِكُمْ قَوْلُهُ تَعَالَى{ وَكَذَلِكَ جَعَلْنَاكُمْ أُمَّةً وَسَطًا لِتَكُونُوا شُهَدَاءَ عَلَى النَّاسِ وَيَكُونَ الرَّسُولُ عَلَيْكُمْ شَهِيدًا }","id":"Telah menceritakan kepada kami [Abu Kuraib] dan [Ahmad bin Sinan] keduanya berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Sa'id] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang Nabi akan datang bersama dengan dua orang laki-laki, dan Nabi yang lain akan datang pula bersama dengan tiga orang, dan ada juga yang lebih banyak dari itu atau lebih sedikit. Kemudian di katakan kepadanya; \"Apakah kamu telah menyampaikan (ajaran Allah) kepada kaummu?\" ia menjawab; \"Ya.\" maka kaumnya di panggil; \"Apakah ia telah menyampaikannya kepada kalian?\" mereka menjawab; \"Tidak.\" maka di tanyakan (kepada Nabi tersebut); \"Siapakah yang menjadi saksi atas pernyataan itu?\" Ia menjawab; \"Muhammad dan ummatnya.\" kemudian ummat Muhammad dipanggil dan ditanya; \"Apakah ia (nabi tersebut) telah menyampaikan?\" mereka (ummat Muhammad) menjawab; \"Ya.\" Penanya bertanya; \"Apa alasanmu tentang hal itu?\" mereka menjawab; \"Nabi kami telah memberitahukan kepada kami bahwa para Rasul telah menyampaikan (risalah Allah), dan kami pun mempercayainya.\" begitulah kondisi kalian yang disebutkan dalam firman Allah: \"Dan demikianlah Kami jadikan kalian ummat yang adil dan pilihan agar kamu menjadi saksi atas (aperbuatan) manusia dan agar rasul (Muhammad) menjadi saksi atas perbuatan kalian.\""},"4235":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ مُصْعَبٍ عَنْ الْأَوْزَاعِيِّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ هِلَالِ بْنِ أَبِي مَيْمُونَةَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ رِفَاعَةَ الْجُهَنِيِّ قَالَصَدَرْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ وَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ مَا مِنْ عَبْدٍ يُؤْمِنُ ثُمَّ يُسَدِّدُ إِلَّا سُلِكَ بِهِ فِي الْجَنَّةِ وَأَرْجُو أَلَّا يَدْخُلُوهَا حَتَّى تَبَوَّءُوا أَنْتُمْ وَمَنْ صَلَحَ مِنْ ذَرَارِيِّكُمْ مَسَاكِنَ فِي الْجَنَّةِ وَلَقَدْ وَعَدَنِي رَبِّي عَزَّ وَجَلَّ أَنْ يُدْخِلَ الْجَنَّةَ مِنْ أُمَّتِي سَبْعِينَ أَلْفًا بِغَيْرِ حِسَابِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Muhammad bin Mush'ab] dari [Al Auza'i] dari [Yahya bin Abu Katsir] dari [Hilal bin Abu Maimunah] dari ['Atha` bin Yasar] dari [rifa'ah Al Juhani] dia berkata; Kami berada di hadapan Rasulullah shallallahu 'alaihi wasallam, maka beliau bersabda: \"Demi dzat yang jiwa Muhammad berada di tangan-Nya, tidaklah seorang hamba beriman, lalu ia bersungguh-sungguh (menjalankan keimanannya), melainkan ia akan dimasukkan ke dalam surga. Dan aku berharap tidaklah mereka memasukinya sehingga kalian telah mendudukinya (terlebih dahulu), juga orang-orang shalih dari keturunan kelian akan di sediakan tempat di surga. Rabbku telah menjanjikan kepadaku bahwa ummatku akan masuk surga sebanyak tujuh puluh ribu orang tanpa hisab.\""},"4236":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ حَدَّثَنَا مُحَمَّدُ بْنُ زِيَادٍ الْأَلْهَانِيُّ قَالَ سَمِعْتُ أَبَا أُمَامَةَ الْبَاهِلِيَّ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ وَعَدَنِي رَبِّي سُبْحَانَهُ أَنْ يُدْخِلَ الْجَنَّةَ مِنْ أُمَّتِي سَبْعِينَ أَلْفًا لَا حِسَابَ عَلَيْهِمْ وَلَا عَذَابَ مَعَ كُلِّ أَلْفٍ سَبْعُونَ أَلْفًا وَثَلَاثُ حَثَيَاتٍ مِنْ حَثَيَاتِ رَبِّي عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Isma'il bin 'Ayyasy] telah menceritakan kepada kami [Muhammad bin Ziyad Al Hani] dia berkata; saya mendengar [Abu Umamah Al Bahili] berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Rabbku Subhanahu telah menjanjikan kepadaku akan memasukkan tujuh puluh ribu orang dari ummatku ke dalam surga tanpa hisab dan siksa. Dan setiap seribu orang (di sertai) dengan tujuh puluh ribu orang, dan dengan tiga raupan Tangan di antara raupan Tangan Rabbku Yang Maha Agung.\""},"4237":{"ar":"حَدَّثَنَا عِيسَى بْنُ مُحَمَّدِ بْنِ النَّحَّاسِ الرَّمْلِيُّ وَأَيُّوبُ بْنُ مُحَمَّدٍ الرَّقِّيُّ قَالَا حَدَّثَنَا ضَمْرَةُ بْنُ رَبِيعَةَ عَنْ ابْنِ شَوْذَبٍ عَنْ بَهْزِ بْنِ حَكِيمٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نُكْمِلُ يَوْمَ الْقِيَامَةِ سَبْعِينَ أُمَّةً نَحْنُ آخِرُهَا وَخَيْرُهَا","id":"Telah menceritakan kepada kami [Isa bin Muhammad bin An Nahas Ar ramli] dan [Ayyub bin Muhammad Ar Raqqi] keduanya berkata; telah menceritakan kepada kami [Dlamrah bin Rabi'ah] dari [Ibnu Syaudzab] dari [Bahz bin Hakim] dari [ayahnya] dari [kakeknya] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kita akan melengkapai (dengan) tujuh puluh ummat kelak di hari Kiamat, kita adalah ummat yang terakhir dari mereka dan yang terbaik dari mereka.\""},"4238":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ خَالِدِ بْنِ خِدَاشٍ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ بَهْزِ بْنِ حَكِيمٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّكُمْ وَفَّيْتُمْ سَبْعِينَ أُمَّةً أَنْتُمْ خَيْرُهَا وَأَكْرَمُهَا عَلَى اللَّهِ","id":"Telah menceritakan kepada kami [Muhammad bin Khalid bin Khidasy] telah menceritakan kepada kami [Isma'il bin 'Ulayyah] dari [Bahz bin Hakim] dari [ayahnya] dari [Kakeknya] dia berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya kalian telah menyempurnakan tujuh puluh ummat, dan kalian adalah yang terbaik dan yang paling mulian di antara mereka di sisi Allah.\""},"4239":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِسْحَقَ الْجَوْهَرِيُّ حَدَّثَنَا حُسَيْنُ بْنُ حَفْصٍ الْأَصْبَهَانِيُّ حَدَّثَنَا سُفْيَانُ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ سُلَيْمَانَ بْنِ بُرَيْدَةَ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَهْلُ الْجَنَّةِ عِشْرُونَ وَمِائَةُ صَفٍّ ثَمَانُونَ مِنْ هَذِهِ الْأُمَّةِ وَأَرْبَعُونَ مِنْ سَائِرِ الْأُمَمِ","id":"Telah menceritakan kepada kami [Abdullah bin Ishaq Al Jauhari] telah menceritakan kepada kami [Husain bin Haffh Al Ashbahani] telah menceritakan kepada kami [Sufyan] dari ['Alqamah bin Martsad] dari [Sulaiman bin Buraidah] dari [ayahnya] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Penduduk surga berjumlah seratus dua puluh baris, sembilan puluh baris terdiri dari ummat ini dan yang empat puluh dari berbagai ummat.\""},"4240":{"ar":"حَدَّثَنَا جُبَارَةُ بْنُ الْمُغَلِّسِ حَدَّثَنَا عَبْدُ الْأَعْلَى بْنُ أَبِي الْمُسَاوِرِ عَنْ أَبِي بُرْدَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا جَمَعَ اللَّهُ الْخَلَائِقَ يَوْمَ الْقِيَامَةِ أُذِنَ لِأُمَّةِ مُحَمَّدٍ فِي السُّجُودِ فَيَسْجُدُونَ لَهُ طَوِيلًا ثُمَّ يُقَالُ ارْفَعُوا رُءُوسَكُمْ قَدْ جَعَلْنَا عِدَّتَكُمْ فِدَاءَكُمْ مِنْ النَّارِ","id":"Telah menceritakan kepada kami [Jubbarah bin Al Mughallas] telah menceritakan kepada kami [Abdul A'la bin Abu Al Musawir] dari [Abu Burdah] dari [ayahnya] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika Allah mengumpulkan para makhluk-Nya di hari Kiamat, maka ummat Muhammad diizinkan untuk bersujud, maka mereka sujud hingga lama, kemudian di katakan kepada mereka: \"Angkatlah kepala kalian, sesungguhnya Kami telah menjadikan tebusan kalian dari api neraka.\""},"4241":{"ar":"حَدَّثَنَا جُبَارَةُ بْنُ الْمُغَلِّسِ حَدَّثَنَا كَثِيرُ بْنُ سُلَيْمٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ هَذِهِ الْأُمَّةَ مَرْحُومَةٌ عَذَابُهَا بِأَيْدِيهَا فَإِذَا كَانَ يَوْمُ الْقِيَامَةِ دُفِعَ إِلَى كُلِّ رَجُلٍ مِنْ الْمُسْلِمِينَ رَجُلٌ مِنْ الْمُشْرِكِينَ فَيُقَالُ هَذَا فِدَاؤُكَ مِنْ النَّارِ","id":"Telah menceritakan kepada kami [Jubbarah bin Al Mughallas] telah menceritakan kepada kami [Katsir bin Sulaim] dari [Anas bin Malik] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya ummat ini adalah ummat yang dikasihi, Adzab-Nya berada di antara kedua tangan-Nya, jika hari Kiamat tiba, maka seorang muslim akan mendorong seorang dari orang Musyrik seraya di katakan; \"Ini adalah tebusanmu dari api neraka.\""},"4242":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا عَبْدُ الْمَلِكِ عَنْ عَطَاءٍ عَن�� أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ لِلَّهِ مِائَةَ رَحْمَةٍ قَسَمَ مِنْهَا رَحْمَةً بَيْنَ جَمِيعِ الْخَلَائِقِ فَبِهَا يَتَرَاحَمُونَ وَبِهَا يَتَعَاطَفُونَ وَبِهَا تَعْطِفُ الْوَحْشُ عَلَى أَوْلَادِهَا وَأَخَّرَ تِسْعَةً وَتِسْعِينَ رَحْمَةً يَرْحَمُ بِهَا عِبَادَهُ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Yazid bin Harun] telah memberitakan kepada kami [Abdul Malik] dari ['Atha`] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Sesungguhnya Allah memiliki seratus rahmat dan satu rahmat di baagikan kepada semua makhluk-Nya, yang dengannya mereka saling berkasih sayang, dan dengannya pula mereka saling mengasihi, dengannya binatang buas mengasihi anak-anaknya. Dan Dia menyisakan sembilan puluh sembilan rahmat yang akan di berikan yang akan dikasihkan kepada hamba-Nya kelak di hari Kiamat.\""},"4243":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ وَأَحْمَدُ بْنُ سِنَانٍ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي سَعِيدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَلَقَ اللَّهُ عَزَّ وَجَلَّ يَوْمَ خَلَقَ السَّمَوَاتِ وَالْأَرْضَ مِائَةَ رَحْمَةٍ فَجَعَلَ فِي الْأَرْضِ مِنْهَا رَحْمَةً فَبِهَا تَعْطِفُ الْوَالِدَةُ عَلَى وَلَدِهَا وَالْبَهَائِمُ بَعْضُهَا عَلَى بَعْضٍ وَالطَّيْرُ وَأَخَّرَ تِسْعَةً وَتِسْعِينَ إِلَى يَوْمِ الْقِيَامَةِ فَإِذَا كَانَ يَوْمُ الْقِيَامَةِ أَكْمَلَهَا اللَّهُ بِهَذِهِ الرَّحْمَةِ","id":"Telah menceritakan kepada kami [Abu Kuraib] dan [Ahmad bin Sinan] keduanya berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Sa'id] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah 'azza wajalla telah menciptakan seratus rahmat di hari saat Dia menciptakan langit dan bumi. Dan Dia meletakkan satu rahmat di muka bumi, yang dengannya seorang ibu dapat menyayangi anaknya, para binatang saling mengasihi dengan sesamanya, begitu juga dengan burung. Dan Dia menyisakan sembilan puluh sembilan rahmat sampai hari Kiamat. Maka jika hari Kiamat telah tiba, Allah akan menyempurnakan dengan rahmat tersebut.\""},"4244":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ وَأَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ قَالَا حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ عَنْ ابْنِ عَجْلَانَ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ عَزَّ وَجَلَّ لَمَّا خَلَقَ الْخَلْقَ كَتَبَ بِيَدِهِ عَلَى نَفْسِهِ إِنَّ رَحْمَتِي تَغْلِبُ غَضَبِي","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] dan [Abu Bakar bin Abu Syaibah] keduanya berkata; telah menceritakan kepada kami [Abu Khalid Al Ahmar] dari [Ibnu Al 'Ajlan] dari [ayahnya] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ketika Allah 'azza wajalla menciptakan makhluk-Nya, Dia berjanji kepada Diri-Nya; Sesungguhnya rahmat-Ku mengalahkan amarah-Ku.\""},"4245":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبِي الشَّوَارِبِ حَدَّثَنَا أَبُو عَوَانَةَ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ عُمَيْرٍ عَنْ ابْنِ أَبِي لَيْلَى عَنْ مُعَاذِ بْنِ جَبَلٍ قَالَمَرَّ بِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا عَلَى حِمَارٍ فَقَالَ يَا مُعَاذُ هَلْ تَدْرِي مَا حَقُّ اللَّهِ عَلَى الْعِبَادِ وَمَا حَقُّ الْعِبَادِ عَلَى اللَّهِ قُلْتُ اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ فَإِنَّ حَقَّ اللَّهِ عَلَى الْعِبَادِ أَنْ يَعْبُدُوهُ وَلَا يُشْرِكُوا بِهِ شَيْئًا وَحَقُّ الْعِبَادِ عَلَى اللَّهِ إِذَا فَعَلُوا ذَلِكَ أَنْ لَا يُعَذِّبَهُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Abdul Malik bin Abu As Syawarib] telah menceritakan kepada kami [Abu 'Awanah] telah menceritakan kepada kami [Abdul Malik bin 'Umair] dari [Ibnu Abu Laila] dari [Mua'dz bin Jabal] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam lewat di dekatku, ketika aku berada di atas keledai, beliau bertanya: \"Wahai Mu'adz, apakah kamu tahu apakah hak Allah terhadap hamba-hamba-Nya? Dan apa hak seorang hamba terhadapa Allah?\" Aku menjawab; \"Allah dan Rasul-Nya yang lebih mengetahui.\" beliau bersabda: \"Sesungguhnya hak Allah terhadap hamba-hamba-Nya ialah supaya mereka menyembah-Nya dan tidak menyekutukan-Nya dengan sesuatu apapun, sedangkan hak seorang hamba terhadap Allah adalah jika mereka melaksanakan hal itu, maka Dia tidak akan mengadzab mereka.\""},"4246":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا إِبْرَاهِيمُ بْنُ أَعْيَنَ حَدَّثَنَا إِسْمَعِيلُ بْنُ يَحْيَى الشَّيْبَانِيُّ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ بْنِ حَفْصٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَعْضِ غَزَوَاتِهِ فَمَرَّ بِقَوْمٍ فَقَالَ مَنْ الْقَوْمُ فَقَالُوا نَحْنُ الْمُسْلِمُونَ وَامْرَأَةٌ تَحْصِبُ تَنُّورَهَا وَمَعَهَا ابْنٌ لَهَا فَإِذَا ارْتَفَعَ وَهَجُ التَّنُّورِ تَنَحَّتْ بِهِ فَأَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ أَنْتَ رَسُولُ اللَّهِ قَالَ نَعَمْ قَالَتْ بِأَبِي أَنْتَ وَأُمِّي أَلَيْسَ اللَّهُ بِأَرْحَمِ الرَّاحِمِينَ قَالَ بَلَى قَالَتْ أَوَلَيْسَ اللَّهُ بِأَرْحَمَ بِعِبَادِهِ مِنْ الْأُمِّ بِوَلَدِهَا قَالَ بَلَى قَالَتْ فَإِنَّ الْأُمَّ لَا تُلْقِي وَلَدَهَا فِي النَّارِ فَأَكَبَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَبْكِي ثُمَّ رَفَعَ رَأْسَهُ إِلَيْهَا فَقَالَ إِنَّ اللَّهَ لَا يُعَذِّبُ مِنْ عِبَادِهِ إِلَّا الْمَارِدَ الْمُتَمَرِّدَ الَّذِي يَتَمَرَّدُ عَلَى اللَّهِ وَأَبَى أَنْ يَقُولَ لَا إِلَهَ إِلَّا اللَّهُ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Ibrahim bin A'yan] telah menceritakan kepada kami [Isma'il bin Yahya As Syaibani] dari [Abdullah bin Umar bin Hafsh] dari [Nafi'] dari [Ibnu Umar] dia berkata; \"Katika kami bersama Nabi shallallahu 'alaihi wasallam di salah satu peperangan, lalu beliau melawti suatu kaum, lantas beliau bertanya: \"Siapakah mereka?\" mereka menjawab; \"Kami adalah orang-orang Muslim\", dan seorang wanita bersama anaknya yang sedang menghidupkan tungku, ketika nyala api tersebut membesar wanita tersebut menjauhkan anaknya, kemudian dia datang kepada Nabi shallallahu ‘alaihi wa sallam dan berkata; “ engkau Rasulullah?” beliau menjawab; “ya” wanita tersebut bertanya; “bapak dan ibuku sebagai tebusanmu. Bukankah Allah maha penyayang dari yang para penyayang?” beliau menjawab; “betul” dia bertanya; “bukankah Allah maha penyayang terhadap hamba-hambaNya melebihi seorang ibu terhadap anaknya?”  wanita tersebut berkata; “sesungguhnya seorang ibu tidak akan melemparkan anaknya kedalam api?” maka Nabi tertelungkup menangis, kemudian mengangkat kepalanya memandang wanita tersebut dan berkata: “sesungguhnya Allah tidak akan mengadzab hamba-hambNya kecuali pembangkang yang bandel yang membangkang Allah dan menolak untuk mengucapkan LAA ILAAHA ILLALLAHU.”"},"4247":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ الْوَلِيدِ الدِّمَشْقِيُّ حَدَّثَنَا عَمْرُو بْنُ هَاشِمٍ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ عَبْدِ رَبِّهِ بْنِ سَعِيدٍ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَدْخُلُ النَّارَ إِلَّا شَقِيٌّ قِيلَ يَا رَسُولَ اللَّهِ وَمَنْ الشَّقِيُّ قَالَ مَنْ لَمْ يَعْمَلْ لِلَّهِ بِطَاعَةٍ وَلَمْ يَتْرُكْ لَهُ مَعْصِيَةً","id":"Telah menceritakan kepada kami [Al 'Abbas bin Al Walid Ad Dimasyqi] telah menceritakan kepada kami ['Amru bin Hasyim] telah menceritakan kepada kami [Ibnu Lahi'ah] dari ['Abd Rabbihi bin Sa'id] dari [Sa'id Al Maqburi] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak akan masuk neraka kecuali orang yang celaka.\" di katakan; \"Siapakan orang yang celaka wahai Rasulullah?\" beliau menjawab: \"Seseorang yang ta'at dan juga meninggalkan kemaksiatan tidak karena Allah.\""},"4248":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ حَدَّثَنَا سُهَيْلُ بْنُ عَبْدِ اللَّهِ أَخُو حَزْمٍ الْقُطَعِيِّ حَدَّثَنَا ثَابِتٌ الْبُنَانِيُّ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرَأَ أَوْ تَلَا هَذِهِ الْآيَةَ{ هُوَ أَهْلُ التَّقْوَى وَأَهْلُ الْمَغْفِرَةِ }فَقَالَ قَالَ اللَّهُ عَزَّ وَجَلَّ أَنَا أَهْلٌ أَنْ أُتَّقَى فَلَا يُجْعَلْ مَعِي إِلَهٌ آخَرُ فَمَنْ اتَّقَى أَنْ يَجْعَلَ مَعِي إِلَهًا آخَرَ فَأَنَا أَهْلٌ أَنْ أَغْفِرَ لَهُقَالَ أَبُو الْحَسَنِ الْقَطَّانُ حَدَّثَنَاهُ إِبْرَاهِيمُ بْنُ نَصْرٍ حَدَّثَنَا هُدْبَةُ بْنُ خَالِدٍ حَدَّثَنَا سُهَيْلُ بْنُ أَبِي حَزْمٍ عَنْ ثَابِتٍ عَنْ أَنَسٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي هَذِهِ الْآيَةِ{ هُوَ أَهْلُ التَّقْوَى وَأَهْلُ الْمَغْفِرَةِ }قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ رَبُّكُمْ أَنَا أَهْلٌ أَنْ أُتَّقَى فَلَا يُشْرَكَ بِي غَيْرِي وَأَنَا أَهْلٌ لِمَنْ اتَّقَى أَنْ يُشْرِكَ بِي أَنْ أَغْفِرَ لَهُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Ziad bin Habab] telah menceritakan kepada kami [Suhail bin Abdullah saudaranya Hazm bin Al Qath'i] telah menceritakan kepada kami [Tsabit Al Bunani] dari [Anas bin Malik] bahwa Rasulullah shallallahu 'alaihi wasallam membaca ayat ini, yaitu: \"Dia (Allah) adalah Rabb yang patut (kita) bertakwa kepada-Nya dan berhak memberi ampun.\" (QS Al Mudatsir; 56) Beliau bersabda: \"Allah 'azza wajalla berfirman: \"Saya adalah dzat yang patut untuk ditakuti, maka tidak di jadikan bersamaKu sesembahan yang lain, maka barangsiapa takut menjadikan bersamaku dengan sesembahan yang lain, maka saya berhak untuk memberi ampunan kepadanya.\" Abu Hasan Al Qatthan berkata; telah menceritakan kepada kami Ibrahim bin Nashr telah menceritakan kepada kami Hudbah bin Khalid telah menceritakan kepada kami Suhail bin Abu Hazm dari Tsabit dari Anas bahwa Rasulullah shallallahu 'alaihi wasallam bersabda mengenai ayat ini, yaitu: \": Dia (Allah) adalah Rabb yang patut (kita) bertakwa kepada-Nya dan berhak memberi ampun.\" (QS Al Mudatsir; 56), Rasulullah shallallahu 'alaihi wasallam bersabda: \"Rabb kalian berfirman: \"Aku adalah dzat yang berhak untuk di takuti, maka janganlah menyekutukan-Ku dengan sesuatu selainku, dan Aku adalah dzat yang barangsiapa takut menyekutukan-Ku, maka Aku berhak untuk memberi ampunan kepadanya.\""},"4249":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا ابْنُ أَبِي مَرْيَمَ حَدَّثَنَا اللَّيْثُ حَدَّثَنِي عَامِرُ بْنُ يَحْيَى عَنْ أَبِي عَبْدِ الرَّحْمَنِ الْحُبُلِيِّ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ عَمْرٍو يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَاحُ بِرَجُلٍ مِنْ أُمَّتِي يَوْمَ الْقِيَامَةِ عَلَى رُءُوسِ الْخَلَائِقِ فَيُنْشَرُ لَهُ تِسْعَةٌ وَتِسْعُونَ سِجِلًّا كُلُّ سِجِلٍّ مَدَّ الْبَصَرِ ثُمَّ يَقُولُ اللَّهُ عَزَّ وَجَلَّ هَلْ تُنْكِرُ مِنْ هَذَا شَيْئًا فَيَقُولُ لَا يَا رَبِّ فَيَقُولُ أَظَلَمَتْكَ كَتَبَتِي الْحَافِظُونَ ثُمَّ يَقُولُ أَلَكَ عَنْ ذَلِكَ حَسَنَةٌ فَيُهَابُ الرَّجُلُ فَيَقُولُ لَا فَيَقُولُ بَلَى إِنَّ لَكَ عِنْدَنَا حَسَنَاتٍ وَإِنَّهُ لَا ظُلْمَ عَلَيْكَ الْيَوْمَ فَتُخْرَجُ لَهُ بِطَاقَةٌ فِيهَا أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ قَالَ فَيَقُولُ يَا رَبِّ مَا هَذِهِ الْبِطَاقَةُ مَعَ هَذِهِ السِّجِلَّاتِ فَيَقُولُ إِنَّكَ لَا تُظْلَمُ فَتُوضَعُ السِّجِلَّاتُ فِي كِفَّةٍ وَالْبِطَاقَةُ فِي كِفَّةٍ فَطَاشَتْ السِّجِلَّاتُ وَثَقُلَتْ الْبِطَاقَةُقَالَ مُحَمَّدُ بْنُ يَحْيَى الْبِطَاقَةُ الرُّقْعَةُ وَأَهْلُ مِصْرَ يَقُولُونَ لِلرُّقْعَةِ بِطَاقَةً","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] telah menceritakan kepada kami [Ibnu Abu Maryam] telah menceritakan kepada kami [Laits] telah menceritakan kepadaku ['Amir bin Yahya] dari [Abu Abdurrahman Al Hubuli] dia berkata; saya mendengar [Abdullah bin 'Amru] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pada hari Kiamat akan di teriakan seorang laki-laki dari ummatku di atas kepala seluruh makhluk, maka di sebarkanlah untuknya sembilan puluh sembilan buku catatan, setiap buku catatan yang panjangnya sejauh mata memandang. Kemudian Allah 'azza wajalla berfirman: \"Apakah kamu mengingkari sesuatu dari catatan ini?\" dia menjawab; \"Tidak wahai Rabbku.\" Allah bertanya lagi; \"Apakah Malaikat penulis-Ku mendzalimimu?\" Kemudian Dia berfirman: \"Apakah kamu punya alasan? Apakah kamu punya kebaikan?\" Maka dengan rasa takut, laki-laki itu menjawab; \"Tidak.\" Allah berfirman: \"Ya, sesungguhnya kamu memiliki beberapa kebaikan di sisi Kami. Sesungguhnya pada hari ini tidak ada lagi kezhaliman bagi dirimu.\" Maka di keluarkanlah untuknya kartu yang bertuliskan; \"Laa ilaaha illallah wa anna Muhammadan 'Abduhu wa rasuuluhu (Tidak ada ilah yang berhak di sembah selain Allah dan bahwa Muhammad adalah hamba dan utusan-Nya).\" Beliau bersabda: \"Lelaki itu berkata; \"Wahai Rabbku, apa hubingannya kartu ini dengan buku catatan ini?\" Allah menjawab: \"Sesungguhnya kamu tidak akan dizhalimi.\" Maka di letakkanlah catatan-catatan itu di atas satu bagian (di sisi) timbangan, dan kartu di bagian lain (sisi yang lain) dari timbangan, ternyata catatan-catatan itu lebih ringan dan kartu itu lebih berat.\" Muhammad bin Yahya berkata; \"Kartu adalah suatu lempengan, dan penduduk Mesir biasa mengatakan lempengan tersebut adalah kartu.\""},"4250":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ حَدَّثَنَا زَكَرِيَّا حَدَّثَنَا عَطِيَّةُ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ لِي حَوْضًا مَا بَيْنَ الْكَعْبَةِ وَبَيْتِ الْمَقْدِسِ أَبْيَضَ مِثْلَ اللَّبَنِ آنِيَتُهُ عَدَدُ النُّجُومِ وَإِنِّي لَأَكْثَرُ الْأَنْبِيَاءِ تَبَعًا يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Muhammad bin Bisyr] telah menceritakan kepada kami [Zakariya] telah menceritakan kepada kami ['Athiyah] dari [Abu Sa'id Al Khudri] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya saya memiliki telaga (yang luasnya) antara Ka'bah hingga Baitul Maqdis, putihnya seperti putih susu, dan tempat minumnya sejumlah bintang-bintang, dan sesungguhnya aku adalah Nabi yang paling banyak pengikut di antara para Nabi kelak di hari Kiamat.\""},"4251":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ أَبِي مَالِكٍ سَعْدِ بْنِ طَارِقٍ عَنْ رِبْعِيٍّ عَنْ حُذَيْفَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ حَوْضِي لَأَبْعَدُ مِنْ أَيْلَةَ إِلَى عَدَنَ وَالَّذِي نَفْسِي بِيَدِهِ لَآنِيَتُهُ أَكْثَرُ مِنْ عَدَدِ النُّجُومِ وَلَهُوَ أَشَدُّ بَيَاضًا مِنْ اللَّبَنِ وَأَحْلَى مِنْ الْعَسَلِ وَالَّذِي نَفْسِي بِيَدِهِ إِنِّي لَأَذُودُ عَنْهُ الرِّجَالَ كَمَا يَذُودُ الرَّجُلُ الْإِبِلَ الْغَرِيبَةَ عَنْ حَوْضِهِ قِيلَ يَا رَسُولَ اللَّهِ أَتَعْرِفُنَا قَالَ نَعَمْ تَرِدُونَ عَلَيَّ غُرًّا مُحَجَّلِينَ مِنْ أَثَرِ الْوُضُوءِ لَيْسَتْ لِأَحَدٍ غَيْرِكُمْ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Ali bin Mushir] dari [Abu Malik Sa'd bin Thariq] dari [Rib'i] dari [Hudzaifah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya telagaku (luasnya) sejauh dari 'Ailah hingga 'Adn, demi dzat yang jiwaku berada di tangan-Nya, sungguh gelas-gelasnya lebih banyak dari jumlah bintang-bintang (di langit), ia lebihi putih dari putihnya susu dan lebih manis dari manisnya madu. Demi dzat yang jiwaku berada di tangan-Nya, sesungguhnya aku akan mempertahankannya dari orang-orang, sebagaimana seorang laki-laki yang mempertahankan telaganya dari unta asing.\" Lalu di tanyakan kepada beliau; \"Wahai Rasulullah, apakah anda mengenali kami?\" beliau menjawab: \"Ya, kalian di tampakkan kepadaku dengan wajah dan pergelangan tangan serta kaki yang putih bekas wudlu, yang tidak dimiliki oleh seorang pun dari selain kalian.\""},"4252":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ خَالِدٍ الدِّمَشْقِيُّ حَدَّثَنَا مَرْوَانُ بْنُ مُحَمَّدٍ حَدَّثَنَا مُحَمَّدُ بْنُ مُهَاجِرٍ حَدَّثَنِي الْعَبَّاسُ بْنُ سَالِمٍ الدِّمَشْقِيُّ نُبِّئْتُ عَنْ أَبِي سَلَّامٍ الْحَبَشِيِّ قَالَبَعَثَ إِلَيَّ عُمَرُ بْنُ عَبْدِ الْعَزِيزِ فَأَتَيْتُهُ عَلَى بَرِيدٍ فَلَمَّا قَدِمْتُ عَلَيْهِ قَالَ لَقَدْ شَقَقْنَا عَلَيْكَ يَا أَبَا سَلَّامٍ فِي مَرْكَبِكَ قَالَ أَجَلْ وَاللَّهِ يَا أَمِيرَ الْمُؤْمِنِينَ قَالَ وَاللَّهِ مَا أَرَدْتُ الْمَشَقَّةَ عَلَيْكَ وَلَكِنْ حَدِيثٌ بَلَغَنِي أَنَّكَ تُحَدِّثُ بِهِ عَنْ ثَوْبَانَ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْحَوْضِ فَأَحْبَبْتُ أَنْ تُشَافِهَنِي بِهِ قَالَ فَقُلْتُ حَدَّثَنِي ثَوْبَانُ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ حَوْضِي مَا بَيْنَ عَدَنَ إِلَى أَيْلَةَ أَشَدُّ بَيَاضًا مِنْ اللَّبَنِ وَأَحْلَى مِنْ الْعَسَلِ أَكَاوِيبُهُ كَعَدَدِ نُجُومِ السَّمَاءِ مَنْ شَرِبَ مِنْهُ شَرْبَةً لَمْ يَظْمَأْ بَعْدَهَا أَبَدًا وَأَوَّلُ مَنْ يَرِدُهُ عَلَيَّ فُقَرَاءُ الْمُهَاجِرِينَ الدُّنْسُ ثِيَابًا وَالشُّعْثُ رُءُوسًا الَّذِينَ لَا يَنْكِحُونَ الْمُنَعَّمَاتِ وَلَا يُفْتَحُ لَهُمْ السُّدَدُقَالَ فَبَكَى عُمَرُ حَتَّى اخْضَلَّتْ لِحْيَتُهُ ثُمَّ قَالَ لَكِنِّي قَدْ نَكَحْتُ الْمُنَعَّمَاتِ وَفُتِحَتْ لِي السُّدَدُ لَا جَرَمَ أَنِّي لَا أَغْسِلُ ثَوْبِي الَّذِي عَلَى جَسَدِي حَتَّى يَتَّسِخَ وَلَا أَدْهُنُ رَأْسِي حَتَّى يَشْعَثَ","id":"Telah menceritakan kepada kami [Mahmud bin Khalid Ad Dimasyqi] telah menceritakan kepada kami [Marwan bin Muhammad] telah menceritakan kepada kami [Muhammad bin Muhajir] telah menceritakan kepadaku [Al 'Abbas bin Salim Ad Dimasyqi] telah di beritakan kepadaku dari [Abu Salam Al Habasyi] dia berkata; Umar bin Abdul Aziz memanaggilku, lantas saya mendatanginya sekitar satu Barid, ketika saya telah tiba, ia berkata; \"Sungguh kami telah memberatkanmu dengan kendaraanmu wahai Abu Salam.\" Dia menjawab; \"Tentu, demi Allah wahai Amirul Mukminin.\" Umar bin Abdul Aziz berkata; \"Demi Allah, saya tidak ingin memberatkan dalam perjalananmu ini melainkan karena hadits yang sampai kepadaku bahwa kamu telah bercerita dari Tsauban bekas budak Rasulullah shallallahu 'alaihi wasallam mengenai telaga. Maka saya lebih suka jika kamu sendiri yang mengabarkan kepadaku dengan lisanmu.\" Abu Salam berkata; \"lalu saya berkata; telah menceritakan kepadaku [Tsauban bekas budak Rasulullah shallallahu 'alaihi wasallam] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya telagaku (luasnya) antara 'Adn dan 'Ailah, lebih putih dari susu dan lebih manis dari manisnya madu. Gelas-gelasnya laksana jumlah bintang di langit. Barangsiapa meminum seteguk darinya, niscaya tidak akan merasa dahaga untuk salama-lamanya. Dan orang pertama kali yang di tampakkan kepadaku adalah orang-orang miskin dari kalangan Muhajirin yang berpakaian lusuh dan rambut yang kusut, yang tidak pernah merasakan kesenangan dan tidak pernah pula (merasakan) di bukakan bagi mereka tempat makanan.\""},"4253":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ حَدَّثَنَا أَبِي حَدَّثَنَا هِشَامٌ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا بَيْنَ نَاحِيَتَيْ حَوْضِي كَمَا بَيْنَ صَنْعَاءَ وَالْمَدِينَةِ أَوْ كَمَا بَيْنَ الْمَدِينَةِ وَعُمَانَ","id":"Telah menceritakan kepada kami [Nashr bin Ali] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Hisyam] dari [Qatadah] dari [Anas] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jarak antara dua sisi telagaku bagaikan jarak antara Shan'a dan Madinah atau bagaikan jarak antara Madinah dan Yaman.\""},"4254":{"ar":"حَدَّثَنَا حُمَيْدُ بْنُ مَسْعَدَةَ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ قَالَ قَالَ أَنَسُ بْنُ مَالِكٍقَالَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُرَى فِيهِ أَبَارِيقُ الذَّهَبِ وَالْفِضَّةِ كَعَدَدِ نُجُومِ السَّمَاءِ","id":"Telah menceritakan kepada kami [Humaid bin Mas'adah] telah menceritakan kepada kami [Khalid bin Al Harits] telah menceritakan kepada kami [Sa'id bin Abu 'Arubah] dari [Qatadah] dia berkata; [Anas bin Malik] berkata; Nabi Allah shallallahu 'alaihi wasallam bersabda: \"Di perlihatkan di dalamnya tempat minum yang terbuat dari emas dan perak, jumlahnya bagaikan bintang-bintang di langit.\""},"4255":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ أَتَى الْمَقْبَرَةَ فَسَلَّمَ عَلَى الْمَقْبَرَةِ فَقَالَ السَّلَامُ عَلَيْكُمْ دَارَ قَوْمٍ مُؤْمِنِينَ وَإِنَّا إِنْ شَاءَ اللَّهُ تَعَالَى بِكُمْ لَاحِقُونَ ثُمَّ قَالَ لَوَدِدْنَا أَنَّا قَدْ رَأَيْنَا إِخْوَانَنَا قَالُوا يَا رَسُولَ اللَّهِ أَوَلَسْنَا إِخْوَانَكَ قَالَ أَنْتُمْ أَصْحَابِي وَإِخْوَانِي الَّذِينَ يَأْتُونَ مِنْ بَعْدِي وَأَنَا فَرَطُكُمْ عَلَى الْحَوْضِ قَالُوا يَا رَسُولَ اللَّهِ كَيْفَ تَعْرِفُ مَنْ لَمْ يَأْتِ مِنْ أُمَّتِكَ قَالَ أَرَأَيْتُمْ لَوْ أَنَّ رَجُلًا لَهُ خَيْلٌ غُرٌّ مُحَجَّلَةٌ بَيْنَ ظَهْرَانَيْ خَيْلٍ دُهْمٍ بُهْمٍ أَلَمْ يَكُنْ يَعْرِفُهَا قَالُوا بَلَى قَالَ فَإِنَّهُمْ يَأْتُونَ يَوْمَ الْقِيَامَةِ غُرًّا مُحَجَّلِينَ مِنْ أَثَرِ الْوُضُوءِ قَالَ أَنَا فَرَطُكُمْ عَلَى الْحَوْضِ ثُمَّ قَالَ لَيُذَادَنَّ رِجَالٌ عَنْ حَوْضِي كَمَا يُذَادُ الْبَعِيرُ الضَّالُّ فَأُنَادِيهِمْ أَلَا هَلُمُّوا فَيُقَالُ إِنَّهُمْ قَدْ بَدَّلُوا بَعْدَكَ وَلَمْ يَزَالُوا يَرْجِعُونَ عَلَى أَعْقَابِهِمْ فَأَقُولُ أَلَا سُحْقًا سُحْقًا","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Al 'Ala` bin Abdurrahman] dari [ayahnya] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau pernah mendatangi pemakaman dan beliau mengucapkan salam kepada ahli kubur, beliau mengucapkan: \"Semoga keselamatan senantiasa tercurah bagimu, rumah bagi kaum Muslimin, dan Insya Allah Ta'ala kami akan menyusulmu.\" Lalu beliau bersabda: \"Sungguh kami berharap untuk dapat berjumpa dengan saudara-saudara kami ini.\" Para sahabat bertanya; \"Wahai Rasulullah, apakah kami bukan saudara-saudaramu?\" beliau menjawab: \"Kalian adalah para sahabatku dan saudara-saudaraku yang datang setelahku, sesungguhnya aku menunggu kalian di telagaku.\" Mereka bertanya; \"Wahai Rasulullah, bagaimana anda bisa mengenali orang-orang yang tidak anda ketahui dari umatmu?\" beliau menjawab: \"Bagaimana menurut kalian jika seseorang memiliki kuda berbulu putih di muka dan di kedua pergelangan kakinya, di tengah-tengah gerombolan kuda hitam pekat? Bukankah ia dapat dikenali?\" Mereka menjawab; \"Tentu.\" Beliau bersabda: \"Sesungguhnya mereka datang pada hari Kiamat dengan muka dan kedua pergelangan tangan dan kaki mereka yang putih bekas air wudlu.\" Beliau bersabda: \"Aku menunggu kalian di tepi telaga.\" Lalu beliau melanjutkan: \"Ketahuilah bahwa telagaku akan dijaga sebagaimana di jaganya telaga dari unta yang tersesat. Kemudian aku akan memanggil mereka; \"Mari datanglah.\" Maka di katakan; \"Sesungguhnya mereka telah merubahnya setelahmu, serta mereka masih terus membalikkan badannya, maka aku berkata; \"Majulah, majulah.\""},"4256":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِكُلِّ نَبِيٍّ دَعْوَةٌ مُسْتَجَابَةٌ فَتَعَجَّلَ كُلُّ نَبِيٍّ دَعْوَتَهُ وَإِنِّي اخْتَبَأْتُ دَعْوَتِي شَفَاعَةً لِأُمَّتِي فَهِيَ نَائِلَةٌ مَنْ مَاتَ مِنْهُمْ لَا يُشْرِكُ بِاللَّهِ شَيْئًا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap Nabi do'anya adalah mustajab (dikabulkan), maka semua Nabi tergesa-gesa mempergunakan do'anya. Sesungguhnya aku menyimpan do'aku untuk memberi syafa'at kepada ummatku (kelak), maka itu akan di dapat oleh orang yang mati di antara mereka dalam keadaan tidak menyekutukan Allah dengan sesuatupun.\""},"4257":{"ar":"حَدَّثَنَا مُجَاهِدُ بْنُ مُوسَى وَأَبُو إِسْحَقَ الْهَرَوِيُّ إِبْرَاهِيمُ بْنُ عَبْدِ اللَّهِ بْنِ حَاتِمٍ قَالَا حَدَّثَنَا هُشَيْمٌ أَنْبَأَنَا عَلِيُّ بْنُ زَيْدِ بْنِ جُدْعَانَ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَا سَيِّدُ وَلَدِ آدَمَ وَلَا فَخْرَ وَأَنَا أَوَّلُ مَنْ تَنْشَقُّ الْأَرْضُ عَنْهُ يَوْمَ الْقِيَامَةِ وَلَا فَخْرَ وَأَنَا أَوَّلُ شَافِعٍ وَأَوَّلُ مُشَفَّعٍ وَلَا فَخْرَ وَلِوَاءُ الْحَمْدِ بِيَدِي يَوْمَ الْقِيَامَةِ وَلَا فَخْرَ","id":"Telah menceritakan kepada kami [Mujahid bin Musa] dan [Abu Ishaq Al Harawi Ibrahim bin Abdullah bin Hatim] keduanya berkata; telah menceritakan kepada kami [Husyaim] telah memberitakan kepada kami [Ali bin Zaid bin Jud'an] dari [Abu Nadlrah] dari [Abu Sa'id] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Saya adalah pemuka anak Adam dan tidak sombong. Aku adalah orang yang pertama kali di bukakan bumi (di bangkitkan) pada hari Kiamat, dan tidak sombong. Aku adalah orang yang pertama kali memberi syafa'at dan di mintai syafa'at dan tidak sombong. Bendera pujian ada di tanganku pada hari Kiamat dan tidak sombong.\""},"4258":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ بْنِ حَبِيبٍ قَالَا حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ حَدَّثَنَا سَعِيدُ بْنُ يَزِيدَ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَّا أَهْلُ النَّارِ الَّذِينَ هُمْ أَهْلُهَا فَلَا يَمُوتُونَ فِيهَا وَلَا يَحْيَوْنَ وَلَكِنْ نَاسٌ أَصَابَتْهُمْ نَارٌ بِذُنُوبِهِمْ أَوْ بِخَطَايَاهُمْ فَأَمَاتَتْهُمْ إِمَاتَةً حَتَّى إِذَا كَانُوا فَحْمًا أُذِنَ لَهُمْ فِي الشَّفَاعَةِ فَجِيءَ بِهِمْ ضَبَائِرَ ضَبَائِرَ فَبُثُّوا عَلَى أَنْهَارِ الْجَنَّةِ فَقِيلَ يَا أَهْلَ الْجَنَّةِ أَفِيضُوا عَلَيْهِمْ فَيَنْبُتُونَ نَبَاتَ الْحِبَّةِ تَكُونُ فِي حَمِيلِ السَّيْلِ قَالَ فَقَالَ رَجُلٌ مِنْ الْقَوْمِ كَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ كَانَ فِي الْبَادِيَةِ","id":"Telah menceritakan kepada kami [Nashr bin 'Ali] dan [Ishaq bin Ibrahim bin Habib] keduanya berkata; telah menceritakan kepada kami [Bisyr bin Al Mufadlal] telah menceritakan kepada kami [Sa'id bin Yazid] dari [Abu Nadlrah] dari [Abu Sa'id] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Penghuni neraka yang mereka benar-benar penghuninya, mereka tidak akan merasakan kematian dan juga tidak hidup di dalamnya. Akan tetapi mereka adalah orang-orang yang terkena api neraka karena dosa-dosa dan kesalahan-kesalahan mereka, maka mereka akan di matikan sesaat. Dan ketika mereka telah menjadi arang, maka mereka di izinkan untuk mendapatkan syafa'at. Lalu mereka di datangkan secara berkelompok-kelompok, kemudian mereka di mandikan di sungai-sungai surga. Maka di katakan; \"Wahai penghuni surga, berilah mereka minuman.\" Maka mereka menumbuhkan tumbuhan hibbah (biji-bijian) yang ada di arus sungai.\" Perawi berkata; \"Maka berkatalah seseorang dari mereka; \"Seakan-akan Rasulullah shallallahu 'alaihi wasallam baru tiba dari pedalaman.\""},"4259":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا زُهَيْرُ بْنُ مُحَمَّدٍ عَنْ جَعْفَرِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ جَابِرٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ شَفَاعَتِي يَوْمَ الْقِيَامَةِ لِأَهْلِ الْكَبَائِرِ مِنْ أُمَّتِي","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibrahim Ad Dimasyqi] telah menceritakan kepada kami [Al Walid bin Muslim] telah menceritakan kepada kami [Zuhair bin Muhammad] dari [Ja'far bin Muhammad] dari [ayahnya] dari [Jabir] dia berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya syafa'atku pada hari Kiamat adalah untuk para pelaku dosa besar dari ummatku.\""},"4260":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ أَسَدٍ حَدَّثَنَا أَبُو بَدْرٍ حَدَّثَنَا زِيَادُ بْنُ خَيْثَمَةَ عَنْ نُعَيْمِ بْنِ أَبِي هِنْدٍ عَنْ رِبْعِيِّ بْنِ حِرَاشٍ عَنْ أَبِي مُوسَى الْأَشْعَرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خُيِّرْتُ بَيْنَ الشَّفَاعَةِ وَبَيْنَ أَنْ يَدْخُلَ نِصْفُ أُمَّتِي الْجَنَّةَ فَاخْتَرْتُ الشَّفَاعَةَ لِأَنَّهَا أَعَمُّ وَأَكْفَى أَتُرَوْنَهَا لِلْمُتَّقِينَ لَا وَلَكِنَّهَا لِلْمُذْنِبِينَ الْخَطَّائِينَ الْمُتَلَوِّثِينَ","id":"Telah menceritakan kepada kami [Isma'il bin Asad] telah menceritakan kepada kami [Abu Badr] telah menceritakan kepada kami [Ziyad bin Khaitsamah] dari [Nu'aim bin Abu Hind] dari [Rib'I bin Hirasy] dari [Abu Musa Al Asy'ari] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Saya di suruh memilih antara setengah ummatku akan di masukkan ke surga dengan di beri syafa'at, maka saya memilih syafa'at, karena sesungguhnya syafa'at lebih mencakup dan lebih mencukupi, bagaimana pendapat kalian, apakah ia hanya di berikan kepada orang-orang yang bertakwa saja? Tidak, akan tetapi ia di berikan juga terhadap orang-orang yang berdosa dan orang-orang yang banyak kesalahan.\""},"4261":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَجْتَمِعُ الْمُؤْمِنُونَ يَوْمَ الْقِيَامَةِ يُلْهَمُونَ أَوْ يَهُمُّونَ شَكَّ سَعِيدٌ فَيَقُولُونَ لَوْ تَشَفَّعْنَا إِلَى رَبِّنَا فَأَرَاحَنَا مِنْ مَكَانِنَا فَيَأْتُونَ آدَمَ فَيَقُولُونَ أَنْتَ آدَمُ أَبُو النَّاسِ خَلَقَكَ اللَّهُ بِيَدِهِ وَأَسْجَدَ لَكَ مَلَائِكَتَهُ فَاشْفَعْ لَنَا عِنْدَ رَبِّكَ يُرِحْنَا مِنْ مَكَانِنَا هَذَا فَي��قُولُ لَسْتُ هُنَاكُمْ وَيَذْكُرُ وَيَشْكُو إِلَيْهِمْ ذَنْبَهُ الَّذِي أَصَابَ فَيَسْتَحْيِي مِنْ ذَلِكَ وَلَكِنْ ائْتُوا نُوحًا فَإِنَّهُ أَوَّلُ رَسُولٍ بَعَثَهُ اللَّهُ إِلَى أَهْلِ الْأَرْضِ فَيَأْتُونَهُ فَيَقُولُ لَسْتُ هُنَاكُمْ وَيَذْكُرُ سُؤَالَهُ رَبَّهُ مَا لَيْسَ لَهُ بِهِ عِلْمٌ وَيَسْتَحْيِي مِنْ ذَلِكَ وَلَكِنْ ائْتُوا خَلِيلَ الرَّحْمَنِ إِبْرَاهِيمَ فَيَأْتُونَهُ فَيَقُولُ لَسْتُ هُنَاكُمْ وَلَكِنْ ائْتُوا مُوسَى عَبْدًا كَلَّمَهُ اللَّهُ وَأَعْطَاهُ التَّوْرَاةَ فَيَأْتُونَهُ فَيَقُولُ لَسْتُ هُنَاكُمْ وَيَذْكُرُ قَتْلَهُ النَّفْسَ بِغَيْرِ النَّفْسِ وَلَكِنْ ائْتُوا عِيسَى عَبْدَ اللَّهِ وَرَسُولَهُ وَكَلِمَةَ اللَّهِ وَرُوحَهُ فَيَأْتُونَهُ فَيَقُولُ لَسْتُ هُنَاكُمْ وَلَكِنْ ائْتُوا مُحَمَّدًا عَبْدًا غَفَرَ اللَّهُ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ وَمَا تَأَخَّرَ قَالَ فَيَأْتُونِي فَأَنْطَلِقُ قَالَ فَذَكَرَ هَذَا الْحَرْفَ عَنْ الْحَسَنِ قَالَ فَأَمْشِي بَيْنَ السِّمَاطَيْنِ مِنْ الْمُؤْمِنِينَ قَالَ ثُمَّ عَادَ إِلَى حَدِيثِ أَنَسٍ قَالَ فَأَسْتَأْذِنُ عَلَى رَبِّي فَيُؤْذَنُ لِي فَإِذَا رَأَيْتُهُ وَقَعْتُ سَاجِدًا فَيَدَعُنِي مَا شَاءَ اللَّهُ أَنْ يَدَعَنِي ثُمَّ يُقَالُ ارْفَعْ يَا مُحَمَّدُ وَقُلْ تُسْمَعْ وَسَلْ تُعْطَهْ وَاشْفَعْ تُشَفَّعْ فَأَحْمَدُهُ بِتَحْمِيدٍ يُعَلِّمُنِيهِ ثُمَّ أَشْفَعُ فَيَحُدُّ لِي حَدًّا فَيُدْخِلُهُمْ الْجَنَّةَ ثُمَّ أَعُودُ الثَّانِيَةَ فَإِذَا رَأَيْتُهُ وَقَعْتُ سَاجِدًا فَيَدَعُنِي مَا شَاءَ اللَّهُ أَنْ يَدَعَنِي ثُمَّ يُقَالُ لِي ارْفَعْ مُحَمَّدُ قُلْ تُسْمَعْ وَسَلْ تُعْطَهْ وَاشْفَعْ تُشَفَّعْ فَأَرْفَعُ رَأْسِي فَأَحْمَدُهُ بِتَحْمِيدٍ يُعَلِّمُنِيهِ ثُمَّ أَشْفَعُ فَيَحُدُّ لِي حَدًّا فَيُدْخِلُهُمْ الْجَنَّةَ ثُمَّ أَعُودُ الثَّالِثَةَ فَإِذَا رَأَيْتُ رَبِّي وَقَعْتُ سَاجِدًا فَيَدَعُنِي مَا شَاءَ اللَّهُ أَنْ يَدَعَنِي ثُمَّ يُقَالُ ارْفَعْ مُحَمَّدُ قُلْ تُسْمَعْ وَسَلْ تُعْطَهْ وَاشْفَعْ تُشَفَّعْ فَأَرْفَعُ رَأْسِي فَأَحْمَدُهُ بِتَحْمِيدٍ يُعَلِّمُنِيهِ ثُمَّ أَشْفَعُ فَيَحُدُّ لِي حَدًّا فَيُدْخِلُهُمْ الْجَنَّةَ ثُمَّ أَعُودُ الرَّابِعَةَ فَأَقُولُ يَا رَبِّ مَا بَقِيَ إِلَّا مَنْ حَبَسَهُ الْقُرْآنُ","id":"Telah menceritakan kepada kami [Nashr bin Ali] telah menceritakan kepada kami [Khalid bin Al Harits] telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Anas bin Malik] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pada hari kiamat kelak, orang-orang beriman berkumpul dan mereka diberi ilham -atau di beri naluri (Sa'id ragu) - sehingga mengatakan; \"Sebaiknya kita meminta syafa'at kepada Rabb kita 'azza wajalla sehingga kita dapat pindah dari tempat kita sekarang juga.' Lalu mereka mendatangi Adam 'Alaihis Salam seraya mengatakan; 'Wahai Adam, engkau adalah bapaknya manusia, Allah menciptakanmu dengan tangan-Nya sendiri dan menjadikan malaikat-malaikat-Nya sujud kepadamu, serta diajarkan pula kepadamu nama-nama segala sesuatu, maka mintakanlah syafa'at kepada Rabbmu agar Dia memindahkan kami dari tempat kami ini! \" Maka Adam berkata; \"Bukan aku yang kalian maksud\" kemudian Adam menyebutkan dosa yang pernah ia lakukan, hingga dosa tersebut membuatnya malu kepada Allah, (Adam berkata); Akan tetapi datanglah kalian kepada Nuh karena ia adalah rasul pertama kali yang Allah utus ke muka bumi, ' kemudian mereka pun mendatangi Nuh, namun dia berkata; \"Bukan aku yang kalian maksud, \" lalu ia menyebutkan kesalahan dan permintaannya kepada Rabbnya dengan tanpa ilmu, hingga membuatnya malu; \"Akan tetapi datangilah Ibrahim kekasih Ar Rahman, \" maka mereka pun mendatanginya, namun dia juga mengatakan; \"Bukan aku yang kalian maksud, tapi datanglah kalian kepada Musa, seorang hamba yang Allah ajak bicara secara langsung dan diberikan Taurat.\" Maka merekapun mendatangi Musa, dan Musa juga berkata; \"Bukan aku yang kalian maksud, \" seraya menyebutkan seseorang yang dia bunuh tanpa alasan yang benar; \"akan tetapi datanglah kalian kepada Isa, hamba Allah dan Rasul-Nya, kalimat serta ruh-Nya.\" Maka merekapun mendatangi Isa, kemudian Isa juga mengatakan; \"Bukan aku yang kalian maksud, akan tetapi datanglah kalian kepada Muhammad, seorang hamba yang dosanya telah diampuni Allah, baik yang lalu atau yang akan datang.\" Beliau bersabda: \"Maka mereka pun mendatangiku, lalu saya pun bertolak.\" Perawi berkata; \"Kemudian ia menyebutkan kalimat tersebut dari Al Hasan beliau bersabda: Maka aku berjalan di antara barisan manusia dari kaum Mukminin.\" Perawi berkata; Kemudian kembali kepada hadits Anas; beliau bersabda: \"Maka aku meminta izin kepada Rabbku, lalu aku pun diizinkan. Ketika aku melihat Rabbku, aku langsung jatuh sujud, kemudian Dia membiarkanku bersujud sekehendak-Nya, Kemudian dikatakan; \"Bangunlah ya Muhammad! berkatalah maka kamu akan didengarkan! memintalah maka kamu akan diberikan! dan mintalah syafa'at maka kamu akan diberi (hak memberi syafa'at).\" Maka aku memuji-Nya dengan pujian yang Dia ajarkan kepadaku, kemudian aku memberikan syafa'at dan Dia memberikan aku batasan, lalu aku memasukkan orang-orang ke dalam surga. Kemudian aku kembali (kepada Rabbku) untuk yang kedua kalinya, ketika aku melihat Rabbku aku langsung jatuh sujud, kemudian Dia membiarkanku bersujud sekehendak-Nya. Lalu dikatakan; 'Bangunlah ya Muhammad! berkatalah maka engkau akan didengarkan! memintalah maka engkau akan diberikan! dan mintalah syafa'at maka engkau akan diberi (hak memberi syafa'at).\" Maka aku mengangkat kepalaku dan memuji-Nya dengan pujian yang Dia ajarkan kepadaku, kemudian aku memberikan syafa'at dan Dia memberikan aku batasan, lalu aku memasukkan orang-orang ke dalam surga.\" Kemudian aku kembali (kepada Rabbku) untuk yang ketiga kalinya, dan ketika aku melihat Rabbku aku langsung tersungkur sujud kepada Rabbku, kemudian Dia membiarkanku bersujud sekehendak-Nya. Kemudian dikatakan; \"Bangunlah ya Muhammad! berkatalah maka engkau akan didengarkan! memintalah maka engkau akan diberikan! dan mintalah syafa'at maka engkau akan diberi (hak memberi syafa'at).\" Maka aku mengangkat kepalaku dan memuji-Nya dengan pujian yang Dia ajarkan kepadaku, kemudian aku memberikan syafa'at dan Dia memberikan aku batasan, lalu aku memasukkan orang-orang ke dalam surga.\" Kemudian aku kembali (kepada Rabbku) untuk yang keempat kalinya, lalu aku berkata: 'Wahai Rabb, tidak ada yang tersisa kecuali orang yang terhalang oleh Al Qur`an.\""},"4262":{"ar":"قَالَ يَقُولُ قَتَادَةُ عَلَى أَثَرِ هَذَا الْحَدِيثِ وَحَدَّثَنَا أَنَسُ بْنُ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَخْرُجُ مِنْ النَّارِ مَنْ قَالَ لَا إِلَهَ إِلَّا اللَّهُ وَكَانَ فِي قَلْبِهِ مِثْقَالُ شَعِيرَةٍ مِنْ خَيْرٍ وَيَخْرُجُ مِنْ النَّارِ مَنْ قَالَ لَا إِلَهَ إِلَّا اللَّهُ وَكَانَ فِي قَلْبِهِ مِثْقَالُ بُرَّةٍ مِنْ خَيْرٍ وَيَخْرُجُ مِنْ النَّارِ مَنْ قَالَ لَا إِلَهَ إِلَّا اللَّهُ وَكَانَ فِي قَلْبِهِ مِثْقَالُ ذَرَّةٍ مِنْ خَيْرٍ","id":"(Masih dari jalur periwayatan yang sama dengan hadits sebelumnya) perawi berkata; [Qatadah] berkata mengenai atsar hadits ini, dan telah menceritakan kepada kami [Anas bin Malik] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Akan keluar dari neraka orang yang berkata LA ILAHA ILLA AllAH (tidak ada ilah kecuali Allah) jika dalam hatinya terdapat kebaikan walau sebiji gandum, dan akan keluar dari neraka orang yang berkata LA ILAHA ILLA AllAH jika dalam hatinya terdapat kebaikan walau sebiji sawi\""},"4263":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ عَبْدِ اللَّهِ الرَّقِّيُّ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَمْرٍو عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ الطُّفَيْلِ بْنِ أُبَيِّ بْنِ كَعْبٍ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا كَانَ يَوْمُ الْقِيَامَةِ كُنْتُ إِمَامَ النَّبِيِّينَ وَخَطِيبَهُمْ وَصَاحِبَ شَفَاعَتِهِمْ غَيْرَ فَخْرٍ","id":"Telah menceritakan kepada kami [Isma'il bin Abdullah Ar Raqqi] telah menceritakan kepada kami ['Ubaidullah bin 'Amru] dari [Abdullah bin Muhammad bin 'Aqil] dari [At Thufail bin Abu Ubay bin Ka'ab] dari [ayahnya] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika datang hari Kimat, maka aku akan menjadi pemimpin para Nabi dan juru bicara mereka, Pemilik syafa'at mereka yang tidak sombong.\""},"4264":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا الْحَسَنُ بْنُ ذَكْوَانَ عَنْ أَبِي رَجَاءٍ الْعُطَارِدِيِّ عَنْ عِمْرَانَ بْنِ الْحُصَيْنِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيَخْرُجَنَّ قَوْمٌ مِنْ النَّارِ بِشَفَاعَتِي يُسَمَّوْنَ الْجَهَنَّمِيِّينَ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Yahya bin Sa'id] telah menceritakan kepada kami [Al Hasan bin Dzakwan] dari [Abu Raja` Al 'Utharidi] dari ['Imran bin Hushain] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Akan keluar suatu kaum dari mereka karena syafa'atku, mereka disebut dengan Al Juhannamiyah.\""},"4265":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَفَّانُ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا خَالِدٌ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي الْجَدْعَاءِأَنَّهُ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَيَدْخُلَنَّ الْجَنَّةَ بِشَفَاعَةِ رَجُلٍ مِنْ أُمَّتِي أَكْثَرُ مِنْ بَنِي تَمِيمٍ قَالُوا يَا رَسُولَ اللَّهِ سِوَاكَ قَالَ سِوَايَ قُلْتُ أَنْتَ سَمِعْتَهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَنَا سَمِعْتُهُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Khalid] dari [Abdullah bin Syaqiq] dari [Abdullah bin Abu Jud'a`] bahwa dia mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Akan masuk surga dari ummatku dengan syafa'atnya seorang laki-laki yang jumlahnya lebih banyak dari Bani Tamim.\" Mereka (para sahabat) bertanya; \"Wahai Rasulullah, apakah (orang yang memberi syafa'at) selain engkau?\" beliau menjawab: \"Ya, orang selain diriku.\" Abdullah bin Syaqiq berkata; \"Apakah kamu mendengarnya dari Rasulullah shallallahu 'alaihi wasallam?\" dia menjawab; \"Ya, saya mendengarnya dari beliau.\""},"4266":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبِي وَيَعْلَى قَالَا حَدَّثَنَا إِسْمَعِيلُ بْنُ أَبِي خَالِدٍ عَنْ نُفَيْعٍ أَبِي دَاوُدَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ نَارَكُمْ هَذِهِ جُزْءٌ مِنْ سَبْعِينَ جُزْءًا مِنْ نَارِ جَهَنَّمَ وَلَوْلَا أَنَّهَا أُطْفِئَتْ بِالْمَاءِ مَرَّتَيْنِ مَا انْتَفَعْتُمْ بِهَا وَإِنَّهَا لَتَدْعُو اللَّهَ عَزَّ وَجَلَّ أَنْ لَا يُعِيدَهَا فِيهَا","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [ayahku] d an [Ya'la] keduanya berkata; telah menceritakan kepada kami [Isma'il bin Abu Khalid] dari [Nufai' Abu Daud] dari [Anas bin Malik] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya api kalian ini adalah satu bagian dari tujuh puluh bagian api neraka Jahannam, kalau sekiranya ia tidak dimatikan dengan air hingga dua kali, niscaya kalian tidak akan bisa memanfa'atkannya, dan sesungguhnya ia selalu berdo'a kepada Allah 'azza wajalla agar tidak mengembalikannya ke jahannam lagi."},"4267":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اشْتَكَتْ النَّارُ إِلَى رَبِّهَا فَقَالَتْ يَا رَبِّ أَكَلَ بَعْضِي بَعْضًا فَجَعَلَ لَهَا نَفَسَيْنِ نَفَسٌ فِي الشِّتَاءِ وَنَفَسٌ فِي الصَّيْفِ فَشِدَّةُ مَا تَجِدُونَ مِنْ الْبَرْدِ مِنْ زَمْهَرِيرِهَا وَشِدَّةُ مَا تَجِدُونَ مِنْ الْحَرِّ مِنْ سَمُومِهَا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdullah bin Idris] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam berabda: \"Api mengelauh kepada Rabbnya, maka ia berkata; \"Wahai Rabbku, sebagian diriku memakan sebagian yang lainnya.\" Maka Dia menjadikan api dua nafas, nafas saat musim dingin dan nafas saat musim panas. Sangat dingin yang kalian dapatkan karena sengatakannya dan sangat panas yang kalian dapatkan karena angin panasnya.\""},"4268":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ مُحَمَّدٍ الدُّورِيُّ حَدَّثَنَا يَحْيَى بْنُ أَبِي بُكَيْرٍ حَدَّثَنَا شَرِيكٌ عَنْ عَاصِمٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أُوقِدَتْ النَّارُ أَلْفَ سَنَةٍ فَابْيَضَّتْ ثُمَّ أُوقِدَتْ أَلْفَ سَنَةٍ فَاحْمَرَّتْ ثُمَّ أُوقِدَتْ أَلْفَ سَنَةٍ فَاسْوَدَّتْ فَهِيَ سَوْدَاءُ كَاللَّيْلِ الْمُظْلِمِ","id":"Telah menceritakan kepada kami [Al 'Abbas bin Muhammad Ad Duuri] telah menceritakan kepada kami [Yahya bin Abu Bukair] telah menceritakan kepada kami [Syarik] dari ['Ashim] dari [Abu Shalih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Api neraka dinyalakan selama seribu tahun lamanya sehingga ia menjadi sangat putih, kemudian di nyalakan lagi selama setahun sehingga ia menjadi sangat merah lalu di nyalakan lagi selama seribu tahun lamanya sehingga ia menjadi sangat hitam, yaitu seperti gelapnya malam.\""},"4269":{"ar":"حَدَّثَنَا الْخَلِيلُ بْنُ عَمْرٍو حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ الْحَرَّانِيُّ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ حُمَيْدٍ الطَّوِيلِ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُؤْتَى يَوْمَ الْقِيَامَةِ بِأَنْعَمِ أَهْلِ الدُّنْيَا مِنْ الْكُفَّارِ فَيُقَالُ اغْمِسُوهُ فِي النَّارِ غَمْسَةً فَيُغْمَسُ فِيهَا ثُمَّ يُقَالُ لَهُ أَيْ فُلَانُ هَلْ أَصَابَكَ نَعِيمٌ قَطُّ فَيَقُولُ لَا مَا أَصَابَنِي نَعِيمٌ قَطُّ وَيُؤْتَى بِأَشَدِّ الْمُؤْمِنِينَ ضُرًّا وَبَلَاءً فَيُقَالُ اغْمِسُوهُ غَمْسَةً فِي الْجَنَّةِ فَيُغْمَسُ فِيهَا غَمْسَةً فَيُقَالُ لَهُ أَيْ فُلَانُ هَلْ أَصَابَكَ ضُرٌّ قَطُّ أَوْ بَلَاءٌ فَيَقُولُ مَا أَصَابَنِي قَطُّ ضُرٌّ وَلَا بَلَاءٌ","id":"Telah menceritakan kepada kami [Al Khalil bin 'Amru] telah menceritakan kepada kami [Muhammad bin Salamah Al Harrani] dari [Muhammad bin Ishaq] dari [Humaid At Thawil] dari [Anas bin Malik] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pada hari Kiamat, akan didatangkan seorang kafir yang paling merasakan ni'mat ketika di dunia, lalu di katakan; \"Celupkanlah ia ke dalam neraka!.\" Maka ia pun di tenggelamkan ke dalam neraka. Kemudian dikatakan kepadanya; \"Wahai fulan, apakah kamu mendapatkan sedikit keni'matan?.\" Ia menjawab; \"Tidak, saya tidak pernah merasakan kenikmatan sama sekali.\" Kemudian di datangkan seorang mukmin yang paling menderita dan paling berat coba'annya (ketika di dunia), lalu di katakan (kepadanya); \"Masukkanlah ia ke dalam surga!.\" Maka ia pun di masukkan ke dalam surga. Kemudian di tanyakan kepadanya; \"Hai fulan, apakah kamu merasakan sedikit penderitaan atau cobaan?\" ia menjawab; \"Tidak, tidak sedikitpun saya merasakan penderitaan atau cobaan.\""},"4270":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا بَكْرُ بْنُ عَبْدِ الرَّحْمَنِ حَدَّثَنَا عِيسَى بْنُ الْمُخْتَارِ عَنْ مُحَمَّدِ بْنِ أَبِي لَيْلَى عَنْ عَطِيَّةَ الْعَوْفِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْكَافِرَ لَيَعْظُمُ حَتَّى إِنَّ ضِرْسَهُ لَأَعْظَمُ مِنْ أُحُدٍ وَفَضِيلَةُ جَسَدِهِ عَلَى ضِرْسِهِ كَفَضِيلَةِ جَسَدِ أَحَدِكُمْ عَلَى ضِرْسِهِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Bakar bin Abdurrahman] telah menceritakan kepada kami [Isa bin Al Muhtar] dari [Muhammad bin Abu Laila] dari ['Athiyah Al 'Aufi] dari [Abu Sa'id Al Khudri] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Sesungguhnya orang-orang kafir akan membesar, sehingga gigi gerahamnya lebih besar daripada gunung uhud, dan besarnya antara badannya dengan gigi gerahamnya (penduduk neraka) sebagaimana besarnya antara badan kalian dengan gigi geraham kalian.\""},"4271":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ الرَّحِيمِ بْنُ سُلَيْمَانَ عَنْ دَاوُدَ بْنِ أَبِي هِنْدٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ قَيْسٍ قَالَكُنْتُ عِنْدَ أَبِي بُرْدَةَ ذَاتَ لَيْلَةٍ فَدَخَلَ عَلَيْنَا الْحَارِثُ بْنُ أُقَيْشٍ فَحَدَّثَنَا الْحَارِثُ لَيْلَتَئِذٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ مِنْ أُمَّتِي مَنْ يَدْخُلُ الْجَنَّةَ بِشَفَاعَتِهِ أَكْثَرُ مِنْ مُضَرَ وَإِنَّ مِنْ أُمَّتِي مَنْ يَعْظُمُ لِلنَّارِ حَتَّى يَكُونَ أَحَدَ زَوَايَاهَا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdurrahim bin Sulaiman] dari [Daud bin Abu Hind] telah menceritakan kepada kami [Abdullah bin Qais] dia berkata; Di suatu malam, ketika saya berada di samping Abu Burdah, tiba-tiba [Al Harits bin 'Uqais] masuk menemui kami, pada malam itu juga dia menceritakan bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya di antara ummatku yang masuk surga karena syafa'atku lebih banyak dari Kabilah Mudlar, dan di antara ummatku ada yang terlalu besar bagi neraka hingga mencapai salah satu tepinya.\""},"4272":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ عَنْ الْأَعْمَشِ عَنْ يَزِيدَ الرَّقَاشِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُرْسَلُ الْبُكَاءُ عَلَى أَهْلِ النَّارِ فَيَبْكُونَ حَتَّى يَنْقَطِعَ الدُّمُوعُ ثُمَّ يَبْكُونَ الدَّمَ حَتَّى يَصِيرَ فِي وُجُوهِهِمْ كَهَيْئَةِ الْأُخْدُودِ لَوْ أُرْسِلَتْ فِيهَا السُّفُنُ لَجَرَتْ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [Muhammad bin 'Ubaid] dari [Al A'masy] dari [Yazid Ar Raqasy] dari [Anas bin Malik] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tangisan dikirimkan kepada penduduk neraka, sehingga penduduknya menangis semua di dalamnya, sampai air mata mereka habis, kemudian mereka menagis dengan air mata darah yang keluar dari wajah-wajah mereka sehingga air-air itu terbentang di hadapan mereka seperti sungai yang jika di datangkan kapal, niscaya kapal-kapal itu akan berlayar di dalamnya.\""},"4273":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ شُعْبَةَ عَنْ سُلَيْمَانَ عَنْ مُجَاهِدٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَرَأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ يَا أَيُّهَا الَّذِينَ آمَنُوا اتَّقُوا اللَّهَ حَقَّ تُقَاتِهِ وَلَا تَمُوتُنَّ إِلَّا وَأَنْتُمْ مُسْلِمُونَ }وَلَوْ أَنَّ قَطْرَةً مِنْ الزَّقُّومِ قَطَرَتْ فِي الْأَرْضِ لَأَفْسَدَتْ عَلَى أَهْلِ الدُّنْيَا مَعِيشَتَهُمْ فَكَيْفَ بِمَنْ لَيْسَ لَهُ طَعَامٌ غَيْرُهُ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Ibnu Abu 'Adi] dari [Syu'bah] dari [Sulaiman] dari [Mujahid] dari [Ibnu Abbas] dia berkata; Rasulullah shallallahu 'alaihi wasallam membaca: \"Wahai orang-orang yang beriman, janganlah kalian mati kecuali jika kalian benar-benar telah berserah diri, sekiranya tetesan dari buah Zaqum menetes di bumi, sungguh ia akan merusak kehidupan penduduk bumi, lalu bagaimana jika tidak ada makanan selain dari buah tersebut?.\""},"4274":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَادَةَ الْوَاسِطِيُّ حَدَّثَنَا يَعْقُوبُ بْنُ مُحَمَّدٍ الزُّهْرِيُّ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ الزُّهْرِيِّ عَنْ عَطَاءِ بْنِ يَزِيدَ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تَأْكُلُ النَّارُ ابْنَ آدَمَ إِلَّا أَثَرَ السُّجُودِ حَرَّمَ اللَّهُ عَلَى النَّارِ أَنْ تَأْكُلَ أَثَرَ السُّجُودِ","id":"Telah menceritakan kepada kami [Muhammad bin 'Ubadah Al Washithi] telah menceritakan kepada kami [Ya'qub bin Muhammad Az Zuhri] telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Az Zuhri] dari ['Atha` bin Yazid] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Api neraka akan membakar anak Adam, kecuali mereka yang terdapat bekas sujud, sebab Allah mengharamkan api neraka untuk membakar bekas sujud.\""},"4275":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُؤْتَى بِالْمَوْتِ يَوْمَ الْقِيَامَةِ فَيُوقَفُ عَلَى الصِّرَاطِ فَيُقَالُ يَا أَهْلَ الْجَنَّةِ فَيَطَّلِعُونَ خَائِفِينَ وَجِلِينَ أَنْ يُخْرَجُوا مِنْ مَكَانِهِمْ الَّذِي هُمْ فِيهِ ثُمَّ يُقَالُ يَا أَهْلَ النَّارِ فَيَطَّلِعُونَ مُسْتَبْشِرِينَ فَرِحِينَ أَنْ يُخْرَجُوا مِنْ مَكَانِهِمْ الَّذِي هُمْ فِيهِ فَيُقَالُ هَلْ تَعْرِفُونَ هَذَا قَالُوا نَعَمْ هَذَا الْمَوْتُ قَالَ فَيُؤْمَرُ بِهِ فَيُذْبَحُ عَلَى الصِّرَاطِ ثُمَّ يُقَالُ لِلْفَرِيقَيْنِ كِلَاهُمَا خُلُودٌ فِيمَا تَجِدُونَ لَا مَوْتَ فِيهَا أَبَدًا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Muhammad bin Bisyr] dari [Muhammad bin 'Amru] dari [Abu Salamah] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ketika hari Kiamat terjadi, maka akan di datangkan kematian. Lalu ia di berhentikan di tengah jembatan shirath. Maka di katakan; \"Wahai penghuni surga.\" Mereka menoleh di sertai dengan rasa takut akan di keluarkan dari tempat mereka berada. Kemudian di katakan; \"Wahai penghuni Neraka.\" Maka mereka menoleh di sertai rasa gembira dan bangga akan di keluarkan dari tempat mereka berada. Lalu di katakan; \"Apakah kalian mengetahui ini?\" mereka menjawab; \"Ya, itu adalah kematian.\" (Rasulullah bersabda): \"Maka di perintahkanlah agar kematian itu di datangkan. Lalu ia di sembelih di atas jembatan shirath. Lalu di katakan kepada kedua kkelompok itu; \"Kekallah (kalian) di tempat yang kalian dapatkan, dan tidak akan pernah ada lagi kematian di dalamnya.\""},"4276":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَقَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُ عَزَّ وَجَلَّ أَعْدَدْتُ لِعِبَادِيَ الصَّالِحِينَ مَا لَا عَيْنٌ رَأَتْ وَلَا أُذُنٌ سَمِعَتْ وَلَا خَطَرَ عَلَى قَلْبِ بَشَرٍقَالَ أَبُو هُرَيْرَةَ وَمِنْ بَلْهَ مَا قَدْ أَطْلَعَكُمْ اللَّهُ عَلَيْهِ اقْرَءُوا إِنْ شِئْتُمْ{ فَلَا تَعْلَمُ نَفْسٌ مَا أُخْفِيَ لَهُمْ مِنْ قُرَّةِ أَعْيُنٍ جَزَاءً بِمَا كَانُوا يَعْمَلُونَ }قَالَ وَكَانَ أَبُو هُرَيْرَةَ يَقْرَؤُهَا مِنْ قُرَّاتِ أَعْيُنٍ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah 'azza wajalla berfirman; \"Aku persiapkan untuk hamba-hamba-Ku yang Shalih sesuatu yang tidak pernah dilihat oleh mata, tidak pernah di dengar oleh telinga, dan tidak pernah terlintas pada hati manusia.\" Abu Hurairah berkata; \"Barangsiapa di antara kalian yang benaknya telah di perlihatkan, maka bacalah, jika kalian mau: \"Seorangpun tidak akan mengetahui apa yang disembunyikan bagi mereka yaitu (bemacam-macam nikmat) yang menyedapkan pandangan mata, sebagai balasan terhadap apa yang telah mereka kerjakan.\" QS As Sajdah; 17."},"4277":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ حَجَّاجٍ عَنْ عَطِيَّةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَشِبْرٌ فِي الْجَنَّةِ خَيْرٌ مِنْ الْأَرْضِ وَمَا عَلَيْهَا الدُّنْيَا وَمَا فِيهَا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Hajjaj] dari ['Athiyah] dari [Abu Sa'id Al Khudri] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Sungguh satu jengkal didalam surga lebih baik daripada bumi dan apa-apa yang ada di muka bumi serta seluruh isinya.\""},"4278":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا زَكَرِيَّا بْنُ مَنْظُورٍ حَدَّثَنَا أَبُو حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَوْضِعُ سَوْطٍ فِي الْجَنَّةِ خَيْرٌ مِنْ الدُّنْيَا وَمَا فِيهَا","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Zakariya` bin Mandzur] telah menceritakan kepada kami [Abu Hazim] dari [Sahl bin Sa'd] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tempat cambuk di surga, lebih baik daripada dunia seisinya.\""},"4279":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ عُثْمَانَ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا مُحَمَّدُ بْنُ مُهَاجِرٍ الْأَنْصَارِيُّ حَدَّثَنِي الضَّحَّاكُ الْمَعَافِرِيُّ عَنْ سُلَيْمَانَ بْنِ مُوسَى عَنْ كُرَيْبٍ مَوْلَى ابْنِ عَبَّاسٍ قَالَ حَدَّثَنِي أُسَامَةُ بْنُ زَيْدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ يَوْمٍ لِأَصْحَابِهِ أَلَا مُشَمِّرٌ لِلْجَنَّةِ فَإِنَّ الْجَنَّةَ لَا خَطَرَ لَهَا هِيَ وَرَبِّ الْكَعْبَةِ نُورٌ يَتَلَأْلَأُ وَرَيْحَانَةٌ تَهْتَزُّ وَقَصْرٌ مَشِيدٌ وَنَهَرٌ مُطَّرِدٌ وَفَاكِهَةٌ كَثِيرَةٌ نَضِيجَةٌ وَزَوْجَةٌ حَسْنَاءُ جَمِيلَةٌ وَحُلَلٌ كَثِيرَةٌ فِي مَقَامٍ أَبَدًا فِي حَبْرَةٍ وَنَضْرَةٍ فِي دُورٍ عَالِيَةٍ سَلِيمَةٍ بَهِيَّةٍ قَالُوا نَحْنُ الْمُشَمِّرُونَ لَهَا يَا رَسُولَ اللَّهِ قَالَ قُولُوا إِنْ شَاءَ اللَّهُ ثُمَّ ذَكَرَ الْجِهَادَ وَحَضَّ عَلَيْهِ","id":"Telah menceritakan kepada kami [Al 'Abbas bin 'Utsman Ad Dimasyqi] telah menceritakan kepada kami [Al Walid bin Muslim] telah menceritakan kepada kami [Muhammad bin Muihajir Al Anshari] telah menceritakan kepadaku [Adl Dlahak Al Ma'afiri] dari [Sulaiman bin Musa] dari [Kuraib bekas budak Ibnu Abbas] dia berkata; telah menceritakan kepada kami [Usamah bin Zaid] dia berkata; Suatu hari Rasulullah shallallahu 'alaihi wasallam bersabda kepada para sahabatnya: \"Mengapa kalian tidak bersiap-siap masuk surga? Padahal kenikmatan di surga itu tidak terbayangkan. Demi pemilik Ka'bah, surga itu adalah cahaya yang menyala-nyala dan berbau harum, memiliki istana yang kokoh, sungai yang luas, buah-buahan yang banyak lagi harum, pasangan suami isteri yang gagah dan cantik, serta pakaian yang bagus lagi indah, di tempat yang kekal dan indah, di tingkat-tingkat yang tinggi lagi terpuji.\" Mereka menjawab; \"Kami bersiap-siap wahai Rasulullah.\" Beliau bersabda: \"Katakanlah oleh kalian \"Insya Allah (jika Allah menghendaki).\" Kemudian beliau menyebutkan keutamaan jihad dan menyerukannya.\""},"4280":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ عُمَارَةَ بْنِ الْقَعْقَاعِ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوَّلُ زُمْرَةٍ تَدْخُلُ الْجَنَّةَ عَلَى صُورَةِ الْقَمَرِ لَيْلَةَ الْبَدْرِ ثُمَّ الَّذِينَ يَلُونَهُمْ عَلَى ضَوْءِ أَشَدِّ كَوْكَبٍ دُرِّيٍّ فِي السَّمَاءِ إِضَاءَةً لَا يَبُولُونَ وَلَا يَتَغَوَّطُونَ وَلَا يَمْتَخِطُونَ وَلَا يَتْفُلُونَ أَمْشَاطُهُمْ الذَّهَبُ وَرَشْحُهُمْ الْمِسْكُ وَمَجَامِرُهُمْ الْأَلُوَّةُ أَزْوَاجُهُمْ الْحُورُ الْعِينُ أَخْلَاقُهُمْ عَلَى خُلُقِ رَجُلٍ وَاحِدٍ عَلَى صُورَةِ أَبِيهِمْ آدَمَ سِتُّونَ ذِرَاعًاحَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ مِثْلَ حَدِيثِ ابْنِ فُضَيْلٍ عَنْ عُمَارَةَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Muhammad bin Al Fudlail] dari [Al 'Umarah bin Al Qa'qa'] dari [Abu Zur'ah] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kelompok pertama yang masuk surga adalah sebagaimana bentuk bulan dimalam purnama, kemudian kelompok yang setelahnya adalah dalam bentuk sinar bintang cahaya yang paling terang; mereka tidak kencing dan juga tidak buang air besar, tidak beringus dan tidak pula meludah. Sisirnya mereka terbuat dari emas dan parfum mereka dari misik, bara apinya dari batang kayu yang wangi, pasangan-pasangan mereka adalah bidadari, akhlak mereka seperti akhlak satu orang dalam bentuk bapak mereka yaitu Adam, setinggi enam puluh hasta.\" Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] seperti hadits [Ibnu Fudlail] dari ['Umarah]."},"4281":{"ar":"حَدَّثَنَا أَبُو عُمَرَ الضَّرِيرُ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ عُثْمَانَ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ فِي الْجَنَّةِ شَجَرَةً يَسِيرُ الرَّاكِبُ فِي ظِلِّهَا مِائَةَ سَنَةٍ لَا يَقْطَعُهَا وَاقْرَءُوا إِنْ شِئْتُمْ{ وَظِلٍّ مَمْدُودٍ وَمَاءٍ مَسْكُوبٍ }","id":"Telah menceritakan kepada kami [Abu Umar Adl Dlarir] telah menceritakan kepada kami [Abdurrahman bin 'Utsman] dari [Muhammad bin 'Amru] dari [Abu Salamah] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya di dalam surga terdapat pohon yang apabila ada seorang penunggang kuda berjalan di bawah naungannya selama seratus tahun, ia tidak akan mampu mencapainya. Bacalah jika kalian mau; \"Dan naungan yang terbentang luas dan air yang tercurah.\" QS Al Waqi'ah; 30-31."},"4282":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ حَبِيبِ بْنِ أَبِي الْعِشْرِينَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ عَمْرٍو الْأَوْزَاعِيُّ حَدَّثَنِي حَسَّانُ بْنُ عَطِيَّةَ حَدَّثَنِي سَعِيدُ بْنُ الْمُسَيَّبِأَنَّهُ لَقِيَ أَبَا هُرَيْرَةَ فَقَالَ أَبُو هُرَيْرَةَ أَسْأَلُ اللَّهَ أَنْ يَجْمَعَ بَيْنِي وَبَيْنَكَ فِي سُوقِ الْجَنَّةِ قَالَ سَعِيدٌ أَوَ فِيهَا سُوقٌ قَالَ نَعَمْ أَخْبَرَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ أَهْلَ الْجَنَّةِ إِذَا دَخَلُوهَا نَزَلُوا فِيهَا بِفَضْلِ أَعْمَالِهِمْ فَيُؤْذَنُ لَهُمْ فِي مِقْدَارِ يَوْمِ الْجُمُعَةِ مِنْ أَيَّامِ الدُّنْيَا فَيَزُورُونَ اللَّهَ عَزَّ وَجَلَّ وَيُبْرِزُ لَهُمْ عَرْشَهُ وَيَتَبَدَّى لَهُمْ فِي رَوْضَةٍ مِنْ رِيَاضِ الْجَنَّةِ فَتُوضَعُ لَهُمْ مَنَابِرُ مِنْ نُورٍ وَمَنَابِرُ مِنْ لُؤْلُؤٍ وَمَنَابِرُ مِنْ يَاقُوتٍ وَمَنَابِرُ مِنْ زَبَرْجَدٍ وَمَنَابِرُ مِنْ ذَهَبٍ وَمَنَابِرُ مِنْ فِضَّةٍ وَيَجْلِسُ أَدْنَاهُمْ وَمَا فِيهِمْ دَنِيءٌ عَلَى كُثْبَانِ الْمِسْكِ وَالْكَافُورِ مَا يُرَوْنَ أَنَّ أَصْحَابَ الْكَرَاسِيِّ بِأَفْضَلَ مِنْهُمْ مَجْلِسًا قَالَ أَبُو هُرَيْرَةَ قُلْتُ يَا رَسُولَ اللَّهِ هَلْ نَرَى رَبَّنَا قَالَ نَعَمْ هَلْ تَتَمَارَوْنَ فِي رُؤْيَةِ الشَّمْسِ وَالْقَمَرِ لَيْلَةَ الْبَدْرِ قُلْنَا لَا قَالَ كَذَلِكَ لَا تَتَمَارَوْنَ فِي رُؤْيَةِ رَبِّكُمْ عَزَّ وَجَلَّ وَلَا يَبْقَى فِي ذَلِكَ الْمَجْلِسِ أَحَدٌ إِلَّا حَاضَرَهُ اللَّهُ عَزَّ وَجَلَّ مُحَاضَرَةً حَتَّى إِنَّهُ يَقُولُ لِلرَّجُلِ مِنْكُمْ أَلَا تَذْكُرُ يَا فُلَانُ يَوْمَ عَمِلْتَ كَذَا وَكَذَا يُذَكِّرُهُ بَعْضَ غَدَرَاتِهِ فِي الدُّنْيَا فَيَقُولُ يَا رَبِّ أَفَلَمْ تَغْفِرْ لِي فَيَقُولُ بَلَى فَبِسَعَةِ مَغْفِرَتِي بَلَغْتَ مَنْزِلَتَكَ هَذِهِ فَبَيْنَمَا هُمْ كَذَلِكَ غَشِيَتْهُمْ سَحَابَةٌ مِنْ فَوْقِهِمْ فَأَمْطَرَتْ عَلَيْهِمْ طِيبًا لَمْ يَجِدُوا مِثْلَ رِيحِهِ شَيْئًا قَطُّ ثُمَّ يَقُولُ قُومُوا إِلَى مَا أَعْدَدْتُ لَكُمْ مِنْ الْكَرَامَةِ فَخُذُوا مَا اشْتَهَيْتُمْ قَالَ فَنَأْتِي سُوقًا قَدْ حُفَّتْ بِهِ الْمَلَائِكَةُ فِيهِ مَا لَمْ تَنْظُرْ الْعُيُونُ إِلَى مِثْلِهِ وَلَمْ تَسْمَعْ الْآذَانُ وَلَمْ يَخْطُرْ عَلَى الْقُلُوبِ قَالَ فَيُحْمَلُ لَنَا مَا اشْتَهَيْنَا لَيْسَ يُبَاعُ فِيهِ شَيْءٌ وَلَا يُشْتَرَى وَفِي ذَلِكَ السُّوقِ يَلْقَى أَهْلُ الْجَنَّةِ بَعْضُهُمْ بَعْضًا فَيُقْبِلُ الرَّجُلُ ذُو الْمَنْزِلَةِ الْمُرْتَفِعَةِ فَيَلْقَى مَنْ هُوَ دُونَهُ وَمَا فِيهِمْ دَنِيءٌ فَيَرُوعُهُ مَا يَرَى عَلَيْهِ مِنْ اللِّبَاسِ فَمَا يَنْقَضِي آخِرُ حَدِيثِهِ حَتَّى يَتَمَثَّلَ لَهُ عَلَيْهِ أَحْسَنُ مِنْهُ وَذَلِكَ أَنَّهُ لَا يَنْبَغِي لِأَحَدٍ أَنْ يَحْزَنَ فِيهَا قَالَ ثُمَّ نَنْصَرِفُ إِلَى مَنَازِلِنَا فَتَلْقَانَا أَزْوَاجُنَا فَيَقُلْنَ مَرْحَبًا وَأَهْلًا لَقَدْ جِئْتَ وَإِنَّ بِكَ مِنْ الْجَمَالِ وَالطِّيبِ أَفْضَلَ مِمَّا فَارَقْتَنَا عَلَيْهِ فَنَقُولُ إِنَّا جَالَسْنَا الْيَوْمَ رَبَّنَا الْجَبَّارَ عَزَّ وَجَلَّ وَيَحِقُّنَا أَنْ نَنْقَلِبَ بِمِثْلِ مَا انْقَلَبْنَا","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Abdul Hamid bin Habib bin Abu Al 'Iysrin] telah menceritakan kepadaku [Abdurrahman bin 'Amru Al Auza'i] telah menceritakan kepadaku [Hasan bin 'Athiyah] telah menceritakan kepadaku [Sa'id bin Al Musayyab] bawha dia bertemu dengan Abu Hurairah, maka [Abu Hurairah] berkata: Aku mengharap kepada Allah semoga menyatukanku denganmu di pasar surga.\" Sa'id bertanya: \"Apakah disana ada pasar?\" Abu Hurairah menjawab: Ya, telah mengkhabarkan kepadaku Rasulullah shallallahu 'alaihi wasallam bahwa penghuni surga bila masuk surga, mereka tinggal di sana karena keutamaan amal-amal mereka, kemudian diizinkan pada hari jum'at dari hari-hari dunia lalu mereka mengunjungi Allah 'azza wajalla, maka Dia menampakkan 'arsy-Nya pada mereka, dan menampakkannya kepada mereka di salah satu taman dari taman-taman surga, sedangkan mimbar-mimbar dari cahaya, mimbar-mimbar dari mutiara, mimbar-mimbar dari yaqut, mimbar-mimbar dari permata, mimbar-mimbar dari emas, mimbar-mimbar dari perak diletakkan untuk mereka, yang paling rendah di antara mereka beserta tingkat kerendahannya duduk di atas gundukan tanah kesturi dan kafur dan mereka tidak menilai tempat duduk para pemilik kursi lebih baik dari mereka.\" Abu Hurairah berkata; lalu saya bertanya; \"Wahai Rasulullah, apakah kita akan melihat Rabb kita?\" Beliau menjawab: \"Ya.\" Rasulullah shallallahu 'alaihi wasallam bertanya: \"Apakah kalian saling berbantahan saat melihat matahari dan bulan dimalam purnama?\" Kami menjawab: \"Tidak.\" Beliau bersabda: \"Seperti itu juga kalian tidak berbantahan dalam melihat Rabb kalian. Dan dimajlis itu tidak ada seorang pun melainkan Allah akan mendatanginya dengan sebenarnya hingga Dia akan bertanya kepada salah seorang dari kalian: \"Hai fulan, tidak ingatkah kau saat berkata begini dan begini?\" Allah mengingatkan sebagian kemaksiatan-kemaksiatannya ketika di dunia. Orang itu menjawab: \"Wahai Rabb, tidakkah Engkau mengampuniku?\" Allah menjawab: \"Ya, Demi luasnya ampunan-Ku sampai pada tempatmu ini.\" Saat mereka seperti itu, mega menaungi di atas mereka lalu turun hujan minyak wangi yang baunya sama sekali belum pernah mereka temukan, kemudian Dia berfirman: \"Berdirilah menuju kemuliaan yang telah Aku persiapkan untuk kalian, lalu ambillah yang kalian inginkan.\" Beliau bersabda: \"Lalu kami mendatangi pasar yang diliputi oleh Malaikat, di dalamnya ada yang belum pernah dilihat mata sama sekali, belum pernah terdengar oleh telinga dan tidak terlintas dihati.\" Beliau meneruskan: \"Lalu apa yang kami inginkan dibawakan untuk kami, di sana tidak dijual dan tidak juga dibeli. Di pasar itu, para penghuni surga saling bertemu satu sama lain. Seseorang yang memiliki derajat tinggi datang lalu bertemu dengan orang yang tingkatnya berada dibawahnya beserta kerendahan yang ada padanya, lalu ia gentar pada pakaian yang diperlihatkan padanya, akhir kata-katanya belum juga habis hingga ia berhayal yang lebih baik darinya, itu karena tidak layak bagi siapa pun untuk bersedih di surga. Setelah itu kami pulang ke rumah-rumah kami, kami disambut oleh isteri-isteri kami, mereka berkata: \"Selamat datang, kamu telah datang dengan keindahan yang lebih baik dari saat kamu meninggalkan kami. Kami menjawab: \"Sesungguhnya hari ini kami menemani Rabb kami Al Jabbar 'azza wajalla, dan tak layak bagi kami untuk pulang seperti ini.\""},"4283":{"ar":"حَدَّثَنَا هِشَامُ بْنُ خَالِدٍ الْأَزْرَقُ أَبُو مَرْوَانَ الدِّمَشْقِيُّ حَدَّثَنَا خَالِدُ بْنُ يَزِيدَ بْنِ أَبِي مَالِكٍ عَنْ أَبِيهِ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ أَبِي أُمَامَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ أَحَدٍ يُدْخِلُهُ اللَّهُ الْجَنَّةَ إِلَّا زَوَّجَهُ اللَّهُ عَزَّ وَجَلَّ ثِنْتَيْنِ وَسَبْعِينَ زَوْجَةً ثِنْتَيْنِ مِنْ الْحُورِ الْعِينِ وَسَبْعِينَ مِنْ مِيرَاثِهِ مِنْ أَهْلِ النَّارِ مَا مِنْهُنَّ وَاحِدَةٌ إِلَّا وَلَهَا قُبُلٌ شَهِيٌّ وَ��َهُ ذَكَرٌ لَا يَنْثَنِيقَالَ هِشَامُ بْنُ خَالِدٍ مِنْ مِيرَاثِهِ مِنْ أَهْلِ النَّارِ يَعْنِي رِجَالًا دَخَلُوا النَّارَ فَوَرِثَ أَهْلُ الْجَنَّةِ نِسَاءَهُمْ كَمَا وُرِثَتْ امْرَأَةُ فِرْعَوْنَ","id":"Telah menceritakan kepada kami [Hisyam bin Khalid Al Azraq Abu Marwan Ad Dimasyqi] telah menceritakan kepada kami [Khalid bin Yazid bin Abu Malik] dari [ayahnya] dari [Khalid bin Ma'dan] dari [Abu Umamah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang hamba yang dimasukkan ke dalam surga melainkan Allah 'azza wajalla akan menikahkan dengan tujuh puluh dua istri, dua istri dari bidadari dan yang tujuh puluh dari warisannya penduduk neraka (isterinya penghuni neraka yang masuk surga), dan tidaklah salah seorang dari mereka melainkan memiliki vagina yang rapat dan ia memiliki penis yang tidak loyo.\" Khalid bin Hisyam berkata; Maksud dari warisannya penduduk neraka adalah laki-laki yang masuk neraka kemudian mereka mewarisi isterinya untuk penghuni surga sebagaimana fir'aun mewarisi isterinya.\""},"4284":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَبِيدَةَ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي لَأَعْلَمُ آخِرَ أَهْلِ النَّارِ خُرُوجًا مِنْهَا وَآخِرَ أَهْلِ الْجَنَّةِ دُخُولًا الْجَنَّةَ رَجُلٌ يَخْرُجُ مِنْ النَّارِ حَبْوًا فَيُقَالُ لَهُ اذْهَبْ فَادْخُلْ الْجَنَّةَ فَيَأْتِيهَا فَيُخَيَّلُ إِلَيْهِ أَنَّهَا مَلْأَى فَيَرْجِعُ فَيَقُولُ يَا رَبِّ وَجَدْتُهَا مَلْأَى فَيَقُولُ اللَّهُ اذْهَبْ فَادْخُلْ الْجَنَّةَ فَيَأْتِيهَا فَيُخَيَّلُ إِلَيْهِ أَنَّهَا مَلْأَى فَيَرْجِعُ فَيَقُولُ يَا رَبِّ وَجَدْتُهَا مَلْأَى فَيَقُولُ اللَّهُ سُبْحَانَهُ اذْهَبْ فَادْخُلْ الْجَنَّةَ فَيَأْتِيهَا فَيُخَيَّلُ إِلَيْهِ أَنَّهَا مَلْأَى فَيَرْجِعُ فَيَقُولُ يَا رَبِّ إِنَّهَا مَلْأَى فَيَقُولُ اللَّهُ اذْهَبْ فَادْخُلْ الْجَنَّةَ فَإِنَّ لَكَ مِثْلَ الدُّنْيَا وَعَشَرَةَ أَمْثَالِهَا أَوْ إِنَّ لَكَ مِثْلَ عَشَرَةِ أَمْثَالِ الدُّنْيَا فَيَقُولُ أَتَسْخَرُ بِي أَوْ أَتَضْحَكُ بِي وَأَنْتَ الْمَلِكُ قَالَ فَلَقَدْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ضَحِكَ حَتَّى بَدَتْ نَوَاجِذُهُ فَكَانَ يُقَالُ هَذَا أَدْنَى أَهْلِ الْجَنَّةِ مَنْزِلًا","id":"Telah menceritakan kepada kami ['Utsman bin Abu Syaibah] telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Ibrahim] dari ['Abidah] dari [Abdullah bin Mas'ud] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh aku mengetahui penghuni neraka yang terakhir keluar darinya, dan penghuni surga yang terakhir masuk ke dalam surga, yaitu; laki-laki yang keluar dari neraka dengan merangkak, maka di katakan kepadanya; \"Pergilah dan masuklah ke dalam surga.\" Ia pun mendatanginya, maka di khayalkan kepadanya bahwa itu adalah padang sahara. Maka ia kembali seraya berkata; \"Wahai Rabb, aku mendapatkannya padang sahara.\" Maka Allah berfirman; \"Pergilah dan masuklah ke dalam surga.\" Ia pun mendatanginya, maka di khayalkan kepadanya bahwa itu adalah padang sahara. Maka ia kembali seraya berkata; \"Wahai Rabb, aku mendapatkannya padang sahara.\" Maka Allah Subhanahu berfirman; \"Pergilah dan masuklah ke dalam surga.\" Ia pun mendatanginya, maka di khayalkan kepadanya bahwa itu adalah padang sahara. Maka ia kembali seraya berkata; \"Wahai Rabb, aku mendapatkannya padang sahara.\" Maka Allah berfirman; \"Pergilah dan masuklah ke surga, maka bagimu seperti dunia dan sepuluh yang serupa dengannya -atau sesungguhnya baginya sepuluh kali lipat yang seperti dunia- maka orang itu berkata; \"Apakah Engkau mengejekku ataukah amenertaewaiku -sedangkan Engkau adalah sang Raja?\" Abdullah bin Mas'ud berkata; \"Aku melihat Rasulullah shallallahu 'alaihi wasallam tertawa sehingga nampak gigi serinya.\" Maka di katakan; \"Ini adalah penghuni surga yang paling rendah kedudukannya.\""},"4285":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ أَبِي إِسْحَقَ عَنْ يَزِيدَ بْنِ أَبِي مَرْيَمَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ سَأَلَ الْجَنَّةَ ثَلَاثَ مَرَّاتٍ قَالَتْ الْجَنَّةُ اللَّهُمَّ أَدْخِلْهُ الْجَنَّةَ وَمَنْ اسْتَجَارَ مِنْ النَّارِ ثَلَاثَ مَرَّاتٍ قَالَتْ النَّارُ اللَّهُمَّ أَجِرْهُ مِنْ النَّارِ","id":"Telah menceritakan kepada kami [Hannad bin As Sari] telah menceritakan kepada kami [Abu Al Ahwash] dari [Abu Ishaq] dari [Yazid bin Abu Maryam] dari [Anas bin Malik] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa meminta surga kepada Allah sebanyak tiga kali, maka surga akan berkata; \"Ya Allah, masukkanlah ia ke dalam surga.\" Dan barangsiapa meminta di jauhkan dari api neraka tiga kali, maka neraka akan berkata; \"Ya Allah, jauhkanlah ia dari api neraka.\""}};
